export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export enum UserRole {
  ADMIN = 'ADMIN',
  MEMBER = 'MEMBER',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  role: UserRole;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  budgetLimit: number; // 0 means no limit
  color: string;
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
  date: string; // ISO string
  description: string;
  photoUrl?: string;
  location?: GeoLocation;
}

export interface BudgetStatus {
  categoryId: string;
  spent: number;
  limit: number;
  percentage: number;
  status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED';
}

import { GoogleGenAI, Type } from "@google/genai";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

export const analyzeReceiptImage = async (base64Image: string): Promise<{ amount: number; description: string; date: string; categoryGuess: string }> => {
  try {
    const ai = getAiClient();
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: cleanBase64,
            },
          },
          {
            text: "Analyze this receipt image. Extract the total amount, the date (ISO format YYYY-MM-DD), a short description (merchant name), and guess a generic category (e.g., Food, Transport, Shopping).",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            description: { type: Type.STRING },
            categoryGuess: { type: Type.STRING },
          },
          required: ["amount", "date", "description", "categoryGuess"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Receipt analysis failed:", error);
    throw error;
  }
};

export const getSpendingAdvice = async (
  summary: string
): Promise<string> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `You are a financial advisor. Analyze this spending summary and give 3 short, bulleted tips in Korean: ${summary}`,
      config: {
        systemInstruction: "Keep it encouraging and concise. Use Korean language.",
      }
    });
    return response.text || "조언을 생성할 수 없습니다.";
  } catch (error) {
    console.error("Advice generation failed:", error);
    return "AI 조언을 가져오는 중 오류가 발생했습니다.";
  }
};

