          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-2xl font-bold text-gray-800 mt-1">
                {(totalIncome - totalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 수입</span>
              <div className="text-2xl font-bold text-emerald-600 mt-1">
                + {totalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 지출</span>
              <div className="text-2xl font-bold text-rose-600 mt-1">
                - {totalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* Charts Row */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {/* Pie Chart */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col">
               <h3 className="text-lg font-bold text-gray-800 mb-4">카테고리별 지출</h3>
               {chartData.length > 0 ? (
                 <>
                   <div className="h-64 w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={chartData}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            paddingAngle={5}
                            dataKey="value"
                            label={({ name, value }) => `${name} ${value.toLocaleString()}`}
                          >
                            {chartData.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                          </Pie>
                          <Tooltip formatter={(value: number) => `${value.toLocaleString()}원`} />
                        </PieChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="mt-6 flex flex-col gap-2">
                      <h4 className="text-sm font-semibold text-gray-500 mb-1">상세 지출 내역</h4>
                      {chartData.map((d, i) => (
                        <div key={i} className="flex items-center justify-between p-2 rounded-lg hover:bg-gray-50">
                          <div className="flex items-center gap-2">
                            <span className="w-3 h-3 rounded-full" style={{ backgroundColor: d.color }}></span>
                            <span className="text-sm font-medium text-gray-700">{d.name}</span>
                          </div>
                          <span className="text-sm font-bold text-gray-900">{d.value.toLocaleString()}원</span>
                        </div>
                      ))}
                    </div>
                 </>
               ) : (
                 <div className="h-64 flex items-center justify-center text-gray-400">데이터가 없습니다</div>
               )}
             </div>

             {/* Recent Quick List */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <h3 className="text-lg font-bold text-gray-800 mb-4">최근 내역</h3>
               <div className="space-y-4">
                 {filteredTransactions.slice(0, 4).map(tx => {
                   const user = users.find(u => u.id === tx.userId);
                   const category = categories.find(c => c.id === tx.categoryId);
                   return (
                     <div key={tx.id} className="flex items-center justify-between">
                       <div className="flex items-center gap-3">
                         <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center text-lg" style={{ color: category?.color }}>
                           {/* Simple Icon placeholder based on first char */}
                           {category?.name[0]}
                         </div>
                         <div>
                           <p className="font-semibold text-gray-800 text-sm">{tx.description}</p>
                           <p className="text-xs text-gray-400 flex items-center gap-1">
                             {user?.name} · {tx.date}
                             {tx.photoUrl && <ImageIcon size={12} className="text-brand-500" />}
                             {tx.location && <MapPin size={12} className="text-emerald-500" />}
                           </p>
                         </div>
                       </div>
                       <span className={`font-bold text-sm ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                         {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                       </span>
                     </div>
                   );
                 })}
                 {filteredTransactions.length === 0 && <p className="text-center text-gray-400 text-sm py-4">내역이 없습니다.</p>}
               </div>
             </div>
          </div>
        </div>
      )}

      {/* --- BUDGET TAB --- */}
      {activeTab === 'BUDGET' && (
        <div className="space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border mb-4">
            <h2 className="font-bold text-gray-800">예산 현황</h2>
            <p className="text-sm text-gray-500 mt-1">
              {viewMode === 'JOINT' ? '전체 예산 대비 사용량입니다.' : '개인 할당 예산(50%) 대비 사용량입니다.'}
            </p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {budgetStatuses.map((status) => {
              const category = categories.find(c => c.id === status.categoryId);
              if (!category) return null;
              return <BudgetCard key={status.categoryId} category={category} status={status} />;
            })}
          </div>
        </div>
      )}

      {/* --- HISTORY TAB --- */}
      {activeTab === 'HISTORY' && (
        <div className="space-y-4">
          {/* Date Selector */}
          <div className="bg-white p-4 rounded-xl shadow-sm border flex items-center justify-between sticky top-0 z-10">
            <button 
              onClick={handlePrevMonth} 
              className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition"
            >
              <ChevronLeft size={24} />
            </button>
            <div className="flex items-center gap-2 font-bold text-lg text-gray-800">
              <Calendar className="text-brand-600" size={20} />
              {historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월
            </div>
            <button 
              onClick={handleNextMonth} 
              className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition"
            >
              <ChevronRight size={24} />
            </button>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[50vh]">
            {historyTransactions.length > 0 ? (
              historyTransactions.map((tx, idx) => {
                  const user = users.find(u => u.id === tx.userId);
                  const category = categories.find(c => c.id === tx.categoryId);
                  return (
                    <div key={tx.id} className={`p-4 flex items-center justify-between hover:bg-gray-50 transition ${idx !== historyTransactions.length - 1 ? 'border-b' : ''}`}>
                      <div className="flex items-center gap-4">
                        <div className="relative">
                          <div className="w-12 h-12 rounded-xl bg-gray-100 flex items-center justify-center font-bold text-xl" style={{ color: category?.color, backgroundColor: `${category?.color}20` }}>
                            {category?.name[0]}
                          </div>
                          <div className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold" style={{ backgroundColor: user?.color }}>
                            {user?.name[0]}
                          </div>
                        </div>
                        <div>
                          <p className="font-bold text-gray-800">{tx.description}</p>
                          <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-xs text-gray-500 bg-gray-100 px-1.5 py-0.5 rounded">{category?.name}</span>
                            <span className="text-xs text-gray-400">{tx.date}</span>
                          </div>
                          <div className="flex gap-2 mt-1">
                            {tx.photoUrl && (
                              <div className="flex items-center gap-1 text-[10px] text-brand-600 bg-brand-50 px-1.5 rounded-full border border-brand-100">
                                <ImageIcon size={10} /> <span>영수증</span>
                              </div>
                            )}
                            {tx.location && (
                              <div className="flex items-center gap-1 text-[10px] text-emerald-600 bg-emerald-50 px-1.5 rounded-full border border-emerald-100">
                                <MapPin size={10} /> <span>{tx.location.address || '위치'}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className={`block font-bold text-lg ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-gray-800'}`}>
                          {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                        </span>
                        <span className="text-xs text-gray-400">원</span>
                      </div>
                    </div>
                  );
              })
            ) : (
              <div className="flex flex-col items-center justify-center h-48 text-gray-400">
                <p>선택하신 달의 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Add Modal */}
      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={handleAddTransaction}
          categories={categories}
          users={users}
          currentUser={currentUser}
        />
      )}
    </Layout>
  );
};

export default App;

