import React, { useState, useRef } from 'react';
import { Camera, MapPin, Loader2, X, Upload } from 'lucide-react';
import { TransactionType, Category, User, GeoLocation, UserRole } from '../types';
import { analyzeReceiptImage } from '../services/geminiService';

interface TransactionFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  categories: Category[];
  users: User[];
  currentUser: User;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onClose, onSubmit, categories, users, currentUser }) => {
  const [type, setType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [amount, setAmount] = useState<string>('');
  const [categoryId, setCategoryId] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState<string>('');

  // Requirement: Pre-select their own user ID by default, especially for non-admins.
  const [userId, setUserId] = useState<string>(() => {
    if (currentUser.role !== UserRole.ADMIN) {
      return currentUser.id;
    }
    return currentUser.id;
  });

  const [location, setLocation] = useState<GeoLocation | undefined>(undefined);
  const [photoUrl, setPhotoUrl] = useState<string | undefined>(undefined);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        setPhotoUrl(base64);

        // Trigger AI analysis
        if (base64) {
          setIsAnalyzing(true);
          try {
            const result = await analyzeReceiptImage(base64);
            if (result.amount) setAmount(result.amount.toString());
            if (result.date) setDate(result.date);
            if (result.description) setDescription(result.description);
            // Basic category matching
            if (result.categoryGuess) {
              const matchedCat = categories.find(c => c.name.toLowerCase().includes(result.categoryGuess.toLowerCase()) || result.categoryGuess.toLowerCase().includes(c.name.toLowerCase()));
              if (matchedCat) setCategoryId(matchedCat.id);
            }
            setType(TransactionType.EXPENSE); // Receipts are usually expenses
          } catch (err) {
            alert("영수증 분석에 실패했습니다. 직접 입력해주세요.");
          } finally {
            setIsAnalyzing(false);
          }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGetLocation = () => {
    if (!navigator.geolocation) {
      alert("이 브라우저는 위치 정보를 지원하지 않습니다.");
      return;
    }
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
          address: "현재 위치 (좌표 저장됨)"
        });
        setIsLocating(false);
      },
      (error) => {
        console.error(error);
        setIsLocating(false);
        alert("위치를 가져올 수 없습니다.");
      }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !categoryId || !description) return;

    onSubmit({
      type,
      amount: parseFloat(amount),
      categoryId,
      userId,
      date,
      description,
      location,
      photoUrl
    });
    onClose();
  };

  const filteredCategories = categories.filter(c => c.type === type);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]">
        <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-2xl">
          <h2 className="text-lg font-bold">새 기록 추가</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-700">
            <X size={24} />
          </button>
        </div>

        <div className="overflow-y-auto p-6 flex-1">
          {/* Receipt Upload Banner */}
          {!photoUrl && (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="mb-6 border-2 border-dashed border-brand-300 bg-brand-50 rounded-xl p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-brand-100 transition h-32"
            >
              <Camera className="text-brand-500 mb-2" size={32} />
              <span className="text-brand-700 font-medium">영수증 촬영/업로드</span>
              <span className="text-brand-400 text-xs mt-1">AI가 내용을 자동으로 입력합니다</span>
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept="image/*" 
                onChange={handleFileChange} 
              />
            </div>
          )}

          {/* Photo Preview & Loading */}
          {photoUrl && (
            <div className="mb-6 relative rounded-xl overflow-hidden bg-gray-100 h-48 flex items-center justify-center border">
               <img src={photoUrl} alt="Receipt" className="h-full w-full object-contain" />
               <button 
                onClick={() => { setPhotoUrl(undefined); setAmount(''); setDescription(''); }}
                className="absolute top-2 right-2 bg-black/50 text-white p-1 rounded-full hover:bg-black/70"
               >
                 <X size={16} />
               </button>
               {isAnalyzing && (
                 <div className="absolute inset-0 bg-black/40 flex flex-col items-center justify-center text-white backdrop-blur-sm">
                   <Loader2 className="animate-spin mb-2" size={32} />
                   <span className="font-medium">영수증 분석 중...</span>
                 </div>
               )}
            </div>
          )}

          <form id="transaction-form" onSubmit={handleSubmit} className="space-y-4">
            {/* Type Toggle */}
            <div className="flex bg-gray-100 p-1 rounded-lg">
              <button
                type="button"
                className={`flex-1 py-2 rounded-md text-sm font-semibold transition ${type === TransactionType.EXPENSE ? 'bg-white text-rose-600 shadow-sm' : 'text-gray-500'}`}
                onClick={() => setType(TransactionType.EXPENSE)}
              >
                지출
              </button>
              <button
                type="button"
                className={`flex-1 py-2 rounded-md text-sm font-semibold transition ${type === TransactionType.INCOME ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500'}`}
                onClick={() => setType(TransactionType.INCOME)}
              >
                수입
              </button>
            </div>

            {/* Main Inputs */}
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">금액</label>
              <div className="relative">
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="w-full text-2xl font-bold border-b-2 border-gray-200 focus:border-brand-500 outline-none py-2 bg-transparent"
                  placeholder="0"
                  required
                />
                <span className="absolute right-0 top-3 text-gray-400 font-medium">원</span>
              </div>
            </div>

            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">날짜</label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full border rounded-lg p-3 bg-white focus:ring-2 focus:ring-brand-500 focus:outline-none"
                required
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">항목</label>
              <select
                value={categoryId}
                onChange={(e) => setCategoryId(e.target.value)}
                className="w-full border rounded-lg p-3 bg-white focus:ring-2 focus:ring-brand-500 focus:outline-none"
                required
              >
                <option value="">카테고리 선택</option>
                {filteredCategories.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">내용</label>
              <input
                type="text"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full border rounded-lg p-3 bg-white focus:ring-2 focus:ring-brand-500 focus:outline-none"
                placeholder="어디서 무엇을 하셨나요?"
                required
              />
            </div>

            {/* User Selection */}
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">결제자</label>
              <div className="flex gap-2">
                {users.map(u => (
                  <button
                    key={u.id}
                    type="button"
                    onClick={() => setUserId(u.id)}
                    className={`flex items-center gap-2 px-3 py-2 rounded-lg border transition ${userId === u.id ? 'bg-brand-50 border-brand-500 ring-1 ring-brand-500' : 'bg-white border-gray-200'}`}
                  >
                    <div className="w-6 h-6 rounded-full flex items-center justify-center text-xs text-white font-bold" style={{ backgroundColor: u.color }}>
                      {u.name[0]}
                    </div>
                    <span className="text-sm">{u.name}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Location */}
            <div>
               <button
                type="button"
                onClick={handleGetLocation}
                disabled={isLocating}
                className={`w-full flex items-center justify-center gap-2 border border-dashed rounded-lg p-3 transition ${location ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-gray-300 text-gray-500 hover:bg-gray-50'}`}
               >
                 {isLocating ? <Loader2 className="animate-spin" size={18} /> : <MapPin size={18} />}
                 <span className="text-sm font-medium">
                   {location ? "위치 정보가 추가되었습니다" : "현재 위치 추가하기"}
                 </span>
               </button>
            </div>

          </form>
        </div>

        <div className="p-4 border-t bg-gray-50 rounded-b-2xl">
          <button
            type="submit"
            form="transaction-form"
            className="w-full bg-brand-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-brand-700 transition shadow-md"
          >
            저장하기
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { MapPin, Image as ImageIcon, ChevronLeft, ChevronRight, Calendar } from 'lucide-react';

import { Transaction, User, Category, TransactionType, UserRole, BudgetStatus } from './types';
import { Layout } from './components/Layout';
import { TransactionForm } from './components/TransactionForm';
import { BudgetCard } from './components/BudgetCard';

// --- MOCK DATA ---
const MOCK_USERS: User[] = [
  { id: 'u1', name: '김철수', avatar: 'K', role: UserRole.ADMIN, color: '#3b82f6' },
  { id: 'u2', name: '이영희', avatar: 'L', role: UserRole.MEMBER, color: '#ec4899' },
