const MOCK_CATEGORIES: Category[] = [
  { id: 'c1', name: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#f59e0b' },
  { id: 'c2', name: '교통', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#3b82f6' },
  { id: 'c3', name: '쇼핑', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#ec4899' },
  { id: 'c4', name: '주거', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#8b5cf6' },
  { id: 'c5', name: '월급', type: TransactionType.INCOME, budgetLimit: 0, color: '#10b981' },
  { id: 'c6', name: '부수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#6366f1' },
];

const MOCK_TRANSACTIONS: Transaction[] = [
  { id: 't1', type: TransactionType.INCOME, amount: 3500000, categoryId: 'c5', userId: 'u1', date: '2023-10-01', description: '10월 급여' },
  { id: 't2', type: TransactionType.EXPENSE, amount: 12000, categoryId: 'c1', userId: 'u1', date: '2023-10-02', description: '점심 식사' },
  { id: 't3', type: TransactionType.EXPENSE, amount: 55000, categoryId: 'c3', userId: 'u2', date: '2023-10-03', description: '올리브영 쇼핑', location: { lat: 37.5, lng: 127.0, address: '강남구' } },
  { id: 't4', type: TransactionType.EXPENSE, amount: 12500, categoryId: 'c2', userId: 'u2', date: '2023-10-04', description: '택시비' },
  { id: 't5', type: TransactionType.EXPENSE, amount: 320000, categoryId: 'c4', userId: 'u1', date: '2023-10-05', description: '관리비' },
  { id: 't6', type: TransactionType.EXPENSE, amount: 480000, categoryId: 'c1', userId: 'u1', date: '2023-10-10', description: '가족 외식 (한우)' }, // Budget warning trigger
];

// --- APP COMPONENT ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories] = useState<Category[]>(MOCK_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  // View Mode State
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);

  // History Date Filter State
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01')); // Default to mock data date

  // Derived Data
  const filteredTransactions = useMemo(() => {
    if (viewMode === 'JOINT') return transactions;
    return transactions.filter(t => t.userId === selectedUserId);
  }, [transactions, viewMode, selectedUserId]);

  const historyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredTransactions, historyDate]);

  const totalIncome = useMemo(() => filteredTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [filteredTransactions]);
  const totalExpense = useMemo(() => filteredTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [filteredTransactions]);

  const budgetStatuses: BudgetStatus[] = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
        // Calculate spent based on filtered context (User or Joint)
        const spent = filteredTransactions
          .filter(t => t.categoryId === cat.id)
          .reduce((sum, t) => sum + t.amount, 0);

        const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2); // Simple logic: halve budget for individual view for demo
        const percentage = limit > 0 ? (spent / limit) * 100 : 0;

        let status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED' = 'SAFE';
        if (percentage >= 100) status = 'EXCEEDED';
        else if (percentage >= 80) status = 'DANGER';
        else if (percentage >= 50) status = 'WARNING';

        return { categoryId: cat.id, spent, limit, percentage, status };
      })
      .sort((a, b) => b.percentage - a.percentage); // Sort by highest usage
  }, [categories, filteredTransactions, viewMode]);

  const chartData = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = filteredTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);
         return { name: cat.name, value: val, color: cat.color };
      })
      .filter(d => d.value > 0);
  }, [categories, filteredTransactions]);

  const handleAddTransaction = (newTx: any) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const handlePrevMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >

      {/* Mode Switcher */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="flex bg-white rounded-xl p-1 shadow-sm border">
          <button 
            onClick={() => setViewMode('JOINT')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'JOINT' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            공동 관리
          </button>
          <button 
            onClick={() => setViewMode('INDIVIDUAL')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'INDIVIDUAL' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            개인 관리
          </button>
        </div>

        {viewMode === 'INDIVIDUAL' && (
           <div className="flex gap-2">
             {users.map(u => (
               <button 
                key={u.id}
                onClick={() => setSelectedUserId(u.id)}
                className={`flex items-center gap-2 px-3 py-2 rounded-full border transition ${selectedUserId === u.id ? 'bg-white border-brand-500 ring-2 ring-brand-100' : 'bg-gray-50 border-transparent opacity-60'}`}
               >
                 <div className="w-6 h-6 rounded-full flex items-center justify-center text-xs text-white font-bold" style={{ backgroundColor: u.color }}>{u.name[0]}</div>
                 <span className="text-sm font-medium">{u.name}</span>
               </button>
             ))}
           </div>
        )}
      </div>

      {/* --- DASHBOARD TAB --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-2xl font-bold text-gray-800 mt-1">
                {(totalIncome - totalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 수입</span>
              <div className="text-2xl font-bold text-emerald-600 mt-1">
                + {totalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 지출</span>
              <div className="text-2xl font-bold text-rose-600 mt-1">
                - {totalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* Charts Row */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             {/* Pie Chart */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col">
               <h3 className="text-lg font-bold text-gray-800 mb-4">카테고리별 지출</h3>
               {chartData.length > 0 ? (
                 <>
                   <div className="h-64 w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={chartData}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            paddingAngle={5}
                            dataKey="value"
                            label={({ name, value }) => `${name} ${value.toLocaleString()}`}
                          >
                            {chartData.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                          </Pie>
                          <Tooltip formatter={(value: number) => `${value.toLocaleString()}원`} />
                        </PieChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="mt-6 flex flex-col gap-2">
                      <h4 className="text-sm font-semibold text-gray-500 mb-1">상세 지출 내역</h4>
                      {chartData.map((d, i) => (
                        <div key={i} className="flex items-center justify-between p-2 rounded-lg hover:bg-gray-50">
                          <div className="flex items-center gap-2">
                            <span className="w-3 h-3 rounded-full" style={{ backgroundColor: d.color }}></span>
                            <span className="text-sm font-medium text-gray-700">{d.name}</span>
                          </div>
                          <span className="text-sm font-bold text-gray-900">{d.value.toLocaleString()}원</span>
                        </div>
                      ))}
                    </div>
                 </>
               ) : (
                 <div className="h-64 flex items-center justify-center text-gray-400">데이터가 없습니다</div>
               )}
             </div>

             {/* Recent Quick List */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <h3 className="text-lg font-bold text-gray-800 mb-4">최근 내역</h3>
               <div className="space-y-4">
                 {filteredTransactions.slice(0, 4).map(tx => {
                   const user = users.find(u => u.id === tx.userId);
                   const category = categories.find(c => c.id === tx.categoryId);
                   return (
                     <div key={tx.id} className="flex items-center justify-between">
                       <div className="flex items-center gap-3">
                         <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center text-lg" style={{ color: category?.color }}>
                           {/* Simple Icon placeholder based on first char */}
                           {category?.name[0]}
                         </div>
                         <div>
                           <p className="font-semibold text-gray-800 text-sm">{tx.description}</p>
                           <p className="text-xs text-gray-400 flex items-center gap-1">
                             {user?.name} · {tx.date}
                             {tx.photoUrl && <ImageIcon size={12} className="text-brand-500" />}
                             {tx.location && <MapPin size={12} className="text-emerald-500" />}
                           </p>
                         </div>
                       </div>
                       <span className={`font-bold text-sm ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                         {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                       </span>
                     </div>
                   );
                 })}
                 {filteredTransactions.length === 0 && <p className="text-center text-gray-400 text-sm py-4">내역이 없습니다.</p>}
               </div>
             </div>
          </div>
        </div>
      )}

      {/* --- BUDGET TAB --- */}
      {activeTab === 'BUDGET' && (
        <div className="space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border mb-4">
            <h2 className="font-bold text-gray-800">예산 현황</h2>
            <p className="text-sm text-gray-500 mt-1">
              {viewMode === 'JOINT' ? '전체 예산 대비 사용량입니다.' : '개인 할당 예산(50%) 대비 사용량입니다.'}
            </p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {budgetStatuses.map((status) => {
              const category = categories.find(c => c.id === status.categoryId);
              if (!category) return null;
              return <BudgetCard key={status.categoryId} category={category} status={status} />;
            })}
          </div>
        </div>
      )}

      {/* --- HISTORY TAB --- */}
      {activeTab === 'HISTORY' && (
        <div className="space-y-4">
          {/* Date Selector */}
          <div className="bg-white p-4 rounded-xl shadow-sm border flex items-center justify-between sticky top-0 z-10">
            <button 
              onClick={handlePrevMonth} 
              className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition"
            >
              <ChevronLeft size={24} />
            </button>
            <div className="flex items-center gap-2 font-bold text-lg text-gray-800">
              <Calendar className="text-brand-600" size={20} />
              {historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월
            </div>
            <button 
              onClick={handleNextMonth} 
              className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition"
            >
              <ChevronRight size={24} />
            </button>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[50vh]">
            {historyTransactions.length > 0 ? (
              historyTransactions.map((tx, idx) => {
                  const user = users.find(u => u.id === tx.userId);
                  const category = categories.find(c => c.id === tx.categoryId);
                  return (
                    <div key={tx.id} className={`p-4 flex items-center justify-between hover:bg-gray-50 transition ${idx !== historyTransactions.length - 1 ? 'border-b' : ''}`}>
                      <div className="flex items-center gap-4">
                        <div className="relative">
                          <div className="w-12 h-12 rounded-xl bg-gray-100 flex items-center justify-center font-bold text-xl" style={{ color: category?.color, backgroundColor: `${category?.color}20` }}>
                            {category?.name[0]}
                          </div>
                          <div className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold" style={{ backgroundColor: user?.color }}>
                            {user?.name[0]}
                          </div>
                        </div>
                        <div>
                          <p className="font-bold text-gray-800">{tx.description}</p>
                          <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-xs text-gray-500 bg-gray-100 px-1.5 py-0.5 rounded">{category?.name}</span>
                            <span className="text-xs text-gray-400">{tx.date}</span>
                          </div>
                          <div className="flex gap-2 mt-1">
                            {tx.photoUrl && (
                              <div className="flex items-center gap-1 text-[10px] text-brand-600 bg-brand-50 px-1.5 rounded-full border border-brand-100">
                                <ImageIcon size={10} /> <span>영수증</span>
                              </div>
                            )}
                            {tx.location && (
                              <div className="flex items-center gap-1 text-[10px] text-emerald-600 bg-emerald-50 px-1.5 rounded-full border border-emerald-100">
                                <MapPin size={10} /> <span>{tx.location.address || '위치'}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className={`block font-bold text-lg ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-gray-800'}`}>
                          {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                        </span>
                        <span className="text-xs text-gray-400">원</span>
                      </div>
                    </div>
                  );
              })
            ) : (
              <div className="flex flex-col items-center justify-center h-48 text-gray-400">
                <p>선택하신 달의 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Add Modal */}
      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={handleAddTransaction}
          categories={categories}
          users={users}
          currentUser={currentUser}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { X, Save } from 'lucide-react';
import { Category, TransactionType } from '../types';

interface BudgetSettingModalProps {
  categories: Category[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const BudgetSettingModal: React.FC<BudgetSettingModalProps> = ({ categories, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);

  const handleChange = (id: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, budgetLimit: limit } : c));
  };

  const handleSave = () => {
    onSave(localCategories);
    onClose();
  };

  const expenseCategories = localCategories.filter(c => c.type === TransactionType.EXPENSE);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[80vh]">
        <div className="p-4 border-b flex justify-between items-center bg-gray-50 rounded-t-2xl">
          <h2 className="text-lg font-bold">예산 한도 설정</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-700">
            <X size={24} />
          </button>
        </div>

        <div className="overflow-y-auto p-6 flex-1 space-y-4">
          <p className="text-sm text-gray-500 mb-4">
            각 카테고리별 월간 예산 한도를 설정하세요. 사용량이 한도에 가까워질수록 경고 색상이 변경됩니다.
          </p>
          {expenseCategories.map(cat => (
            <div key={cat.id} className="flex items-center gap-3">
              <div className="w-3 h-3 rounded-full" style={{ backgroundColor: cat.color }}></div>
              <span className="font-semibold text-gray-700 w-24">{cat.name}</span>
              <div className="flex-1 relative">
                <input
                  type="text"
                  value={cat.budgetLimit.toLocaleString()}
                  onChange={(e) => handleChange(cat.id, e.target.value)}
                  className="w-full border rounded-lg p-2 pr-8 text-right font-medium focus:ring-2 focus:ring-brand-500 focus:outline-none"
                />
                <span className="absolute right-3 top-2.5 text-gray-400 text-sm">원</span>
              </div>
            </div>
          ))}
        </div>

        <div className="p-4 border-t bg-gray-50 rounded-b-2xl">
          <button
            onClick={handleSave}
            className="w-full bg-brand-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-brand-700 transition"
          >
            <Save size={18} />
            변경사항 저장
          </button>
        </div>
      </div>
    </div>
  );
};

