const MOCK_TRANSACTIONS: Transaction[] = [
  { id: 't1', type: TransactionType.INCOME, amount: 3500000, categoryId: 'c5', userId: 'u1', date: '2023-10-01', description: '10월 급여' },
  { id: 't2', type: TransactionType.EXPENSE, amount: 12000, categoryId: 'c1', userId: 'u1', date: '2023-10-02', description: '점심 식사' },
  { id: 't3', type: TransactionType.EXPENSE, amount: 55000, categoryId: 'c3', userId: 'u2', date: '2023-10-03', description: '올리브영 쇼핑', location: { lat: 37.5, lng: 127.0, address: '강남구' } },
  { id: 't4', type: TransactionType.EXPENSE, amount: 12500, categoryId: 'c2', userId: 'u2', date: '2023-10-04', description: '택시비' },
  { id: 't5', type: TransactionType.EXPENSE, amount: 320000, categoryId: 'c4', userId: 'u1', date: '2023-10-05', description: '관리비' },
  { id: 't6', type: TransactionType.EXPENSE, amount: 480000, categoryId: 'c1', userId: 'u1', date: '2023-10-10', description: '가족 외식 (한우)' }, // Budget warning trigger
];

// --- APP COMPONENT ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(MOCK_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isBudgetEditOpen, setIsBudgetEditOpen] = useState(false);

  // View Mode State
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);

  // Dashboard Chart Selection State
  const [selectedChartCategoryId, setSelectedChartCategoryId] = useState<string | null>(null);

  // Calendar System State
  const [calendarViewDate, setCalendarViewDate] = useState(new Date('2023-10-01'));
  const [calendarType, setCalendarType] = useState<'EXPENSE' | 'INCOME' | 'BALANCE'>('EXPENSE');

  // History Date Filter State
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01')); // Default to mock data date

  // Derived Data: Base Filter by User/Mode
  const filteredTransactions = useMemo(() => {
    if (viewMode === 'JOINT') return transactions;
    return transactions.filter(t => t.userId === selectedUserId);
  }, [transactions, viewMode, selectedUserId]);

  // Derived Data: Monthly Transactions for Chart & Summaries (Based on historyDate for consistency with "This Month")
  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [filteredTransactions, historyDate]);

  // 1. Chart Data with Dynamic Budget Colors
  const chartData = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         // Calculate Color based on Budget Limit
         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let statusColor = '#10b981'; // Safe (Emerald-500)
         if (percentage >= 100) statusColor = '#e11d48'; // Exceeded (Rose-600)
         else if (percentage >= 90) statusColor = '#f97316'; // Danger (Orange-500)
         else if (percentage >= 70) statusColor = '#facc15'; // Warning (Yellow-400)

         return { 
           id: cat.id, 
           name: cat.name, 
           value: val, 
           color: statusColor,
           originalColor: cat.color 
         };
      })
      .filter(d => d.value > 0);
  }, [categories, monthlyTransactions, viewMode]);

  // 2. Data for Dashboard Side Panel (Specific Category Details)
  const selectedCategoryTransactions = useMemo(() => {
    if (!selectedChartCategoryId) return [];
    return monthlyTransactions
      .filter(t => t.categoryId === selectedChartCategoryId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [monthlyTransactions, selectedChartCategoryId]);

  const groupedSelectedCategoryTransactions = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    selectedCategoryTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [selectedCategoryTransactions]);

  // 3. Calendar Data Calculation
  const calendarData = useMemo(() => {
    const year = calendarViewDate.getFullYear();
    const month = calendarViewDate.getMonth();

    // Group transactions by day
    const dailyTotals: Record<number, number> = {};

    filteredTransactions.forEach(tx => {
      const d = new Date(tx.date);
      if (d.getFullYear() === year && d.getMonth() === month) {
        const day = d.getDate();
        if (!dailyTotals[day]) dailyTotals[day] = 0;

        if (calendarType === 'EXPENSE' && tx.type === TransactionType.EXPENSE) {
          dailyTotals[day] += tx.amount;
        } else if (calendarType === 'INCOME' && tx.type === TransactionType.INCOME) {
          dailyTotals[day] += tx.amount;
        } else if (calendarType === 'BALANCE') {
          if (tx.type === TransactionType.INCOME) dailyTotals[day] += tx.amount;
          else dailyTotals[day] -= tx.amount;
        }
      }
    });

    return dailyTotals;
  }, [filteredTransactions, calendarViewDate, calendarType]);

  const calendarGrid = useMemo(() => {
    const year = calendarViewDate.getFullYear();
    const month = calendarViewDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(i);

    return days;
  }, [calendarViewDate]);

  // History Tab Data (All time / Monthly filtered for the main list)
  const historyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredTransactions, historyDate]);

  // Group by Date for History Table
  const groupedHistory = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    historyTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [historyTransactions]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const budgetStatuses: BudgetStatus[] = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
        const spent = filteredTransactions
          .filter(t => t.categoryId === cat.id)
          .reduce((sum, t) => sum + t.amount, 0);

        const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
        const percentage = limit > 0 ? (spent / limit) * 100 : 0;

        let status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED' = 'SAFE';
        if (percentage >= 100) status = 'EXCEEDED';
        else if (percentage >= 90) status = 'DANGER'; 
        else if (percentage >= 70) status = 'WARNING';

        return { categoryId: cat.id, spent, limit, percentage, status };
      })
      .sort((a, b) => b.percentage - a.percentage);
  }, [categories, filteredTransactions, viewMode]);

  const handleAddTransaction = (newTx: any) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };
    setTransactions(prev => [tx, ...prev]);
  };

  const handleUpdateBudgets = (updatedCategories: Category[]) => {
    setCategories(updatedCategories);
  };

  const handlePrevMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  const handleCalendarPrevMonth = () => {
    setCalendarViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleCalendarNextMonth = () => {
    setCalendarViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  const selectedCategoryInfo = categories.find(c => c.id === selectedChartCategoryId);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >

      {/* Mode Switcher */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="flex bg-white rounded-xl p-1 shadow-sm border">
          <button 
            onClick={() => setViewMode('JOINT')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'JOINT' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            공동 관리
          </button>
          <button 
            onClick={() => setViewMode('INDIVIDUAL')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'INDIVIDUAL' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            개인 관리
          </button>
        </div>

        {viewMode === 'INDIVIDUAL' && (
           <div className="flex gap-2">
             {users.map(u => (
               <button 
                key={u.id}
                onClick={() => setSelectedUserId(u.id)}
                className={`flex items-center gap-2 px-3 py-2 rounded-full border transition ${selectedUserId === u.id ? 'bg-white border-brand-500 ring-2 ring-brand-100' : 'bg-gray-50 border-transparent opacity-60'}`}
               >
                 <div className="w-6 h-6 rounded-full flex items-center justify-center text-xs text-white font-bold" style={{ backgroundColor: u.color }}>{u.name[0]}</div>
                 <span className="text-sm font-medium">{u.name}</span>
               </button>
             ))}
           </div>
        )}
      </div>

      {/* --- DASHBOARD TAB --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-2xl font-bold text-gray-800 mt-1">
                {(totalIncome - totalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 수입</span>
              <div className="text-2xl font-bold text-emerald-600 mt-1">
                + {totalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 지출</span>
              <div className="text-2xl font-bold text-rose-600 mt-1">
                - {totalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* Charts Section */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-8">
             {/* Chart */}
             <div className="flex-1 flex flex-col items-center justify-center relative">
               <div className="flex items-center justify-between w-full mb-4">
                  <h3 className="text-lg font-bold text-gray-800">카테고리별 지출 (한도 기준)</h3>
                  <button 
                    onClick={() => setIsBudgetEditOpen(true)}
                    className="flex items-center gap-1 text-xs font-bold bg-gray-100 text-gray-600 px-3 py-1.5 rounded-full hover:bg-gray-200 transition"
                  >
                    <Settings size={14} />
                    한도 설정
                  </button>
               </div>

               {chartData.length > 0 ? (
                 <div className="h-72 w-full relative">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={chartData}
                          cx="50%"
                          cy="50%"
                          innerRadius={70}
                          outerRadius={100}
                          paddingAngle={3}
                          dataKey="value"
                          label={({ name, value }) => `${name}`}
                          onClick={(data) => {
                            if (data && data.payload) {
                                setSelectedChartCategoryId(data.payload.id);
                            }
                          }}
                          className="cursor-pointer focus:outline-none"
                        >
                          {chartData.map((entry, index) => (
                            <Cell 
                              key={`cell-${index}`} 
                              fill={entry.color} 
                              className={`stroke-white stroke-2 hover:opacity-80 transition ${selectedChartCategoryId === entry.id ? 'opacity-100 ring-2 ring-offset-2 ring-brand-500' : 'opacity-90'}`}
                            />
                          ))}
                        </Pie>
                        <Tooltip formatter={(value: number) => `${value.toLocaleString()}원`} />
                      </PieChart>
                    </ResponsiveContainer>
                    {/* Center Text */}
                    <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                       <span className="text-xs text-gray-400">총 지출</span>
                       <span className="text-xl font-bold text-gray-800">{totalExpense.toLocaleString()}</span>
                    </div>
                 </div>
               ) : (
                 <div className="h-64 w-full flex flex-col items-center justify-center text-gray-300 border-2 border-dashed rounded-xl">
                    <p className="mb-2">데이터가 없습니다</p>
                    <button onClick={() => setIsAddModalOpen(true)} className="text-brand-500 text-sm font-bold">첫 지출 기록하기</button>
                 </div>
               )}
               {/* Color Legend */}
                <div className="flex gap-3 text-[10px] text-gray-500 mt-2">
                  <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div>안전</div>
                  <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-yellow-400"></div>주의</div>
                  <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-orange-500"></div>위험</div>
                  <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-rose-600"></div>초과</div>
                </div>
             </div>

             {/* Side Panel: Detail List or Summary */}
             <div className="flex-1 border-l border-gray-100 pl-0 md:pl-8 pt-4 md:pt-0">
                {selectedChartCategoryId && selectedCategoryInfo ? (
                  // Selected Category Details
                  <div className="flex flex-col h-full">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-2">
                         <button onClick={() => setSelectedChartCategoryId(null)} className="p-1 hover:bg-gray-100 rounded-full transition">
                            <ArrowLeft size={18} className="text-gray-500" />
                         </button>
                         <h4 className="text-sm font-bold text-gray-800 flex items-center gap-2">
                           <span className="w-3 h-3 rounded-full" style={{ backgroundColor: selectedCategoryInfo.color }}></span>
                           {selectedCategoryInfo.name} 상세 내역
                         </h4>
                      </div>
                    </div>

                    <div className="space-y-3 max-h-72 overflow-y-auto pr-2 custom-scrollbar">
                      {Object.keys(groupedSelectedCategoryTransactions).sort((a,b) => b.localeCompare(a)).map(dateStr => (
                        <div key={dateStr}>
                          <div className="text-xs font-semibold text-gray-400 mb-1 px-1">
                            {new Date(dateStr).getMonth() + 1}월 {new Date(dateStr).getDate()}일
                          </div>
                          {groupedSelectedCategoryTransactions[dateStr].map(tx => (
                            <div key={tx.id} className="flex items-center justify-between p-3 mb-2 rounded-xl bg-gray-50 border border-gray-100">
                               <div className="flex items-center gap-2">
                                  <div className="text-sm text-gray-700">{tx.description}</div>
                               </div>
                               <span className="text-sm font-bold text-gray-900">-{tx.amount.toLocaleString()}원</span>
                            </div>
                          ))}
                        </div>
                      ))}
                      {selectedCategoryTransactions.length === 0 && <p className="text-center text-gray-400 text-xs py-4">이 카테고리의 내역이 없습니다.</p>}
                    </div>
                  </div>
                ) : (
                  // Default Summary List
                  <div className="flex flex-col h-full">
                    <h4 className="text-sm font-semibold text-gray-500 mb-4">카테고리별 요약</h4>
                    <div className="space-y-3 max-h-72 overflow-y-auto pr-2 custom-scrollbar">
                      {chartData.map((d, i) => (
                        <div 
                          key={i} 
                          onClick={() => setSelectedChartCategoryId(d.id)}
                          className="flex items-center justify-between p-3 rounded-xl bg-gray-50 hover:bg-gray-100 transition cursor-pointer"
                        >
                          <div className="flex items-center gap-3">
                            <div className="w-4 h-4 rounded-full shadow-sm" style={{ backgroundColor: d.color }}></div>
                            <span className="text-sm font-bold text-gray-700">{d.name}</span>
                          </div>
                          <span className="text-sm font-bold text-gray-900">{d.value.toLocaleString()}원</span>
                        </div>
                      ))}
                      {chartData.length === 0 && <p className="text-sm text-gray-400">지출 내역이 표시됩니다.</p>}
                    </div>
                  </div>
                )}
             </div>
          </div>

          {/* New Section: Monthly Calendar Status */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
             <div className="flex flex-col md:flex-row items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-2 w-full md:w-auto">
                   <div className="bg-brand-50 text-brand-600 p-2 rounded-lg">
                      <CalendarIcon size={20} />
                   </div>
                   <h3 className="text-lg font-bold text-gray-800">월별 현황 달력</h3>
                </div>

                <div className="flex items-center gap-4 w-full md:w-auto justify-between md:justify-end">
                   {/* Month Navigation */}
                   <div className="flex items-center gap-2 bg-gray-50 rounded-lg p-1">
                      <button onClick={handleCalendarPrevMonth} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronLeft size={16} /></button>
                      <span className="text-sm font-bold text-gray-700 min-w-[80px] text-center">
                        {calendarViewDate.getFullYear()}. {calendarViewDate.getMonth() + 1}
                      </span>
                      <button onClick={handleCalendarNextMonth} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronRight size={16} /></button>
                   </div>

                   {/* Type Toggles */}
                   <div className="flex bg-gray-100 rounded-lg p-1">
                    <button 
                      onClick={() => setCalendarType('INCOME')}
                      className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'INCOME' ? 'bg-white shadow text-emerald-600' : 'text-gray-500'}`}
                    >
                      수입
                    </button>
                    <button 
                      onClick={() => setCalendarType('EXPENSE')}
                      className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'EXPENSE' ? 'bg-white shadow text-rose-600' : 'text-gray-500'}`}
                    >
                      지출
                    </button>
                    <button 
                      onClick={() => setCalendarType('BALANCE')}
                      className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'BALANCE' ? 'bg-white shadow text-brand-600' : 'text-gray-500'}`}
                    >
                      잔액
                    </button>
                   </div>
                </div>
             </div>

             {/* Calendar Grid */}
             <div className="w-full">
                {/* Headers */}
                <div className="grid grid-cols-7 mb-2 text-center">
                  {['일', '월', '화', '수', '목', '금', '토'].map((day, i) => (
                    <div key={day} className={`text-xs font-bold ${i === 0 ? 'text-rose-500' : i === 6 ? 'text-blue-500' : 'text-gray-400'}`}>
                      {day}
                    </div>
                  ))}
                </div>

                {/* Days */}
                <div className="grid grid-cols-7 gap-1 md:gap-2">
                  {calendarGrid.map((day, index) => {
                    if (day === null) return <div key={`empty-${index}`} className="aspect-square"></div>;

                    const amount = calendarData[day] || 0;
                    const hasAmount = amount !== 0;

                    let textColor = 'text-gray-800';
                    let bgColor = 'bg-gray-50';

                    if (hasAmount) {
                      if (calendarType === 'INCOME') {
                        textColor = 'text-emerald-600';
                        bgColor = 'bg-emerald-50';
                      } else if (calendarType === 'EXPENSE') {
                        textColor = 'text-rose-600';
                        bgColor = 'bg-rose-50';
                      } else { // BALANCE
                        textColor = amount >= 0 ? 'text-brand-600' : 'text-rose-600';
                        bgColor = amount >= 0 ? 'bg-brand-50' : 'bg-rose-50';
                      }
                    }

                    return (
                      <div key={`day-${day}`} className={`aspect-square rounded-xl border border-transparent p-1 flex flex-col justify-between transition ${hasAmount ? bgColor : 'hover:bg-gray-50'}`}>
                        <span className={`text-xs font-semibold ${hasAmount ? 'text-gray-600' : 'text-gray-400'}`}>{day}</span>
                        {hasAmount && (
                          <div className={`text-[10px] md:text-xs font-bold text-right truncate ${textColor}`}>
                            {amount.toLocaleString()}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
             </div>
          </div>
        </div>
      )}

      {/* --- BUDGET TAB --- */}
      {activeTab === 'BUDGET' && (
        <div className="space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border mb-4 flex justify-between items-center">
            <div>
              <h2 className="font-bold text-gray-800">예산 현황</h2>
              <p className="text-sm text-gray-500 mt-1">
                {viewMode === 'JOINT' ? '전체 예산 대비 사용량입니다.' : '개인 할당 예산(50%) 대비 사용량입니다.'}
              </p>
            </div>
            <button 
              onClick={() => setIsBudgetEditOpen(true)}
              className="flex items-center gap-1.5 bg-gray-100 text-gray-700 px-3 py-2 rounded-lg text-sm font-bold hover:bg-gray-200 transition"
            >
              <Settings size={16} />
              한도 설정
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {budgetStatuses.map((status) => {
              const category = categories.find(c => c.id === status.categoryId);
              if (!category) return null;
              return <BudgetCard key={status.categoryId} category={category} status={status} />;
            })}
          </div>
        </div>
      )}

      {/* --- HISTORY TAB --- */}
      {activeTab === 'HISTORY' && (
        <div className="space-y-4">
           {/* Date Selector Header with Title and Add Button */}
           <div className="bg-white p-4 rounded-xl shadow-sm border space-y-3 sticky top-0 z-10">
              <div className="flex justify-between items-center">
                 <h2 className="font-bold text-lg text-gray-800">전체 상세 내역</h2>
                 <button 
                  onClick={() => setIsAddModalOpen(true)}
                  className="flex items-center gap-1 bg-brand-600 text-white px-3 py-1.5 rounded-lg text-sm font-bold hover:bg-brand-700 transition"
                 >
                   <Plus size={16} />
                   기록 추가
                 </button>
              </div>

              <div className="flex items-center justify-between bg-gray-50 rounded-lg p-1">
                <button 
                  onClick={handlePrevMonth} 
                  className="p-2 hover:bg-gray-200 rounded-md text-gray-500 transition"
                >
                  <ChevronLeft size={20} />
                </button>
                <div className="flex items-center gap-2 font-bold text-gray-800">
                  <CalendarIcon className="text-brand-600" size={18} />
                  {historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월
                </div>
                <button 
                  onClick={handleNextMonth} 
                  className="p-2 hover:bg-gray-200 rounded-md text-gray-500 transition"
                >
                  <ChevronRight size={20} />
                </button>
              </div>
          </div>

          {/* User Specific Daily/Monthly Detailed Table */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[50vh]">
            {Object.keys(groupedHistory).length > 0 ? (
              <div className="divide-y divide-gray-100">
                {Object.keys(groupedHistory).sort((a,b) => b.localeCompare(a)).map(dateStr => (
                  <div key={dateStr} className="flex flex-col">
                    {/* Date Header */}
                    <div className="bg-gray-50 px-4 py-2 flex items-center justify-between">
                       <span className="text-sm font-bold text-gray-600">
                         {new Date(dateStr).getDate()}일
                         <span className="ml-1 text-xs font-normal text-gray-400">
                           ({new Date(dateStr).toLocaleDateString('ko-KR', { weekday: 'short' })})
                         </span>
                       </span>
                       <span className="text-xs text-gray-400">
                         {groupedHistory[dateStr].length}건
                       </span>
                    </div>
                    {/* Transactions for this date */}
                    <div>
                      {groupedHistory[dateStr].map((tx) => {
                        const user = users.find(u => u.id === tx.userId);
                        const category = categories.find(c => c.id === tx.categoryId);
                        return (
                          <div key={tx.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition border-b border-gray-50 last:border-0">
                            <div className="flex items-center gap-4">
                              <div className="relative">
                                <div className="w-10 h-10 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-lg" style={{ color: category?.color, backgroundColor: `${category?.color}15` }}>
                                  {category?.name[0]}
                                </div>
                                <div className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white flex items-center justify-center text-[9px] text-white font-bold" style={{ backgroundColor: user?.color }}>
                                  {user?.name[0]}
                                </div>
                              </div>
                              <div>
                                <p className="font-bold text-gray-800 text-sm">{tx.description}</p>
                                <div className="flex items-center gap-2 mt-0.5">
                                  <span className="text-xs text-gray-500">{category?.name}</span>
                                  {tx.photoUrl && <ImageIcon size={10} className="text-gray-400" />}
                                  {tx.location && <MapPin size={10} className="text-gray-400" />}
                                </div>
                              </div>
                            </div>
                            <div className="text-right">
                              <span className={`block font-bold text-sm ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-gray-800'}`}>
                                {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                              </span>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-48 text-gray-400">
                <CalendarIcon size={48} className="mb-2 opacity-20" />
                <p>선택하신 달의 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Add Modal */}
      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={handleAddTransaction}
          categories={categories}
          users={users}
          currentUser={currentUser}
        />
      )}

      {/* Budget Setting Modal */}
      {isBudgetEditOpen && (
        <BudgetSettingModal 
          categories={categories}
          onClose={() => setIsBudgetEditOpen(false)}
          onSave={handleUpdateBudgets}
        />
      )}
    </Layout>
  );
};

