// --- APP COMPONENT ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(MOCK_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isBudgetEditOpen, setIsBudgetEditOpen] = useState(false);

  // View Mode State
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);

  // Dashboard Chart Selection State
  const [selectedChartCategoryId, setSelectedChartCategoryId] = useState<string | null>(null);

  // Calendar System State
  const [calendarViewDate, setCalendarViewDate] = useState(new Date('2023-10-01'));
  const [calendarType, setCalendarType] = useState<'EXPENSE' | 'INCOME' | 'BALANCE'>('EXPENSE');

  // History Date Filter State
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01')); // Default to mock data date

  // Notification State
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  useEffect(() => {
    // Request notification permission on mount
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  // Derived Data: Base Filter by User/Mode
  const filteredTransactions = useMemo(() => {
    if (viewMode === 'JOINT') return transactions;
    return transactions.filter(t => t.userId === selectedUserId);
  }, [transactions, viewMode, selectedUserId]);

  // Derived Data: Monthly Transactions for Chart & Summaries (Based on historyDate for consistency with "This Month")
  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [filteredTransactions, historyDate]);

  // 1. Chart Data with Dynamic Budget Colors
  const chartData = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         // Calculate Color based on Budget Limit
         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let statusColor = '#10b981'; // Safe (Emerald-500)
         if (percentage >= 100) statusColor = '#e11d48'; // Exceeded (Rose-600)
         else if (percentage >= 90) statusColor = '#f97316'; // Danger (Orange-500)
         else if (percentage >= 70) statusColor = '#facc15'; // Warning (Yellow-400)

         return { 
           id: cat.id, 
           name: cat.name, 
           value: val, 
           color: statusColor,
           originalColor: cat.color 
         };
      })
      .filter(d => d.value > 0);
  }, [categories, monthlyTransactions, viewMode]);

  // 2. Data for Dashboard Side Panel (Specific Category Details)
  const selectedCategoryTransactions = useMemo(() => {
    if (!selectedChartCategoryId) return [];
    return monthlyTransactions
      .filter(t => t.categoryId === selectedChartCategoryId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [monthlyTransactions, selectedChartCategoryId]);

  const groupedSelectedCategoryTransactions = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    selectedCategoryTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [selectedCategoryTransactions]);

  // 3. Calendar Data Calculation
  const calendarData = useMemo(() => {
    const year = calendarViewDate.getFullYear();
    const month = calendarViewDate.getMonth();

    // Group transactions by day
    const dailyTotals: Record<number, number> = {};

    filteredTransactions.forEach(tx => {
      const d = new Date(tx.date);
      if (d.getFullYear() === year && d.getMonth() === month) {
        const day = d.getDate();
        if (!dailyTotals[day]) dailyTotals[day] = 0;

        if (calendarType === 'EXPENSE' && tx.type === TransactionType.EXPENSE) {
          dailyTotals[day] += tx.amount;
        } else if (calendarType === 'INCOME' && tx.type === TransactionType.INCOME) {
          dailyTotals[day] += tx.amount;
        } else if (calendarType === 'BALANCE') {
          if (tx.type === TransactionType.INCOME) dailyTotals[day] += tx.amount;
          else dailyTotals[day] -= tx.amount;
        }
      }
    });

    return dailyTotals;
  }, [filteredTransactions, calendarViewDate, calendarType]);

  const calendarGrid = useMemo(() => {
    const year = calendarViewDate.getFullYear();
    const month = calendarViewDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(i);

    return days;
  }, [calendarViewDate]);

  // History Tab Data (All time / Monthly filtered for the main list)
  const historyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredTransactions, historyDate]);

  // Group by Date for History Table
  const groupedHistory = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    historyTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [historyTransactions]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const budgetStatuses: BudgetStatus[] = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
        const spent = filteredTransactions
          .filter(t => t.categoryId === cat.id)
          .reduce((sum, t) => sum + t.amount, 0);

        const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
        const percentage = limit > 0 ? (spent / limit) * 100 : 0;

        let status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED' = 'SAFE';
        if (percentage >= 100) status = 'EXCEEDED';
        else if (percentage >= 90) status = 'DANGER'; 
        else if (percentage >= 70) status = 'WARNING';

        return { categoryId: cat.id, spent, limit, percentage, status };
      })
      .sort((a, b) => b.percentage - a.percentage);
  }, [categories, filteredTransactions, viewMode]);

  const checkBudgetAndNotify = (newTx: Transaction, allTransactions: Transaction[]) => {
    if (newTx.type !== TransactionType.EXPENSE) return;

    const category = categories.find(c => c.id === newTx.categoryId);
    if (!category || category.budgetLimit === 0) return;

    const txDate = new Date(newTx.date);
    // Use the relevant context for alerts. 
    // If ViewMode is JOINT, we check total. If INDIVIDUAL, we check filtered user's total vs half limit.
    // For simplicity and safety, alerts usually track the ViewMode the user is currently operating in.

    const limit = viewMode === 'JOINT' ? category.budgetLimit : category.budgetLimit / 2;
    const alertPrefix = viewMode === 'JOINT' ? '[공동]' : '[개인]';

    const currentSpent = allTransactions
      .filter(t => {
        // Filter needs to match ViewMode logic (Joint=All, Individual=SelectedUser)
        // AND match the specific month of the new transaction
        const isUserMatch = viewMode === 'JOINT' ? true : t.userId === selectedUserId;
        if (!isUserMatch) return false;

        const d = new Date(t.date);
        return t.categoryId === newTx.categoryId && 
               d.getFullYear() === txDate.getFullYear() && 
               d.getMonth() === txDate.getMonth() &&
               t.type === TransactionType.EXPENSE;
      })
      .reduce((sum, t) => sum + t.amount, 0);

    const totalSpent = currentSpent + newTx.amount;
    const percentage = (totalSpent / limit) * 100;

    let alertMessage = '';
    let alertType: ToastType | null = null;

    if (percentage >= 100) {
      alertMessage = `${alertPrefix} ${category.name} 예산을 초과했습니다! (${percentage.toFixed(0)}%)`;
      alertType = 'error';
    } else if (percentage >= 90) {
      alertMessage = `${alertPrefix} ${category.name} 예산의 90%를 사용했습니다.`;
      alertType = 'error';
    } else if (percentage >= 70) {
      alertMessage = `${alertPrefix} ${category.name} 예산의 70%를 도달했습니다.`;
      alertType = 'warning';
    }

    if (alertMessage && alertType) {
      setToast({ message: alertMessage, type: alertType });

      // Native Push Notification
      if ('Notification' in window && Notification.permission === 'granted') {
        new Notification('Co-Budget 경고', {
          body: alertMessage,
          icon: '/icon.png'
        });
      }
    }
  };

  const handleAddTransaction = (newTx: any) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };

    // Check budget before update to include existing transactions + new one logic
    checkBudgetAndNotify(tx, transactions);

    setTransactions(prev => [tx, ...prev]);
  };

  const handleUpdateBudgets = (updatedCategories: Category[]) => {
    setCategories(updatedCategories);
  };

  const handlePrevMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  const handleCalendarPrevMonth = () => {
    setCalendarViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleCalendarNextMonth = () => {
    setCalendarViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  const selectedCategoryInfo = categories.find(c => c.id === selectedChartCategoryId);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && (
        <Toast 
          message={toast.message} 
          type={toast.type} 
          onClose={() => setToast(null)} 
        />
      )}

      {/* Mode Switcher */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="flex bg-white rounded-xl p-1 shadow-sm border">
          <button 
            onClick={() => setViewMode('JOINT')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'JOINT' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            공동 관리
          </button>
          <button 
            onClick={() => setViewMode('INDIVIDUAL')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'INDIVIDUAL' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            개인 관리
          </button>
        </div>

        {viewMode === 'INDIVIDUAL' && (
           <div className="flex gap-2">
             {users.map(u => (
               <button 
                key={u.id}
                onClick={() => setSelectedUserId(u.id)}
                className={`flex items-center gap-2 px-3 py-2 rounded-full border transition ${selectedUserId === u.id ? 'bg-white border-brand-500 ring-2 ring-brand-100' : 'bg-gray-50 border-transparent opacity-60'}`}
               >
                 <div className="w-6 h-6 rounded-full flex items-center justify-center text-xs text-white font-bold" style={{ backgroundColor: u.color }}>{u.name[0]}</div>
                 <span className="text-sm font-medium">{u.name}</span>
               </button>
             ))}
           </div>
        )}
      </div>

      {/* --- DASHBOARD TAB --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-2xl font-bold text-gray-800 mt-1">
                {(totalIncome - totalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 수입</span>
              <div className="text-2xl font-bold text-emerald-600 mt-1">
                + {totalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 지출</span>
              <div className="text-2xl font-bold text-rose-600 mt-1">
                - {totalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* Charts Section */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-8">
             {/* Chart */}
             <div className="flex-1 flex flex-col items-center justify-center relative">
               <div className="flex items-center justify-between w-full mb-4">
                  <h3 className="text-lg font-bold text-gray-800">카테고리별 지출 (한도 기준)</h3>
                  <button 
                    onClick={() => setIsBudgetEditOpen(true)}
                    className="flex items-center gap-1 text-xs font-bold bg-gray-100 text-gray-600 px-3 py-1.5 rounded-full hover:bg-gray-200 transition"
                  >
                    <Settings size={14} />
                    한도 설정
                  </button>
               </div>

               {chartData.length > 0 ? (
                 <div className="h-72 w-full relative">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={chartData}
                          cx="50%"
                          cy="50%"
                          innerRadius={70}
                          outerRadius={100}
                          paddingAngle={3}
                          dataKey="value"
                          label={({ name, value }) => `${name}`}
                          onClick={(data) => {
                            if (data && data.payload) {
