                            <div className="w-4 h-4 rounded-full shadow-sm" style={{ backgroundColor: d.color }}></div>
                            <span className="text-sm font-bold text-gray-700">{d.name}</span>
                          </div>
                          <span className="text-sm font-bold text-gray-900">{d.value.toLocaleString()}원</span>
