                )}
             </div>
          </div>

          {/* New Section: Category Expenses Grid with Icons */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="text-lg font-bold text-gray-800 mb-4">카테고리별 지출 현황</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {categories
                .filter(c => c.type === TransactionType.EXPENSE)
                .map(cat => {
                  const amount = monthlyTransactions
                    .filter(t => t.categoryId === cat.id)
                    .reduce((sum, t) => sum + t.amount, 0);

                  return (
                    <div key={cat.id} className="flex items-center p-4 rounded-xl bg-gray-50 border border-gray-100">
                       <div className="w-10 h-10 rounded-full flex items-center justify-center mr-4 shadow-sm" style={{ backgroundColor: `${cat.color}15`, color: cat.color }}>
                          {getCategoryIcon(cat.name)}
                       </div>
                       <div>
                          <p className="text-sm font-medium text-gray-500 mb-0.5">{cat.name}</p>
                          <p className="text-lg font-bold text-gray-900">{amount.toLocaleString()}원</p>
                       </div>
                    </div>
                  );
                })}
            </div>
          </div>

          {/* Monthly Calendar Status */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
             <div className="flex flex-col xl:flex-row items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-2 w-full xl:w-auto">
                   <div className="bg-brand-50 text-brand-600 p-2 rounded-lg">
                      <CalendarIcon size={20} />
                   </div>
                   <h3 className="text-lg font-bold text-gray-800">현황 달력</h3>

                   {/* Scope Toggles */}
                   <div className="flex bg-gray-100 rounded-lg p-0.5 ml-2">
                      <button 
                        onClick={() => setCalendarScope('MONTH')}
                        className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarScope === 'MONTH' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
                      >
                        월간
                      </button>
                      <button 
                        onClick={() => setCalendarScope('WEEK')}
                        className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarScope === 'WEEK' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
                      >
                        주간
                      </button>
                      <button 
                        onClick={() => setCalendarScope('DAY')}
                        className={`px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarScope === 'DAY' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
                      >
                        일간
                      </button>
                   </div>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-4 w-full xl:w-auto justify-between xl:justify-end">
                   {/* Navigation */}
                   <div className="flex items-center gap-2 bg-gray-50 rounded-lg p-1 w-full sm:w-auto justify-between">
                      <button onClick={() => moveCalendar('prev')} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronLeft size={16} /></button>
                      <span className="text-sm font-bold text-gray-700 min-w-[100px] text-center">
                        {calendarTitle}
                      </span>
                      <button onClick={() => moveCalendar('next')} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronRight size={16} /></button>
                   </div>

                   {/* Type Toggles */}
                   <div className="flex bg-gray-100 rounded-lg p-1 w-full sm:w-auto justify-center">
                    <button 
                      onClick={() => setCalendarType('INCOME')}
                      className={`flex-1 sm:flex-none px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'INCOME' ? 'bg-white shadow text-emerald-600' : 'text-gray-500'}`}
                    >
                      수입
                    </button>
                    <button 
                      onClick={() => setCalendarType('EXPENSE')}
                      className={`flex-1 sm:flex-none px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'EXPENSE' ? 'bg-white shadow text-rose-600' : 'text-gray-500'}`}
                    >
                      지출
                    </button>
                    <button 
                      onClick={() => setCalendarType('BALANCE')}
                      className={`flex-1 sm:flex-none px-3 py-1.5 rounded-md text-xs font-bold transition ${calendarType === 'BALANCE' ? 'bg-white shadow text-brand-600' : 'text-gray-500'}`}
                    >
                      잔액
                    </button>
                   </div>
                </div>
             </div>

             {/* Calendar Grid */}
             <div className="w-full">
                {/* Headers - Hide if Scope is DAY */}
                {calendarScope !== 'DAY' && (
                  <div className="grid grid-cols-7 mb-2 text-center">
                    {['일', '월', '화', '수', '목', '금', '토'].map((day, i) => (
                      <div key={day} className={`text-xs font-bold ${i === 0 ? 'text-rose-500' : i === 6 ? 'text-blue-500' : 'text-gray-400'}`}>
                        {day}
                      </div>
                    ))}
                  </div>
                )}

                {/* Days Grid */}
                <div className={`grid gap-1 md:gap-2 ${calendarScope === 'DAY' ? 'grid-cols-1' : 'grid-cols-7'}`}>
                  {calendarCells.map((dateObj, index) => {
                    if (dateObj === null) return <div key={`empty-${index}`} className="aspect-square"></div>;

                    const dateKey = toDateKey(dateObj);
                    const amount = calendarDataMap[dateKey] || 0;
                    const hasAmount = amount !== 0;

                    let textColor = 'text-gray-800';
                    let bgColor = 'bg-gray-50';

                    if (hasAmount) {
                      if (calendarType === 'INCOME') {
                        textColor = 'text-emerald-600';
                        bgColor = 'bg-emerald-50';
                      } else if (calendarType === 'EXPENSE') {
                        textColor = 'text-rose-600';
                        bgColor = 'bg-rose-50';
                      } else { // BALANCE
                        textColor = amount >= 0 ? 'text-brand-600' : 'text-rose-600';
                        bgColor = amount >= 0 ? 'bg-brand-50' : 'bg-rose-50';
                      }
                    }

                    return (
                      <div 
                        key={`day-${dateKey}`} 
                        className={`rounded-xl border border-transparent p-2 md:p-3 flex flex-col justify-between transition ${hasAmount ? bgColor : 'hover:bg-gray-50'} ${calendarScope === 'DAY' ? 'aspect-[3/1] items-center justify-center gap-2' : 'aspect-square'}`}
                      >
                        <span className={`text-xs font-semibold ${hasAmount ? 'text-gray-600' : 'text-gray-400'} ${calendarScope === 'DAY' ? 'text-lg' : ''}`}>
                          {dateObj.getDate()}
                          {calendarScope === 'DAY' && <span className="ml-2 text-sm font-normal">({['일', '월', '화', '수', '목', '금', '토'][dateObj.getDay()]})</span>}
                        </span>
                        {hasAmount && (
                          <div className={`font-bold text-right truncate ${textColor} ${calendarScope === 'DAY' ? 'text-3xl' : 'text-[10px] md:text-xs'}`}>
                            {amount.toLocaleString()}
                          </div>
                        )}
                        {calendarScope === 'DAY' && !hasAmount && (
                           <div className="text-gray-400 text-sm">내역 없음</div>
                        )}
                      </div>
                    );
                  })}
                </div>
             </div>
          </div>
        </div>
      )}

      {/* --- BUDGET TAB --- */}
      {activeTab === 'BUDGET' && (
        <div className="space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border mb-4 flex justify-between items-center">
            <div>
              <h2 className="font-bold text-gray-800">예산 현황</h2>
              <p className="text-sm text-gray-500 mt-1">
                {viewMode === 'JOINT' ? '전체 예산 대비 사용량입니다.' : '개인 할당 예산(50%) 대비 사용량입니다.'}
              </p>
            </div>
            <button 
              onClick={() => setIsBudgetEditOpen(true)}
              className="flex items-center gap-1.5 bg-gray-100 text-gray-700 px-3 py-2 rounded-lg text-sm font-bold hover:bg-gray-200 transition"
            >
              <Settings size={16} />
              한도 설정
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {budgetStatuses.map((status) => {
              const category = categories.find(c => c.id === status.categoryId);
              if (!category) return null;
              return <BudgetCard key={status.categoryId} category={category} status={status} />;
            })}
          </div>
        </div>
      )}

      {/* --- HISTORY TAB --- */}
      {activeTab === 'HISTORY' && (
        <div className="space-y-4">
           {/* Date Selector Header with Title and Add Button */}
           <div className="bg-white p-4 rounded-xl shadow-sm border space-y-3 sticky top-0 z-10">
              <div className="flex justify-between items-center">
                 <h2 className="font-bold text-lg text-gray-800">전체 상세 내역</h2>
                 <button 
                  onClick={() => setIsAddModalOpen(true)}
                  className="flex items-center gap-1 bg-brand-600 text-white px-3 py-1.5 rounded-lg text-sm font-bold hover:bg-brand-700 transition"
                 >
                   <Plus size={16} />
                   기록 추가
                 </button>
              </div>

              <div className="flex items-center justify-between bg-gray-50 rounded-lg p-1">
                <button 
                  onClick={handlePrevMonth} 
                  className="p-2 hover:bg-gray-200 rounded-md text-gray-500 transition"
                >
                  <ChevronLeft size={20} />
                </button>
                <div className="flex items-center gap-2 font-bold text-gray-800">
                  <CalendarIcon className="text-brand-600" size={18} />
                  {historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월
                </div>
                <button 
                  onClick={handleNextMonth} 
                  className="p-2 hover:bg-gray-200 rounded-md text-gray-500 transition"
                >
                  <ChevronRight size={20} />
                </button>
              </div>
          </div>

          {/* User Specific Daily/Monthly Detailed Table */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[50vh]">
            {Object.keys(groupedHistory).length > 0 ? (
              <div className="divide-y divide-gray-100">
                {Object.keys(groupedHistory).sort((a,b) => b.localeCompare(a)).map(dateStr => (
                  <div key={dateStr} className="flex flex-col">
                    {/* Date Header */}
                    <div className="bg-gray-50 px-4 py-2 flex items-center justify-between">
                       <span className="text-sm font-bold text-gray-600">
                         {new Date(dateStr).getDate()}일
                         <span className="ml-1 text-xs font-normal text-gray-400">
                           ({new Date(dateStr).toLocaleDateString('ko-KR', { weekday: 'short' })})
                         </span>
                       </span>
                       <span className="text-xs text-gray-400">
                         {groupedHistory[dateStr].length}건
                       </span>
                    </div>
                    {/* Transactions for this date */}
                    <div>
                      {groupedHistory[dateStr].map((tx) => {
                        const user = users.find(u => u.id === tx.userId);
                        const category = categories.find(c => c.id === tx.categoryId);
                        return (
                          <div key={tx.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition border-b border-gray-50 last:border-0">
                            <div className="flex items-center gap-4">
                              <div className="relative">
                                <div className="w-10 h-10 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-lg" style={{ color: category?.color, backgroundColor: `${category?.color}15` }}>
                                  {category ? getCategoryIcon(category.name, 20) : category?.name[0]}
                                </div>
                                <div className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white flex items-center justify-center text-[9px] text-white font-bold" style={{ backgroundColor: user?.color }}>
                                  {user?.name[0]}
                                </div>
                              </div>
                              <div>
                                <p className="font-bold text-gray-800 text-sm">{tx.description}</p>
                                <div className="flex items-center gap-2 mt-0.5">
                                  <span className="text-xs text-gray-500">{category?.name}</span>
                                  {tx.photoUrl && <ImageIcon size={10} className="text-gray-400" />}
                                  {tx.location && <MapPin size={10} className="text-gray-400" />}
                                </div>
                              </div>
                            </div>
                            <div className="text-right">
                              <span className={`block font-bold text-sm ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-gray-800'}`}>
                                {tx.type === TransactionType.INCOME ? '+' : '-'}{tx.amount.toLocaleString()}
                              </span>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-48 text-gray-400">
                <CalendarIcon size={48} className="mb-2 opacity-20" />
                <p>선택하신 달의 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Add Modal */}
      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={handleAddTransaction}
          categories={categories}
          users={users}
          currentUser={currentUser}
        />
      )}

      {/* Budget Setting Modal */}
      {isBudgetEditOpen && (
        <BudgetSettingModal 
          categories={categories}
          onClose={() => setIsBudgetEditOpen(false)}
          onSave={handleUpdateBudgets}
        />
      )}
    </Layout>
  );
};

