const getCategoryIcon = (categoryName: string, size: number = 20) => {
  if (categoryName.includes('식비')) return <Utensils size={size} />;
  if (categoryName.includes('교통')) return <Bus size={size} />;
  if (categoryName.includes('쇼핑')) return <ShoppingBag size={size} />;
  if (categoryName.includes('주거')) return <Home size={size} />;
  if (categoryName.includes('월급')) return <Banknote size={size} />;
  if (categoryName.includes('부수입')) return <Coins size={size} />;
  if (categoryName.includes('카페') || categoryName.includes('간식')) return <Coffee size={size} />;
  if (categoryName.includes('여가') || categoryName.includes('문화')) return <Palmtree size={size} />;
  if (categoryName.includes('의료') || categoryName.includes('병원')) return <HeartPulse size={size} />;
  if (categoryName.includes('교육')) return <GraduationCap size={size} />;
  return <ShoppingBag size={size} />; // Default
};

// --- APP COMPONENT ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY' | 'SUMMARY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(MOCK_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isBudgetEditOpen, setIsBudgetEditOpen] = useState(false);

  // View Mode State
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);

  // Dashboard Chart Selection State
  const [selectedChartCategoryId, setSelectedChartCategoryId] = useState<string | null>(null);

  // Dashboard Summary Sort State
  const [summarySortOrder, setSummarySortOrder] = useState<'DESC' | 'ASC'>('DESC');

  // Calendar System State
  const [calendarViewDate, setCalendarViewDate] = useState(new Date('2023-10-01'));
  const [calendarType, setCalendarType] = useState<'EXPENSE' | 'INCOME' | 'BALANCE'>('EXPENSE');
  const [calendarScope, setCalendarScope] = useState<'MONTH' | 'WEEK' | 'DAY'>('MONTH');

  // History & Report Date Filter State
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01')); // Default to mock data date

  // Notification State
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  useEffect(() => {
    // Request notification permission on mount
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  // Derived Data: Base Filter by User/Mode
  const filteredTransactions = useMemo(() => {
    if (viewMode === 'JOINT') return transactions;
    return transactions.filter(t => t.userId === selectedUserId);
  }, [transactions, viewMode, selectedUserId]);

  // Derived Data: Monthly Transactions for Chart & Summaries
  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [filteredTransactions, historyDate]);

  // --- REPORT SUMMARY DATA CALCULATIONS ---
  const reportTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [transactions, historyDate]);

  const reportTotalIncome = useMemo(() => reportTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [reportTransactions]);
  const reportTotalExpense = useMemo(() => reportTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [reportTransactions]);

  const reportUserStats = useMemo(() => {
    return users.map(u => {
      const userTx = reportTransactions.filter(t => t.userId === u.id);
      const income = userTx.filter(t => t.type === TransactionType.INCOME).reduce((s, t) => s + t.amount, 0);
      const expense = userTx.filter(t => t.type === TransactionType.EXPENSE).reduce((s, t) => s + t.amount, 0);
      return { ...u, income, expense };
    });
  }, [users, reportTransactions]);

  const reportTopCategories = useMemo(() => {
    const expenses = reportTransactions.filter(t => t.type === TransactionType.EXPENSE);
    const catMap: Record<string, number> = {};
    expenses.forEach(t => {
      if (!catMap[t.categoryId]) catMap[t.categoryId] = 0;
      catMap[t.categoryId] += t.amount;
    });
    return Object.entries(catMap)
      .map(([id, amount]) => ({
        category: categories.find(c => c.id === id)!,
        amount
      }))
      .sort((a, b) => b.amount - a.amount)
      .slice(0, 5);
  }, [reportTransactions, categories]);
  // ------------------------------------------

  // 1. Chart Data with Dynamic Budget Colors
  const chartData = useMemo(() => {
    const data = categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         // Calculate Color based on Budget Limit
         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let statusColor = '#10b981'; // Safe
         if (percentage >= 100) statusColor = '#e11d48'; 
         else if (percentage >= 90) statusColor = '#f97316'; 
         else if (percentage >= 70) statusColor = '#facc15'; 

         return { 
           id: cat.id, 
           name: cat.name, 
           value: val, 
           color: statusColor,
           originalColor: cat.color 
         };
      })
      .filter(d => d.value > 0);

    // Sort for the list view primarily
    return data.sort((a, b) => {
      return summarySortOrder === 'DESC' ? b.value - a.value : a.value - b.value;
    });
  }, [categories, monthlyTransactions, viewMode, summarySortOrder]);

  // 2. Data for Dashboard Side Panel (Specific Category Details)
  const selectedCategoryTransactions = useMemo(() => {
    if (!selectedChartCategoryId) return [];
    return monthlyTransactions
      .filter(t => t.categoryId === selectedChartCategoryId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [monthlyTransactions, selectedChartCategoryId]);

  const groupedSelectedCategoryTransactions = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    selectedCategoryTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [selectedCategoryTransactions]);

  // 3. Calendar Data Calculation
  const toDateKey = (date: Date) => {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, '0');
    const d = String(date.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  };

  const calendarDataMap = useMemo(() => {
    const map: Record<string, number> = {};
    filteredTransactions.forEach(tx => {
      const key = tx.date; 
      if (!map[key]) map[key] = 0;

      if (calendarType === 'EXPENSE' && tx.type === TransactionType.EXPENSE) {
        map[key] += tx.amount;
      } else if (calendarType === 'INCOME' && tx.type === TransactionType.INCOME) {
        map[key] += tx.amount;
      } else if (calendarType === 'BALANCE') {
        if (tx.type === TransactionType.INCOME) map[key] += tx.amount;
        else map[key] -= tx.amount;
      }
    });
    return map;
  }, [filteredTransactions, calendarType]);

  const calendarCells = useMemo(() => {
    const cells = [];
    if (calendarScope === 'MONTH') {
        const year = calendarViewDate.getFullYear();
        const month = calendarViewDate.getMonth();
        const firstDay = new Date(year, month, 1).getDay();
        const daysInMonth = new Date(year, month + 1, 0).getDate();

        for(let i=0; i<firstDay; i++) cells.push(null);
        for(let i=1; i<=daysInMonth; i++) cells.push(new Date(year, month, i));
    } else if (calendarScope === 'WEEK') {
        const current = new Date(calendarViewDate);
        const day = current.getDay();
        const start = new Date(current);
        start.setDate(current.getDate() - day);
        for(let i=0; i<7; i++) {
            const date = new Date(start);
            date.setDate(start.getDate() + i);
            cells.push(date);
        }
    } else {
        cells.push(new Date(calendarViewDate));
    }
    return cells;
  }, [calendarViewDate, calendarScope]);

  const calendarTitle = useMemo(() => {
    const y = calendarViewDate.getFullYear();
    const m = calendarViewDate.getMonth() + 1;
    const d = calendarViewDate.getDate();

    if (calendarScope === 'MONTH') return `${y}. ${m}`;
    if (calendarScope === 'DAY') return `${y}. ${m}. ${d}`;
    if (calendarScope === 'WEEK') {
        const day = calendarViewDate.getDay(); 
        const start = new Date(calendarViewDate);
        start.setDate(d - day);
        const end = new Date(start);
        end.setDate(start.getDate() + 6);
        return `${start.getMonth()+1}.${start.getDate()} - ${end.getMonth()+1}.${end.getDate()}`;
    }
    return '';
  }, [calendarViewDate, calendarScope]);

  // History Tab Data 
  const historyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return filteredTransactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredTransactions, historyDate]);

  const groupedHistory = useMemo(() => {
    const groups: { [key: string]: Transaction[] } = {};
    historyTransactions.forEach(tx => {
      if (!groups[tx.date]) groups[tx.date] = [];
      groups[tx.date].push(tx);
    });
    return groups;
  }, [historyTransactions]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const budgetStatuses: BudgetStatus[] = useMemo(() => {
    return categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
        const spent = filteredTransactions
          .filter(t => t.categoryId === cat.id)
          .reduce((sum, t) => sum + t.amount, 0);

        const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
        const percentage = limit > 0 ? (spent / limit) * 100 : 0;

        let status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED' = 'SAFE';
        if (percentage >= 100) status = 'EXCEEDED';
        else if (percentage >= 90) status = 'DANGER'; 
        else if (percentage >= 70) status = 'WARNING';

        return { categoryId: cat.id, spent, limit, percentage, status };
      })
      .sort((a, b) => b.percentage - a.percentage);
  }, [categories, filteredTransactions, viewMode]);

  const checkBudgetAndNotify = (newTx: Transaction, allTransactions: Transaction[]) => {
    if (newTx.type !== TransactionType.EXPENSE) return;

    const category = categories.find(c => c.id === newTx.categoryId);
    if (!category || category.budgetLimit === 0) return;

    const txDate = new Date(newTx.date);
    const limit = viewMode === 'JOINT' ? category.budgetLimit : category.budgetLimit / 2;
    const alertPrefix = viewMode === 'JOINT' ? '[공동]' : '[개인]';

    const currentSpent = allTransactions
      .filter(t => {
        const isUserMatch = viewMode === 'JOINT' ? true : t.userId === selectedUserId;
        if (!isUserMatch) return false;

        const d = new Date(t.date);
        return t.categoryId === newTx.categoryId && 
               d.getFullYear() === txDate.getFullYear() && 
               d.getMonth() === txDate.getMonth() &&
               t.type === TransactionType.EXPENSE;
      })
      .reduce((sum, t) => sum + t.amount, 0);

    const totalSpent = currentSpent + newTx.amount;
    const percentage = (totalSpent / limit) * 100;

    let alertMessage = '';
    let alertType: ToastType | null = null;

    if (percentage >= 100) {
      alertMessage = `${alertPrefix} ${category.name} 예산을 초과했습니다! (${percentage.toFixed(0)}%)`;
      alertType = 'error';
    } else if (percentage >= 90) {
      alertMessage = `${alertPrefix} ${category.name} 예산의 90%를 사용했습니다.`;
      alertType = 'error';
    } else if (percentage >= 70) {
      alertMessage = `${alertPrefix} ${category.name} 예산의 70%를 도달했습니다.`;
      alertType = 'warning';
    }

    if (alertMessage && alertType) {
      setToast({ message: alertMessage, type: alertType });

      if ('Notification' in window && Notification.permission === 'granted') {
        new Notification('Co-Budget 경고', {
          body: alertMessage,
          icon: '/icon.png'
        });
      }
    }
  };

  const handleAddTransaction = (newTx: any) => {
    const tx: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };
    checkBudgetAndNotify(tx, transactions);
    setTransactions(prev => [tx, ...prev]);
  };

  const handleUpdateBudgets = (updatedCategories: Category[]) => {
    setCategories(updatedCategories);
  };

  const handlePrevMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  const moveCalendar = (direction: 'prev' | 'next') => {
    const diff = direction === 'next' ? 1 : -1;
    const newDate = new Date(calendarViewDate);
    if (calendarScope === 'MONTH') {
        newDate.setMonth(newDate.getMonth() + diff);
    } else if (calendarScope === 'WEEK') {
        newDate.setDate(newDate.getDate() + (diff * 7));
    } else {
        newDate.setDate(newDate.getDate() + diff);
    }
    setCalendarViewDate(newDate);
  };

  const selectedCategoryInfo = categories.find(c => c.id === selectedChartCategoryId);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && (
        <Toast 
          message={toast.message} 
          type={toast.type} 
          onClose={() => setToast(null)} 
        />
      )}

      {/* View Mode Switcher - Only show on Dashboard, Budget, History tabs */}
      {activeTab !== 'SUMMARY' && (
        <div className="mb-6 flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="flex bg-white rounded-xl p-1 shadow-sm border">
            <button 
              onClick={() => setViewMode('JOINT')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'JOINT' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              공동 관리
            </button>
            <button 
              onClick={() => setViewMode('INDIVIDUAL')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition ${viewMode === 'INDIVIDUAL' ? 'bg-brand-600 text-white shadow' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              개인 관리
            </button>
          </div>

          {viewMode === 'INDIVIDUAL' && (
             <div className="flex gap-2">
               {users.map(u => (
                 <button 
                  key={u.id}
                  onClick={() => setSelectedUserId(u.id)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-full border transition ${selectedUserId === u.id ? 'bg-white border-brand-500 ring-2 ring-brand-100' : 'bg-gray-50 border-transparent opacity-60'}`}
                 >
                   <div className="w-6 h-6 rounded-full flex items-center justify-center text-xs text-white font-bold" style={{ backgroundColor: u.color }}>{u.name[0]}</div>
                   <span className="text-sm font-medium">{u.name}</span>
                 </button>
               ))}
             </div>
          )}
        </div>
      )}

      {/* --- SUMMARY REPORT TAB --- */}
      {activeTab === 'SUMMARY' && (
        <div className="space-y-6">
          {/* Header Date Controller */}
          <div className="bg-white p-4 rounded-xl shadow-sm border flex items-center justify-between">
              <button onClick={handlePrevMonth} className="p-2 hover:bg-gray-100 rounded-full transition"><ChevronLeft size={20} /></button>
              <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                 <ClipboardList className="text-brand-600" />
                 {historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월 총정리
              </h2>
              <button onClick={handleNextMonth} className="p-2 hover:bg-gray-100 rounded-full transition"><ChevronRight size={20} /></button>
          </div>

          {/* Big Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-3xl font-bold text-gray-800">
                {(reportTotalIncome - reportTotalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32">
              <span className="text-sm text-gray-500 font-medium">총 수입</span>
              <div className="text-3xl font-bold text-emerald-600">
                +{reportTotalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32">
              <span className="text-sm text-gray-500 font-medium">총 지출</span>
              <div className="text-3xl font-bold text-rose-600">
                -{reportTotalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* User Breakdown */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                  <PieChart size={18} /> 사용자별 기여도
                </h3>
                <div className="space-y-4">
                   {reportUserStats.map(stat => (
                     <div key={stat.id} className="p-4 rounded-xl bg-gray-50 border border-gray-100">
                        <div className="flex items-center gap-3 mb-3">
                           <div className="w-8 h-8 rounded-full flex items-center justify-center text-white font-bold" style={{ backgroundColor: stat.color }}>
                              {stat.name[0]}
                           </div>
                           <span className="font-bold text-gray-800">{stat.name}</span>
                        </div>
                        <div className="grid grid-cols-2 gap-4 text-sm">
                           <div>
                              <span className="text-gray-400 text-xs block">지출</span>
                              <span className="text-rose-600 font-bold">{stat.expense.toLocaleString()}원</span>
                           </div>
                           <div>
                              <span className="text-gray-400 text-xs block">수입</span>
                              <span className="text-emerald-600 font-bold">{stat.income.toLocaleString()}원</span>
                           </div>
                        </div>
                        {/* Simple Bar for Ratio */}
                        <div className="mt-3 h-2 bg-gray-200 rounded-full overflow-hidden flex">
                            <div className="bg-rose-500 h-full" style={{ width: `${(stat.expense / (reportTotalExpense || 1)) * 100}%` }}></div>
                        </div>
                     </div>
                   ))}
                </div>
             </div>

             {/* Top Spending Categories */}
             <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                   <BarChart3 size={18} /> 지출 TOP 5 카테고리
                </h3>
                <div className="space-y-3">
                   {reportTopCategories.map((item, index) => (
                      <div key={item.category.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-gray-50 transition">
                         <div className="flex items-center gap-3">
                            <div className="w-6 h-6 flex items-center justify-center font-bold text-xs rounded-full bg-gray-100 text-gray-500 border">
                               {index + 1}
                            </div>
                            <div className="flex items-center gap-2">
                               <div className="text-gray-500" style={{ color: item.category.color }}>
                                 {getCategoryIcon(item.category.name, 18)}
                               </div>
                               <span className="font-semibold text-gray-700">{item.category.name}</span>
                            </div>
                         </div>
                         <div className="font-bold text-gray-900">
                            {item.amount.toLocaleString()}원
                         </div>
                      </div>
                   ))}
                   {reportTopCategories.length === 0 && (
                      <div className="text-center py-10 text-gray-400">지출 내역이 없습니다.</div>
                   )}
                </div>
             </div>
          </div>
        </div>
      )}

      {/* --- DASHBOARD TAB --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">총 잔액</span>
              <div className="text-2xl font-bold text-gray-800 mt-1">
                {(totalIncome - totalExpense).toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 수입</span>
              <div className="text-2xl font-bold text-emerald-600 mt-1">
                + {totalIncome.toLocaleString()}원
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
              <span className="text-sm text-gray-500 font-medium">이번 달 지출</span>
              <div className="text-2xl font-bold text-rose-600 mt-1">
                - {totalExpense.toLocaleString()}원
              </div>
            </div>
          </div>

          {/* Charts Section */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-8">
             {/* Chart */}
             <div className="flex-1 flex flex-col items-center justify-center relative min-h-[350px]">
               <div className="flex items-center justify-between w-full mb-4">
                  <h3 className="text-lg font-bold text-gray-800">카테고리별 지출 (한도 기준)</h3>
                  <button 
                    onClick={() => setIsBudgetEditOpen(true)}
                    className="flex items-center gap-1 text-xs font-bold bg-gray-100 text-gray-600 px-3 py-1.5 rounded-full hover:bg-gray-200 transition"
                  >
                    <Settings size={14} />
                    한도 설정
                  </button>
               </div>

               {chartData.length > 0 ? (
                 <div className="h-full w-full relative min-h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart
                        layout="vertical"
                        data={chartData}
                        margin={{ top: 10, right: 30, left: 20, bottom: 5 }}
                        barSize={20}
                      >
                        <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                        <XAxis type="number" hide />
                        <YAxis 
                          dataKey="name" 
                          type="category" 
                          width={60} 
                          tick={{ fontSize: 12, fill: '#6b7280' }} 
                        />
                        <Tooltip 
                          cursor={{ fill: '#f3f4f6' }}
                          formatter={(value: number) => [`${value.toLocaleString()}원`, '지출']}
