          <button onClick={onClose} className="hover:rotate-90 transition-transform"><X size={20} /></button>
        </div>

        <div className="overflow-y-auto p-8 flex-1 space-y-8">
          {/* Form Content */}
          <div className="flex bg-zinc-100 p-1 border border-zinc-200">
            <button type="button" onClick={() => setType(TransactionType.EXPENSE)} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-widest transition ${type === TransactionType.EXPENSE ? 'bg-black text-white' : 'text-zinc-500 hover:text-black'}`}>Expense</button>
            <button type="button" onClick={() => setType(TransactionType.INCOME)} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-widest transition ${type === TransactionType.INCOME ? 'bg-black text-white' : 'text-zinc-500 hover:text-black'}`}>Income</button>
          </div>

          <div className="space-y-6">
