import React from 'react';
import { AlertCircle } from 'lucide-react';
import { BudgetStatus, Category } from '../types';

interface BudgetCardProps {
  category: Category;
  status: BudgetStatus;
}

export const BudgetCard: React.FC<BudgetCardProps> = ({ category, status }) => {
  const isAlert = status.status === 'DANGER' || status.status === 'EXCEEDED';
  const progressWidth = Math.min(status.percentage, 100);

  // Monochrome intensity
  const getProgressBg = () => {
    if (status.status === 'EXCEEDED') return 'bg-black';
    if (status.status === 'DANGER') return 'bg-zinc-800';
    if (status.status === 'WARNING') return 'bg-zinc-400';
    return 'bg-zinc-200';
  };

  return (
    <div className="bg-white border border-black p-6 flex flex-col gap-4">
      <div className="flex justify-between items-start">
        <div className="space-y-1">
          <h4 className="text-xs font-bold uppercase tracking-widest">{category.name}</h4>
          <p className="text-[9px] font-bold text-zinc-400 uppercase">Limit: {category.budgetLimit.toLocaleString()} KRW</p>
        </div>
        {isAlert && <div className="bg-black text-white px-2 py-0.5 text-[8px] font-bold uppercase tracking-widest">Alert</div>}
      </div>

      <div className="space-y-2">
        <div className="h-1 w-full bg-zinc-100 overflow-hidden">
          <div className={`h-full transition-all duration-700 ${getProgressBg()}`} style={{ width: `${progressWidth}%` }} />
        </div>
        <div className="flex justify-between items-center text-[10px] font-bold tabular-nums">
           <span>{status.spent.toLocaleString()} / {category.budgetLimit.toLocaleString()}</span>
           <span className={status.status === 'EXCEEDED' ? 'text-black underline font-black' : 'text-zinc-400'}>{status.percentage.toFixed(0)}%</span>
        </div>
      </div>

      {status.status === 'EXCEEDED' && (
        <div className="bg-zinc-50 border border-black p-3 text-[9px] font-bold uppercase flex items-center gap-2">
          <AlertCircle size={12} />
          <span>Variance: {Math.abs(status.limit - status.spent).toLocaleString()} Over Budget</span>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

// Analyze receipt image using the recommended gemini-3-flash-preview model.
export const analyzeReceiptImage = async (base64Image: string): Promise<{ amount: number; description: string; date: string; categoryGuess: string }> => {
  try {
    // Initialize Gemini API client using the environment variable directly.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: cleanBase64,
            },
          },
          {
            text: "Analyze this receipt image. Extract the total amount, the date (ISO format YYYY-MM-DD), a short description (merchant name), and guess a generic category (e.g., Food, Transport, Shopping).",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            description: { type: Type.STRING },
            categoryGuess: { type: Type.STRING },
          },
          required: ["amount", "date", "description", "categoryGuess"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    // Ensure the response text is trimmed and parsed correctly.
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Receipt analysis failed:", error);
    throw error;
  }
};

