                       </div>
                       <div>
                          <p className="text-lg font-bold tabular-nums truncate">{amount.toLocaleString()}</p>
                       </div>
                    </div>
                  );
                })}
            </div>
          </div>
        </div>
      )}

      {/* HISTORY & OTHER TABS RENDER LOGIC */}
      {activeTab === 'HISTORY' && (
        <div className="border border-black bg-white">
