        <div className="p-8 border-t border-black bg-zinc-50">
          <button type="submit" onClick={handleSubmit} className="w-full bg-black text-white py-4 font-bold uppercase tracking-widest hover:bg-zinc-800 transition">내역 저장하기</button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { AlertCircle } from 'lucide-react';
import { BudgetStatus, Category } from '../types';

interface BudgetCardProps {
  category: Category;
  status: BudgetStatus;
}

export const BudgetCard: React.FC<BudgetCardProps> = ({ category, status }) => {
  const isAlert = status.status === 'DANGER' || status.status === 'EXCEEDED';
  const progressWidth = Math.min(status.percentage, 100);

  // Monochrome intensity
  const getProgressBg = () => {
    if (status.status === 'EXCEEDED') return 'bg-black';
    if (status.status === 'DANGER') return 'bg-zinc-800';
    if (status.status === 'WARNING') return 'bg-zinc-400';
    return 'bg-zinc-200';
  };

  return (
    <div className="bg-white border border-black p-6 flex flex-col gap-4">
      <div className="flex justify-between items-start">
        <div className="space-y-1">
          <h4 className="text-xs font-bold uppercase tracking-widest">{category.name}</h4>
          <p className="text-[9px] font-bold text-zinc-400 uppercase">한도: {category.budgetLimit.toLocaleString()} 원</p>
        </div>
        {isAlert && <div className="bg-black text-white px-2 py-0.5 text-[8px] font-bold uppercase tracking-widest">경고</div>}
      </div>

      <div className="space-y-2">
        <div className="h-1 w-full bg-zinc-100 overflow-hidden">
          <div className={`h-full transition-all duration-700 ${getProgressBg()}`} style={{ width: `${progressWidth}%` }} />
        </div>
        <div className="flex justify-between items-center text-[10px] font-bold tabular-nums">
           <span>{status.spent.toLocaleString()} / {category.budgetLimit.toLocaleString()}</span>
           <span className={status.status === 'EXCEEDED' ? 'text-black underline font-black' : 'text-zinc-400'}>{status.percentage.toFixed(0)}%</span>
        </div>
      </div>

      {status.status === 'EXCEEDED' && (
        <div className="bg-zinc-50 border border-black p-3 text-[9px] font-bold uppercase flex items-center gap-2">
          <AlertCircle size={12} />
          <span>차액: {Math.abs(status.limit - status.spent).toLocaleString()} 원 예산 초과</span>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { X, Save } from 'lucide-react';
import { Category, TransactionType } from '../types';

interface BudgetSettingModalProps {
  categories: Category[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const BudgetSettingModal: React.FC<BudgetSettingModalProps> = ({ categories, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);

  const handleChange = (id: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, budgetLimit: limit } : c));
  };

  const handleSave = () => {
    onSave(localCategories);
    onClose();
  };

  const expenseCategories = localCategories.filter(c => c.type === TransactionType.EXPENSE);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white border-2 border-black w-full max-w-lg shadow-[20px_20px_0px_0px_rgba(0,0,0,1)] flex flex-col max-h-[80vh]">
        <div className="p-6 border-b border-black flex justify-between items-center bg-zinc-50">
          <h2 className="text-xs font-bold uppercase tracking-widest">예산 한도 구성</h2>
          <button onClick={onClose} className="hover:rotate-90 transition-transform">
            <X size={20} />
          </button>
        </div>

        <div className="overflow-y-auto p-8 flex-1 space-y-6">
          <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest leading-relaxed">
            각 카테고리별 월간 지출 한도를 설정하십시오. 한도 근접 시 모니터링 색상이 변경됩니다.
          </p>
          <div className="space-y-4">
            {expenseCategories.map(cat => (
              <div key={cat.id} className="flex flex-col gap-1">
                <label className="text-[9px] font-bold uppercase text-zinc-500">{cat.name}</label>
                <div className="flex items-center gap-3">
                  <div className="flex-1 relative">
                    <input
                      type="text"
                      value={cat.budgetLimit.toLocaleString()}
                      onChange={(e) => handleChange(cat.id, e.target.value)}
                      className="w-full border border-black p-3 text-xs font-bold outline-none text-right pr-8 tabular-nums focus:bg-zinc-50 transition"
                    />
                    <span className="absolute right-3 top-3 text-[10px] font-bold text-zinc-400">원</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="p-8 border-t border-black bg-zinc-50">
          <button
            onClick={handleSave}
            className="w-full bg-black text-white py-4 font-bold uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-zinc-800 transition"
          >
            <Save size={16} />
            구성 저장하기
          </button>
        </div>
      </div>
    </div>
  );
};

