                  ))}
                </div>
             </div>

             {/* 요약 리스트 사이드 */}
             <div className="p-8 bg-zinc-50">
                <div className="flex items-center justify-between mb-8">
                  <h4 className="text-[10px] font-bold uppercase tracking-widest text-zinc-500">지출 요약 리스트</h4>
