                  >
                     <ArrowUpDown size={12} /> {summarySortOrder === 'DESC' ? '높은순' : '낮은순'}
                  </button>
                </div>

                <div className="space-y-1 max-h-[300px] overflow-y-auto custom-scrollbar">
                  {chartData.map((d, i) => (
                    <div 
