import React, { useState } from 'react';
import { X, Save, Plus, Trash2, Palette } from 'lucide-react';
import { Category, TransactionType } from '../types';

interface CategoryManagerModalProps {
  categories: Category[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const CategoryManagerModal: React.FC<CategoryManagerModalProps> = ({ categories, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeType, setActiveType] = useState<TransactionType>(TransactionType.EXPENSE);

  const handleUpdate = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAdd = () => {
    const newId = `c_new_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 분류',
      group: activeType === TransactionType.EXPENSE ? '기타' : '수입',
      type: activeType,
      budgetLimit: 0,
      color: '#000000'
    };
    setLocalCategories([...localCategories, newCat]);
  };

  const handleDelete = (id: string) => {
    setLocalCategories(prev => prev.filter(c => c.id !== id));
  };

  const currentCats = localCategories.filter(c => c.type === activeType);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white border-2 border-black w-full max-w-2xl shadow-[20px_20px_0px_0px_rgba(0,0,0,1)] flex flex-col max-h-[85vh]">
        <div className="p-6 border-b border-black flex justify-between items-center bg-zinc-50">
          <h2 className="text-xs font-bold uppercase tracking-widest">분류 체계 관리</h2>
          <button onClick={onClose} className="hover:rotate-90 transition-transform"><X size={20} /></button>
        </div>

        <div className="flex border-b border-black">
          <button onClick={() => setActiveType(TransactionType.EXPENSE)} className={`flex-1 py-4 text-[10px] font-bold uppercase tracking-widest transition ${activeType === TransactionType.EXPENSE ? 'bg-black text-white' : 'hover:bg-zinc-50'}`}>지출 분류</button>
          <button onClick={() => setActiveType(TransactionType.INCOME)} className={`flex-1 py-4 text-[10px] font-bold uppercase tracking-widest transition ${activeType === TransactionType.INCOME ? 'bg-black text-white' : 'hover:bg-zinc-50'}`}>수입 분류</button>
        </div>

        <div className="overflow-y-auto p-6 flex-1 space-y-4 custom-scrollbar bg-zinc-50/50">
          <div className="flex justify-between items-center mb-6">
            <span className="text-[10px] font-bold text-zinc-400 uppercase">총 {currentCats.length}개의 카테고리</span>
            <button onClick={handleAdd} className="flex items-center gap-2 bg-black text-white px-4 py-2 text-[10px] font-bold uppercase hover:bg-zinc-800 transition">
              <Plus size={14} /> 추가하기
            </button>
          </div>

          <div className="space-y-3">
            {currentCats.map(cat => (
              <div key={cat.id} className="bg-white border border-black p-4 grid grid-cols-12 gap-4 items-center">
                <div className="col-span-1">
                  <input 
                    type="color" 
                    value={cat.color} 
                    onChange={(e) => handleUpdate(cat.id, 'color', e.target.value)}
                    className="w-full h-8 cursor-pointer border-none bg-transparent"
                  />
                </div>
                <div className="col-span-3">
                  <input 
                    type="text" 
                    value={cat.group} 
                    onChange={(e) => handleUpdate(cat.id, 'group', e.target.value)}
                    placeholder="그룹명"
                    className="w-full text-[10px] font-bold border-b border-zinc-200 outline-none p-1 uppercase"
                  />
                </div>
                <div className="col-span-3">
                  <input 
                    type="text" 
                    value={cat.name} 
                    onChange={(e) => handleUpdate(cat.id, 'name', e.target.value)}
                    placeholder="분류명"
                    className="w-full text-xs font-bold border-b border-zinc-200 outline-none p-1"
                  />
                </div>
                <div className="col-span-4 relative">
                  <input 
                    type="text" 
                    value={cat.budgetLimit.toLocaleString()} 
                    onChange={(e) => handleUpdate(cat.id, 'budgetLimit', parseInt(e.target.value.replace(/[^0-9]/g, '')) || 0)}
                    placeholder="예산"
                    disabled={activeType === TransactionType.INCOME}
                    className="w-full text-xs font-bold border-b border-zinc-200 outline-none p-1 text-right pr-4 tabular-nums"
                  />
                  <span className="absolute right-0 bottom-1 text-[8px] font-bold text-zinc-400">₩</span>
                </div>
                <div className="col-span-1 flex justify-end">
                  <button onClick={() => handleDelete(cat.id)} className="text-zinc-300 hover:text-rose-500 transition"><Trash2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="p-6 border-t border-black bg-zinc-50">
          <button onClick={() => { onSave(localCategories); onClose(); }} className="w-full bg-black text-white py-4 font-bold uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-zinc-800 transition">
            <Save size={16} /> 설정 저장하기
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { X, Camera, MapPin, Loader2 } from 'lucide-react';
import { TransactionType, Category, User, GeoLocation } from '../types';

interface TransactionFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  categories: Category[];
  users: User[];
  currentUser: User;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onClose, onSubmit, categories, users, currentUser }) => {
  const [type, setType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [amount, setAmount] = useState<string>('');
  const [categoryId, setCategoryId] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState<string>('');
  const [userId, setUserId] = useState<string>(currentUser.id);

  // 그룹별 카테고리 구성
  const groupedOptions = useMemo(() => {
    const filtered = categories.filter(c => c.type === type);
    const groups: Record<string, Category[]> = {};
    filtered.forEach(cat => {
      if (!groups[cat.group]) groups[cat.group] = [];
      groups[cat.group].push(cat);
    });
    return groups;
  }, [categories, type]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !categoryId || !description) return;
    onSubmit({ type, amount: parseFloat(amount), categoryId, userId, date, description });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white border-2 border-black w-full max-w-lg shadow-[20px_20px_0px_0px_rgba(0,0,0,1)] flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-black flex justify-between items-center bg-zinc-50">
          <h2 className="text-xs font-bold uppercase tracking-widest">새 거래 내역</h2>
          <button onClick={onClose} className="hover:rotate-90 transition-transform"><X size={20} /></button>
        </div>

        <div className="overflow-y-auto p-8 flex-1 space-y-8 custom-scrollbar">
          <div className="flex bg-zinc-100 p-1 border border-zinc-200">
            <button type="button" onClick={() => setType(TransactionType.EXPENSE)} className={`flex-1 py-2 text-[10px] font-bold uppercase transition ${type === TransactionType.EXPENSE ? 'bg-black text-white' : 'text-zinc-500 hover:text-black'}`}>지출</button>
            <button type="button" onClick={() => setType(TransactionType.INCOME)} className={`flex-1 py-2 text-[10px] font-bold uppercase transition ${type === TransactionType.INCOME ? 'bg-black text-white' : 'text-zinc-500 hover:text-black'}`}>수입</button>
          </div>

          <div className="space-y-6">
            <div>
              <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">거래 금액</label>
              <input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full text-4xl font-bold border-b border-black outline-none py-2 bg-transparent tabular-nums" placeholder="0" required />
            </div>

            <div className="grid grid-cols-2 gap-6">
              <div>
                <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">날짜</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full border border-black p-3 text-xs font-bold outline-none" required />
              </div>
              <div>
                <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">상세 분류</label>
                <select value={categoryId} onChange={(e) => setCategoryId(e.target.value)} className="w-full border border-black p-3 text-xs font-bold outline-none appearance-none bg-white" required>
                  <option value="">분류 선택...</option>
                  {Object.entries(groupedOptions).map(([group, cats]) => (
                    <optgroup key={group} label={group}>
                      {cats.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </optgroup>
                  ))}
                </select>
              </div>
            </div>

            <div>
              <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">거래 설명</label>
              <input type="text" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full border border-black p-3 text-xs font-bold outline-none" placeholder="내용을 입력하세요" required />
            </div>

            <div>
              <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">기록 주체</label>
              <div className="flex gap-2">
                {users.map(u => (
                  <button key={u.id} type="button" onClick={() => setUserId(u.id)} className={`px-4 py-2 border text-[10px] font-bold uppercase transition ${userId === u.id ? 'bg-black text-white border-black' : 'bg-white text-zinc-400 border-zinc-200'}`}>{u.name}</button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="p-8 border-t border-black bg-zinc-50">
          <button type="submit" onClick={handleSubmit} className="w-full bg-black text-white py-4 font-bold uppercase tracking-widest hover:bg-zinc-800 transition">기록 저장하기</button>
        </div>
      </div>
    </div>
  );
};

