  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export enum UserRole {
  ADMIN = 'ADMIN',
  MEMBER = 'MEMBER',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  role: UserRole;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string; // '식비', '생활', '교통' 등의 상위 그룹
  type: TransactionType;
  budgetLimit: number;
  color: string;
  iconId: string; // 아이콘 식별자 추가
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

