const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY' | 'SUMMARY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);

  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);
  const [summarySortOrder, setSummarySortOrder] = useState<'DESC' | 'ASC'>('DESC');

  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [calendarType, setCalendarType] = useState<'EXPENSE' | 'INCOME' | 'BALANCE'>('EXPENSE');
  const [selectedCalendarDateKey, setSelectedCalendarDateKey] = useState<string | null>(null);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedUserId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [transactions, historyDate, viewMode, selectedUserId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const chartData = useMemo<ChartDataItem[]>(() => {
    const data = categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let displayColor = cat.color !== '#000000' ? cat.color : (percentage >= 100 ? '#000000' : '#e5e5e5');
         return { id: cat.id, name: cat.name, value: val, color: displayColor };
      })
      .filter(d => d.value > 0);

    return data.sort((a, b) => summarySortOrder === 'DESC' ? b.value - a.value : a.value - b.value);
  }, [categories, monthlyTransactions, viewMode, summarySortOrder]);

  const groupedCategories = useMemo<Record<string, Category[]>>(() => {
    const expenseCats = categories.filter(c => c.type === TransactionType.EXPENSE);
    const groups: Record<string, Category[]> = {};
    expenseCats.forEach(cat => {
      if (!groups[cat.group]) groups[cat.group] = [];
      groups[cat.group].push(cat);
    });
    return groups;
  }, [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {activeTab !== 'SUMMARY' && (
        <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
          <div className="flex bg-white border border-black p-0.5">
            <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>공동 관리</button>
            <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>개인 관리</button>
          </div>
        </div>
      )}

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12">
          {/* 주요 지표 */}
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white">
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">총 잔액</span><div className="text-3xl font-bold mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div></div>
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">이번 달 수입</span><div className="text-3xl font-bold mt-2 tabular-nums text-black underline underline-offset-4 decoration-zinc-300">+ {totalIncome.toLocaleString()}</div></div>
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">이번 달 지출</span><div className="text-3xl font-bold mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div></div>
          </div>

          {/* Seamless 카테고리 그리드 (아이콘 지정을 통한 고도화) */}
          <div className="border border-black overflow-hidden bg-black">
            <div className="bg-zinc-50 p-6 border-b border-black flex items-center justify-between">
              <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2">
                <ClipboardList size={16} /> 세부 지출 분류 현황
              </h3>
              <button onClick={() => setIsCategoryManagerOpen(true)} className="text-[10px] font-bold uppercase underline">분류 및 아이콘 수정</button>
            </div>

            <div className="grid grid-cols-1 gap-px">
              {(Object.entries(groupedCategories) as [string, Category[]][]).map(([group, cats]) => (
                <div key={group} className="bg-white">
                  <div className="bg-zinc-100 px-6 py-2 border-b border-black flex items-center justify-between">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-zinc-500">{group} 그룹</span>
                  </div>
                  <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-px bg-black">
                    {cats.map(cat => {
                      const amount = monthlyTransactions.filter(t => t.categoryId === cat.id).reduce((sum, t) => sum + t.amount, 0);
                      return (
                        <div key={cat.id} className="bg-white p-6 h-32 flex flex-col justify-between hover:bg-zinc-50 transition-colors group/card">
                           <div className="flex items-start justify-between">
                              <div className="p-2 border border-zinc-100 transition-transform group-hover/card:scale-110" style={{ backgroundColor: cat.color + '15' }}>
                                <div style={{ color: cat.color }}>
                                  {renderCategoryIcon(cat.iconId, 16)}
                                </div>
                              </div>
                              <p className="text-[9px] font-bold text-zinc-400 uppercase truncate max-w-[60px]">{cat.name}</p>
                           </div>
                           <div className="mt-auto">
                              <p className="text-lg font-bold tabular-nums tracking-tight">{amount.toLocaleString()}</p>
                              <div className="w-0 group-hover/card:w-full h-0.5 bg-black transition-all duration-300"></div>
                           </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* 일간 통합 장부 (캘린더 부분은 생략 - 로직 동일) */}
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{...tx, id: Math.random().toString(36).substr(2,9)}, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

