import React, { useState } from 'react';
import { X, Save, Plus, Trash2, Smile } from 'lucide-react';
import { Category, TransactionType } from '../types';
import { ICON_MAP } from '../App';

interface CategoryManagerModalProps {
  categories: Category[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const CategoryManagerModal: React.FC<CategoryManagerModalProps> = ({ categories, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeType, setActiveType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [editingIconId, setEditingIconId] = useState<string | null>(null);

  const handleUpdate = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAdd = () => {
    const newId = `c_new_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 분류',
      group: activeType === TransactionType.EXPENSE ? '기타' : '수입',
      type: activeType,
      budgetLimit: 0,
      color: '#000000',
      iconId: 'other'
    };
    setLocalCategories([...localCategories, newCat]);
  };

  const handleDelete = (id: string) => {
    setLocalCategories(prev => prev.filter(c => c.id !== id));
  };

  const currentCats = localCategories.filter(c => c.type === activeType);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white border-2 border-black w-full max-w-3xl shadow-[20px_20px_0px_0px_rgba(0,0,0,1)] flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-black flex justify-between items-center bg-zinc-50">
          <h2 className="text-xs font-bold uppercase tracking-widest">분류 체계 및 아이콘 관리</h2>
          <button onClick={onClose} className="hover:rotate-90 transition-transform"><X size={20} /></button>
        </div>

        <div className="flex border-b border-black">
          <button onClick={() => setActiveType(TransactionType.EXPENSE)} className={`flex-1 py-4 text-[10px] font-bold uppercase transition ${activeType === TransactionType.EXPENSE ? 'bg-black text-white' : 'hover:bg-zinc-50'}`}>지출 분류</button>
          <button onClick={() => setActiveType(TransactionType.INCOME)} className={`flex-1 py-4 text-[10px] font-bold uppercase transition ${activeType === TransactionType.INCOME ? 'bg-black text-white' : 'hover:bg-zinc-50'}`}>수입 분류</button>
        </div>

        <div className="overflow-y-auto p-6 flex-1 space-y-4 custom-scrollbar bg-zinc-50/50">
          <div className="flex justify-between items-center mb-6">
            <span className="text-[10px] font-bold text-zinc-400 uppercase">총 {currentCats.length}개의 카테고리</span>
            <button onClick={handleAdd} className="flex items-center gap-2 bg-black text-white px-4 py-2 text-[10px] font-bold uppercase hover:bg-zinc-800 transition">
              <Plus size={14} /> 분류 추가
            </button>
          </div>

          <div className="space-y-3">
            {currentCats.map(cat => (
              <div key={cat.id} className="bg-white border border-black p-4 grid grid-cols-12 gap-3 items-center">
                <div className="col-span-1 relative">
                  <button 
                    onClick={() => setEditingIconId(editingIconId === cat.id ? null : cat.id)}
                    className="w-full aspect-square border border-zinc-200 flex items-center justify-center hover:bg-zinc-50 transition"
                    style={{ color: cat.color }}
                  >
                    {React.createElement(ICON_MAP[cat.iconId] || ICON_MAP.other, { size: 18 })}
                  </button>

                  {editingIconId === cat.id && (
                    <div className="absolute left-0 top-full mt-2 w-48 bg-white border-2 border-black z-10 p-2 grid grid-cols-4 gap-1 shadow-2xl">
                      {Object.keys(ICON_MAP).map(key => (
                        <button 
                          key={key} 
                          onClick={() => { handleUpdate(cat.id, 'iconId', key); setEditingIconId(null); }}
                          className={`p-2 hover:bg-zinc-100 flex items-center justify-center ${cat.iconId === key ? 'bg-zinc-100 outline outline-1 outline-black' : ''}`}
                        >
                          {React.createElement(ICON_MAP[key], { size: 16 })}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
                <div className="col-span-1">
                  <input 
                    type="color" 
                    value={cat.color} 
                    onChange={(e) => handleUpdate(cat.id, 'color', e.target.value)}
                    className="w-full h-8 cursor-pointer border-none bg-transparent"
                  />
                </div>
                <div className="col-span-3">
                  <input 
                    type="text" 
                    value={cat.group} 
                    onChange={(e) => handleUpdate(cat.id, 'group', e.target.value)}
                    placeholder="그룹"
                    className="w-full text-[10px] font-bold border-b border-zinc-100 outline-none p-1 uppercase"
                  />
                </div>
                <div className="col-span-3">
                  <input 
                    type="text" 
                    value={cat.name} 
                    onChange={(e) => handleUpdate(cat.id, 'name', e.target.value)}
                    placeholder="분류명"
                    className="w-full text-xs font-bold border-b border-zinc-100 outline-none p-1"
                  />
                </div>
                <div className="col-span-3">
                  <input 
                    type="text" 
                    value={cat.budgetLimit.toLocaleString()} 
                    onChange={(e) => handleUpdate(cat.id, 'budgetLimit', parseInt(e.target.value.replace(/[^0-9]/g, '')) || 0)}
                    placeholder="예산"
                    disabled={activeType === TransactionType.INCOME}
                    className="w-full text-xs font-bold border-b border-zinc-100 outline-none p-1 text-right tabular-nums"
                  />
