          <div className="border border-black bg-black grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-px">
            <div className="col-span-full bg-zinc-50 p-6 flex items-center justify-between border-b border-black">
              <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2">
                <ClipboardList size={16} /> 세부 지출 분류 현황
              </h3>
              <button onClick={() => setIsCategoryManagerOpen(true)} className="text-[10px] font-bold uppercase underline hover:text-zinc-500">분류 체계 수정</button>
            </div>

            {(Object.entries(groupedCategories) as [string, Category[]][]).map(([group, cats]) => (
              <React.Fragment key={group}>
                <div className="col-span-full bg-zinc-100 px-6 py-2 flex items-center justify-between border-y border-black -mt-px first:mt-0">
                  <span className="text-[10px] font-bold uppercase tracking-widest text-zinc-500">{group} 그룹</span>
                  <span className="text-[9px] font-bold text-zinc-400">{cats.length} Categories</span>
                </div>
                {cats.map(cat => {
                  const catTransactions = monthlyTransactions
                    .filter(t => t.categoryId === cat.id)
                    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                  const amount = catTransactions.reduce((sum, t) => sum + t.amount, 0);
                  const isFoodGroup = group === '식비';

                  return (
                    <div key={cat.id} className={`bg-white p-6 ${isFoodGroup ? 'h-[280px]' : 'h-36'} flex flex-col hover:bg-zinc-50 transition-colors group/card cursor-default`}>
                       <div className="flex items-start justify-between mb-4">
                          <div className="p-2 border border-black/5 bg-zinc-50 transition-transform group-hover/card:scale-110" style={{ color: cat.color }}>
                            {renderCategoryIcon(cat.iconId, 18)}
                          </div>
                          <p className="text-[9px] font-black text-zinc-300 uppercase tracking-tighter truncate max-w-[70px] group-hover/card:text-zinc-400 transition-colors">{cat.name}</p>
                       </div>

                       <div className="mb-4">
                          <p className="text-[10px] font-bold text-zinc-400 uppercase mb-1">지출액</p>
                          <p className="text-xl font-bold tabular-nums tracking-tighter">{amount.toLocaleString()}</p>
                          <div className="w-0 group-hover/card:w-full h-0.5 bg-black transition-all duration-500 mt-2"></div>
                       </div>

                       {/* 식비 그룹 전용 상세 내역 영역 */}
                       {isFoodGroup && (
                         <div className="flex-1 mt-2 border-t border-zinc-100 pt-3 overflow-hidden flex flex-col">
                            <p className="text-[9px] font-bold text-zinc-400 uppercase mb-2">상세 내역</p>
                            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                               {catTransactions.length > 0 ? (
                                 catTransactions.map(t => (
                                   <div key={t.id} className="flex justify-between items-start gap-2 border-b border-zinc-50 pb-1.5 last:border-0">
                                      <div className="flex flex-col">
                                         <span className="text-[9px] font-bold text-zinc-600 truncate max-w-[80px]">{t.description}</span>
                                         <span className="text-[8px] text-zinc-400 tabular-nums">{t.date.split('-').slice(1).join('/')}</span>
                                      </div>
                                      <span className="text-[9px] font-bold tabular-nums">{t.amount.toLocaleString()}</span>
                                   </div>
                                 ))
                               ) : (
                                 <span className="text-[9px] text-zinc-300 italic">내역 없음</span>
                               )}
                            </div>
                         </div>
                       )}
                    </div>
                  );
                })}
              </React.Fragment>
            ))}
          </div>

          {/* 일간 통합 장부 (캘린더) */}
          <div className="border-2 border-black bg-white overflow-hidden shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8 border-b border-black flex flex-col md:flex-row items-center justify-between gap-6 bg-zinc-50">
               <div className="flex items-center gap-3">
                  <div className="bg-black text-white p-2"><CalendarIcon size={18} /></div>
                  <h3 className="text-sm font-bold uppercase tracking-widest">일간 통합 장부</h3>
               </div>
               <div className="flex items-center gap-4 border border-black bg-white p-1">
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
                  <span className="text-xs font-bold uppercase tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
               </div>
               <div className="flex bg-white border border-black p-0.5">
                  <button onClick={() => setCalendarType('INCOME')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'INCOME' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>수입</button>
                  <button onClick={() => setCalendarType('EXPENSE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'EXPENSE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>지출</button>
                  <button onClick={() => setCalendarType('BALANCE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'BALANCE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>잔액</button>
               </div>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{...tx, id: Math.random().toString(36).substr(2,9)}, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

