interface ChartDataItem {
  id: string;
  name: string;
  value: number;
  color: string;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'BUDGET' | 'HISTORY' | 'SUMMARY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);

  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId, setSelectedUserId] = useState<string>(currentUser.id);
  const [summarySortOrder, setSummarySortOrder] = useState<'DESC' | 'ASC'>('DESC');

  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [calendarType, setCalendarType] = useState<'EXPENSE' | 'INCOME' | 'BALANCE'>('EXPENSE');
  const [selectedCalendarDateKey, setSelectedCalendarDateKey] = useState<string | null>(null);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedUserId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
  }, [transactions, historyDate, viewMode, selectedUserId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const chartData = useMemo<ChartDataItem[]>(() => {
    const data = categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let displayColor = cat.color !== '#000000' ? cat.color : (percentage >= 100 ? '#000000' : '#e5e5e5');
         return { id: cat.id, name: cat.name, value: val, color: displayColor };
      })
      .filter(d => d.value > 0);

    return data.sort((a, b) => summarySortOrder === 'DESC' ? b.value - a.value : a.value - b.value);
  }, [categories, monthlyTransactions, viewMode, summarySortOrder]);

  const groupedCategories = useMemo<Record<string, Category[]>>(() => {
    const expenseCats = categories.filter(c => c.type === TransactionType.EXPENSE);
    const groups: Record<string, Category[]> = {};
    expenseCats.forEach(cat => {
      if (!groups[cat.group]) groups[cat.group] = [];
      groups[cat.group].push(cat);
    });
    return groups;
  }, [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {activeTab !== 'SUMMARY' && (
        <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
          <div className="flex bg-white border border-black p-0.5">
            <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>공동 관리</button>
            <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>개인 관리</button>
          </div>
        </div>
      )}

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12">
          {/* 주요 지표 */}
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white">
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">총 잔액</span><div className="text-3xl font-bold mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div></div>
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">이번 달 수입</span><div className="text-3xl font-bold mt-2 tabular-nums text-black underline underline-offset-4 decoration-zinc-300">+ {totalIncome.toLocaleString()}</div></div>
            <div className="p-8"><span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">이번 달 지출</span><div className="text-3xl font-bold mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div></div>
          </div>

          {/* 차트와 리스트 */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-0 border border-black bg-white">
             <div className="p-8 border-b lg:border-b-0 lg:border-r border-black">
                <div className="flex items-center justify-between mb-8">
                   <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2"><BarChart3 size={16} /> 지출 비중</h3>
                   <button onClick={() => setIsCategoryManagerOpen(true)} className="p-1 hover:bg-zinc-100 border border-transparent hover:border-black transition"><Settings size={14} /></button>
                </div>
                <div className="h-[300px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart layout="vertical" data={chartData} margin={{ top: 0, right: 30, left: 40, bottom: 0 }} barSize={12}>
                      <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e5e5e5" />
                      <XAxis type="number" hide />
                      <YAxis dataKey="name" type="category" tick={{ fontSize: 10, fontWeight: 700, fill: '#000' }} axisLine={false} tickLine={false} />
                      <Tooltip cursor={{ fill: '#fafafa' }} contentStyle={{ backgroundColor: '#000', color: '#fff', border: 'none', borderRadius: '0px', fontSize: '10px' }} itemStyle={{ color: '#fff' }} formatter={(val: number) => [`${val.toLocaleString()} 원`, '지출']} />
                      <Bar dataKey="value">{chartData.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.color} />))}</Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>
             <div className="p-8 bg-zinc-50 overflow-y-auto max-h-[420px] custom-scrollbar">
                <div className="flex items-center justify-between mb-8">
                  <h4 className="text-[10px] font-bold uppercase tracking-widest text-zinc-500">요약 리스트</h4>
                  <button 
                    onClick={() => setSummarySortOrder(prev => prev === 'DESC' ? 'ASC' : 'DESC')} 
                    className="flex items-center gap-2 text-[10px] font-bold hover:text-black transition uppercase bg-white border border-black px-3 py-1 shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] active:translate-x-0.5 active:translate-y-0.5 active:shadow-none"
                    title="금액 기준 정렬"
                  >
                    <ArrowUpDown size={12} />
                    {summarySortOrder === 'DESC' ? '높은순' : '낮은순'}
                  </button>
                </div>
                <div className="space-y-1">
                  {chartData.map((d, i) => (
                    <div key={i} className="flex items-center justify-between p-4 bg-white border border-zinc-200 hover:border-black cursor-pointer transition group">
                      <div className="flex items-center gap-4">
                        <div className="w-1 h-4" style={{ backgroundColor: d.color }}></div>
                        <span className="text-xs font-bold tracking-tight uppercase">{d.name}</span>
                      </div>
                      <span className="text-xs font-bold tabular-nums">{d.value.toLocaleString()}</span>
                    </div>
                  ))}
                </div>
             </div>
          </div>

          {/* Seamless 카테고리 그리드 (초밀착 울트라 컴팩트 버전) */}
          <div className="border border-black bg-black grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-px">
            <div className="col-span-full bg-zinc-50 p-3 px-4 flex items-center justify-between border-b border-black">
              <h3 className="text-xs font-bold uppercase tracking-widest flex items-center gap-2">
                <ClipboardList size={14} /> 세부 지출 분류 현황
              </h3>
              <button onClick={() => setIsCategoryManagerOpen(true)} className="text-[9px] font-bold uppercase underline hover:text-zinc-500">수정</button>
            </div>

            {(Object.entries(groupedCategories) as [string, Category[]][]).map(([group, cats]) => (
              <React.Fragment key={group}>
                <div className="col-span-full bg-zinc-100 px-4 py-1.5 flex items-center justify-between border-y border-black -mt-px first:mt-0">
                  <span className="text-[9px] font-black uppercase tracking-widest text-zinc-500">{group}</span>
                  <span className="text-[8px] font-bold text-zinc-400">{cats.length} Items</span>
                </div>
                {cats.map(cat => {
                  const catTransactions = monthlyTransactions
                    .filter(t => t.categoryId === cat.id)
                    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                  const amount = catTransactions.reduce((sum, t) => sum + t.amount, 0);
                  const isFoodGroup = group === '식비';

                  return (
                    <div key={cat.id} className={`bg-white p-3 ${isFoodGroup ? 'h-[220px]' : 'h-28'} flex flex-col hover:bg-zinc-50 transition-colors group/card cursor-default`}>
                       <div className="flex items-start justify-between mb-1">
                          <div className="p-1.5 border border-black/5 bg-zinc-50" style={{ color: cat.color }}>
                            {renderCategoryIcon(cat.iconId, 14)}
                          </div>
                          <p className="text-[8px] font-black text-zinc-300 uppercase tracking-tighter truncate max-w-[60px] group-hover/card:text-zinc-400 transition-colors">{cat.name}</p>
                       </div>

                       <div className="mb-2">
                          <p className="text-[12px] font-black tabular-nums tracking-tighter">{amount.toLocaleString()}</p>
                          <div className="w-0 group-hover/card:w-full h-0.5 bg-black transition-all duration-500 mt-1"></div>
                       </div>

                       {/* 식비 그룹 전용 상세 내역 영역 (컴팩트 조정) */}
                       {isFoodGroup && (
                         <div className="flex-1 mt-1 border-t border-zinc-100 pt-2 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-1.5 pr-1">
                               {catTransactions.length > 0 ? (
                                 catTransactions.map(t => (
                                   <div key={t.id} className="flex justify-between items-center gap-1 border-b border-zinc-50 pb-1 last:border-0">
                                      <div className="flex flex-col min-w-0">
                                         <span className="text-[8px] font-bold text-zinc-600 truncate">{t.description}</span>
                                         <span className="text-[7px] text-zinc-400 tabular-nums">{t.date.split('-').slice(2).join('/')}일</span>
                                      </div>
                                      <span className="text-[8px] font-black tabular-nums shrink-0">{t.amount.toLocaleString()}</span>
                                   </div>
                                 ))
                               ) : (
                                 <span className="text-[8px] text-zinc-300 italic">내역 없음</span>
                               )}
                            </div>
                         </div>
                       )}
                    </div>
                  );
                })}
              </React.Fragment>
            ))}
          </div>

          {/* 일간 통합 장부 (캘린더) */}
          <div className="border-2 border-black bg-white overflow-hidden shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8 border-b border-black flex flex-col md:flex-row items-center justify-between gap-6 bg-zinc-50">
               <div className="flex items-center gap-3">
                  <div className="bg-black text-white p-2"><CalendarIcon size={18} /></div>
                  <h3 className="text-sm font-bold uppercase tracking-widest">일간 통합 장부</h3>
               </div>
               <div className="flex items-center gap-4 border border-black bg-white p-1">
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
                  <span className="text-xs font-bold uppercase tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
               </div>
               <div className="flex bg-white border border-black p-0.5">
                  <button onClick={() => setCalendarType('INCOME')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'INCOME' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>수입</button>
                  <button onClick={() => setCalendarType('EXPENSE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'EXPENSE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>지출</button>
                  <button onClick={() => setCalendarType('BALANCE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'BALANCE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>잔액</button>
               </div>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{...tx, id: Math.random().toString(36).substr(2,9)}, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

