                  .filter(t => t.categoryId === cat.id)
                  .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                const amount = catTransactions.reduce((sum, t) => sum + t.amount, 0);
                const isExpanded = expandedCategoryId === cat.id;
                const isOverBudget = cat.budgetLimit > 0 && amount > cat.budgetLimit;

                return (
                  <div 
                    key={cat.id} 
                    className={`
                      bg-white border transition-all duration-300 flex flex-col overflow-hidden
                      ${isExpanded ? 'col-span-full border-black ring-1 ring-black' : 'border-zinc-200 hover:border-black shadow-sm hover:shadow-md'}
