                              </div>
                            </div>
                            <div className="p-4 bg-zinc-50 border border-zinc-100 border-l-4 border-l-black">
                              <h5 className="text-[9px] font-black uppercase text-zinc-400 mb-2">항목 데이터</h5>
                              <p className="text-xs font-bold leading-relaxed">이번 달 지출 비중: <span className="text-black underline">{( (amount / totalExpense) * 100 || 0 ).toFixed(1)}%</span></p>
                              <p className="text-xs font-bold leading-relaxed mt-1 text-zinc-400">총 기록 횟수: {catTransactions.length}회</p>
                            </div>
                          </div>

                          {/* 메인: 상세 리스트 */}
                          <div className="lg:col-span-2 space-y-4">
                            <div className="flex items-center justify-between">
                              <h4 className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Transactions List</h4>
                              <button 
                                onClick={() => toggleExpand(cat.id)}
                                className="text-[9px] font-black uppercase hover:underline flex items-center gap-1"
                              >
                                <ChevronUp size={12} /> 접기
                              </button>
                            </div>
                            <div className="border border-zinc-100 max-h-[300px] overflow-y-auto custom-scrollbar">
                              {catTransactions.length > 0 ? (
                                <table className="w-full text-left border-collapse">
                                  <thead className="sticky top-0 bg-white border-b border-zinc-100 z-10 shadow-sm">
                                    <tr>
                                      <th className="p-4 text-[9px] font-black uppercase text-zinc-400">날짜</th>
                                      <th className="p-4 text-[9px] font-black uppercase text-zinc-400">설명</th>
                                      <th className="p-4 text-[9px] font-black uppercase text-zinc-400 text-right">금액</th>
                                    </tr>
                                  </thead>
                                  <tbody className="divide-y divide-zinc-50">
                                    {catTransactions.map(t => (
                                      <tr key={t.id} className="hover:bg-zinc-50/50 transition-colors">
                                        <td className="p-4 text-[10px] font-bold tabular-nums text-zinc-400">{t.date}</td>
                                        <td className="p-4 text-[10px] font-bold">{t.description}</td>
                                        <td className="p-4 text-[10px] font-black tabular-nums text-right">{t.amount.toLocaleString()}</td>
                                      </tr>
                                    ))}
                                  </tbody>
                                </table>
                              ) : (
                                <div className="py-16 text-center">
                                  <p className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">기록된 내역이 없습니다</p>
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </section>

          {/* 일간 통합 장부 (캘린더) */}
          <div className="border-2 border-black bg-white overflow-hidden shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8 border-b border-black flex flex-col md:flex-row items-center justify-between gap-6 bg-zinc-50">
               <div className="flex items-center gap-3">
                  <div className="bg-black text-white p-2"><CalendarIcon size={18} /></div>
                  <h3 className="text-sm font-bold uppercase tracking-widest">일간 통합 장부</h3>
               </div>
               <div className="flex items-center gap-4 border border-black bg-white p-1">
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
                  <span className="text-xs font-bold uppercase tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
                  <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
               </div>
               <div className="flex bg-white border border-black p-0.5">
                  <button onClick={() => setCalendarType('INCOME')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'INCOME' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>수입</button>
                  <button onClick={() => setCalendarType('EXPENSE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'EXPENSE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>지출</button>
                  <button onClick={() => setCalendarType('BALANCE')} className={`px-4 py-1 text-[10px] font-bold transition ${calendarType === 'BALANCE' ? 'bg-black text-white' : 'hover:bg-zinc-100'}`}>잔액</button>
               </div>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{...tx, id: Math.random().toString(36).substr(2,9)}, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

