interface ChartDataItem {
  id: string;
  name: string;
  value: number;
  color: string;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'SUMMARY'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);

  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedUserId] = useState<string>(currentUser.id);
  const [summarySortOrder, setSummarySortOrder] = useState<'DESC' | 'ASC'>('DESC');

  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const [expandedCategoryId, setExpandedCategoryId] = useState<string | null>(null);

  // 월간 필터링된 데이터
  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedUserId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedUserId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const chartData = useMemo<ChartDataItem[]>(() => {
    const data = categories
      .filter(c => c.type === TransactionType.EXPENSE)
      .map(cat => {
         const val = monthlyTransactions
           .filter(t => t.categoryId === cat.id)
           .reduce((sum, t) => sum + t.amount, 0);

         const limit = viewMode === 'JOINT' ? cat.budgetLimit : (cat.budgetLimit / 2);
         const percentage = limit > 0 ? (val / limit) * 100 : 0;

         let displayColor = cat.color !== '#000000' ? cat.color : (percentage >= 100 ? '#000000' : '#e5e5e5');
         return { id: cat.id, name: cat.name, value: val, color: displayColor };
      })
      .filter(d => d.value > 0);

    return data.sort((a, b) => summarySortOrder === 'DESC' ? b.value - a.value : a.value - b.value);
  }, [categories, monthlyTransactions, viewMode, summarySortOrder]);

  const expenseCategories = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE);
  }, [categories]);

  const toggleExpand = (id: string) => {
    setExpandedCategoryId(prev => prev === id ? null : id);
  };

  // 날짜별로 그룹화된 내역
  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
        <div className="flex bg-white border border-black p-0.5">
          <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>공동 관리</button>
          <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-xs font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>개인 관리</button>
        </div>

        {/* 공통 월 선택 컨트롤 */}
        <div className="flex items-center gap-4 border border-black bg-white p-1">
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
          <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          {/* 주요 지표 */}
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> 현재 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums text-black underline underline-offset-8 decoration-zinc-200">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>

          {/* 지출 항목 상세 관리 (플랫 카드 그리드) */}
          <section className="space-y-6">
            <div className="flex items-center justify-between border-b border-black pb-4">
              <h3 className="text-sm font-black uppercase tracking-widest flex items-center gap-3">
                <ClipboardList size={20} /> 지출 카테고리 현황
              </h3>
              <button onClick={() => setIsCategoryManagerOpen(true)} className="text-[10px] font-bold uppercase underline hover:text-zinc-500">지출 한도 및 분류 설정 (SETTINGS)</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {expenseCategories.map((cat) => {
                const catAmount = monthlyTransactions
                  .filter(t => t.categoryId === cat.id)
                  .reduce((sum, t) => sum + t.amount, 0);
                const isExpanded = expandedCategoryId === cat.id;
                const isOverBudget = cat.budgetLimit > 0 && catAmount > cat.budgetLimit;

                return (
                  <div key={cat.id} className={`bg-white border transition-all duration-300 flex flex-col ${isExpanded ? 'col-span-full border-black ring-1 ring-black' : 'border-zinc-200 shadow-sm'}`}>
                    <div className={`p-5 flex flex-col h-full ${isExpanded ? 'bg-zinc-50/50' : ''}`}>
                      <div className="flex items-start justify-between mb-4">
                        <button onClick={() => toggleExpand(cat.id)} className="p-3 border border-zinc-100 bg-white shadow-sm hover:border-black transition-all group/icon" style={{ color: cat.color }}>
                          <div className="group-hover/icon:scale-110 transition-transform">{renderCategoryIcon(cat.iconId, 24)}</div>
                        </button>
                        <div className="text-right">
                          <p className="text-[9px] font-black text-zinc-300 uppercase tracking-widest mb-1">{cat.group}</p>
                          <p className="text-[11px] font-bold uppercase">{cat.name}</p>
                        </div>
                      </div>

                      <div>
                        <div className="flex items-baseline justify-between">
                          <p className={`font-black tabular-nums tracking-tighter ${isExpanded ? 'text-2xl' : 'text-lg'}`}>{catAmount.toLocaleString()} <span className="text-[10px] font-normal text-zinc-400">원</span></p>
                          {cat.budgetLimit > 0 && <span className={`text-[9px] font-bold uppercase ${isOverBudget ? 'text-red-500' : 'text-zinc-400'}`}>/ {cat.budgetLimit.toLocaleString()}</span>}
                        </div>
                        {cat.budgetLimit > 0 && (
                          <div className="mt-3 h-1 w-full bg-zinc-100"><div className={`h-full transition-all duration-1000 ${isOverBudget ? 'bg-red-500' : 'bg-black'}`} style={{ width: `${Math.min((catAmount / cat.budgetLimit) * 100, 100)}%` }}></div></div>
                        )}
                      </div>
                    </div>

                    {isExpanded && (
                      <div className="bg-white p-6 border-t border-zinc-100 animate-in slide-in-from-top-4 duration-500">
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                          <div className="p-4 bg-zinc-50 border border-zinc-100">
                             <h4 className="text-[10px] font-black uppercase text-zinc-400 mb-4 tracking-[0.2em]">카테고리 요약</h4>
                             <p className="text-xs font-bold">이번 달 지출 점유율: <span className="text-black underline">{( (catAmount / totalExpense) * 100 || 0 ).toFixed(1)}%</span></p>
                             <div className="mt-6 flex gap-2">
                               <button onClick={() => setIsAddModalOpen(true)} className="flex-1 bg-black text-white py-3 text-[10px] font-bold uppercase hover:bg-zinc-800 transition">내역 추가</button>
                               <button onClick={() => toggleExpand(cat.id)} className="flex-1 border border-black py-3 text-[10px] font-bold uppercase hover:bg-zinc-50 transition">닫기</button>
                             </div>
                          </div>
                          <div className="max-h-[200px] overflow-y-auto custom-scrollbar border border-zinc-100">
                             <table className="w-full text-left">
                               <thead className="bg-white sticky top-0 border-b border-zinc-100"><tr className="text-[9px] font-black text-zinc-400 uppercase"><th className="p-3">일자</th><th className="p-3">내용</th><th className="p-3 text-right">금액</th></tr></thead>
                               <tbody className="divide-y divide-zinc-50">
                                 {monthlyTransactions.filter(t => t.categoryId === cat.id).map(t => (
                                   <tr key={t.id} className="text-[10px] font-bold"><td className="p-3 text-zinc-400">{t.date.split('-')[2]}일</td><td className="p-3">{t.description}</td><td className="p-3 text-right">{t.amount.toLocaleString()}</td></tr>
                                 ))}
                               </tbody>
                             </table>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </section>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          {/* 실시간 월간 통계 배너 */}
          <div className="bg-black text-white p-10 flex flex-col md:flex-row items-center justify-between gap-8 shadow-[15px_15px_0px_0px_rgba(0,0,0,0.1)]">
             <div className="space-y-1">
                <span className="text-[10px] font-bold uppercase tracking-[0.4em] opacity-50">Monthly Report</span>
                <h2 className="text-3xl font-black uppercase">{historyDate.toLocaleString('ko-KR', { month: 'long', year: 'numeric' })}</h2>
             </div>
             <div className="flex gap-12 text-center">
                <div>
                   <span className="text-[10px] font-bold uppercase opacity-50 block mb-2">Total Income</span>
                   <span className="text-xl font-black tabular-nums text-emerald-400">+ {totalIncome.toLocaleString()}</span>
                </div>
                <div>
                   <span className="text-[10px] font-bold uppercase opacity-50 block mb-2">Total Expense</span>
                   <span className="text-xl font-black tabular-nums text-rose-400">- {totalExpense.toLocaleString()}</span>
                </div>
                <div className="pl-12 border-l border-white/20">
                   <span className="text-[10px] font-bold uppercase opacity-50 block mb-2">Balance</span>
                   <span className="text-xl font-black tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</span>
                </div>
             </div>
          </div>

          {/* 타임라인 스타일 거래내역 리스트 */}
          <div className="space-y-10">
            {Object.keys(transactionsByDate).length > 0 ? (
              // Cast Object.entries result to ensure correct type inference for 'items' and prevent 'map' property error on line 310
              (Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
                <div key={date} className="flex flex-col md:flex-row gap-6 md:gap-12">
                   <div className="md:w-32 shrink-0 pt-2">
                      <div className="sticky top-28">
                         <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest block mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                         <span className="text-2xl font-black tabular-nums">{date.split('-')[2]}</span>
                      </div>
                   </div>
                   <div className="flex-1 space-y-3">
                      {items.map(t => {
                        const cat = categories.find(c => c.id === t.categoryId);
                        return (
                          <div key={t.id} className="group bg-white border border-zinc-100 hover:border-black p-5 flex items-center justify-between transition-all">
                             <div className="flex items-center gap-6">
                                <div className="p-3 bg-zinc-50 border border-zinc-100 group-hover:border-black transition-colors" style={{ color: cat?.color }}>
                                   {renderCategoryIcon(cat?.iconId || 'other', 20)}
                                </div>
                                <div>
                                   <div className="flex items-center gap-3 mb-1">
                                      <span className="text-[9px] font-black uppercase text-zinc-400 tracking-wider">{cat?.name}</span>
                                      <span className="w-1 h-1 bg-zinc-200 rounded-full"></span>
                                      <span className="text-[9px] font-bold uppercase text-zinc-300 tracking-tight">{users.find(u => u.id === t.userId)?.name}</span>
                                   </div>
                                   <p className="text-sm font-bold tracking-tight">{t.description}</p>
                                </div>
                             </div>
                             <div className="text-right">
                                <span className={`text-base font-black tabular-nums ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-black'}`}>
                                   {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                                </span>
                                <p className="text-[8px] font-bold text-zinc-300 uppercase mt-1 tracking-tighter">KRW CURRENCY</p>
                             </div>
                          </div>
                        );
                      })}
                   </div>
                </div>
              ))
            ) : (
              <div className="py-32 border-2 border-dashed border-zinc-100 text-center">
                 <div className="mb-4 text-zinc-200 flex justify-center"><CalendarIcon size={48} /></div>
                 <p className="text-xs font-black uppercase text-zinc-300 tracking-widest">해당 월에 기록된 거래 내역이 없습니다</p>
                 <button onClick={() => setIsAddModalOpen(true)} className="mt-6 text-[10px] font-bold uppercase underline hover:text-black">첫 기록 추가하기</button>
              </div>
            )}
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{...tx, id: Math.random().toString(36).substr(2,9)}, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string; // '식비', '생활', '교통' 등의 상위 그룹
  type: TransactionType;
  budgetLimit: number;
  color: string;
  iconId: string; // 아이콘 식별자 추가
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
  date: string; // ISO string
  description: string;
  photoUrl?: string;
  location?: GeoLocation;
}

export interface BudgetStatus {
  categoryId: string;
  spent: number;
  limit: number;
  percentage: number;
  status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED';
}

