];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedIndividualId, setSelectedIndividualId] = useState<string>(MOCK_USERS[0].id);
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Quick Input State
  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES.find(c => c.type === TransactionType.EXPENSE)?.id || '');

  // Budget Edit State
  const [tempBudgets, setTempBudgets] = useState<Record<string, number>>({});

  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedIndividualId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedIndividualId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const handleQuickSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!quickAmount || !quickDesc || !quickCat) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount('');
    setQuickDesc('');
    setToast({ message: '거래 기록이 반영되었습니다.', type: 'success' });
  };

  const handleSaveBudgets = () => {
    setCategories(prev => prev.map(c => ({
      ...c,
      budgetLimit: tempBudgets[c.id] !== undefined ? tempBudgets[c.id] : c.budgetLimit
    })));
    setToast({ message: '예산 설정이 저장되었습니다.', type: 'success' });
    setActiveTab('DASHBOARD');
  };

  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const expenseCategories = useMemo(() => categories.filter(c => c.type === TransactionType.EXPENSE), [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
        <div className="flex flex-col gap-4">
          <div className="flex bg-white border border-black p-0.5">
            <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>함께 관리</button>
            <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>따로 관리</button>
          </div>
          {viewMode === 'INDIVIDUAL' && (
            <div className="flex gap-1 animate-in slide-in-from-left-2">
              {users.map(u => (
                <button key={u.id} onClick={() => setSelectedIndividualId(u.id)} className={`px-3 py-1 text-[9px] font-bold uppercase border transition ${selectedIndividualId === u.id ? 'bg-black text-white border-black' : 'bg-white text-zinc-400 border-zinc-200'}`}>{u.name}</button>
              ))}
            </div>
          )}
        </div>

        <div className="flex items-center gap-4 border border-black bg-white p-1">
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
          <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> {viewMode === 'JOINT' ? '공동' : users.find(u => u.id === selectedIndividualId)?.name} 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums text-black">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>

          <section className="space-y-8">
            <div className="flex items-center justify-between border-b border-black pb-4">
              <h3 className="text-sm font-black uppercase tracking-widest flex items-center gap-3"><ClipboardList size={20} /> 예산 집행 현황</h3>
              <button onClick={() => setActiveTab('BUDGET')} className="text-[10px] font-bold uppercase underline hover:text-zinc-500">예산 한도 조정</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {expenseCategories.map((cat) => {
                const amount = transactions.filter(t => t.categoryId === cat.id && new Date(t.date).getMonth() === historyDate.getMonth()).reduce((s,t) => s + t.amount, 0);
                const limit = cat.budgetLimit;
                const percent = limit > 0 ? (amount / limit) * 100 : 0;
                const isOver = limit > 0 && amount > limit;
                return (
                  <div key={cat.id} className="bg-white border border-black p-6 flex flex-col gap-4 group hover:shadow-lg transition-shadow">
                    <div className="flex justify-between items-start">
                      <div className="flex items-center gap-3">
                        <div className="p-2 border border-zinc-100" style={{ color: cat.color }}>{renderCategoryIcon(cat.iconId, 20)}</div>
                        <span className="text-[10px] font-black uppercase tracking-widest">{cat.name}</span>
                      </div>
                      {isOver && <span className="bg-black text-white px-2 py-0.5 text-[8px] font-black uppercase">초과</span>}
                    </div>
                    <div className="space-y-2">
                      <div className="h-1 w-full bg-zinc-100 overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${isOver ? 'bg-red-500' : 'bg-black'}`} 
                          style={{ width: `${Math.min(percent, 100)}%` }} 
                        />
                      </div>
                      <div className="flex justify-between items-center">
                         <span className="text-lg font-black tabular-nums">{amount.toLocaleString()} <span className="text-[10px] font-normal text-zinc-400">/ {limit.toLocaleString()}</span></span>
                         <span className={`text-[10px] font-bold tabular-nums ${isOver ? 'text-red-500' : 'text-zinc-400'}`}>{percent.toFixed(0)}%</span>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="sticky top-20 z-40 bg-white/90 backdrop-blur-md py-4 -mx-4 px-4 border-b border-zinc-100 flex justify-center">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-2 bg-white border-2 border-black p-2 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] w-full max-w-4xl">
                <select 
                  value={quickCat} 
                  onChange={(e) => setQuickCat(e.target.value)}
                  className="bg-zinc-50 border border-zinc-200 px-3 py-3 text-[10px] font-black uppercase outline-none focus:border-black transition"
                >
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input 
                  type="text" 
                  placeholder="지출 내용" 
                  value={quickDesc}
                  onChange={(e) => setQuickDesc(e.target.value)}
                  className="flex-1 min-w-[150px] border border-zinc-100 px-4 py-3 text-xs font-bold outline-none focus:border-black transition"
                />
                <div className="relative">
                  <input 
                    type="number" 
                    placeholder="0" 
                    value={quickAmount}
                    onChange={(e) => setQuickAmount(e.target.value)}
                    className="w-32 border border-zinc-100 px-4 py-3 text-xs font-black tabular-nums outline-none focus:border-black transition text-right pr-8"
                  />
                  <span className="absolute right-3 top-3.5 text-[8px] font-bold text-zinc-400 uppercase">원</span>
                </div>
                <button 
                  type="submit"
                  className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition active:scale-95 shrink-0"
                >
                  <Send size={14} /> 기록
                </button>
             </form>
          </div>

          <div className="space-y-10">
            {Object.keys(transactionsByDate).length > 0 ? (
              (Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
                <div key={date} className="flex flex-col md:flex-row gap-6 md:gap-12">
                   <div className="md:w-32 shrink-0 pt-2 border-l-4 border-black pl-4">
                      <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest block mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                      <span className="text-2xl font-black tabular-nums">{date.split('-')[2]}</span>
                   </div>
                   <div className="flex-1 space-y-3">
                      {items.map(t => {
                        const cat = categories.find(c => c.id === t.categoryId);
                        const user = users.find(u => u.id === t.userId);
                        return (
                          <div key={t.id} className="group bg-white border border-zinc-100 hover:border-black p-5 flex items-center justify-between transition-all">
                             <div className="flex items-center gap-6">
                                <div className="p-3 bg-zinc-50 border border-zinc-100 group-hover:border-black transition-colors" style={{ color: cat?.color }}>
                                   {renderCategoryIcon(cat?.iconId || 'other', 20)}
                                </div>
                                <div>
                                   <div className="flex items-center gap-3 mb-1">
                                      <span className="text-[9px] font-black uppercase text-zinc-400 tracking-wider">{cat?.name}</span>
                                      <span className="w-1 h-1 bg-zinc-200 rounded-full"></span>
                                      <span className="text-[9px] font-bold uppercase px-2 bg-zinc-100 tracking-tight" style={{ color: user?.color }}>{user?.name}</span>
                                   </div>
                                   <p className="text-sm font-bold tracking-tight">{t.description}</p>
                                </div>
                             </div>
                             <div className="text-right">
                                <span className={`text-base font-black tabular-nums ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-black'}`}>
                                   {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                                </span>
                             </div>
                          </div>
                        );
                      })}
                   </div>
                </div>
              ))
            ) : (
              <div className="py-32 border-2 border-dashed border-zinc-100 text-center">
                 <p className="text-xs font-black uppercase text-zinc-300 tracking-widest">이 달의 거래 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'BUDGET' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500 max-w-2xl mx-auto">
          <div className="border-b border-black pb-6">
            <h2 className="text-2xl font-black uppercase tracking-tighter">예산 한도 편성</h2>
            <p className="text-xs font-bold text-zinc-400 uppercase mt-2">각 카테고리별 월간 지출 목표를 설정하여 소비를 제어하세요.</p>
          </div>

          <div className="space-y-4">
            {expenseCategories.map(cat => (
              <div key={cat.id} className="flex flex-col gap-2 p-6 border border-zinc-100 bg-white hover:border-black transition-colors">
                <div className="flex items-center gap-3">
                  <div style={{ color: cat.color }}>{renderCategoryIcon(cat.iconId, 18)}</div>
                  <span className="text-[10px] font-black uppercase tracking-widest">{cat.name}</span>
                </div>
                <div className="relative">
                  <input 
                    type="number"
                    defaultValue={cat.budgetLimit}
                    onChange={(e) => setTempBudgets(prev => ({ ...prev, [cat.id]: parseInt(e.target.value) || 0 }))}
                    className="w-full text-xl font-black border-b border-zinc-200 outline-none py-2 focus:border-black transition tabular-nums"
                  />
                  <span className="absolute right-0 bottom-2 text-[10px] font-bold text-zinc-400">KRW</span>
                </div>
              </div>
            ))}
          </div>

          <div className="pt-10">
            <button 
              onClick={handleSaveBudgets}
              className="w-full bg-black text-white py-5 font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-zinc-800 transition shadow-[10px_10px_0px_0px_rgba(0,0,0,0.1)]"
            >
              <Save size={20} /> 예산 설정 저장
            </button>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [tx, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string; // '식비', '생활', '교통' 등의 상위 그룹
  type: TransactionType;
  budgetLimit: number;
  color: string;
  iconId: string; // 아이콘 식별자 추가
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Comment {
  id: string;
  userId: string;
  text: string;
  date: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
  date: string; // ISO string
  description: string;
  photoUrl?: string;
  location?: GeoLocation;
  likes?: string[]; // user IDs
  dislikes?: string[]; // user IDs
  comments?: Comment[];
}

export interface BudgetStatus {
  categoryId: string;
  spent: number;
  limit: number;
  percentage: number;
  status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED';
}

import React, { useState, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, Calendar as CalendarIcon, 
  Settings, ClipboardList, Utensils, Bus, ShoppingBag, 
  Home, Banknote, Coins, Palmtree, HeartPulse, GraduationCap, Coffee,
  MoreHorizontal, Smartphone, Car, PawPrint, Gift, Scissors, BookOpen,
  Wine, Music, Plane, Zap, Shirt, CreditCard, ChevronDown, ChevronUp, Plus, Target,
  ArrowUpRight, ArrowDownLeft, Wallet, Send, Save, ThumbsUp, ThumbsDown, MessageSquare
} from 'lucide-react';

import { Transaction, User, Category, TransactionType, Comment } from './types';
import { Layout } from './components/Layout';
import { TransactionForm } from './components/TransactionForm';
import { CategoryManagerModal } from './components/CategoryManagerModal';
import { Toast, ToastType } from './components/Toast';

// --- 아이콘 매핑 ---
export const ICON_MAP: Record<string, React.ElementType> = {
  food: Utensils, transport: Bus, shopping: ShoppingBag, home: Home, salary: Banknote,
  money: Coins, leisure: Palmtree, health: HeartPulse, education: GraduationCap, cafe: Coffee,
  phone: Smartphone, car: Car, pet: PawPrint, gift: Gift, beauty: Scissors,
  book: BookOpen, drink: Wine, culture: Music, travel: Plane, utility: Zap,
  clothes: Shirt, card: CreditCard, other: MoreHorizontal
};

export const renderCategoryIcon = (iconId: string, size: number = 20) => {
  const IconComponent = ICON_MAP[iconId] || ICON_MAP.other;
  return <IconComponent size={size} />;
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: '장보기', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#FF0000', iconId: 'shopping' },
  { id: 'c2', name: '외식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#FF5F5F', iconId: 'food' },
  { id: 'c3', name: '카페/간식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#FF9B9B', iconId: 'cafe' },
  { id: 'c4', name: '월세', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#000000', iconId: 'home' },
  { id: 'c5', name: '공과금', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 200000, color: '#404040', iconId: 'utility' },
  { id: 'c7', name: '대중교통', group: '교통', type: TransactionType.EXPENSE, budgetLimit: 120000, color: '#2563EB', iconId: 'transport' },
  { id: 'i1', name: '급여', group: '수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#10B981', iconId: 'salary' },
];

const MOCK_USERS: User[] = [
  { id: 'u1', name: '사용자 1', avatar: '1', color: '#000000' },
  { id: 'u2', name: '사용자 2', avatar: '2', color: '#71717a' },
];

const MOCK_TRANSACTIONS: Transaction[] = [
  { id: 't1', type: TransactionType.INCOME, amount: 3500000, categoryId: 'i1', userId: 'u1', date: '2023-10-01', description: '사용자1 정기 급여', likes: [], dislikes: [], comments: [] },
  { id: 't2', type: TransactionType.EXPENSE, amount: 12000, categoryId: 'c2', userId: 'u1', date: '2023-10-02', description: '점심 식사', likes: ['u2'], dislikes: [], comments: [{ id: 'com1', userId: 'u2', text: '맛있었겠네요!', date: '2023-10-02' }] },
  { id: 't3', type: TransactionType.EXPENSE, amount: 55000, categoryId: 'c1', userId: 'u2', date: '2023-10-03', description: '마트 장보기', likes: [], dislikes: [], comments: [] },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedIndividualId, setSelectedIndividualId] = useState<string>(MOCK_USERS[0].id);
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Quick Input State
  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES.find(c => c.type === TransactionType.EXPENSE)?.id || '');

  // Comments/Interaction UI states
  const [activeCommentId, setActiveCommentId] = useState<string | null>(null);
  const [commentText, setCommentText] = useState('');

  // Budget Edit State
  const [tempBudgets, setTempBudgets] = useState<Record<string, number>>({});

  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedIndividualId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedIndividualId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const handleQuickSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!quickAmount || !quickDesc || !quickCat) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc,
      likes: [],
      dislikes: [],
      comments: []
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount('');
    setQuickDesc('');
    setToast({ message: '거래 기록이 반영되었습니다.', type: 'success' });
  };

  const handleReaction = (transactionId: string, reactionType: 'like' | 'dislike') => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;

      const likes = t.likes || [];
      const dislikes = t.dislikes || [];
      const isLiked = likes.includes(currentUser.id);
      const isDisliked = dislikes.includes(currentUser.id);

      if (reactionType === 'like') {
        return {
          ...t,
          likes: isLiked ? likes.filter(id => id !== currentUser.id) : [...likes, currentUser.id],
          dislikes: dislikes.filter(id => id !== currentUser.id)
        };
      } else {
        return {
          ...t,
          dislikes: isDisliked ? dislikes.filter(id => id !== currentUser.id) : [...dislikes, currentUser.id],
          likes: likes.filter(id => id !== currentUser.id)
        };
      }
    }));
  };

  const handleAddComment = (transactionId: string) => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      text: commentText,
      date: new Date().toISOString().split('T')[0]
    };

    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;
      return { ...t, comments: [...(t.comments || []), newComment] };
    }));
    setCommentText('');
    setActiveCommentId(null);
  };

  const handleSaveBudgets = () => {
    setCategories(prev => prev.map(c => ({
      ...c,
      budgetLimit: tempBudgets[c.id] !== undefined ? tempBudgets[c.id] : c.budgetLimit
    })));
    setToast({ message: '예산 설정이 저장되었습니다.', type: 'success' });
    setActiveTab('DASHBOARD');
  };

  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const expenseCategories = useMemo(() => categories.filter(c => c.type === TransactionType.EXPENSE), [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
        <div className="flex flex-col gap-4">
          <div className="flex bg-white border border-black p-0.5">
            <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>함께 관리</button>
            <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>따로 관리</button>
          </div>
          {viewMode === 'INDIVIDUAL' && (
            <div className="flex gap-1 animate-in slide-in-from-left-2">
              {users.map(u => (
                <button key={u.id} onClick={() => setSelectedIndividualId(u.id)} className={`px-3 py-1 text-[9px] font-bold uppercase border transition ${selectedIndividualId === u.id ? 'bg-black text-white border-black' : 'bg-white text-zinc-400 border-zinc-200'}`}>{u.name}</button>
              ))}
            </div>
          )}
        </div>

        <div className="flex items-center gap-4 border border-black bg-white p-1">
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
          <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> {viewMode === 'JOINT' ? '공동' : users.find(u => u.id === selectedIndividualId)?.name} 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums text-black">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>

          <section className="space-y-8">
            <div className="flex items-center justify-between border-b border-black pb-4">
              <h3 className="text-sm font-black uppercase tracking-widest flex items-center gap-3"><ClipboardList size={20} /> 예산 집행 현황</h3>
              <button onClick={() => setActiveTab('BUDGET')} className="text-[10px] font-bold uppercase underline hover:text-zinc-500">예산 한도 조정</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {expenseCategories.map((cat) => {
                const amount = transactions.filter(t => t.categoryId === cat.id && new Date(t.date).getMonth() === historyDate.getMonth()).reduce((s,t) => s + t.amount, 0);
                const limit = cat.budgetLimit;
                const percent = limit > 0 ? (amount / limit) * 100 : 0;
                const isOver = limit > 0 && amount > limit;
                return (
                  <div key={cat.id} className="bg-white border border-black p-6 flex flex-col gap-4 group hover:shadow-lg transition-shadow">
                    <div className="flex justify-between items-start">
                      <div className="flex items-center gap-3">
                        <div className="p-2 border border-zinc-100" style={{ color: cat.color }}>{renderCategoryIcon(cat.iconId, 20)}</div>
                        <span className="text-[10px] font-black uppercase tracking-widest">{cat.name}</span>
                      </div>
                      {isOver && <span className="bg-black text-white px-2 py-0.5 text-[8px] font-black uppercase">초과</span>}
                    </div>
                    <div className="space-y-2">
                      <div className="h-1 w-full bg-zinc-100 overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${isOver ? 'bg-red-500' : 'bg-black'}`} 
                          style={{ width: `${Math.min(percent, 100)}%` }} 
                        />
                      </div>
                      <div className="flex justify-between items-center">
                         <span className="text-lg font-black tabular-nums">{amount.toLocaleString()} <span className="text-[10px] font-normal text-zinc-400">/ {limit.toLocaleString()}</span></span>
                         <span className={`text-[10px] font-bold tabular-nums ${isOver ? 'text-red-500' : 'text-zinc-400'}`}>{percent.toFixed(0)}%</span>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="sticky top-20 z-40 bg-white/90 backdrop-blur-md py-4 -mx-4 px-4 border-b border-zinc-100 flex justify-center">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-2 bg-white border-2 border-black p-2 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] w-full max-w-4xl">
                <select 
                  value={quickCat} 
                  onChange={(e) => setQuickCat(e.target.value)}
                  className="bg-zinc-50 border border-zinc-200 px-3 py-3 text-[10px] font-black uppercase outline-none focus:border-black transition"
                >
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input 
                  type="text" 
                  placeholder="지출 내용" 
                  value={quickDesc}
                  onChange={(e) => setQuickDesc(e.target.value)}
                  className="flex-1 min-w-[150px] border border-zinc-100 px-4 py-3 text-xs font-bold outline-none focus:border-black transition"
                />
                <div className="relative">
                  <input 
                    type="number" 
                    placeholder="0" 
                    value={quickAmount}
                    onChange={(e) => setQuickAmount(e.target.value)}
                    className="w-32 border border-zinc-100 px-4 py-3 text-xs font-black tabular-nums outline-none focus:border-black transition text-right pr-8"
                  />
                  <span className="absolute right-3 top-3.5 text-[8px] font-bold text-zinc-400 uppercase">원</span>
                </div>
                <button 
                  type="submit"
                  className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition active:scale-95 shrink-0"
                >
                  <Send size={14} /> 기록
                </button>
             </form>
          </div>

          <div className="space-y-10">
            {Object.keys(transactionsByDate).length > 0 ? (
              (Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
                <div key={date} className="flex flex-col md:flex-row gap-6 md:gap-12">
                   <div className="md:w-32 shrink-0 pt-2 border-l-4 border-black pl-4">
                      <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest block mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                      <span className="text-2xl font-black tabular-nums">{date.split('-')[2]}</span>
                   </div>
                   <div className="flex-1 space-y-4">
                      {items.map(t => {
                        const cat = categories.find(c => c.id === t.categoryId);
                        const user = users.find(u => u.id === t.userId);
                        const isLiked = t.likes?.includes(currentUser.id);
                        const isDisliked = t.dislikes?.includes(currentUser.id);
                        const commentsCount = t.comments?.length || 0;

                        return (
                          <div key={t.id} className="group bg-white border border-zinc-100 hover:border-black flex flex-col transition-all">
                             <div className="p-5 flex items-center justify-between">
                               <div className="flex items-center gap-6">
                                  <div className="p-3 bg-zinc-50 border border-zinc-100 group-hover:border-black transition-colors" style={{ color: cat?.color }}>
                                     {renderCategoryIcon(cat?.iconId || 'other', 20)}
                                  </div>
                                  <div>
                                     <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[9px] font-black uppercase text-zinc-400 tracking-wider">{cat?.name}</span>
                                        <span className="w-1 h-1 bg-zinc-200 rounded-full"></span>
                                        <span className="text-[9px] font-bold uppercase px-2 bg-zinc-100 tracking-tight" style={{ color: user?.color }}>{user?.name}</span>
                                     </div>
                                     <p className="text-sm font-bold tracking-tight">{t.description}</p>
                                  </div>
                               </div>
                               <div className="text-right">
                                  <span className={`text-base font-black tabular-nums ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-black'}`}>
                                     {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                                  </span>
                               </div>
                             </div>

                             {/* Interaction Bar */}
                             <div className="border-t border-zinc-50 px-5 py-3 flex items-center justify-between bg-zinc-50/20">
                                <div className="flex items-center gap-4">
                                   <button 
                                      onClick={() => handleReaction(t.id, 'like')}
                                      className={`flex items-center gap-1.5 transition-colors ${isLiked ? 'text-black' : 'text-zinc-300 hover:text-zinc-500'}`}
                                   >
                                      <ThumbsUp size={14} fill={isLiked ? "currentColor" : "none"} />
                                      <span className="text-[10px] font-black tabular-nums">{t.likes?.length || 0}</span>
                                   </button>
                                   <button 
                                      onClick={() => handleReaction(t.id, 'dislike')}
                                      className={`flex items-center gap-1.5 transition-colors ${isDisliked ? 'text-black' : 'text-zinc-300 hover:text-zinc-500'}`}
                                   >
                                      <ThumbsDown size={14} fill={isDisliked ? "currentColor" : "none"} />
                                      <span className="text-[10px] font-black tabular-nums">{t.dislikes?.length || 0}</span>
                                   </button>
                                   <button 
                                      onClick={() => setActiveCommentId(activeCommentId === t.id ? null : t.id)}
                                      className={`flex items-center gap-1.5 transition-colors ${activeCommentId === t.id ? 'text-black' : 'text-zinc-300 hover:text-zinc-500'}`}
                                   >
                                      <MessageSquare size={14} />
                                      <span className="text-[10px] font-black tabular-nums">{commentsCount}</span>
                                   </button>
                                </div>
                             </div>

                             {/* Comments Section */}
                             {(activeCommentId === t.id || commentsCount > 0) && (
                                <div className="border-t border-zinc-50 p-5 bg-white space-y-4">
                                   {t.comments?.map(com => {
                                      const comUser = users.find(u => u.id === com.userId);
                                      return (
                                         <div key={com.id} className="flex items-start gap-3 animate-in fade-in slide-in-from-top-1">
                                            <div className="w-5 h-5 bg-black text-white text-[8px] font-black flex items-center justify-center shrink-0" style={{ backgroundColor: comUser?.color }}>{comUser?.avatar}</div>
                                            <div className="flex-1">
                                               <div className="flex items-center justify-between">
                                                  <span className="text-[9px] font-black uppercase tracking-tighter">{comUser?.name}</span>
                                                  <span className="text-[8px] font-bold text-zinc-300">{com.date}</span>
                                               </div>
                                               <p className="text-[11px] text-zinc-600 mt-1">{com.text}</p>
                                            </div>
                                         </div>
                                      );
                                   })}

                                   {activeCommentId === t.id && (
                                      <div className="flex gap-2 pt-2">
                                         <input 
                                            autoFocus
                                            type="text" 
                                            placeholder="의견을 남겨주세요..." 
                                            value={commentText}
                                            onChange={(e) => setCommentText(e.target.value)}
                                            onKeyDown={(e) => e.key === 'Enter' && handleAddComment(t.id)}
                                            className="flex-1 border-b border-black outline-none text-[11px] py-1 placeholder:text-zinc-300"
                                         />
                                         <button 
                                            onClick={() => handleAddComment(t.id)}
                                            className="text-[10px] font-black uppercase text-black hover:opacity-50"
                                         >
                                            전송
                                         </button>
                                      </div>
                                   )}
                                </div>
                             )}
                          </div>
                        );
                      })}
                   </div>
                </div>
              ))
            ) : (
              <div className="py-32 border-2 border-dashed border-zinc-100 text-center">
                 <p className="text-xs font-black uppercase text-zinc-300 tracking-widest">이 달의 거래 내역이 없습니다.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'BUDGET' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500 max-w-2xl mx-auto">
          <div className="border-b border-black pb-6">
            <h2 className="text-2xl font-black uppercase tracking-tighter">예산 한도 편성</h2>
            <p className="text-xs font-bold text-zinc-400 uppercase mt-2">각 카테고리별 월간 지출 목표를 설정하여 소비를 제어하세요.</p>
          </div>

          <div className="space-y-4">
            {expenseCategories.map(cat => (
              <div key={cat.id} className="flex flex-col gap-2 p-6 border border-zinc-100 bg-white hover:border-black transition-colors">
                <div className="flex items-center gap-3">
                  <div style={{ color: cat.color }}>{renderCategoryIcon(cat.iconId, 18)}</div>
                  <span className="text-[10px] font-black uppercase tracking-widest">{cat.name}</span>
                </div>
                <div className="relative">
                  <input 
                    type="number"
                    defaultValue={cat.budgetLimit}
                    onChange={(e) => setTempBudgets(prev => ({ ...prev, [cat.id]: parseInt(e.target.value) || 0 }))}
                    className="w-full text-xl font-black border-b border-zinc-200 outline-none py-2 focus:border-black transition tabular-nums"
                  />
                  <span className="absolute right-0 bottom-2 text-[10px] font-bold text-zinc-400">KRW</span>
                </div>
              </div>
            ))}
          </div>

          <div className="pt-10">
            <button 
              onClick={handleSaveBudgets}
              className="w-full bg-black text-white py-5 font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-zinc-800 transition shadow-[10px_10px_0px_0px_rgba(0,0,0,0.1)]"
            >
              <Save size={20} /> 예산 설정 저장
            </button>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [tx, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string; // '식비', '생활', '교통' 등의 상위 그룹
  type: TransactionType;
  budgetLimit: number;
  color: string;
  iconId: string; // 아이콘 식별자 추가
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Comment {
  id: string;
  userId: string;
  text: string;
  date: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
  date: string; // ISO string
  description: string;
  photoUrl?: string;
  location?: GeoLocation;
  likes?: string[]; // user IDs
  dislikes?: string[]; // user IDs
  comments?: Comment[];
}

export interface StickerGoal {
  id: string;
  title: string;
  targetCount: number;
  currentCount: number;
  assignedToUserId: string;
  createdByUserId: string;
  isCompleted: boolean;
}

export interface BudgetStatus {
  categoryId: string;
  spent: number;
  limit: number;
  percentage: number;
  status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED';
}

import React, { useState } from 'react';
import { LayoutDashboard, PlusCircle, ChevronDown, ClipboardList, Briefcase, Settings, Smile } from 'lucide-react';
import { User } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: 'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE';
  onTabChange: (tab: 'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE') => void;
  onOpenAddModal: () => void;
  currentUser: User;
  users: User[];
  onSwitchUser: (user: User) => void;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, activeTab, onTabChange, onOpenAddModal,
  currentUser, users, onSwitchUser
}) => {
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);

  return (
    <div className="min-h-screen bg-white flex flex-col pb-20 md:pb-0 font-sans">
      {/* 상단 헤더 */}
      <header className="bg-white border-b border-black sticky top-0 z-50 px-6 py-4 flex items-center justify-between">
        <div 
          className="flex items-center gap-3 cursor-pointer group" 
          onClick={() => onTabChange('DASHBOARD')}
        >
          <div className="bg-black text-white p-2">
            <Briefcase size={18} />
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter">CO-BUDGET</h1>
        </div>

        <div className="flex items-center gap-6">
          <nav className="hidden md:flex items-center gap-8">
            <button onClick={() => onTabChange('DASHBOARD')} className={`text-[10px] font-black uppercase tracking-widest hover:underline ${activeTab === 'DASHBOARD' ? 'underline' : 'opacity-40'}`}>대시보드</button>
            <button onClick={() => onTabChange('HISTORY')} className={`text-[10px] font-black uppercase tracking-widest hover:underline ${activeTab === 'HISTORY' ? 'underline' : 'opacity-40'}`}>거래내역</button>
            <button onClick={() => onTabChange('BUDGET')} className={`text-[10px] font-black uppercase tracking-widest hover:underline ${activeTab === 'BUDGET' ? 'underline' : 'opacity-40'}`}>예산설정</button>
            <button onClick={() => onTabChange('PRAISE')} className={`text-[10px] font-black uppercase tracking-widest hover:underline ${activeTab === 'PRAISE' ? 'underline' : 'opacity-40'}`}>칭찬스티커</button>
          </nav>

          <div className="h-6 w-px bg-zinc-200 hidden md:block"></div>

          {/* 사용자 프로필 스위처 */}
          <div className="relative">
            <button 
              onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
              className="flex items-center gap-3 bg-zinc-50 border border-zinc-200 p-1.5 pr-4 hover:border-black transition"
            >
              <div className="w-6 h-6 bg-black text-white flex items-center justify-center text-[10px] font-black" style={{ backgroundColor: currentUser.color }}>
                {currentUser.avatar}
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden md:block">{currentUser.name}</span>
              <ChevronDown size={12} className="text-zinc-400" />
            </button>

            {isUserMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsUserMenuOpen(false)}></div>
                <div className="absolute right-0 top-full mt-1 w-48 bg-white border border-black p-1 z-20 shadow-xl">
                  <div className="p-3 border-b border-zinc-100 mb-1">
                    <span className="text-[8px] font-black text-zinc-400 uppercase tracking-widest">사용자 전환</span>
                  </div>
                  {users.map(u => (
                    <button
                      key={u.id}
                      onClick={() => {
                        onSwitchUser(u);
                        setIsUserMenuOpen(false);
                      }}
                      className={`w-full flex items-center gap-3 px-4 py-3 text-[10px] font-black uppercase tracking-widest transition ${currentUser.id === u.id ? 'bg-zinc-100' : 'hover:bg-zinc-50'}`}
                    >
                      <div className="w-4 h-4 rounded-full" style={{ backgroundColor: u.color }}></div>
                      {u.name}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto w-full p-6 md:p-12">
        {children}
      </main>

      {/* 모바일 하단 내비게이션 */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-black flex justify-around py-4 z-40 safe-area-pb">
        <button onClick={() => onTabChange('DASHBOARD')} className={activeTab === 'DASHBOARD' ? 'text-black' : 'text-zinc-300'}><LayoutDashboard size={24} /></button>
        <button onClick={() => onTabChange('HISTORY')} className={activeTab === 'HISTORY' ? 'text-black' : 'text-zinc-300'}><ClipboardList size={24} /></button>
        <button onClick={() => onTabChange('BUDGET')} className={activeTab === 'BUDGET' ? 'text-black' : 'text-zinc-300'}><Settings size={24} /></button>
        <button onClick={() => onTabChange('PRAISE')} className={activeTab === 'PRAISE' ? 'text-black' : 'text-zinc-300'}><Smile size={24} /></button>
      </nav>

      {/* 상세 추가 버튼 */}
      <button 
        onClick={onOpenAddModal}
        className="fixed bottom-10 right-10 bg-black text-white p-4 shadow-2xl hover:scale-110 transition active:scale-95 z-40 group"
      >
        <PlusCircle size={24} className="group-hover:rotate-90 transition-transform duration-300" />
      </button>
    </div>
  );
};

