const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 10번 하기', targetCount: 10, currentCount: 7, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '이번 달 외식 줄이기', targetCount: 5, currentCount: 5, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedIndividualId, setSelectedIndividualId] = useState<string>(MOCK_USERS[0].id);
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);

  // Sticker Creation State
  const [isNewGoalOpen, setIsNewGoalOpen] = useState(false);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState(10);
  const [newGoalAssignee, setNewGoalAssignee] = useState(MOCK_USERS[1].id);

  // Quick Input State
  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES.find(c => c.type === TransactionType.EXPENSE)?.id || '');

  // Comments/Interaction UI states
  const [activeCommentId, setActiveCommentId] = useState<string | null>(null);
  const [commentText, setCommentText] = useState('');

  // Budget Edit State
  const [tempBudgets, setTempBudgets] = useState<Record<string, number>>({});

  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedIndividualId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedIndividualId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const handleQuickSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!quickAmount || !quickDesc || !quickCat) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc,
      likes: [], dislikes: [], comments: []
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount(''); setQuickDesc('');
    setToast({ message: '거래 기록이 반영되었습니다.', type: 'success' });
  };

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const isNowCompleted = nextCount >= g.targetCount;
      if (isNowCompleted && !g.isCompleted) {
        setSuccessGoal(g);
      }
      return { ...g, currentCount: nextCount, isCompleted: isNowCompleted };
    }));
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
  };

  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const expenseCategories = useMemo(() => categories.filter(c => c.type === TransactionType.EXPENSE), [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 성공 팝업 */}
      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in zoom-in duration-300">
           <div className="bg-white border-4 border-black p-10 max-w-md w-full text-center shadow-[20px_20px_0px_0px_rgba(255,255,255,0.2)]">
              <PartyPopper size={64} className="mx-auto mb-6 text-emerald-500 animate-bounce" />
              <h2 className="text-3xl font-black uppercase tracking-tighter mb-2">GOAL REACHED!</h2>
              <p className="text-sm font-bold text-zinc-500 uppercase mb-8">"{successGoal.title}" 목표를 달성했습니다!</p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-black text-white py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition"
              >
                축하합니다! (닫기)
              </button>
           </div>
        </div>
      )}

      {activeTab !== 'PRAISE' && (
        <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
          <div className="flex flex-col gap-4">
            <div className="flex bg-white border border-black p-0.5">
              <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>함께 관리</button>
              <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>따로 관리</button>
            </div>
          </div>
          <div className="flex items-center gap-4 border border-black bg-white p-1">
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
            <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
          </div>
        </div>
      )}

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4">
          <div className="sticky top-20 z-40 bg-white/90 backdrop-blur-md py-4 -mx-4 px-4 border-b border-zinc-100 flex justify-center">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-2 bg-white border-2 border-black p-2 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] w-full max-w-4xl">
                <select value={quickCat} onChange={(e) => setQuickCat(e.target.value)} className="bg-zinc-50 border border-zinc-200 px-3 py-3 text-[10px] font-black uppercase outline-none focus:border-black transition">
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input type="text" placeholder="지출 내용" value={quickDesc} onChange={(e) => setQuickDesc(e.target.value)} className="flex-1 min-w-[150px] border border-zinc-100 px-4 py-3 text-xs font-bold outline-none focus:border-black transition" />
                <input type="number" placeholder="0" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} className="w-32 border border-zinc-100 px-4 py-3 text-xs font-black tabular-nums outline-none focus:border-black transition text-right" />
                <button type="submit" className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition active:scale-95 shrink-0"><Send size={14} /> 기록</button>
             </form>
          </div>
        </div>
      )}

      {activeTab === 'BUDGET' && (
        <div className="space-y-8 animate-in fade-in max-w-2xl mx-auto">
          <div className="border-b border-black pb-6">
            <h2 className="text-2xl font-black uppercase tracking-tighter">예산 한도 편성</h2>
          </div>
          {/* 예산 폼들... */}
        </div>
      )}

      {activeTab === 'PRAISE' && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-500">
          <div className="flex items-center justify-between border-b-2 border-black pb-6">
             <div>
                <h2 className="text-2xl font-black uppercase tracking-tighter flex items-center gap-3"><Smile size={28} /> 칭찬 스티커</h2>
                <p className="text-[10px] font-bold text-zinc-400 uppercase mt-1 tracking-widest">포도알을 모아 약속한 목표를 달성해보세요!</p>
             </div>
             <button 
               onClick={() => setIsNewGoalOpen(true)}
               className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition"
             >
               <Plus size={16} /> 새 포도송이
             </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {stickerGoals.map(goal => {
              const assignee = users.find(u => u.id === goal.assignedToUserId);
              return (
                <div key={goal.id} className={`bg-white border-2 border-black p-8 relative flex flex-col gap-6 shadow-[10px_10px_0px_0px_rgba(0,0,0,0.1)] ${goal.isCompleted ? 'opacity-60' : ''}`}>
                   {goal.isCompleted && (
                     <div className="absolute top-4 right-4 text-emerald-500"><CheckCircle2 size={24} /></div>
                   )}
                   <div>
                      <div className="flex items-center gap-3 mb-2">
                        <div className="w-6 h-6 text-[10px] font-black text-white flex items-center justify-center" style={{ backgroundColor: assignee?.color }}>{assignee?.avatar}</div>
                        <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">{assignee?.name}의 목표</span>
                      </div>
                      <h3 className="text-xl font-black uppercase tracking-tight">{goal.title}</h3>
                   </div>

                   {/* 포도알 시각화 */}
                   <div className="flex flex-wrap gap-2 py-4">
                      {Array.from({ length: goal.targetCount }).map((_, i) => (
                        <div 
                          key={i} 
                          className={`w-6 h-6 rounded-full border border-black transition-all duration-500 ${i < goal.currentCount ? 'bg-black' : 'bg-zinc-100 scale-90 opacity-30'}`}
                        />
                      ))}
                   </div>

                   <div className="flex items-center justify-between mt-auto pt-6 border-t border-zinc-100">
                      <span className="text-sm font-black tabular-nums">{goal.currentCount} / {goal.targetCount} <span className="text-[10px] text-zinc-400 font-normal">포도알</span></span>
                      {!goal.isCompleted && (
                        <button 
                          onClick={() => handleAddSticker(goal.id)}
                          className="bg-zinc-50 border border-black px-4 py-2 text-[10px] font-black uppercase hover:bg-black hover:text-white transition"
                        >
                          포도알 선물하기
                        </button>
                      )}
                   </div>
                </div>
              );
            })}
          </div>

          {isNewGoalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
              <div className="bg-white border-2 border-black w-full max-w-md shadow-[20px_20px_0px_0px_rgba(0,0,0,1)]">
                 <div className="p-6 border-b border-black flex justify-between items-center bg-zinc-50">
                    <h2 className="text-[10px] font-black uppercase tracking-widest">새 포도송이 생성</h2>
                    <button onClick={() => setIsNewGoalOpen(false)}><Plus className="rotate-45" size={20} /></button>
                 </div>
                 <div className="p-8 space-y-6">
                    <div>
                       <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">칭찬 목표</label>
                       <input type="text" placeholder="예: 설거지 10번" value={newGoalTitle} onChange={(e) => setNewGoalTitle(e.target.value)} className="w-full border border-black p-3 text-xs font-bold outline-none" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">목표 알 개수</label>
                          <input type="number" value={newGoalTarget} onChange={(e) => setNewGoalTarget(parseInt(e.target.value))} className="w-full border border-black p-3 text-xs font-bold outline-none" />
                       </div>
                       <div>
                          <label className="text-[9px] font-bold uppercase text-zinc-400 mb-1 block">대상자</label>
                          <select value={newGoalAssignee} onChange={(e) => setNewGoalAssignee(e.target.value)} className="w-full border border-black p-3 text-xs font-bold outline-none">
                             {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                       </div>
                    </div>
                    <button onClick={createGoal} className="w-full bg-black text-white py-4 text-[10px] font-black uppercase tracking-widest hover:bg-zinc-800 transition">생성하기</button>
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [tx, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

