};

// --- 포도알 컴포넌트 ---
const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number }> = ({ filled, color = '#8B5CF6', index }) => (
  <div 
    className={`relative w-8 h-8 rounded-full border-2 transition-all duration-500 ease-out flex items-center justify-center
      ${filled ? 'scale-100 opacity-100 shadow-lg' : 'scale-90 opacity-20 border-zinc-300 bg-zinc-100'}`}
    style={{ 
      backgroundColor: filled ? color : 'transparent',
      borderColor: filled ? 'rgba(0,0,0,0.2)' : 'rgba(0,0,0,0.1)',
      transitionDelay: `${index * 50}ms`
    }}
  >
    {filled && (
      <div className="absolute top-1 left-1.5 w-2 h-2 bg-white/30 rounded-full blur-[1px]" />
    )}
  </div>
);

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: '장보기', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#FF0000', iconId: 'shopping' },
  { id: 'c2', name: '외식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#FF5F5F', iconId: 'food' },
  { id: 'c3', name: '카페/간식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#FF9B9B', iconId: 'cafe' },
  { id: 'c4', name: '월세', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#000000', iconId: 'home' },
  { id: 'c5', name: '공과금', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 200000, color: '#404040', iconId: 'utility' },
  { id: 'c7', name: '대중교통', group: '교통', type: TransactionType.EXPENSE, budgetLimit: 120000, color: '#2563EB', iconId: 'transport' },
  { id: 'i1', name: '급여', group: '수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#10B981', iconId: 'salary' },
];

const MOCK_USERS: User[] = [
  { id: 'u1', name: '사용자 1', avatar: '1', color: '#000000' },
  { id: 'u2', name: '사용자 2', avatar: '2', color: '#71717a' },
];

const MOCK_TRANSACTIONS: Transaction[] = [
  { id: 't1', type: TransactionType.INCOME, amount: 3500000, categoryId: 'i1', userId: 'u1', date: '2023-10-01', description: '사용자1 정기 급여', likes: [], dislikes: [], comments: [] },
  { id: 't2', type: TransactionType.EXPENSE, amount: 12000, categoryId: 'c2', userId: 'u1', date: '2023-10-02', description: '점심 식사', likes: ['u2'], dislikes: [], comments: [{ id: 'com1', userId: 'u2', text: '맛있었겠네요!', date: '2023-10-02' }] },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 10번 하기', targetCount: 10, currentCount: 7, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '이번 달 외식 줄이기', targetCount: 15, currentCount: 15, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedIndividualId, setSelectedIndividualId] = useState<string>(MOCK_USERS[0].id);
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);

  // Sticker Creation State
  const [isNewGoalOpen, setIsNewGoalOpen] = useState(false);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState(10);
  const [newGoalAssignee, setNewGoalAssignee] = useState(MOCK_USERS[1].id);

  // Quick Input State
  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES.find(c => c.type === TransactionType.EXPENSE)?.id || '');

  // Comments/Interaction UI states
  const [activeCommentId, setActiveCommentId] = useState<string | null>(null);
  const [commentText, setCommentText] = useState('');

  // Budget Edit State
  const [tempBudgets, setTempBudgets] = useState<Record<string, number>>({});

  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedIndividualId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedIndividualId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const handleQuickSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!quickAmount || !quickDesc || !quickCat) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc,
      likes: [], dislikes: [], comments: []
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount(''); setQuickDesc('');
    setToast({ message: '거래 기록이 반영되었습니다.', type: 'success' });
  };

  const handleReaction = (transactionId: string, reactionType: 'like' | 'dislike') => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;
      const likes = t.likes || [];
      const dislikes = t.dislikes || [];
      const isLiked = likes.includes(currentUser.id);
      if (reactionType === 'like') {
        return {
          ...t,
          likes: isLiked ? likes.filter(id => id !== currentUser.id) : [...likes, currentUser.id],
          dislikes: dislikes.filter(id => id !== currentUser.id)
        };
      } else {
        const isDisliked = dislikes.includes(currentUser.id);
        return {
          ...t,
          dislikes: isDisliked ? dislikes.filter(id => id !== currentUser.id) : [...dislikes, currentUser.id],
          likes: likes.filter(id => id !== currentUser.id)
        };
      }
    }));
  };

  const handleAddComment = (transactionId: string) => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      text: commentText,
      date: new Date().toISOString().split('T')[0]
    };
    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;
      return { ...t, comments: [...(t.comments || []), newComment] };
    }));
    setCommentText('');
    setActiveCommentId(null);
  };

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const isNowCompleted = nextCount >= g.targetCount;
      if (isNowCompleted && !g.isCompleted) {
        setSuccessGoal(g);
      }
      return { ...g, currentCount: nextCount, isCompleted: isNowCompleted };
    }));
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
  };

  const handleSaveBudgets = () => {
    setCategories(prev => prev.map(c => ({
      ...c,
      budgetLimit: tempBudgets[c.id] !== undefined ? tempBudgets[c.id] : c.budgetLimit
    })));
    setToast({ message: '예산 설정이 저장되었습니다.', type: 'success' });
    setActiveTab('DASHBOARD');
  };

  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const expenseCategories = useMemo(() => categories.filter(c => c.type === TransactionType.EXPENSE), [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 성공 팝업 */}
      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in zoom-in duration-300">
           <div className="bg-white border-4 border-black p-10 max-w-md w-full text-center shadow-[20px_20px_0px_0px_rgba(255,255,255,0.2)]">
              <PartyPopper size={64} className="mx-auto mb-6 text-purple-600 animate-bounce" />
              <h2 className="text-3xl font-black uppercase tracking-tighter mb-2">GRAPE COMPLETE!</h2>
              <p className="text-sm font-bold text-zinc-500 uppercase mb-8">"{successGoal.title}" 포도송이를 모두 채웠습니다!</p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-black text-white py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition"
              >
                축하합니다! (닫기)
              </button>
           </div>
        </div>
      )}

      {activeTab !== 'PRAISE' && (
        <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
          <div className="flex flex-col gap-4">
            <div className="flex bg-white border border-black p-0.5">
              <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>함께 관리</button>
              <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>따로 관리</button>
            </div>
          </div>
          <div className="flex items-center gap-4 border border-black bg-white p-1">
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
            <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
          </div>
        </div>
      )}

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4">
          <div className="sticky top-20 z-40 bg-white/90 backdrop-blur-md py-4 -mx-4 px-4 border-b border-zinc-100 flex justify-center">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-2 bg-white border-2 border-black p-2 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] w-full max-w-4xl">
                <select value={quickCat} onChange={(e) => setQuickCat(e.target.value)} className="bg-zinc-50 border border-zinc-200 px-3 py-3 text-[10px] font-black uppercase outline-none focus:border-black transition">
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input type="text" placeholder="지출 내용" value={quickDesc} onChange={(e) => setQuickDesc(e.target.value)} className="flex-1 min-w-[150px] border border-zinc-100 px-4 py-3 text-xs font-bold outline-none focus:border-black transition" />
                <input type="number" placeholder="0" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} className="w-32 border border-zinc-100 px-4 py-3 text-xs font-black tabular-nums outline-none focus:border-black transition text-right" />
                <button type="submit" className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition active:scale-95 shrink-0"><Send size={14} /> 기록</button>
             </form>
          </div>
          {/* 거래내역 리스트 (생략 - 기존 유지) */}
          <div className="space-y-10">
            {Object.entries(transactionsByDate).map(([date, items]) => (
              <div key={date} className="flex flex-col md:flex-row gap-6 md:gap-12">
                <div className="md:w-32 shrink-0 pt-2 border-l-4 border-black pl-4">
                  <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest block mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-2xl font-black tabular-nums">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-4">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    return (
                      <div key={t.id} className="group bg-white border border-zinc-100 hover:border-black flex flex-col transition-all">
                        <div className="p-5 flex items-center justify-between">
                          <div className="flex items-center gap-6">
                            <div className="p-3 bg-zinc-50 border border-zinc-100 group-hover:border-black transition-colors" style={{ color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 20)}</div>
                            <div>
                              <div className="flex items-center gap-3 mb-1">
                                <span className="text-[9px] font-black uppercase text-zinc-400 tracking-wider">{cat?.name}</span>
                                <span className="text-[9px] font-bold uppercase px-2 bg-zinc-100 tracking-tight" style={{ color: user?.color }}>{user?.name}</span>
                              </div>
                              <p className="text-sm font-bold tracking-tight">{t.description}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <span className={`text-base font-black tabular-nums ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-black'}`}>
                              {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                            </span>
                          </div>
                        </div>
                        <div className="border-t border-zinc-50 px-5 py-3 flex items-center gap-4 bg-zinc-50/20">
                           <button onClick={() => handleReaction(t.id, 'like')} className={`flex items-center gap-1.5 transition-colors ${t.likes?.includes(currentUser.id) ? 'text-black' : 'text-zinc-300'}`}><ThumbsUp size={14} /><span className="text-[10px] font-black">{t.likes?.length || 0}</span></button>
                           <button onClick={() => handleReaction(t.id, 'dislike')} className={`flex items-center gap-1.5 transition-colors ${t.dislikes?.includes(currentUser.id) ? 'text-black' : 'text-zinc-300'}`}><ThumbsDown size={14} /><span className="text-[10px] font-black">{t.dislikes?.length || 0}</span></button>
                           <button onClick={() => setActiveCommentId(activeCommentId === t.id ? null : t.id)} className="flex items-center gap-1.5 text-zinc-300 hover:text-black transition-colors"><MessageSquare size={14} /><span className="text-[10px] font-black">{t.comments?.length || 0}</span></button>
                        </div>
                        {activeCommentId === t.id && (
                          <div className="p-5 border-t border-zinc-50 bg-white">
                            <div className="flex gap-2">
                              <input autoFocus type="text" placeholder="의견 입력..." value={commentText} onChange={(e) => setCommentText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAddComment(t.id)} className="flex-1 border-b border-black outline-none text-[11px] py-1" />
                              <button onClick={() => handleAddComment(t.id)} className="text-[10px] font-black uppercase">전송</button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'PRAISE' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-500 pb-20">
          <div className="flex flex-col md:flex-row items-center justify-between border-b-2 border-black pb-8 gap-6">
             <div>
                <h2 className="text-3xl font-black uppercase tracking-tighter flex items-center gap-4">
                  <div className="p-2 bg-purple-600 text-white rounded-lg"><PartyPopper size={32} /></div>
                  칭찬 포도송이
                </h2>
                <p className="text-[11px] font-bold text-zinc-400 uppercase mt-2 tracking-[0.2em] ml-1">상대방의 노력을 포도알 스티커로 응원해주세요!</p>
             </div>
             <button 
               onClick={() => setIsNewGoalOpen(true)}
               className="bg-black text-white px-8 py-4 text-[10px] font-black uppercase flex items-center gap-3 hover:bg-zinc-800 transition shadow-[6px_6px_0px_0px_rgba(0,0,0,0.1)] active:translate-x-1 active:translate-y-1 active:shadow-none"
             >
               <Plus size={18} /> 새 포도송이 키우기
             </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            {stickerGoals.map(goal => {
              const assignee = users.find(u => u.id === goal.assignedToUserId);
              return (
                <div key={goal.id} className={`bg-white border-4 border-black p-10 relative flex flex-col gap-10 shadow-[15px_15px_0px_0px_rgba(139,92,246,0.1)] transition-all ${goal.isCompleted ? 'bg-zinc-50/50' : 'hover:shadow-[15px_15px_0px_0px_rgba(139,92,246,0.2)]'}`}>
                   {goal.isCompleted && (
                     <div className="absolute -top-4 -right-4 bg-emerald-500 text-white p-2 rounded-full border-4 border-black shadow-lg animate-bounce z-10"><CheckCircle2 size={32} /></div>
                   )}

                   <div className="flex justify-between items-start">
                      <div className="flex-1">
                        <div className="flex items-center gap-3 mb-3">
                          <div className="w-8 h-8 text-xs font-black text-white flex items-center justify-center rounded-md" style={{ backgroundColor: assignee?.color }}>{assignee?.avatar}</div>
                          <span className="text-[11px] font-black uppercase tracking-[0.1em] text-zinc-400">{assignee?.name}의 약속</span>
                        </div>
                        <h3 className="text-2xl font-black uppercase tracking-tight leading-tight">{goal.title}</h3>
                      </div>
                   </div>

                   {/* 포도송이 시각화 영역 */}
                   <div className="relative bg-zinc-50/50 border-2 border-dashed border-zinc-200 p-8 flex flex-col items-center min-h-[240px] rounded-3xl">
                      <div className="absolute -top-6 text-green-600 opacity-80"><Leaf size={48} fill="currentColor" /></div>
                      <div className="flex flex-wrap justify-center gap-3 max-w-[280px] mt-4">
                        {Array.from({ length: goal.targetCount }).map((_, i) => (
                          <GrapeGrain key={i} index={i} filled={i < goal.currentCount} color={assignee?.color || '#8B5CF6'} />
                        ))}
                      </div>
                   </div>

                   <div className="flex items-center justify-between pt-8 border-t-2 border-zinc-100 mt-auto">
                      <div>
                        <span className="text-3xl font-black tabular-nums tracking-tighter">{goal.currentCount} <span className="text-sm text-zinc-300 font-bold uppercase">/ {goal.targetCount} Grains</span></span>
                        <div className="w-full h-1.5 bg-zinc-100 mt-2 rounded-full overflow-hidden">
                           <div className="h-full bg-black transition-all duration-1000" style={{ width: `${(goal.currentCount / goal.targetCount) * 100}%` }} />
                        </div>
                      </div>
                      {!goal.isCompleted && (
                        <button 
                          onClick={() => handleAddSticker(goal.id)}
                          className="bg-purple-600 text-white px-6 py-4 text-[10px] font-black uppercase hover:bg-purple-700 transition flex items-center gap-2 rounded-xl shadow-lg hover:scale-105 active:scale-95"
                        >
                          <Plus size={16} /> 포도알 선물
                        </button>
                      )}
                      {goal.isCompleted && (
                        <div className="text-[10px] font-black uppercase text-emerald-500 bg-emerald-50 px-4 py-2 border border-emerald-100 rounded-full">성공한 목표</div>
                      )}
                   </div>
                </div>
              );
            })}
          </div>

          {/* 새 목표 생성 모달 (생략 - 기존 로직 유지) */}
          {isNewGoalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
              <div className="bg-white border-4 border-black w-full max-w-md shadow-[20px_20px_0px_0px_rgba(0,0,0,1)]">
                 <div className="p-6 border-b-4 border-black flex justify-between items-center bg-zinc-50">
                    <h2 className="text-xs font-black uppercase tracking-widest">새 포도송이 심기</h2>
                    <button onClick={() => setIsNewGoalOpen(false)} className="hover:rotate-90 transition-transform"><Plus className="rotate-45" size={24} /></button>
                 </div>
                 <div className="p-10 space-y-8">
                    <div>
                       <label className="text-[10px] font-black uppercase text-zinc-400 mb-2 block tracking-widest">어떤 일을 칭찬할까요?</label>
                       <input type="text" placeholder="예: 매일 가계부 쓰기" value={newGoalTitle} onChange={(e) => setNewGoalTitle(e.target.value)} className="w-full border-2 border-black p-4 text-sm font-bold outline-none focus:bg-zinc-50 transition" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <label className="text-[10px] font-black uppercase text-zinc-400 mb-2 block tracking-widest">목표 포도알</label>
                          <input type="number" min="1" max="50" value={newGoalTarget} onChange={(e) => setNewGoalTarget(parseInt(e.target.value))} className="w-full border-2 border-black p-4 text-sm font-bold outline-none tabular-nums" />
                       </div>
                       <div>
                          <label className="text-[10px] font-black uppercase text-zinc-400 mb-2 block tracking-widest">대상자</label>
                          <select value={newGoalAssignee} onChange={(e) => setNewGoalAssignee(e.target.value)} className="w-full border-2 border-black p-4 text-sm font-bold outline-none appearance-none bg-white">
                             {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                       </div>
                    </div>
                    <button onClick={createGoal} className="w-full bg-black text-white py-5 text-[11px] font-black uppercase tracking-[0.2em] hover:bg-zinc-800 transition active:translate-y-1">포도송이 생성</button>
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* 기타 모달 (생략) */}
      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [tx, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, Calendar as CalendarIcon, 
  Settings, ClipboardList, Utensils, Bus, ShoppingBag, 
  Home, Banknote, Coins, Palmtree, HeartPulse, GraduationCap, Coffee,
  MoreHorizontal, Smartphone, Car, PawPrint, Gift, Scissors, BookOpen,
  Wine, Music, Plane, Zap, Shirt, CreditCard, ChevronDown, ChevronUp, Plus, Target,
  ArrowUpRight, ArrowDownLeft, Wallet, Send, Save, ThumbsUp, ThumbsDown, MessageSquare,
  Smile, PartyPopper, Trash2, CheckCircle2, Leaf
} from 'lucide-react';

import { Transaction, User, Category, TransactionType, Comment, StickerGoal } from './types';
import { Layout } from './components/Layout';
import { TransactionForm } from './components/TransactionForm';
import { CategoryManagerModal } from './components/CategoryManagerModal';
import { Toast, ToastType } from './components/Toast';

// --- 아이콘 매핑 ---
export const ICON_MAP: Record<string, React.ElementType> = {
  food: Utensils, transport: Bus, shopping: ShoppingBag, home: Home, salary: Banknote,
  money: Coins, leisure: Palmtree, health: HeartPulse, education: GraduationCap, cafe: Coffee,
  phone: Smartphone, car: Car, pet: PawPrint, gift: Gift, beauty: Scissors,
  book: BookOpen, drink: Wine, culture: Music, travel: Plane, utility: Zap,
  clothes: Shirt, card: CreditCard, other: MoreHorizontal
};

export const renderCategoryIcon = (iconId: string, size: number = 20) => {
  const IconComponent = ICON_MAP[iconId] || ICON_MAP.other;
  return <IconComponent size={size} />;
};

// --- 포도알 컴포넌트 ---
const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number }> = ({ filled, color = '#8B5CF6', index }) => (
  <div 
    className={`relative w-8 h-8 rounded-full border-2 transition-all duration-500 ease-out flex items-center justify-center
      ${filled ? 'scale-100 opacity-100 shadow-lg' : 'scale-90 opacity-20 border-zinc-300 bg-zinc-100'}`}
    style={{ 
      backgroundColor: filled ? color : 'transparent',
      borderColor: filled ? 'rgba(0,0,0,0.2)' : 'rgba(0,0,0,0.1)',
      transitionDelay: `${index * 50}ms`
    }}
  >
    {filled && (
      <div className="absolute top-1 left-1.5 w-2 h-2 bg-white/30 rounded-full blur-[1px]" />
    )}
  </div>
);

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: '장보기', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#FF0000', iconId: 'shopping' },
  { id: 'c2', name: '외식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#FF5F5F', iconId: 'food' },
  { id: 'c3', name: '카페/간식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#FF9B9B', iconId: 'cafe' },
  { id: 'c4', name: '월세', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#000000', iconId: 'home' },
  { id: 'c5', name: '공과금', group: '생활', type: TransactionType.EXPENSE, budgetLimit: 200000, color: '#404040', iconId: 'utility' },
  { id: 'c7', name: '대중교통', group: '교통', type: TransactionType.EXPENSE, budgetLimit: 120000, color: '#2563EB', iconId: 'transport' },
  { id: 'i1', name: '급여', group: '수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#10B981', iconId: 'salary' },
];

const MOCK_USERS: User[] = [
  { id: 'u1', name: '사용자 1', avatar: '1', color: '#000000' },
  { id: 'u2', name: '사용자 2', avatar: '2', color: '#71717a' },
];

const MOCK_TRANSACTIONS: Transaction[] = [
  { id: 't1', type: TransactionType.INCOME, amount: 3500000, categoryId: 'i1', userId: 'u1', date: '2023-10-01', description: '사용자1 정기 급여', likes: [], dislikes: [], comments: [] },
  { id: 't2', type: TransactionType.EXPENSE, amount: 12000, categoryId: 'c2', userId: 'u1', date: '2023-10-02', description: '점심 식사', likes: ['u2'], dislikes: [], comments: [{ id: 'com1', userId: 'u2', text: '맛있었겠네요!', date: '2023-10-02' }] },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 10번 하기', targetCount: 10, currentCount: 7, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '이번 달 외식 줄이기', targetCount: 15, currentCount: 15, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [selectedIndividualId, setSelectedIndividualId] = useState<string>(MOCK_USERS[0].id);
  const [historyDate, setHistoryDate] = useState(new Date('2023-10-01'));
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);

  // Sticker Creation State
  const [isNewGoalOpen, setIsNewGoalOpen] = useState(false);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState(10);
  const [newGoalAssignee, setNewGoalAssignee] = useState(MOCK_USERS[1].id);

  // Quick Input State
  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES.find(c => c.type === TransactionType.EXPENSE)?.id || '');

  // Comments/Interaction UI states
  const [activeCommentId, setActiveCommentId] = useState<string | null>(null);
  const [commentText, setCommentText] = useState('');

  // Budget Edit State
  const [tempBudgets, setTempBudgets] = useState<Record<string, number>>({});

  const monthlyTransactions = useMemo<Transaction[]>(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filteredByMode = viewMode === 'JOINT' ? transactions : transactions.filter(t => t.userId === selectedIndividualId);
    return filteredByMode.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate, viewMode, selectedIndividualId]);

  const totalIncome = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);
  const totalExpense = useMemo(() => monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((acc, t) => acc + t.amount, 0), [monthlyTransactions]);

  const handleQuickSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!quickAmount || !quickDesc || !quickCat) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc,
      likes: [], dislikes: [], comments: []
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount(''); setQuickDesc('');
    setToast({ message: '거래 기록이 반영되었습니다.', type: 'success' });
  };

  const handleReaction = (transactionId: string, reactionType: 'like' | 'dislike') => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;
      const likes = t.likes || [];
      const dislikes = t.dislikes || [];
      const isLiked = likes.includes(currentUser.id);
      if (reactionType === 'like') {
        return {
          ...t,
          likes: isLiked ? likes.filter(id => id !== currentUser.id) : [...likes, currentUser.id],
          dislikes: dislikes.filter(id => id !== currentUser.id)
        };
      } else {
        const isDisliked = dislikes.includes(currentUser.id);
        return {
          ...t,
          dislikes: isDisliked ? dislikes.filter(id => id !== currentUser.id) : [...dislikes, currentUser.id],
          likes: likes.filter(id => id !== currentUser.id)
        };
      }
    }));
  };

  const handleAddComment = (transactionId: string) => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      text: commentText,
      date: new Date().toISOString().split('T')[0]
    };
    setTransactions(prev => prev.map(t => {
      if (t.id !== transactionId) return t;
      return { ...t, comments: [...(t.comments || []), newComment] };
    }));
    setCommentText('');
    setActiveCommentId(null);
  };

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const isNowCompleted = nextCount >= g.targetCount;
      if (isNowCompleted && !g.isCompleted) {
        setSuccessGoal(g);
      }
      return { ...g, currentCount: nextCount, isCompleted: isNowCompleted };
    }));
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
  };

  const handleSaveBudgets = () => {
    setCategories(prev => prev.map(c => ({
      ...c,
      budgetLimit: tempBudgets[c.id] !== undefined ? tempBudgets[c.id] : c.budgetLimit
    })));
    setToast({ message: '예산 설정이 저장되었습니다.', type: 'success' });
    setActiveTab('DASHBOARD');
  };

  const transactionsByDate = useMemo<Record<string, Transaction[]>>(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const expenseCategories = useMemo(() => categories.filter(c => c.type === TransactionType.EXPENSE), [categories]);

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 성공 팝업 */}
      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in zoom-in duration-300">
           <div className="bg-white border-4 border-black p-10 max-w-md w-full text-center shadow-[20px_20px_0px_0px_rgba(255,255,255,0.2)]">
              <PartyPopper size={64} className="mx-auto mb-6 text-purple-600 animate-bounce" />
              <h2 className="text-3xl font-black uppercase tracking-tighter mb-2">GRAPE COMPLETE!</h2>
              <p className="text-sm font-bold text-zinc-500 uppercase mb-8">"{successGoal.title}" 포도송이를 모두 채웠습니다!</p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-black text-white py-4 text-xs font-black uppercase tracking-widest hover:bg-zinc-800 transition"
              >
                축하합니다! (닫기)
              </button>
           </div>
        </div>
      )}

      {activeTab !== 'PRAISE' && (
        <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between border-b border-black pb-4">
          <div className="flex flex-col gap-4">
            <div className="flex bg-white border border-black p-0.5">
              <button onClick={() => setViewMode('JOINT')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'JOINT' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>함께 관리</button>
              <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-6 py-1 text-[10px] font-bold uppercase transition ${viewMode === 'INDIVIDUAL' ? 'bg-black text-white' : 'text-black hover:bg-zinc-100'}`}>따로 관리</button>
            </div>
          </div>
          <div className="flex items-center gap-4 border border-black bg-white p-1">
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronLeft size={16} /></button>
            <span className="text-[10px] font-black uppercase tabular-nums min-w-[100px] text-center tracking-widest">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
            <button onClick={() => setHistoryDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))} className="p-1 hover:bg-zinc-100 transition"><ChevronRight size={16} /></button>
          </div>
        </div>
      )}

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x border border-black bg-white shadow-[10px_10px_0px_0px_rgba(0,0,0,0.05)]">
            <div className="p-8">
              <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2"><Wallet size={12} /> 잔액</span>
              <div className="text-3xl font-black mt-2 tabular-nums">{(totalIncome - totalExpense).toLocaleString()}</div>
            </div>
            <div className="p-8 bg-zinc-50/30">
              <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2"><ArrowUpRight size={12} /> 월간 수입</span>
              <div className="text-3xl font-black mt-2 tabular-nums">+ {totalIncome.toLocaleString()}</div>
            </div>
            <div className="p-8">
              <span className="text-[10px] font-bold text-rose-500 uppercase tracking-widest flex items-center gap-2"><ArrowDownLeft size={12} /> 월간 지출</span>
              <div className="text-3xl font-black mt-2 tabular-nums">- {totalExpense.toLocaleString()}</div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4">
          <div className="sticky top-20 z-40 bg-white/90 backdrop-blur-md py-4 -mx-4 px-4 border-b border-zinc-100 flex justify-center">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-2 bg-white border-2 border-black p-2 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] w-full max-w-4xl">
                <select value={quickCat} onChange={(e) => setQuickCat(e.target.value)} className="bg-zinc-50 border border-zinc-200 px-3 py-3 text-[10px] font-black uppercase outline-none focus:border-black transition">
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input type="text" placeholder="지출 내용" value={quickDesc} onChange={(e) => setQuickDesc(e.target.value)} className="flex-1 min-w-[150px] border border-zinc-100 px-4 py-3 text-xs font-bold outline-none focus:border-black transition" />
                <input type="number" placeholder="0" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} className="w-32 border border-zinc-100 px-4 py-3 text-xs font-black tabular-nums outline-none focus:border-black transition text-right" />
                <button type="submit" className="bg-black text-white px-6 py-3 text-[10px] font-black uppercase flex items-center gap-2 hover:bg-zinc-800 transition active:scale-95 shrink-0"><Send size={14} /> 기록</button>
             </form>
          </div>
          {/* 거래내역 리스트 (생략 - 기존 유지) */}
          <div className="space-y-10">
            {/* Fix: Explicit cast to solve 'map' does not exist on type 'unknown' error by providing proper type for Object.entries results */}
            {(Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
              <div key={date} className="flex flex-col md:flex-row gap-6 md:gap-12">
                <div className="md:w-32 shrink-0 pt-2 border-l-4 border-black pl-4">
                  <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest block mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-2xl font-black tabular-nums">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-4">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    return (
                      <div key={t.id} className="group bg-white border border-zinc-100 hover:border-black flex flex-col transition-all">
                        <div className="p-5 flex items-center justify-between">
                          <div className="flex items-center gap-6">
                            <div className="p-3 bg-zinc-50 border border-zinc-100 group-hover:border-black transition-colors" style={{ color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 20)}</div>
                            <div>
                              <div className="flex items-center gap-3 mb-1">
                                <span className="text-[9px] font-black uppercase text-zinc-400 tracking-wider">{cat?.name}</span>
                                <span className="text-[9px] font-bold uppercase px-2 bg-zinc-100 tracking-tight" style={{ color: user?.color }}>{user?.name}</span>
                              </div>
                              <p className="text-sm font-bold tracking-tight">{t.description}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <span className={`text-base font-black tabular-nums ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-black'}`}>
                              {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                            </span>
                          </div>
                        </div>
                        <div className="border-t border-zinc-50 px-5 py-3 flex items-center gap-4 bg-zinc-50/20">
                           <button onClick={() => handleReaction(t.id, 'like')} className={`flex items-center gap-1.5 transition-colors ${t.likes?.includes(currentUser.id) ? 'text-black' : 'text-zinc-300'}`}><ThumbsUp size={14} /><span className="text-[10px] font-black">{t.likes?.length || 0}</span></button>
                           <button onClick={() => handleReaction(t.id, 'dislike')} className={`flex items-center gap-1.5 transition-colors ${t.dislikes?.includes(currentUser.id) ? 'text-black' : 'text-zinc-300'}`}><ThumbsDown size={14} /><span className="text-[10px] font-black">{t.dislikes?.length || 0}</span></button>
                           <button onClick={() => setActiveCommentId(activeCommentId === t.id ? null : t.id)} className="flex items-center gap-1.5 text-zinc-300 hover:text-black transition-colors"><MessageSquare size={14} /><span className="text-[10px] font-black">{t.comments?.length || 0}</span></button>
                        </div>
                        {activeCommentId === t.id && (
                          <div className="p-5 border-t border-zinc-50 bg-white">
                            <div className="flex gap-2">
                              <input autoFocus type="text" placeholder="의견 입력..." value={commentText} onChange={(e) => setCommentText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAddComment(t.id)} className="flex-1 border-b border-black outline-none text-[11px] py-1" />
                              <button onClick={() => handleAddComment(t.id)} className="text-[10px] font-black uppercase">전송</button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
