const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number; number: number }> = ({ filled, color = '#8B5CF6', index, number }) => (
  <div 
    className={`relative w-10 h-10 rounded-full border-[1.5px] transition-all duration-500 ease-out flex items-center justify-center text-[10px] font-black
      ${filled ? 'scale-105 shadow-md border-black/10' : 'scale-100 border-zinc-200 bg-white text-zinc-300'}`}
    style={{ 
      backgroundColor: filled ? color : 'white',
      color: filled ? 'white' : '#d4d4d8',
      transitionDelay: `${index * 30}ms`
    }}
  >
    {number}
