    )}
  </div>
);

// --- 포도송이 묶음 컴포넌트 (도안 레이아웃 재현) ---
const GrapeBunch: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  // 포도송이 모양을 위한 행별 개수 정의 (V자 형태)
  const getRows = (total: number) => {
    if (total === 33) return [3, 5, 6, 5, 4, 3, 3, 2, 1, 1]; // 도안과 유사한 배치
    // 일반적인 배치를 위한 계산
    const rows = [];
    let remaining = total;
    let currentRowSize = Math.ceil(Math.sqrt(total)) + 1;
    while (remaining > 0) {
      const size = Math.min(currentRowSize, remaining);
      rows.push(size);
      remaining -= size;
      if (currentRowSize > 1) currentRowSize--;
    }
    return rows;
  };

  const rows = getRows(target);
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-1.5 py-6">
      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-1.5 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

