const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number; number: number }> = ({ filled, color = '#8B5CF6', index, number }) => (
  <div 
    className={`relative w-11 h-11 rounded-full border-2 transition-all duration-500 ease-out flex items-center justify-center text-[11px] font-black
      ${filled ? 'scale-105 shadow-lg border-black/10' : 'scale-100 border-zinc-200 bg-white text-zinc-300'}`}
    style={{ 
      backgroundColor: filled ? color : 'white',
      color: filled ? 'white' : '#d4d4d8',
      transitionDelay: `${(index % 10) * 30}ms`
    }}
  >
    {number}
    {filled && (
      <div className="absolute top-1.5 left-2 w-3 h-3 bg-white/30 rounded-full blur-[1px]" />
    )}
  </div>
);

// --- 포도송이 레이아웃 컴포넌트 ---
const GrapeBunchLayout: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  const getRows = (total: number) => {
    // 도안 기반 배치: 3, 5, 6, 5, 4, 3, 3, 2, 1, 1 (Total 33)
    if (total === 33) return [3, 5, 6, 5, 4, 3, 3, 2, 1, 1];

    // 동적 배치 (삼각형 형태)
    const rows = [];
    let remaining = total;
    let currentRowSize = Math.ceil(Math.sqrt(total * 2)) || 1;
    while (remaining > 0) {
      const size = Math.min(currentRowSize, remaining);
      rows.push(size);
      remaining -= size;
      if (currentRowSize > 1) currentRowSize--;
    }
    return rows;
  };

  const rows = getRows(target);
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-2 py-8 w-full max-w-[320px] mx-auto">
      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-2 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

