];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE'>('DASHBOARD');
  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: TransactionType.INCOME, amount: 4500000, categoryId: 'i1', userId: 'u1', date: new Date().toISOString().split('T')[0], description: '이번 달 고생했어 월급!', likes: [], dislikes: [], comments: [] },
  ]);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 요정 미션', targetCount: 33, currentCount: 18, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '배달 음식 참기', targetCount: 15, currentCount: 15, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [historyDate, setHistoryDate] = useState(new Date());
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);

  const [isNewGoalOpen, setIsNewGoalOpen] = useState(false);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState(33);
  const [newGoalAssignee, setNewGoalAssignee] = useState(MOCK_USERS[1].id);

  const [quickAmount, setQuickAmount] = useState('');
  const [quickDesc, setQuickDesc] = useState('');
  const [quickCat, setQuickCat] = useState(INITIAL_CATEGORIES[0].id);

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate]);

  const stats = useMemo(() => {
    const income = monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [monthlyTransactions]);

  const transactionsByDate = useMemo(() => {
    const groups: Record<string, Transaction[]> = {};
    monthlyTransactions.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions]);

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const completed = nextCount >= g.targetCount;
      if (completed) setSuccessGoal(g);
      return { ...g, currentCount: nextCount, isCompleted: completed };
    }));
    setToast({ message: '포근한 마음을 담아 스티커를 붙였어요 ✨', type: 'success' });
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
    setToast({ message: '설레는 마음으로 새 보드를 만들었어요!', type: 'info' });
  };

  const handleQuickSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!quickAmount || !quickDesc) return;
    const cat = categories.find(c => c.id === quickCat);
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: cat?.type || TransactionType.EXPENSE,
      amount: parseFloat(quickAmount),
      categoryId: quickCat,
      userId: currentUser.id,
      date: new Date().toISOString().split('T')[0],
      description: quickDesc,
      likes: [], dislikes: [], comments: []
    };
    setTransactions(prev => [newTx, ...prev]);
    setQuickAmount(''); setQuickDesc('');
    setToast({ message: '소중한 기록이 저장되었습니다.', type: 'success' });
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 성공 팝업 */}
      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-500">
           <div className="bg-white rounded-5xl p-12 max-w-md w-full text-center shadow-2xl border border-pastel-lavender/50">
              <PartyPopper size={64} className="mx-auto mb-6 text-pastel-purple animate-bounce" />
              <h2 className="text-3xl font-bold mb-3 tracking-tight">너무 멋져요!</h2>
              <p className="text-zinc-500 mb-10 leading-relaxed">
                "{successGoal.title}" 보드를<br/>정성스레 가득 채우셨네요. 고마워요!
              </p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold hover:brightness-95 transition-all shadow-lg"
              >
                닫기
              </button>
           </div>
        </div>
      )}

      {/* 헤더 필터 영역 */}
      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between">
        <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow">
          <button onClick={() => setViewMode('JOINT')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'JOINT' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>우리 함께</button>
          <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'INDIVIDUAL' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>나의 기록</button>
        </div>
        <div className="flex items-center gap-4 bg-white px-5 py-2.5 rounded-3xl soft-shadow border border-pastel-lavender/30">
          <button onClick={() => setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() - 1, 1))} className="text-zinc-400 hover:text-pastel-text"><ChevronLeft size={20} /></button>
          <span className="text-sm font-bold tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() + 1, 1))} className="text-zinc-400 hover:text-pastel-text"><ChevronRight size={20} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-8 animate-in fade-in duration-1000">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-gradient-to-br from-pastel-lavender to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">우리 자산</span>
              <div className="text-4xl font-bold tracking-tighter tabular-nums">{stats.balance.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-mint to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">반가운 수입</span>
              <div className="text-4xl font-bold tracking-tighter text-emerald-600/70 tabular-nums">+{stats.income.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-rose to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">필요한 지출</span>
              <div className="text-4xl font-bold tracking-tighter text-rose-600/60 tabular-nums">-{stats.expense.toLocaleString()}</div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="sticky top-24 z-30 py-4">
             <form onSubmit={handleQuickSubmit} className="flex flex-wrap items-center gap-4 bg-white/60 backdrop-blur-xl p-5 rounded-4xl soft-shadow border border-white/50 w-full">
                <select value={quickCat} onChange={(e) => setQuickCat(e.target.value)} className="w-40 py-3.5 px-4 text-xs font-semibold focus:ring-0 outline-none">
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <input type="text" placeholder="어떤 이야기가 담긴 지출인가요?" value={quickDesc} onChange={(e) => setQuickDesc(e.target.value)} className="flex-1 min-w-[200px] py-3.5 px-5 text-sm font-medium outline-none" />
                <input type="number" placeholder="금액" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} className="w-32 py-3.5 px-5 text-sm font-bold tabular-nums outline-none text-right" />
                <button type="submit" className="bg-pastel-purple text-white px-8 py-3.5 rounded-2xl text-xs font-bold hover:brightness-95 transition-all"><Send size={16} className="inline mr-2" />기록</button>
             </form>
          </div>

          <div className="space-y-16">
            {(Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
              <div key={date} className="flex flex-col lg:flex-row gap-8">
                <div className="lg:w-28 shrink-0 flex flex-col pt-2">
                  <span className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-3xl font-bold tabular-nums text-pastel-text/40 tracking-tighter">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-4">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    return (
                      <div key={t.id} className="bg-white p-6 rounded-3xl soft-shadow border border-pastel-lavender/20 flex items-center justify-between group transition-all hover:scale-[1.01]">
                        <div className="flex items-center gap-6">
                          <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 22)}</div>
                          <div>
                            <div className="flex items-center gap-3 mb-1">
                              <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{cat?.name}</span>
                              <span className="text-[9px] font-bold text-zinc-400 bg-pastel-sand px-2 py-0.5 rounded-full">{user?.name}</span>
                            </div>
                            <p className="text-sm font-medium text-pastel-text/90">{t.description}</p>
                          </div>
                        </div>
                        <div className="text-right">
                          <span className={`text-xl font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500/80' : 'text-pastel-text'}`}>
                            {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'PRAISE' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-12 duration-1000 pb-32">
          <div className="flex flex-col md:flex-row items-center justify-between">
             <div>
                <h2 className="text-3xl font-bold flex items-center gap-4">
                  <div className="p-3 bg-pastel-rose text-white rounded-2xl"><Heart size={24} fill="white" /></div>
                  사랑의 칭찬 보드
                </h2>
                <p className="text-xs text-zinc-400 mt-2 tracking-widest">따뜻한 마음을 담아 포도알 스티커를 붙여주세요.</p>
             </div>
             <button 
               onClick={() => setIsNewGoalOpen(true)}
               className="bg-white text-pastel-text px-8 py-4 rounded-3xl text-xs font-bold soft-shadow border border-pastel-lavender/30 hover:bg-pastel-sand transition-all"
             >
               <Plus size={18} className="inline mr-2" /> 새 보드 만들기
             </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            {stickerGoals.map(goal => {
              const assignee = users.find(u => u.id === goal.assignedToUserId);
              return (
                <div key={goal.id} className="bg-white rounded-[3rem] p-12 relative flex flex-col soft-shadow border border-pastel-lavender/20 overflow-hidden">
                   <PraiseStamp />

                   <div className="mb-10">
                      <div className="flex items-center gap-3 mb-4">
                        <div className="w-9 h-9 text-xs font-bold text-white flex items-center justify-center rounded-xl shadow-sm" style={{ backgroundColor: assignee?.color }}>{assignee?.avatar}</div>
                        <span className="text-[12px] font-bold text-zinc-300 uppercase tracking-widest">{assignee?.name}의 약속</span>
                      </div>
                      <h3 className="text-2xl font-bold pr-20 leading-tight text-pastel-text/80">{goal.title}</h3>
                   </div>

                   <div className="relative bg-pastel-sand/30 rounded-4xl p-8 flex flex-col items-center min-h-[420px]">
                      <div className="absolute top-2 opacity-30 text-emerald-700/50"><Leaf size={60} fill="currentColor" /></div>
                      <GrapeBunchLayout target={goal.targetCount} count={goal.currentCount} color={assignee?.color} />
                   </div>

                   <div className="flex items-center justify-between pt-10">
                      <div>
                        <span className="text-4xl font-bold tabular-nums tracking-tighter leading-none">{goal.currentCount}</span>
                        <span className="text-[11px] text-zinc-300 font-bold uppercase tracking-[0.2em] ml-2">/ {goal.targetCount} Grains</span>
                      </div>
                      {!goal.isCompleted && (
                        <button 
                          onClick={() => handleAddSticker(goal.id)}
                          className="bg-pastel-purple text-white px-10 py-5 rounded-3xl text-xs font-bold shadow-lg hover:brightness-95 transition-all"
                        >
                          스티커 선물하기
                        </button>
                      )}
                      {goal.isCompleted && (
                        <div className="flex items-center gap-2 text-xs font-bold text-emerald-500/80 bg-emerald-50 px-6 py-3 rounded-full">
                          <CheckCircle2 size={16} /> 미션 성공
                        </div>
                      )}
                   </div>
                </div>
              );
            })}
          </div>

          {/* 새 보드 생성 모달 */}
          {isNewGoalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md">
              <div className="bg-white rounded-5xl w-full max-w-md shadow-2xl p-10 space-y-8 border border-pastel-lavender/30">
                 <div className="flex justify-between items-center">
                    <h2 className="text-sm font-bold uppercase tracking-widest">새로운 칭찬 기록장</h2>
                    <button onClick={() => setIsNewGoalOpen(false)} className="text-zinc-300 hover:text-pastel-text"><X size={24} /></button>
                 </div>
                 <div className="space-y-6">
                    <div>
                       <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">무엇을 칭찬할까요?</label>
                       <input type="text" placeholder="예: 매일 저녁 맛있게 먹어주기" value={newGoalTitle} onChange={(e) => setNewGoalTitle(e.target.value)} className="w-full p-4 text-sm font-medium" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">스티커 개수</label>
                          <select value={newGoalTarget} onChange={(e) => setNewGoalTarget(parseInt(e.target.value))} className="w-full p-4 text-sm font-medium">
                             <option value={15}>15개 (귀여운 보드)</option>
                             <option value={33}>33개 (뿌듯한 보드)</option>
                          </select>
                       </div>
                       <div>
                          <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">주인공</label>
                          <select value={newGoalAssignee} onChange={(e) => setNewGoalAssignee(e.target.value)} className="w-full p-4 text-sm font-medium">
                             {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                       </div>
                    </div>
                    <button onClick={createGoal} className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold shadow-lg hover:brightness-95 transition-all">보드 만들기</button>
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [tx, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { LayoutDashboard, ChevronDown, ClipboardList, Briefcase, Settings, Smile } from 'lucide-react';
import { User } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: 'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE';
  onTabChange: (tab: 'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE') => void;
  onOpenAddModal: () => void;
  currentUser: User;
  users: User[];
  onSwitchUser: (user: User) => void;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, activeTab, onTabChange, onOpenAddModal,
  currentUser, users, onSwitchUser
}) => {
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);

  return (
    <div className="min-h-screen bg-[#FDFBFA] flex flex-col pb-24 md:pb-0 font-sans text-pastel-text">
      {/* 상단 헤더 - Glassmorphism */}
      <header className="glass sticky top-0 z-50 px-8 py-5 flex items-center justify-between shadow-sm">
        <div 
          className="flex items-center gap-3 cursor-pointer group" 
          onClick={() => onTabChange('DASHBOARD')}
        >
          <div className="bg-pastel-purple text-white p-2.5 rounded-2xl shadow-md group-hover:scale-105 transition-all">
            <Briefcase size={20} />
          </div>
          <h1 className="text-xl font-bold tracking-tighter text-pastel-text">Co-Budget</h1>
        </div>

        <div className="flex items-center gap-8">
          <nav className="hidden md:flex items-center gap-10">
            {['DASHBOARD', 'HISTORY', 'BUDGET', 'PRAISE'].map((tab) => (
              <button 
                key={tab}
                onClick={() => onTabChange(tab as any)} 
                className={`text-[11px] font-bold uppercase tracking-[0.2em] transition-all hover:text-pastel-purple ${activeTab === tab ? 'text-pastel-purple underline underline-offset-8' : 'text-zinc-300'}`}
              >
                {tab === 'DASHBOARD' ? '홈' : tab === 'HISTORY' ? '내역' : tab === 'BUDGET' ? '예산' : '칭찬'}
              </button>
            ))}
          </nav>

          <div className="h-6 w-px bg-zinc-100 hidden md:block"></div>

          {/* 프로필 스위처 */}
          <div className="relative">
            <button 
              onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
              className="flex items-center gap-3 bg-white px-4 py-2 rounded-2xl soft-shadow border border-pastel-lavender/30 transition-all hover:border-pastel-purple"
            >
              <div className="w-6 h-6 rounded-full text-white flex items-center justify-center text-[10px] font-bold" style={{ backgroundColor: currentUser.color }}>
                {currentUser.avatar}
              </div>
              <span className="text-xs font-bold hidden md:block">{currentUser.name}</span>
              <ChevronDown size={14} className="text-zinc-300" />
            </button>

            {isUserMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsUserMenuOpen(false)}></div>
                <div className="absolute right-0 top-full mt-3 w-56 bg-white rounded-3xl p-2 z-20 shadow-2xl border border-pastel-lavender/20 animate-in fade-in slide-in-from-top-2">
                  <div className="p-4 border-b border-zinc-50 mb-1">
                    <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">누구의 눈으로 볼까요?</span>
                  </div>
                  {users.map(u => (
                    <button
                      key={u.id}
                      onClick={() => {
                        onSwitchUser(u);
                        setIsUserMenuOpen(false);
                      }}
                      className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl text-xs font-semibold transition-all ${currentUser.id === u.id ? 'bg-pastel-sand text-pastel-purple' : 'hover:bg-pastel-sand/50'}`}
                    >
                      <div className="w-4 h-4 rounded-full" style={{ backgroundColor: u.color }}></div>
                      {u.name}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto w-full p-8 md:p-16">
        {children}
      </main>

      {/* 모바일 하단 내비게이션 - Floating Glassmorphism */}
      <div className="md:hidden fixed bottom-6 left-6 right-6 z-40">
        <nav className="glass rounded-[2.5rem] flex justify-around py-5 soft-shadow border border-white/40">
          <button onClick={() => onTabChange('DASHBOARD')} className={activeTab === 'DASHBOARD' ? 'text-pastel-purple' : 'text-zinc-300'}><LayoutDashboard size={24} /></button>
          <button onClick={() => onTabChange('HISTORY')} className={activeTab === 'HISTORY' ? 'text-pastel-purple' : 'text-zinc-300'}><ClipboardList size={24} /></button>
          <button onClick={() => onTabChange('BUDGET')} className={activeTab === 'BUDGET' ? 'text-pastel-purple' : 'text-zinc-300'}><Settings size={24} /></button>
          <button onClick={() => onTabChange('PRAISE')} className={activeTab === 'PRAISE' ? 'text-pastel-purple' : 'text-zinc-300'}><Smile size={24} /></button>
        </nav>
