      {/* 기록 추가 버튼 */}
      <button 
        onClick={onOpenAddModal}
        className="fixed bottom-10 right-10 md:bottom-16 md:right-16 bg-pastel-purple text-white w-16 h-16 rounded-3xl shadow-xl hover:scale-110 transition-all active:scale-95 z-40 flex items-center justify-center group"
      >
        <Plus size={32} className="group-hover:rotate-90 transition-transform duration-500" />
      </button>
    </div>
  );
};

import React from 'react';
import { AlertCircle } from 'lucide-react';
import { BudgetStatus, Category } from '../types';

interface BudgetCardProps {
  category: Category;
  status: BudgetStatus;
}

export const BudgetCard: React.FC<BudgetCardProps> = ({ category, status }) => {
  const isAlert = status.status === 'DANGER' || status.status === 'EXCEEDED';
  const progressWidth = Math.min(status.percentage, 100);

  return (
    <div className="bg-white rounded-4xl p-8 soft-shadow border border-pastel-lavender/20 group hover:border-pastel-lavender transition-all">
      <div className="flex justify-between items-start mb-6">
        <div className="space-y-1">
          <h4 className="text-sm font-bold text-pastel-text/80">{category.name}</h4>
          <p className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">목표: {category.budgetLimit.toLocaleString()} 원</p>
        </div>
        {isAlert && (
          <div className="bg-rose-50 text-rose-400 px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest animate-pulse">
            주의
          </div>
        )}
      </div>

      <div className="space-y-4">
        <div className="h-2 w-full bg-pastel-sand rounded-full overflow-hidden">
          <div 
            className="h-full transition-all duration-1000 ease-out rounded-full" 
            style={{ 
              width: `${progressWidth}%`, 
              backgroundColor: status.status === 'EXCEEDED' ? '#FDA4AF' : (category.color || '#D4C6F0') 
            }} 
          />
        </div>
        <div className="flex justify-between items-center text-[11px] font-bold tabular-nums">
           <span className="text-zinc-400">{status.spent.toLocaleString()} / {category.budgetLimit.toLocaleString()}</span>
           <span className={status.status === 'EXCEEDED' ? 'text-rose-400' : 'text-pastel-purple'}>{status.percentage.toFixed(0)}%</span>
        </div>
      </div>

      {status.status === 'EXCEEDED' && (
        <div className="mt-6 bg-rose-50/50 rounded-2xl p-4 text-[10px] font-medium text-rose-500 flex items-center gap-3">
          <AlertCircle size={14} />
          <span>예산보다 {Math.abs(status.limit - status.spent).toLocaleString()}원을 더 사용했어요.</span>
        </div>
      )}
    </div>
  );
};

