import React, { useState, useMemo } from 'react';
import { X, Camera, Sparkles, Calendar, Tag, FileText, User as UserIcon } from 'lucide-react';
import { TransactionType, Category, User } from '../types';
import { renderCategoryIcon } from '../App';
import { analyzeReceiptImage } from '../services/geminiService';

interface TransactionFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  categories: Category[];
  users: User[];
  currentUser: User;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onClose, onSubmit, categories, users, currentUser }) => {
  const [type, setType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [amount, setAmount] = useState<string>('');
  const [categoryId, setCategoryId] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState<string>('');
  const [userId, setUserId] = useState<string>(currentUser.id);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const groupedOptions = useMemo<Record<string, Category[]>>(() => {
    const filtered = categories.filter(c => c.type === type);
    const groups: Record<string, Category[]> = {};
    filtered.forEach(cat => {
      if (!groups[cat.group]) groups[cat.group] = [];
      groups[cat.group].push(cat);
    });
    return groups;
  }, [categories, type]);

  const handleReceiptUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    try {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        const result = await analyzeReceiptImage(base64);
        setAmount(result.amount.toString());
        setDescription(result.description);
        setDate(result.date);
        // 간단한 카테고리 매칭 로직 (개선 가능)
        const matched = categories.find(c => c.name.includes(result.categoryGuess) || result.categoryGuess.includes(c.name));
        if (matched) setCategoryId(matched.id);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !categoryId || !description) return;
    onSubmit({ type, amount: parseFloat(amount), categoryId, userId, date, description });
    onClose();
  };

  const selectedCategory = categories.find(c => c.id === categoryId);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-lg shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center bg-white/50">
          <div>
            <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">기억하고 싶은 기록</h2>
            <p className="text-[10px] text-zinc-400 mt-1">오늘의 소중한 소비와 수입을 남겨주세요.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        <div className="overflow-y-auto p-10 flex-1 space-y-10 custom-scrollbar">
          {/* AI 영수증 분석 버튼 */}
          <div className="relative group">
            <input type="file" accept="image/*" onChange={handleReceiptUpload} className="hidden" id="receipt-upload" />
            <label 
              htmlFor="receipt-upload"
              className={`flex items-center justify-center gap-3 w-full py-4 rounded-3xl border-2 border-dashed transition-all cursor-pointer
                ${isAnalyzing ? 'bg-pastel-mint/30 border-pastel-mint animate-pulse' : 'bg-pastel-mint/10 border-pastel-mint/40 hover:bg-pastel-mint/20'}`}
            >
              <Camera size={20} className="text-emerald-500" />
              <span className="text-xs font-bold text-emerald-700/70 uppercase tracking-widest">
                {isAnalyzing ? '똑똑한 AI가 읽고 있어요...' : '영수증으로 자동 입력하기'}
              </span>
              {!isAnalyzing && <Sparkles size={14} className="text-emerald-400" />}
            </label>
          </div>

          {/* Type Toggle */}
          <div className="flex bg-pastel-sand/50 p-1.5 rounded-3xl border border-pastel-lavender/10">
            <button 
              type="button" 
              onClick={() => setType(TransactionType.EXPENSE)} 
              className={`flex-1 py-3 rounded-2xl text-[11px] font-bold uppercase transition-all
                ${type === TransactionType.EXPENSE ? 'bg-white text-rose-400 shadow-sm' : 'text-zinc-400'}`}
            >
              지출
            </button>
            <button 
              type="button" 
              onClick={() => setType(TransactionType.INCOME)} 
              className={`flex-1 py-3 rounded-2xl text-[11px] font-bold uppercase transition-all
                ${type === TransactionType.INCOME ? 'bg-white text-emerald-500 shadow-sm' : 'text-zinc-400'}`}
            >
              수입
            </button>
          </div>

          <div className="space-y-8">
            {/* Amount */}
            <div className="text-center">
              <label className="text-[10px] font-bold uppercase text-zinc-300 mb-3 block tracking-widest">거래 금액</label>
              <div className="relative inline-block w-full">
                <input 
                  type="number" 
                  value={amount} 
                  onChange={(e) => setAmount(e.target.value)} 
                  className="w-full text-5xl font-bold text-pastel-text text-center outline-none bg-transparent tabular-nums placeholder:text-pastel-sand" 
                  placeholder="0" 
                  required 
                />
                <span className="block mt-2 text-xs font-bold text-zinc-300">KRW</span>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Date */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 text-[10px] font-bold uppercase text-zinc-300 tracking-widest">
                  <Calendar size={12} /> 날짜
                </label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={(e) => setDate(e.target.value)} 
                  className="w-full py-3 px-5 text-xs font-bold" 
                  required 
                />
              </div>

              {/* Category */}
              <div className="space-y-2">
                <label className="flex items-center gap-2 text-[10px] font-bold uppercase text-zinc-300 tracking-widest">
                  <Tag size={12} /> 분류
                </label>
                <div className="relative flex items-center">
                  <div className="absolute left-4 z-10 pointer-events-none">
                    {selectedCategory ? (
                      <div style={{ color: selectedCategory.color }}>
                        {renderCategoryIcon(selectedCategory.iconId, 16)}
                      </div>
                    ) : <Tag size={16} className="text-zinc-200" />}
                  </div>
                  <select 
                    value={categoryId} 
                    onChange={(e) => setCategoryId(e.target.value)} 
                    className="w-full py-3 pl-12 pr-10 text-xs font-bold appearance-none" 
                    required
                  >
                    <option value="">선택해주세요</option>
                    {(Object.entries(groupedOptions) as [string, Category[]][]).map(([group, cats]) => (
                      <optgroup key={group} label={group} className="text-[10px]">
                        {cats.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </optgroup>
                    ))}
                  </select>
                </div>
              </div>
            </div>

            {/* Description */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] font-bold uppercase text-zinc-300 tracking-widest">
                <FileText size={12} /> 상세 내용
              </label>
              <input 
                type="text" 
                value={description} 
                onChange={(e) => setDescription(e.target.value)} 
                className="w-full py-4 px-5 text-sm font-medium" 
                placeholder="어디에서 사용했나요? (예: 별다방 카페)" 
                required 
              />
            </div>

            {/* User Selector */}
            <div className="space-y-3">
              <label className="flex items-center gap-2 text-[10px] font-bold uppercase text-zinc-300 tracking-widest">
                <UserIcon size={12} /> 기록하는 사람
              </label>
              <div className="flex gap-3">
                {users.map(u => (
                  <button 
                    key={u.id} 
                    type="button" 
                    onClick={() => setUserId(u.id)} 
                    className={`flex-1 py-3 px-4 rounded-2xl text-[10px] font-bold transition-all border
                      ${userId === u.id ? 'bg-white border-pastel-purple text-pastel-purple shadow-sm ring-4 ring-pastel-purple/5' : 'bg-pastel-sand/30 border-transparent text-zinc-300'}`}
                  >
                    <span className="mr-2" style={{ color: u.color }}>●</span>
                    {u.name}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Footer Action */}
        <div className="p-10 bg-pastel-sand/20 border-t border-pastel-sand">
          <button 
            type="submit" 
            onClick={handleSubmit} 
            className="w-full bg-pastel-purple text-white py-5 rounded-3xl font-bold uppercase tracking-[0.2em] shadow-lg hover:brightness-95 active:scale-95 transition-all"
          >
            기록 저장하기
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Save, Plus, Trash2, Palette, Type as FontIcon, Layout } from 'lucide-react';
import { Category, TransactionType } from '../types';
import { ICON_MAP } from '../App';

interface CategoryManagerModalProps {
  categories: Category[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const CategoryManagerModal: React.FC<CategoryManagerModalProps> = ({ categories, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeType, setActiveType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [editingIconId, setEditingIconId] = useState<string | null>(null);

  const handleUpdate = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAdd = () => {
    const newId = `c_new_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 분류',
      group: activeType === TransactionType.EXPENSE ? '기타' : '수입',
      type: activeType,
      budgetLimit: 0,
      color: '#D4C6F0',
      iconId: 'other'
    };
    setLocalCategories([...localCategories, newCat]);
  };

  const handleDelete = (id: string) => {
    setLocalCategories(prev => prev.filter(c => c.id !== id));
  };

  const currentCats = localCategories.filter(c => c.type === activeType);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in zoom-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-3xl shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center bg-white/50">
          <div>
            <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">분류 정하기</h2>
            <p className="text-[10px] text-zinc-400 mt-1">우리만의 특별한 소비 카테고리를 만들어보세요.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        {/* Tab Toggle */}
        <div className="flex border-b border-pastel-sand p-2 bg-pastel-sand/20">
          <button 
            onClick={() => setActiveType(TransactionType.EXPENSE)} 
            className={`flex-1 py-3 rounded-2xl text-[11px] font-bold uppercase transition-all
              ${activeType === TransactionType.EXPENSE ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300 hover:text-zinc-500'}`}
          >
            지출 카테고리
          </button>
          <button 
            onClick={() => setActiveType(TransactionType.INCOME)} 
            className={`flex-1 py-3 rounded-2xl text-[11px] font-bold uppercase transition-all
              ${activeType === TransactionType.INCOME ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300 hover:text-zinc-500'}`}
          >
            수입 카테고리
          </button>
        </div>

        <div className="overflow-y-auto p-8 flex-1 space-y-6 custom-scrollbar bg-pastel-sand/5">
          <div className="flex justify-between items-center px-2">
            <span className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest">총 {currentCats.length}개의 분류</span>
            <button 
              onClick={handleAdd} 
              className="flex items-center gap-2 bg-pastel-purple text-white px-5 py-2.5 rounded-full text-[10px] font-bold uppercase hover:brightness-95 transition-all shadow-md"
            >
              <Plus size={16} /> 분류 추가하기
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {currentCats.map(cat => (
              <div key={cat.id} className="bg-white border border-pastel-lavender/20 p-5 rounded-3xl soft-shadow group hover:border-pastel-purple/30 transition-all">
                <div className="flex items-start gap-4">
                  {/* Icon Picker Trigger */}
                  <div className="relative">
                    <button 
                      onClick={() => setEditingIconId(editingIconId === cat.id ? null : cat.id)}
                      className="w-12 h-12 rounded-2xl flex items-center justify-center transition-all bg-pastel-sand/50"
                      style={{ color: cat.color }}
                    >
                      {React.createElement(ICON_MAP[cat.iconId] || ICON_MAP.other, { size: 22 })}
                    </button>

                    {editingIconId === cat.id && (
                      <div className="absolute left-0 top-full mt-3 w-64 bg-white rounded-3xl p-4 z-20 shadow-2xl border border-pastel-lavender/20 animate-in fade-in zoom-in">
                        <p className="text-[9px] font-bold text-zinc-300 uppercase mb-3 px-1">아이콘 선택</p>
                        <div className="grid grid-cols-5 gap-1.5 max-h-48 overflow-y-auto custom-scrollbar">
                          {Object.keys(ICON_MAP).map(key => (
                            <button 
                              key={key} 
                              onClick={() => { handleUpdate(cat.id, 'iconId', key); setEditingIconId(null); }}
                              className={`p-2.5 rounded-xl hover:bg-pastel-sand transition-all flex items-center justify-center
                                ${cat.iconId === key ? 'bg-pastel-sand ring-1 ring-pastel-purple' : ''}`}
                            >
                              {React.createElement(ICON_MAP[key], { size: 16, className: 'text-pastel-text/60' })}
                            </button>
                          ))}
                        </div>
                      </div>
