              <PartyPopper size={64} className="mx-auto mb-6 text-pastel-purple animate-bounce" />
              <h2 className="text-3xl font-bold mb-3 tracking-tight">너무 멋져요!</h2>
              <p className="text-zinc-500 mb-10 leading-relaxed">
                "{successGoal.title}" 보드를<br/>정성스레 가득 채우셨네요. 고마워요!
              </p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold hover:brightness-95 transition-all shadow-lg"
              >
                닫기
              </button>
           </div>
        </div>
      )}

      {/* 헤더 필터 영역 */}
      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between">
        <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow">
          <button onClick={() => setViewMode('JOINT')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'JOINT' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>우리 함께</button>
          <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'INDIVIDUAL' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>나의 기록</button>
        </div>
        <div className="flex items-center gap-4 bg-white px-5 py-2.5 rounded-3xl soft-shadow border border-pastel-lavender/30">
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() - 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronLeft size={20} /></button>
          <span className="text-sm font-bold tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() + 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronRight size={20} /></button>
