import React, { useState } from 'react';
import { AlertCircle, ChevronDown, ChevronUp, User as UserIcon } from 'lucide-react';
import { BudgetStatus, Category, User } from '../types';

interface BudgetCardProps {
  category: Category;
  status: BudgetStatus;
  users: User[];
}

export const BudgetCard: React.FC<BudgetCardProps> = ({ category, status, users }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const progressWidth = Math.min(status.percentage, 100);

  // 예산 상태에 따른 색상 정의
  const getStatusColor = (percentage: number) => {
    if (percentage >= 100) return 'bg-rose-500'; // 초과
    if (percentage >= 85) return 'bg-rose-300'; // 위험 (DANGER)
    if (percentage >= 60) return 'bg-orange-300'; // 주의 (WARNING)
    return 'bg-emerald-300'; // 안전 (SAFE)
  };

  const getStatusText = (percentage: number) => {
    if (percentage >= 100) return '예산 초과';
    if (percentage >= 85) return '위험';
    if (percentage >= 60) return '주의';
    return '안전';
  };

  const getStatusBg = (percentage: number) => {
    if (percentage >= 100) return 'bg-rose-50 text-rose-600';
    if (percentage >= 85) return 'bg-rose-50 text-rose-400';
    if (percentage >= 60) return 'bg-orange-50 text-orange-400';
    return 'bg-emerald-50 text-emerald-600';
  };

  return (
    <div className="bg-white rounded-4xl p-8 soft-shadow border border-pastel-lavender/20 group hover:border-pastel-lavender transition-all">
      <div className="flex justify-between items-start mb-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl flex items-center justify-center bg-pastel-sand/50" style={{ color: category.color }}>
            {/* 아이콘 렌더링은 상위에서 처리하거나 ICON_MAP 사용 필요 */}
            <div className="text-xl">●</div> 
          </div>
          <div className="space-y-1">
            <h4 className="text-sm font-bold text-pastel-text/80">{category.name}</h4>
            <p className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">공동 예산: {category.budgetLimit.toLocaleString()} 원</p>
          </div>
        </div>
        <div className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase tracking-widest ${getStatusBg(status.percentage)}`}>
          {getStatusText(status.percentage)}
        </div>
      </div>

      <div className="space-y-4">
        <div className="h-3 w-full bg-pastel-sand rounded-full overflow-hidden">
          <div 
            className={`h-full transition-all duration-1000 ease-out rounded-full ${getStatusColor(status.percentage)}`}
            style={{ width: `${progressWidth}%` }} 
          />
        </div>
        <div className="flex justify-between items-center text-[11px] font-bold tabular-nums">
           <span className="text-zinc-400">지출 {status.spent.toLocaleString()} 원</span>
           <span className={status.percentage >= 85 ? 'text-rose-400' : 'text-pastel-purple'}>{status.percentage.toFixed(0)}%</span>
        </div>
      </div>

      {status.individualStatus && (
        <div className="mt-6 pt-6 border-t border-pastel-sand">
          <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className="flex items-center justify-between w-full text-[10px] font-bold text-zinc-400 uppercase tracking-widest hover:text-pastel-purple transition-colors"
          >
            <span className="flex items-center gap-2"><UserIcon size={12} /> 개인별 상세 현황</span>
            {isExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </button>

          {isExpanded && (
            <div className="mt-4 space-y-4 animate-in slide-in-from-top-2">
              {users.map(user => {
                const indStatus = status.individualStatus?.[user.id];
                if (!indStatus || indStatus.limit === 0) return null;
                const indProgress = Math.min(indStatus.percentage, 100);

                return (
                  <div key={user.id} className="space-y-2">
                    <div className="flex justify-between items-center text-[10px] font-bold">
                      <span className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: user.color }}></span>
                        {user.name}
                      </span>
                      <span className="text-zinc-300">{indStatus.spent.toLocaleString()} / {indStatus.limit.toLocaleString()}</span>
                    </div>
                    <div className="h-1.5 w-full bg-pastel-sand rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-700 rounded-full ${getStatusColor(indStatus.percentage)}`}
                        style={{ width: `${indProgress}%` }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {status.status === 'EXCEEDED' && (
        <div className="mt-6 bg-rose-50/50 rounded-2xl p-4 text-[10px] font-medium text-rose-500 flex items-center gap-3">
          <AlertCircle size={14} />
          <span>예산보다 {Math.abs(status.limit - status.spent).toLocaleString()}원을 더 사용했어요.</span>
        </div>
      )}
    </div>
  );
};

