        <div className="flex flex-1 overflow-hidden">
          {/* Left: Category List */}
          <div className="w-1/3 border-r border-pastel-sand bg-pastel-sand/10 overflow-y-auto custom-scrollbar">
            {expenseCategories.map(cat => (
              <button
                key={cat.id}
                onClick={() => setActiveCategoryId(cat.id)}
                className={`w-full text-left p-6 transition-all border-b border-pastel-sand/50
