          </div>

          {historyViewMode === 'CALENDAR' && (
            <CalendarView 
              currentDate={historyDate} 
              transactions={monthlyTransactions} 
              onDateClick={handleCalendarDateClick} 
            />
          )}

          {selectedHistoryDate && (
            <div className="flex items-center justify-between bg-pastel-lavender/20 px-6 py-4 rounded-2xl border border-pastel-lavender/30 animate-in slide-in-from-top-4">
              <span className="text-xs font-bold text-pastel-purple">{selectedHistoryDate} 내역만 보는 중</span>
              <button onClick={() => setSelectedHistoryDate(null)} className="text-[10px] font-bold text-zinc-400 hover:text-pastel-text underline underline-offset-4">전체 보기</button>
            </div>
          )}

          <div className="space-y-16">
            {(Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
              <div key={date} className="flex flex-col lg:flex-row gap-8">
                <div className="lg:w-28 shrink-0 flex flex-col pt-2">
                  <span className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-3xl font-bold tabular-nums text-pastel-text/40 tracking-tighter">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-6">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    const isLiked = (t.likes || []).includes(currentUser.id);
                    const isDisliked = (t.dislikes || []).includes(currentUser.id);

                    return (
                      <div key={t.id} className="bg-white rounded-3xl soft-shadow border border-pastel-lavender/20 flex flex-col overflow-hidden transition-all hover:scale-[1.01]">
                        <div className="p-6 flex items-center justify-between">
                          <div className="flex items-center gap-6">
                            <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 22)}</div>
                            <div>
                              <div className="flex items-center gap-3 mb-1">
                                <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{cat?.name}</span>
                                <span className="text-[9px] font-bold text-zinc-400 bg-pastel-sand px-2 py-0.5 rounded-full">{user?.name}</span>
                              </div>
                              <p className="text-sm font-medium text-pastel-text/90">{t.description}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <span className={`text-xl font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500/80' : 'text-pastel-text'}`}>
                              {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                            </span>
                          </div>
                        </div>

                        <div className="px-6 py-3 bg-pastel-sand/10 border-t border-pastel-sand/30 flex items-center justify-between">
                          <div className="flex items-center gap-4">
                            <button 
                              onClick={() => toggleLike(t.id)} 
                              className={`flex items-center gap-1.5 text-[10px] font-bold transition-all px-2 py-1 rounded-full ${isLiked ? 'text-pastel-purple bg-pastel-purple/10' : 'text-zinc-300 hover:text-zinc-400'}`}
                            >
                              <ThumbsUp size={14} fill={isLiked ? 'currentColor' : 'none'} />
                              {(t.likes || []).length}
                            </button>
                            <button 
                              onClick={() => toggleDislike(t.id)} 
                              className={`flex items-center gap-1.5 text-[10px] font-bold transition-all px-2 py-1 rounded-full ${isDisliked ? 'text-rose-400 bg-rose-400/10' : 'text-zinc-300 hover:text-zinc-400'}`}
                            >
                              <ThumbsDown size={14} fill={isDisliked ? 'currentColor' : 'none'} />
                              {(t.dislikes || []).length}
                            </button>
                          </div>
                          <div className="flex items-center gap-1.5 text-[10px] font-bold text-zinc-300">
                             <MessageSquare size={14} />
                             {(t.comments || []).length}
                          </div>
                        </div>

                        {(t.comments && t.comments.length > 0) && (
                          <div className="px-6 py-4 bg-pastel-sand/5 space-y-3">
                            {t.comments.map(c => {
                              const cUser = users.find(u => u.id === c.userId);
                              return (
                                <div key={c.id} className="flex gap-3 animate-in slide-in-from-left-2">
                                  <div className="w-5 h-5 rounded-full text-[8px] flex items-center justify-center text-white shrink-0 mt-0.5" style={{ backgroundColor: cUser?.color }}>{cUser?.avatar}</div>
                                  <div className="bg-white px-3 py-2 rounded-2xl rounded-tl-none soft-shadow border border-pastel-lavender/10">
                                    <p className="text-[11px] font-medium text-pastel-text">{c.text}</p>
                                  </div>
                                </div>
                              );
                            })}
                          </div>
                        )}

                        <div className="px-6 py-4 bg-white border-t border-pastel-sand/20">
                          <div className="relative">
                            <input 
                              type="text" 
                              placeholder="칭찬이나 질문을 남겨보세요..." 
                              className="w-full bg-pastel-sand/30 border-none px-4 py-2.5 rounded-2xl text-[11px] font-medium outline-none focus:bg-white focus:ring-1 focus:ring-pastel-purple/30 transition-all pr-12"
                              onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                  addComment(t.id, (e.target as HTMLInputElement).value);
                                  (e.target as HTMLInputElement).value = '';
                                }
                              }}
                            />
                            <button 
                              className="absolute right-3 top-1/2 -translate-y-1/2 text-pastel-purple/50 hover:text-pastel-purple transition-colors"
                              onClick={(e) => {
                                const input = e.currentTarget.previousSibling as HTMLInputElement;
                                addComment(t.id, input.value);
                                input.value = '';
                              }}
                            >
                              <Send size={14} />
                            </button>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
            {Object.keys(transactionsByDate).length === 0 && (
              <div className="py-20 text-center space-y-4">
                <div className="bg-pastel-sand w-16 h-16 rounded-full flex items-center justify-center mx-auto text-zinc-300">
                  <ClipboardList size={32} />
                </div>
                <p className="text-sm font-medium text-zinc-400">아직 기록된 내역이 없어요.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'BUDGET' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-12 duration-700">
          <div className="flex flex-col md:flex-row items-center justify-between">
             <div>
                <h2 className="text-3xl font-bold flex items-center gap-4">
                  <div className="p-3 bg-pastel-mint text-emerald-600 rounded-2xl"><PieChart size={24} /></div>
                  예산 매니저
                </h2>
                <p className="text-xs text-zinc-400 mt-2 tracking-widest">이번 달 지출 한도를 개인별, 그룹별로 스마트하게 관리하세요.</p>
             </div>
             <button 
               onClick={() => setIsBudgetModalOpen(true)}
               className="bg-white text-pastel-text px-8 py-4 rounded-3xl text-xs font-bold soft-shadow border border-pastel-lavender/30 hover:bg-pastel-sand transition-all flex items-center gap-3"
             >
               <Settings size={18} /> 예산 설정하기
             </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {budgetStatuses.map(status => {
              const cat = categories.find(c => c.id === status.categoryId);
              if (!cat) return null;
              return (
                <BudgetCard 
                  key={cat.id} 
                  category={cat} 
                  status={status} 
                  users={users} 
                />
              );
            })}
          </div>

          {budgetStatuses.length === 0 && (
            <div className="py-32 text-center space-y-6">
               <div className="w-20 h-20 bg-pastel-sand rounded-full flex items-center justify-center mx-auto text-zinc-300">
                 <Wallet size={36} />
               </div>
               <p className="text-sm font-bold text-zinc-400 uppercase tracking-widest">설정된 예산 카테고리가 없습니다.</p>
               <button 
                 onClick={() => setIsBudgetModalOpen(true)}
                 className="bg-pastel-purple text-white px-8 py-3 rounded-2xl text-[11px] font-bold shadow-lg"
               >
                 첫 예산 설정하기
               </button>
            </div>
          )}
        </div>
      )}

      {activeTab === 'PRAISE' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-12 duration-1000 pb-32">
          <div className="flex flex-col md:flex-row items-center justify-between">
             <div>
                <h2 className="text-3xl font-bold flex items-center gap-4">
                  <div className="p-3 bg-pastel-rose text-white rounded-2xl"><Heart size={24} fill="white" /></div>
                  사랑의 칭찬 보드
                </h2>
                <p className="text-xs text-zinc-400 mt-2 tracking-widest">따뜻한 마음을 담아 포도알 스티커를 붙여주세요.</p>
             </div>
             <button 
               onClick={() => setIsNewGoalOpen(true)}
               className="bg-white text-pastel-text px-8 py-4 rounded-3xl text-xs font-bold soft-shadow border border-pastel-lavender/30 hover:bg-pastel-sand transition-all"
             >
               <Plus size={18} className="inline mr-2" /> 새 보드 만들기
             </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            {stickerGoals.map(goal => {
              const assignee = users.find(u => u.id === goal.assignedToUserId);
              return (
                <div key={goal.id} className="bg-white rounded-[3rem] p-12 relative flex flex-col soft-shadow border border-pastel-lavender/20 overflow-hidden">
                   <PraiseStamp />

                   <div className="mb-10">
                      <div className="flex items-center gap-3 mb-4">
                        <div className="w-9 h-9 text-xs font-bold text-white flex items-center justify-center rounded-xl shadow-sm" style={{ backgroundColor: assignee?.color }}>{assignee?.avatar}</div>
                        <span className="text-[12px] font-bold text-zinc-300 uppercase tracking-widest">{assignee?.name}의 약속</span>
                      </div>
                      <h3 className="text-2xl font-bold pr-20 leading-tight text-pastel-text/80">{goal.title}</h3>
                   </div>

                   <div className="relative bg-pastel-sand/30 rounded-4xl p-8 flex flex-col items-center min-h-[420px]">
                      <div className="absolute top-2 opacity-30 text-emerald-700/50"><Leaf size={60} fill="currentColor" /></div>
                      <GrapeBunchLayout target={goal.targetCount} count={goal.currentCount} color={assignee?.color} />
                   </div>

                   <div className="flex items-center justify-between pt-10">
                      <div>
                        <span className="text-4xl font-bold tabular-nums tracking-tighter leading-none">{goal.currentCount}</span>
                        <span className="text-[11px] text-zinc-300 font-bold uppercase tracking-[0.2em] ml-2">/ {goal.targetCount} Grains</span>
                      </div>
                      {!goal.isCompleted && (
                        <button 
                          onClick={() => handleAddSticker(goal.id)}
                          className="bg-pastel-purple text-white px-10 py-5 rounded-3xl text-xs font-bold shadow-lg hover:brightness-95 transition-all"
                        >
                          스티커 선물하기
                        </button>
                      )}
                      {goal.isCompleted && (
                        <div className="flex items-center gap-2 text-xs font-bold text-emerald-500/80 bg-emerald-50 px-6 py-3 rounded-full">
                          <CheckCircle2 size={16} /> 미션 성공
                        </div>
                      )}
                   </div>
                </div>
              );
            })}
          </div>

          {isNewGoalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md">
              <div className="bg-white rounded-5xl w-full max-w-md shadow-2xl p-10 space-y-8 border border-pastel-lavender/30">
                 <div className="flex justify-between items-center">
                    <h2 className="text-sm font-bold uppercase tracking-widest">새로운 칭찬 기록장</h2>
                    <button onClick={() => setIsNewGoalOpen(false)} className="text-zinc-300 hover:text-pastel-text"><X size={24} /></button>
                 </div>
                 <div className="space-y-6">
                    <div>
                       <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">무엇을 칭찬할까요?</label>
                       <input type="text" placeholder="예: 매일 저녁 맛있게 먹어주기" value={newGoalTitle} onChange={(e) => setNewGoalTitle(e.target.value)} className="w-full p-4 text-sm font-medium" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">스티커 개수</label>
                          <select value={newGoalTarget} onChange={(e) => setNewGoalTarget(parseInt(e.target.value))} className="w-full p-4 text-sm font-medium">
                             <option value={15}>15개 (귀여운 보드)</option>
                             <option value={33}>33개 (뿌듯한 보드)</option>
                          </select>
                       </div>
                       <div>
                          <label className="text-[11px] font-bold text-zinc-300 mb-2 block uppercase">주인공</label>
                          <select value={newGoalAssignee} onChange={(e) => setNewGoalAssignee(e.target.value)} className="w-full p-4 text-sm font-medium">
                             {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                       </div>
                    </div>
                    <button onClick={createGoal} className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold shadow-lg hover:brightness-95 transition-all">보드 만들기</button>
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={(tx) => setTransactions(prev => [{ ...tx, id: Math.random().toString(36).substr(2,9), likes: [], dislikes: [], comments: [] }, ...prev])} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isCategoryManagerOpen && (
        <CategoryManagerModal categories={categories} onClose={() => setIsCategoryManagerOpen(false)} onSave={setCategories} />
      )}
      {isBudgetModalOpen && (
        <BudgetSettingModal 
          categories={categories} 
          users={users} 
          onClose={() => setIsBudgetModalOpen(false)} 
          onSave={setCategories} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, PlusCircle, Settings, ClipboardList, Utensils, Bus, ShoppingBag, 
  Home, Banknote, Coins, Palmtree, HeartPulse, GraduationCap, Coffee,
  MoreHorizontal, Smartphone, Car, PawPrint, Gift, Scissors, BookOpen,
  Wine, Music, Plane, Zap, Shirt, CreditCard, ChevronDown, Plus, 
  ArrowUpRight, ArrowDownLeft, Wallet, Send, ThumbsUp, ThumbsDown, MessageSquare,
  Smile, PartyPopper, CheckCircle2, Leaf, X, Heart, Calendar as CalendarIcon, List, PieChart, Activity
} from 'lucide-react';

import { Transaction, User, Category, TransactionType, Comment, StickerGoal, BudgetStatus } from './types';
import { Layout } from './components/Layout';
import { TransactionForm } from './components/TransactionForm';
import { CategoryManagerModal } from './components/CategoryManagerModal';
import { Toast, ToastType } from './components/Toast';
import { CalendarView } from './components/CalendarView';
import { BudgetCard } from './components/BudgetCard';
import { BudgetSettingModal } from './components/BudgetSettingModal';

// --- 아이콘 매핑 ---
export const ICON_MAP: Record<string, React.ElementType> = {
  food: Utensils, transport: Bus, shopping: ShoppingBag, home: Home, salary: Banknote,
  money: Coins, leisure: Palmtree, health: HeartPulse, education: GraduationCap, cafe: Coffee,
  phone: Smartphone, car: Car, pet: PawPrint, gift: Gift, beauty: Scissors,
  book: BookOpen, drink: Wine, culture: Music, travel: Plane, utility: Zap,
  clothes: Shirt, card: CreditCard, other: MoreHorizontal
};

export const renderCategoryIcon = (iconId: string, size: number = 20) => {
  const IconComponent = ICON_MAP[iconId] || ICON_MAP.other;
  return <IconComponent size={size} />;
};

const PraiseStamp = () => (
  <div className="absolute top-6 right-6 w-28 h-28 border-[3px] border-pastel-rose rounded-full flex flex-col items-center justify-center p-1 rotate-[12deg] bg-white/40 backdrop-blur-[2px] z-10 select-none pointer-events-none opacity-90 border-dashed">
    <div className="flex gap-1 text-pastel-rose mb-1">
       <Heart size={8} fill="currentColor" />
       <Heart size={12} fill="currentColor" className="-translate-y-1" />
       <Heart size={8} fill="currentColor" />
    </div>
    <span className="text-[13px] font-bold text-pastel-rose leading-tight text-center tracking-tighter">참 잘했어요!</span>
    <span className="text-[9px] font-medium text-pastel-rose/70 mt-1">Co-Budget</span>
  </div>
);

const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number; number: number }> = ({ filled, color = '#D4C6F0', index, number }) => (
  <div 
    className={`relative w-10 h-10 rounded-full transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] flex items-center justify-center text-[10px] font-medium
      ${filled ? 'scale-105 shadow-md' : 'scale-100 bg-white/60 border border-white text-zinc-300'}`}
    style={{ 
      backgroundColor: filled ? color : 'rgba(255,255,255,0.6)',
      color: filled ? 'white' : '#A1A1AA',
      transitionDelay: `${(index % 12) * 40}ms`
    }}
  >
    {number}
    {filled && (
      <div className="absolute inset-0 grape-shine rounded-full" />
    )}
  </div>
);

const GrapeBunchLayout: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  const rows = target === 33 ? [3, 5, 6, 5, 4, 3, 3, 2, 1, 1] : [3, 4, 3, 2, 1, 2];
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-2 py-8 mx-auto animate-in fade-in zoom-in duration-1000">
      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-2 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            if (num > target) return null;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: '장보기', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#F9E2E6', iconId: 'shopping' },
  { id: 'c2', name: '외식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#F7D1BA', iconId: 'food' },
  { id: 'c3', name: '카페/간식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#FAF3DD', iconId: 'cafe' },
  { id: 'c4', name: '생활', group: '주거', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#D1E8E2', iconId: 'home' },
  { id: 'c7', name: '이동', group: '교통', type: TransactionType.EXPENSE, budgetLimit: 120000, color: '#E8E4F8', iconId: 'transport' },
  { id: 'i1', name: '월급', group: '수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#E2F0EB', iconId: 'salary' },
];

const MOCK_USERS: User[] = [
  { id: 'u1', name: '내 사랑', avatar: '♥', color: '#D4C6F0' },
  { id: 'u2', name: '자기야', avatar: '☁', color: '#F9E2E6' },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE'>('DASHBOARD');
  const [historyViewMode, setHistoryViewMode] = useState<'LIST' | 'CALENDAR'>('LIST');
  const [selectedHistoryDate, setSelectedHistoryDate] = useState<string | null>(null);

  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: TransactionType.INCOME, amount: 4500000, categoryId: 'i1', userId: 'u1', date: new Date().toISOString().split('T')[0], description: '이번 달 고생했어 월급!', likes: [], dislikes: [], comments: [] },
  ]);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 요정 미션', targetCount: 33, currentCount: 18, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '배달 음식 참기', targetCount: 15, currentCount: 15, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [isBudgetModalOpen, setIsBudgetModalOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [historyDate, setHistoryDate] = useState(new Date());
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);

  const [isNewGoalOpen, setIsNewGoalOpen] = useState(false);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState(33);
  const [newGoalAssignee, setNewGoalAssignee] = useState(MOCK_USERS[1].id);

  // --- 반응형 기능 핸들러 ---
  const toggleLike = (txId: string) => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== txId) return t;
      const likes = t.likes || [];
      const newLikes = likes.includes(currentUser.id) 
        ? likes.filter(id => id !== currentUser.id)
        : [...likes, currentUser.id];
      return { ...t, likes: newLikes, dislikes: (t.dislikes || []).filter(id => id !== currentUser.id) };
    }));
  };

  const toggleDislike = (txId: string) => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== txId) return t;
      const dislikes = t.dislikes || [];
      const newDislikes = dislikes.includes(currentUser.id) 
        ? dislikes.filter(id => id !== currentUser.id)
        : [...dislikes, currentUser.id];
      return { ...t, dislikes: newDislikes, likes: (t.likes || []).filter(id => id !== currentUser.id) };
    }));
  };

  const addComment = (txId: string, text: string) => {
    if (!text.trim()) return;
    const newComment: Comment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      text: text.trim(),
      date: new Date().toISOString(),
    };
    setTransactions(prev => prev.map(t => t.id === txId ? { ...t, comments: [...(t.comments || []), newComment] } : t));
  };

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate]);

  const stats = useMemo(() => {
    const income = monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [monthlyTransactions]);

  const budgetStatuses = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
      const catTransactions = monthlyTransactions.filter(t => t.categoryId === cat.id);
      const spent = catTransactions.reduce((sum, t) => sum + t.amount, 0);
      const limit = cat.budgetLimit || 1; // 0 방지
      const percentage = (spent / limit) * 100;

      const individualStatus: Record<string, { spent: number; limit: number; percentage: number }> = {};
      users.forEach(u => {
        const uSpent = catTransactions.filter(t => t.userId === u.id).reduce((sum, t) => sum + t.amount, 0);
        const uLimit = cat.individualLimits?.[u.id] || 0;
        individualStatus[u.id] = {
          spent: uSpent,
          limit: uLimit,
          percentage: uLimit > 0 ? (uSpent / uLimit) * 100 : 0
        };
      });

      let status: BudgetStatus['status'] = 'SAFE';
      if (percentage >= 100) status = 'EXCEEDED';
      else if (percentage >= 85) status = 'DANGER';
      else if (percentage >= 60) status = 'WARNING';

      return {
        categoryId: cat.id,
        spent,
        limit,
        percentage,
        status,
        individualStatus
      } as BudgetStatus;
    });
  }, [categories, monthlyTransactions, users]);

  const transactionsByDate = useMemo(() => {
    const groups: Record<string, Transaction[]> = {};
    const filtered = selectedHistoryDate 
      ? monthlyTransactions.filter(t => t.date === selectedHistoryDate)
      : monthlyTransactions;

    filtered.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions, selectedHistoryDate]);

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const completed = nextCount >= g.targetCount;
      if (completed) setSuccessGoal(g);
      return { ...g, currentCount: nextCount, isCompleted: completed };
    }));
    setToast({ message: '포근한 마음을 담아 스티커를 붙였어요 ✨', type: 'success' });
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
    setToast({ message: '설레는 마음으로 새 보드를 만들었어요!', type: 'info' });
  };

  const handleCalendarDateClick = (date: string) => {
    setSelectedHistoryDate(date);
    setActiveTab('HISTORY');
    setHistoryViewMode('LIST');
  };

  const handleHistoryCalendarDateClick = (date: string) => {
    setSelectedHistoryDate(selectedHistoryDate === date ? null : date);
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 성공 팝업 */}
      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-500">
           <div className="bg-white rounded-5xl p-12 max-w-md w-full text-center shadow-2xl border border-pastel-lavender/50">
              <PartyPopper size={64} className="mx-auto mb-6 text-pastel-purple animate-bounce" />
              <h2 className="text-3xl font-bold mb-3 tracking-tight">너무 멋져요!</h2>
              <p className="text-zinc-500 mb-10 leading-relaxed">
                "{successGoal.title}" 보드를<br/>정성스레 가득 채우셨네요. 고마워요!
              </p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold hover:brightness-95 transition-all shadow-lg"
              >
                닫기
              </button>
           </div>
        </div>
      )}

      {/* 헤더 필터 영역 */}
      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between">
        <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow">
          <button onClick={() => setViewMode('JOINT')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'JOINT' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>우리 함께</button>
          <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'INDIVIDUAL' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>나의 기록</button>
        </div>
        <div className="flex items-center gap-4 bg-white px-5 py-2.5 rounded-3xl soft-shadow border border-pastel-lavender/30">
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() - 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronLeft size={20} /></button>
          <span className="text-sm font-bold tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() + 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronRight size={20} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
          {/* 주요 지표 */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-gradient-to-br from-pastel-lavender to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">우리 자산</span>
              <div className="text-4xl font-bold tracking-tighter tabular-nums">{stats.balance.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-mint to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">반가운 수입</span>
              <div className="text-4xl font-bold tracking-tighter text-emerald-600/70 tabular-nums">+{stats.income.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-rose to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">필요한 지출</span>
              <div className="text-4xl font-bold tracking-tighter text-rose-600/60 tabular-nums">-{stats.expense.toLocaleString()}</div>
            </div>
          </div>

          {/* 월간 지출 패턴 달력 */}
          <section className="space-y-6">
            <div className="flex items-center justify-between px-2">
               <h3 className="text-xl font-bold flex items-center gap-3">
                 <div className="p-2.5 bg-pastel-purple text-white rounded-xl shadow-sm"><Activity size={18} /></div>
                 월간 소비 흐름
               </h3>
               <div className="flex gap-4 items-center">
                  <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full bg-emerald-300" />
                    <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">수입</span>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full bg-rose-300" />
                    <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">지출</span>
                  </div>
               </div>
            </div>
            <CalendarView 
              currentDate={historyDate} 
              transactions={monthlyTransactions} 
              onDateClick={handleCalendarDateClick} 
            />
            <p className="text-center text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
              날짜를 클릭하면 해당 일의 상세 내역을 확인할 수 있습니다.
            </p>
          </section>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="flex justify-between items-center bg-white/40 backdrop-blur-md p-2 rounded-3xl border border-white/50 soft-shadow">
            <div className="flex gap-2">
              <button 
                onClick={() => setHistoryViewMode('LIST')} 
                className={`p-3 rounded-2xl transition-all ${historyViewMode === 'LIST' ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300'}`}
              >
                <List size={20} />
              </button>
              <button 
                onClick={() => setHistoryViewMode('CALENDAR')} 
                className={`p-3 rounded-2xl transition-all ${historyViewMode === 'CALENDAR' ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300'}`}
              >
                <CalendarIcon size={20} />
              </button>
            </div>
            <div className="px-4 text-[10px] font-bold text-zinc-400 uppercase tracking-widest">
              {historyViewMode === 'LIST' ? '리스트 보기' : '달력 요약'}
            </div>
          </div>

          {historyViewMode === 'CALENDAR' && (
            <CalendarView 
              currentDate={historyDate} 
              transactions={monthlyTransactions} 
              onDateClick={handleHistoryCalendarDateClick} 
            />
          )}

          {selectedHistoryDate && (
            <div className="flex items-center justify-between bg-pastel-lavender/20 px-6 py-4 rounded-2xl border border-pastel-lavender/30 animate-in slide-in-from-top-4">
              <span className="text-xs font-bold text-pastel-purple">{selectedHistoryDate} 내역만 보는 중</span>
              <button onClick={() => setSelectedHistoryDate(null)} className="text-[10px] font-bold text-zinc-400 hover:text-pastel-text underline underline-offset-4">전체 보기</button>
            </div>
          )}

          <div className="space-y-16">
            {(Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
              <div key={date} className="flex flex-col lg:flex-row gap-8">
                <div className="lg:w-28 shrink-0 flex flex-col pt-2">
                  <span className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-3xl font-bold tabular-nums text-pastel-text/40 tracking-tighter">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-6">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    const isLiked = (t.likes || []).includes(currentUser.id);
                    const isDisliked = (t.dislikes || []).includes(currentUser.id);

                    return (
                      <div key={t.id} className="bg-white rounded-3xl soft-shadow border border-pastel-lavender/20 flex flex-col overflow-hidden transition-all hover:scale-[1.01]">
                        <div className="p-6 flex items-center justify-between">
                          <div className="flex items-center gap-6">
                            <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 22)}</div>
                            <div>
                              <div className="flex items-center gap-3 mb-1">
                                <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{cat?.name}</span>
                                <span className="text-[9px] font-bold text-zinc-400 bg-pastel-sand px-2 py-0.5 rounded-full">{user?.name}</span>
                              </div>
                              <p className="text-sm font-medium text-pastel-text/90">{t.description}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <span className={`text-xl font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500/80' : 'text-pastel-text'}`}>
                              {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                            </span>
                          </div>
                        </div>

                        <div className="px-6 py-3 bg-pastel-sand/10 border-t border-pastel-sand/30 flex items-center justify-between">
                          <div className="flex items-center gap-4">
                            <button 
                              onClick={() => toggleLike(t.id)} 
                              className={`flex items-center gap-1.5 text-[10px] font-bold transition-all px-2 py-1 rounded-full ${isLiked ? 'text-pastel-purple bg-pastel-purple/10' : 'text-zinc-300 hover:text-zinc-400'}`}
                            >
                              <ThumbsUp size={14} fill={isLiked ? 'currentColor' : 'none'} />
                              {(t.likes || []).length}
                            </button>
                            <button 
                              onClick={() => toggleDislike(t.id)} 
                              className={`flex items-center gap-1.5 text-[10px] font-bold transition-all px-2 py-1 rounded-full ${isDisliked ? 'text-rose-400 bg-rose-400/10' : 'text-zinc-300 hover:text-zinc-400'}`}
                            >
                              <ThumbsDown size={14} fill={isDisliked ? 'currentColor' : 'none'} />
                              {(t.dislikes || []).length}
                            </button>
                          </div>
                          <div className="flex items-center gap-1.5 text-[10px] font-bold text-zinc-300">
                             <MessageSquare size={14} />
                             {(t.comments || []).length}
                          </div>
                        </div>

                        {(t.comments && t.comments.length > 0) && (
                          <div className="px-6 py-4 bg-pastel-sand/5 space-y-3">
                            {t.comments.map(c => {
                              const cUser = users.find(u => u.id === c.userId);
                              return (
                                <div key={c.id} className="flex gap-3 animate-in slide-in-from-left-2">
                                  <div className="w-5 h-5 rounded-full text-[8px] flex items-center justify-center text-white shrink-0 mt-0.5" style={{ backgroundColor: cUser?.color }}>{cUser?.avatar}</div>
                                  <div className="bg-white px-3 py-2 rounded-2xl rounded-tl-none soft-shadow border border-pastel-lavender/10">
                                    <p className="text-[11px] font-medium text-pastel-text">{c.text}</p>
                                  </div>
                                </div>
                              );
                            })}
                          </div>
                        )}

                        <div className="px-6 py-4 bg-white border-t border-pastel-sand/20">
                          <div className="relative">
                            <input 
                              type="text" 
                              placeholder="칭찬이나 질문을 남겨보세요..." 
                              className="w-full bg-pastel-sand/30 border-none px-4 py-2.5 rounded-2xl text-[11px] font-medium outline-none focus:bg-white focus:ring-1 focus:ring-pastel-purple/30 transition-all pr-12"
                              onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                  addComment(t.id, (e.target as HTMLInputElement).value);
                                  (e.target as HTMLInputElement).value = '';
                                }
                              }}
                            />
                            <button 
                              className="absolute right-3 top-1/2 -translate-y-1/2 text-pastel-purple/50 hover:text-pastel-purple transition-colors"
                              onClick={(e) => {
                                const input = e.currentTarget.previousSibling as HTMLInputElement;
                                addComment(t.id, input.value);
