           {localExpenses.map(ex => (
             <div key={ex.id} className="bg-white p-6 rounded-3xl soft-shadow border border-pastel-lavender/10 flex flex-wrap md:flex-nowrap items-center gap-6 animate-in slide-in-from-left-2">
