import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, Category, FinancialAdvice } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Analyze receipt image using the recommended gemini-3-flash-preview model.
export const analyzeReceiptImage = async (base64Image: string): Promise<{ amount: number; description: string; date: string; categoryGuess: string }> => {
  try {
    const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: cleanBase64,
            },
          },
          {
            text: "Analyze this receipt image. Extract the total amount, the date (ISO format YYYY-MM-DD), a short description (merchant name), and guess a generic category (e.g., Food, Transport, Shopping).",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            description: { type: Type.STRING },
            categoryGuess: { type: Type.STRING },
          },
          required: ["amount", "date", "description", "categoryGuess"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Receipt analysis failed:", error);
    throw error;
  }
};

// Generate smart financial report based on current month's transactions.
export const generateFinancialReport = async (
  transactions: Transaction[], 
  categories: Category[],
  month: string
): Promise<FinancialAdvice> => {
  try {
    const serializedTransactions = transactions.map(t => ({
      amount: t.amount,
      category: categories.find(c => c.id === t.categoryId)?.name || 'Unknown',
      date: t.date,
      desc: t.description
    }));

    const prompt = `
      Current Month: ${month}
      Total Transactions: ${serializedTransactions.length}
      Transaction History: ${JSON.stringify(serializedTransactions)}

      Please analyze these spending habits and provide:
      1. A short, friendly summary of the spending behavior.
      2. Constructive financial advice to save money or balance the budget.
      3. A prediction of the total end-of-month spending based on the current pace.
      Respond in Korean.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Friendly summary in Korean" },
            advice: { type: Type.STRING, description: "Personalized advice in Korean" },
            prediction: { type: Type.STRING, description: "Spending prediction for end of month in Korean" },
          },
          required: ["summary", "advice", "prediction"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI for report");

    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Financial report generation failed:", error);
    throw error;
  }
};

// Suggest a budget limit for a specific category based on spending history
export const suggestCategoryBudget = async (
  categoryName: string,
  transactions: Transaction[]
): Promise<{ recommendedLimit: number; reasoning: string }> => {
  try {
    const spendingSummary = transactions
      .filter(t => t.type === 'EXPENSE')
      .map(t => ({ amount: t.amount, desc: t.description, date: t.date }));

    const prompt = `
      Category: ${categoryName}
      Recent Spending History: ${JSON.stringify(spendingSummary)}

      Based on this spending history for the category "${categoryName}", suggest a realistic monthly budget limit. 
      Consider the average spending and provide a reasoning. 
      Respond in Korean.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recommendedLimit: { type: Type.NUMBER, description: "The recommended monthly limit amount" },
            reasoning: { type: Type.STRING, description: "Why this limit is recommended" },
          },
          required: ["recommendedLimit", "reasoning"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI for budget suggestion");

    return JSON.parse(text.trim());
  } catch (error) {
    console.error("Budget suggestion failed:", error);
    throw error;
  }
};

