const GrapeBunchLayout: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  const rows = target === 33 ? [3, 5, 6, 5, 4, 3, 3, 2, 1, 1] : [3, 4, 3, 2, 1, 2];
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-2 py-8 mx-auto animate-in fade-in zoom-in duration-1000">
      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-2 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            if (num > target) return null;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

