      text: text.trim(),
      date: new Date().toISOString(),
    };
    setTransactions(prev => prev.map(t => t.id === txId ? { ...t, comments: [...(t.comments || []), newComment] } : t));
  };

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate]);

  const stats = useMemo(() => {
    const income = monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [monthlyTransactions]);

  const budgetStatuses = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
      const catTransactions = monthlyTransactions.filter(t => t.categoryId === cat.id);
      const spent = catTransactions.reduce((sum, t) => sum + t.amount, 0);
      const limit = cat.budgetLimit || 1; 
      const percentage = (spent / limit) * 100;

      const individualStatus: Record<string, { spent: number; limit: number; percentage: number }> = {};
      users.forEach(u => {
        const uSpent = catTransactions.filter(t => t.userId === u.id).reduce((sum, t) => sum + t.amount, 0);
        const uLimit = cat.individualLimits?.[u.id] || 0;
        individualStatus[u.id] = {
          spent: uSpent,
          limit: uLimit,
          percentage: uLimit > 0 ? (uSpent / uLimit) * 100 : 0
        };
      });

      let status: BudgetStatus['status'] = 'SAFE';
      if (percentage >= 100) status = 'EXCEEDED';
      else if (percentage >= 85) status = 'DANGER';
      else if (percentage >= 60) status = 'WARNING';

      return {
        categoryId: cat.id,
        spent,
        limit,
        percentage,
        status,
        individualStatus
      } as BudgetStatus;
    });
  }, [categories, monthlyTransactions, users]);

  const transactionsByDate = useMemo(() => {
    const groups: Record<string, Transaction[]> = {};
    const filtered = selectedHistoryDate 
      ? monthlyTransactions.filter(t => t.date === selectedHistoryDate)
      : monthlyTransactions;

    filtered.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions, selectedHistoryDate]);

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const completed = nextCount >= g.targetCount;
      if (completed) setSuccessGoal(g);
      return { ...g, currentCount: nextCount, isCompleted: completed };
    }));
    setToast({ message: '포근한 마음을 담아 스티커를 붙였어요 ✨', type: 'success' });
  };

  const createGoal = () => {
    if (!newGoalTitle) return;
    const goal: StickerGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: newGoalTitle,
      targetCount: newGoalTarget,
      currentCount: 0,
      assignedToUserId: newGoalAssignee,
      createdByUserId: currentUser.id,
      isCompleted: false
    };
    setStickerGoals(prev => [goal, ...prev]);
    setIsNewGoalOpen(false);
    setNewGoalTitle('');
    setToast({ message: '설레는 마음으로 새 보드를 만들었어요!', type: 'info' });
  };

  const handleCalendarDateClick = (date: string) => {
    setSelectedHistoryDate(date);
    setActiveTab('HISTORY');
    setHistoryViewMode('LIST');
  };

  const handleHistoryCalendarDateClick = (date: string) => {
    setSelectedHistoryDate(selectedHistoryDate === date ? null : date);
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

