interface FixedExpenseManagerProps {
  fixedExpenses: FixedExpense[];
  categories: Category[];
  users: User[];
  onClose: () => void;
  onSave: (expenses: FixedExpense[]) => void;
}

const FixedExpenseManager: React.FC<FixedExpenseManagerProps> = ({ fixedExpenses, categories, users, onClose, onSave }) => {
  const [localExpenses, setLocalExpenses] = useState<FixedExpense[]>(fixedExpenses);

  const addFixedExpense = () => {
    const newEx: FixedExpense = {
      id: Math.random().toString(36).substr(2, 9),
      description: '새 고정 지출',
      amount: 0,
      categoryId: categories[0]?.id || '',
      userId: users[0]?.id || '',
      dayOfMonth: 1
    };
    setLocalExpenses([...localExpenses, newEx]);
  };

  const removeFixedExpense = (id: string) => {
    setLocalExpenses(localExpenses.filter(e => e.id !== id));
  };

  const updateField = (id: string, field: keyof FixedExpense, value: any) => {
    setLocalExpenses(localExpenses.map(e => e.id === id ? { ...e, [field]: value } : e));
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-4xl shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center">
          <div>
            <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">자동 고정 지출 관리</h2>
            <p className="text-[10px] text-zinc-400 mt-1">월세, 구독료 등 매달 반복되는 비용을 설정하세요.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        <div className="overflow-y-auto p-10 flex-1 space-y-6 custom-scrollbar bg-pastel-sand/5">
           {localExpenses.map(ex => (
             <div key={ex.id} className="bg-white p-6 rounded-3xl soft-shadow border border-pastel-lavender/10 flex flex-wrap md:flex-nowrap items-center gap-6 animate-in slide-in-from-left-2">
                <div className="flex-1 min-w-[150px]">
                  <label className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">지출 명칭</label>
                  <input 
                    type="text" 
                    value={ex.description} 
                    onChange={(e) => updateField(ex.id, 'description', e.target.value)}
                    className="w-full text-xs font-bold" 
                  />
                </div>
                <div className="w-32">
                  <label className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">결제일</label>
                  <select 
                    value={ex.dayOfMonth} 
                    onChange={(e) => updateField(ex.id, 'dayOfMonth', parseInt(e.target.value))}
                    className="w-full text-xs font-bold"
                  >
                    {Array.from({length: 31}, (_, i) => i + 1).map(d => <option key={d} value={d}>매달 {d}일</option>)}
                  </select>
                </div>
                <div className="w-40">
                  <label className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">금액</label>
                  <input 
                    type="number" 
                    value={ex.amount} 
                    onChange={(e) => updateField(ex.id, 'amount', parseFloat(e.target.value))}
                    className="w-full text-xs font-bold tabular-nums" 
                  />
                </div>
                <div className="w-40">
                  <label className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">담당자</label>
                  <select 
                    value={ex.userId} 
                    onChange={(e) => updateField(ex.id, 'userId', e.target.value)}
                    className="w-full text-xs font-bold"
                  >
                    {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
                </div>
                <button onClick={() => removeFixedExpense(ex.id)} className="p-2 text-rose-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all">
                   <Trash2 size={20} />
                </button>
             </div>
           ))}

           {localExpenses.length === 0 && (
             <div className="py-20 text-center opacity-30">
               <Repeat size={48} className="mx-auto mb-4" />
