             onClick={addFixedExpense}
             className="w-full py-4 border-2 border-dashed border-pastel-lavender/40 rounded-3xl text-[10px] font-bold text-zinc-400 uppercase tracking-widest hover:bg-pastel-lavender/10 transition-all flex items-center justify-center gap-2"
           >
             <Plus size={16} /> 항목 추가하기
           </button>
        </div>

        <div className="p-10 bg-white border-t border-pastel-sand">
          <button 
            onClick={() => { onSave(localExpenses); onClose(); }} 
            className="w-full bg-pastel-purple text-white py-5 rounded-3xl font-bold uppercase tracking-[0.2em] shadow-lg hover:brightness-95 transition-all"
          >
            변경사항 저장하기
