      ))}
    </div>
  );
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: '장보기', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 500000, color: '#F9E2E6', iconId: 'shopping' },
  { id: 'c2', name: '외식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 300000, color: '#F7D1BA', iconId: 'food' },
  { id: 'c3', name: '카페/간식', group: '식비', type: TransactionType.EXPENSE, budgetLimit: 150000, color: '#FAF3DD', iconId: 'cafe' },
  { id: 'c4', name: '생활', group: '주거', type: TransactionType.EXPENSE, budgetLimit: 600000, color: '#D1E8E2', iconId: 'home' },
  { id: 'c7', name: '이동', group: '교통', type: TransactionType.EXPENSE, budgetLimit: 120000, color: '#E8E4F8', iconId: 'transport' },
  { id: 'i1', name: '월급', group: '수입', type: TransactionType.INCOME, budgetLimit: 0, color: '#E2F0EB', iconId: 'salary' },
];

const MOCK_USERS: User[] = [
  { id: 'u1', name: '내 사랑', avatar: '♥', color: '#D4C6F0' },
  { id: 'u2', name: '자기야', avatar: '☁', color: '#F9E2E6' },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'HISTORY' | 'BUDGET' | 'PRAISE' | 'DIARY'>('DASHBOARD');
  const [historyViewMode, setHistoryViewMode] = useState<'LIST' | 'CALENDAR'>('LIST');
  const [selectedHistoryDate, setSelectedHistoryDate] = useState<string | null>(null);

  const [users] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: TransactionType.INCOME, amount: 4500000, categoryId: 'i1', userId: 'u1', date: new Date().toISOString().split('T')[0], description: '이번 달 고생했어 월급!', likes: [], dislikes: [], comments: [] },
  ]);
  const [diaries, setDiaries] = useState<DiaryEntry[]>([
    { id: 'd1', date: new Date().toISOString().split('T')[0], userId: 'u1', text: '오늘은 맛있는 걸 먹으러 가고 싶어요!', reactions: [] }
  ]);
  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>([
    { id: 'fe1', description: '월세', amount: 550000, categoryId: 'c4', userId: 'u1', dayOfMonth: 25 },
    { id: 'fe2', description: '넷플릭스', amount: 17000, categoryId: 'c4', userId: 'u2', dayOfMonth: 10 }
  ]);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '설거지 요정 미션', targetCount: 33, currentCount: 18, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '배달 음식 참기', targetCount: 15, currentCount: 15, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isBudgetModalOpen, setIsBudgetModalOpen] = useState(false);
  const [isFixedExpenseOpen, setIsFixedExpenseOpen] = useState(false);
  const [isDiaryModalOpen, setIsDiaryModalOpen] = useState(false);
  const [selectedDiaryDate, setSelectedDiaryDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [diaryInput, setDiaryInput] = useState('');

  const [viewMode, setViewMode] = useState<'JOINT' | 'INDIVIDUAL'>('JOINT');
  const [historyDate, setHistoryDate] = useState(new Date());
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [successGoal, setSuccessGoal] = useState<StickerGoal | null>(null);
  const [financialAdvice, setFinancialAdvice] = useState<FinancialAdvice | null>(null);
  const [isAnalyzingAdvice, setIsAnalyzingAdvice] = useState(false);

  // --- 자동 고정 지출 처리 ---
  useEffect(() => {
    const currentYearMonth = `${historyDate.getFullYear()}-${String(historyDate.getMonth() + 1).padStart(2, '0')}`;
    const missingExpenses = fixedExpenses.filter(fe => fe.lastProcessedMonth !== currentYearMonth);

    if (missingExpenses.length > 0) {
      const newTransactions: Transaction[] = missingExpenses.map(fe => ({
        id: `t_fe_${fe.id}_${currentYearMonth}`,
        type: TransactionType.EXPENSE,
        amount: fe.amount,
        categoryId: fe.categoryId,
        userId: fe.userId,
        date: `${currentYearMonth}-${String(fe.dayOfMonth).padStart(2, '0')}`,
        description: `[고정] ${fe.description}`,
        likes: [], dislikes: [], comments: []
      }));

      setTransactions(prev => {
        const filteredNew = newTransactions.filter(nt => !prev.some(pt => pt.id === nt.id));
        return [...filteredNew, ...prev];
      });

      setFixedExpenses(prev => prev.map(fe => ({ ...fe, lastProcessedMonth: currentYearMonth })));
      if (newTransactions.length > 0) {
        setToast({ message: `${newTransactions.length}건의 고정 지출이 자동 등록되었습니다.`, type: 'info' });
      }
    }
  }, [historyDate, fixedExpenses]);

  // --- AI 리포트 생성 ---
  const handleGenerateAdvice = async () => {
    setIsAnalyzingAdvice(true);
    try {
      const monthStr = `${historyDate.getFullYear()}년 ${historyDate.getMonth() + 1}월`;
      const result = await generateFinancialReport(monthlyTransactions, categories, monthStr);
      setFinancialAdvice(result);
      setToast({ message: 'Gemini가 스마트 리포트를 준비했습니다!', type: 'success' });
    } catch (err) {
      setToast({ message: '리포트 생성에 실패했습니다.', type: 'error' });
    } finally {
      setIsAnalyzingAdvice(false);
    }
  };

  const toggleLike = (txId: string) => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== txId) return t;
      const likes = t.likes || [];
      const newLikes = likes.includes(currentUser.id) 
        ? likes.filter(id => id !== currentUser.id)
        : [...likes, currentUser.id];
      return { ...t, likes: newLikes, dislikes: (t.dislikes || []).filter(id => id !== currentUser.id) };
    }));
  };

  const toggleDislike = (txId: string) => {
    setTransactions(prev => prev.map(t => {
      if (t.id !== txId) return t;
      const dislikes = t.dislikes || [];
      const newDislikes = dislikes.includes(currentUser.id) 
        ? dislikes.filter(id => id !== currentUser.id)
        : [...dislikes, currentUser.id];
      return { ...t, dislikes: newDislikes, likes: (t.likes || []).filter(id => id !== currentUser.id) };
    }));
  };

  const addComment = (txId: string, text: string) => {
    if (!text.trim()) return;
    const newComment: Comment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      text: text.trim(),
      date: new Date().toISOString(),
    };
    setTransactions(prev => prev.map(t => t.id === txId ? { ...t, comments: [...(t.comments || []), newComment] } : t));
  };

  const monthlyTransactions = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    return transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, historyDate]);

  const stats = useMemo(() => {
    const income = monthlyTransactions.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = monthlyTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [monthlyTransactions]);

  const budgetStatuses = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
      const catTransactions = monthlyTransactions.filter(t => t.categoryId === cat.id);
      const spent = catTransactions.reduce((sum, t) => sum + t.amount, 0);
      const limit = cat.budgetLimit || 1; 
      const percentage = (spent / limit) * 100;

      const individualStatus: Record<string, { spent: number; limit: number; percentage: number }> = {};
      users.forEach(u => {
        const uSpent = catTransactions.filter(t => t.userId === u.id).reduce((sum, t) => sum + t.amount, 0);
        const uLimit = cat.individualLimits?.[u.id] || 0;
        individualStatus[u.id] = {
          spent: uSpent,
          limit: uLimit,
          percentage: uLimit > 0 ? (uSpent / uLimit) * 100 : 0
        };
      });

      let status: BudgetStatus['status'] = 'SAFE';
      if (percentage >= 100) status = 'EXCEEDED';
      else if (percentage >= 85) status = 'DANGER';
      else if (percentage >= 60) status = 'WARNING';

      return {
        categoryId: cat.id,
        spent,
        limit,
        percentage,
        status,
        individualStatus
      } as BudgetStatus;
    });
  }, [categories, monthlyTransactions, users]);

  const transactionsByDate = useMemo(() => {
    const groups: Record<string, Transaction[]> = {};
    const filtered = selectedHistoryDate 
      ? monthlyTransactions.filter(t => t.date === selectedHistoryDate)
      : monthlyTransactions;

    filtered.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return groups;
  }, [monthlyTransactions, selectedHistoryDate]);

  const handleAddSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const nextCount = g.currentCount + 1;
      const completed = nextCount >= g.targetCount;
      if (completed) setSuccessGoal(g);
      return { ...g, currentCount: nextCount, isCompleted: completed };
    }));
    setToast({ message: '포도알 스티커를 하나 붙였어요! 🍇', type: 'success' });
  };

  const handleCalendarDateClick = (date: string) => {
    setSelectedHistoryDate(date);
    setActiveTab('HISTORY');
    setHistoryViewMode('LIST');
  };

  const handleDiaryCalendarClick = (date: string) => {
    setSelectedDiaryDate(date);
    setIsDiaryModalOpen(true);
  };

  const handleSaveDiary = () => {
    if (!diaryInput.trim()) return;
    const newEntry: DiaryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      date: selectedDiaryDate,
      userId: currentUser.id,
      text: diaryInput.trim(),
      reactions: []
    };
    setDiaries(prev => [newEntry, ...prev]);
    setDiaryInput('');
    setIsDiaryModalOpen(false);
    setToast({ message: '오늘의 마음을 기록했어요 ✍️', type: 'success' });
  };

  const handleDiaryReaction = (diaryId: string) => {
    setDiaries(prev => prev.map(d => {
      if (d.id !== diaryId) return d;
      const reactions = d.reactions || [];
      const newReactions = reactions.includes(currentUser.id)
        ? reactions.filter(id => id !== currentUser.id)
        : [...reactions, currentUser.id];
      return { ...d, reactions: newReactions };
    }));
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {successGoal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-500">
           <div className="bg-white rounded-5xl p-12 max-w-md w-full text-center shadow-2xl border border-pastel-lavender/50">
              <PartyPopper size={64} className="mx-auto mb-6 text-pastel-purple animate-bounce" />
              <h2 className="text-3xl font-bold mb-3 tracking-tight">미션 성공!</h2>
              <p className="text-zinc-500 mb-10 leading-relaxed">
                "{successGoal.title}" 보드를<br/>포도송이처럼 알알이 가득 채우셨네요. 축하해요!
              </p>
              <button 
                onClick={() => setSuccessGoal(null)}
                className="w-full bg-pastel-purple text-white py-4 rounded-3xl font-bold hover:brightness-95 transition-all shadow-lg"
              >
                닫기
              </button>
           </div>
        </div>
      )}

      {/* 헤더 필터 영역 */}
      <div className="mb-10 flex flex-col md:flex-row gap-6 items-center justify-between">
        <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow">
          <button onClick={() => setViewMode('JOINT')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'JOINT' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>우리 함께</button>
          <button onClick={() => setViewMode('INDIVIDUAL')} className={`px-8 py-2.5 rounded-2xl text-xs font-semibold transition-all ${viewMode === 'INDIVIDUAL' ? 'bg-white text-pastel-text shadow-sm' : 'text-zinc-400'}`}>나의 기록</button>
        </div>
        <div className="flex items-center gap-4 bg-white px-5 py-2.5 rounded-3xl soft-shadow border border-pastel-lavender/30">
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() - 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronLeft size={20} /></button>
          <span className="text-sm font-bold tabular-nums min-w-[100px] text-center">{historyDate.getFullYear()}. {historyDate.getMonth() + 1}</span>
          <button onClick={() => { setHistoryDate(new Date(historyDate.getFullYear(), historyDate.getMonth() + 1, 1)); setSelectedHistoryDate(null); }} className="text-zinc-400 hover:text-pastel-text"><ChevronRight size={20} /></button>
        </div>
      </div>

      {activeTab === 'DASHBOARD' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-gradient-to-br from-pastel-lavender to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">우리 자산</span>
              <div className="text-4xl font-bold tracking-tighter tabular-nums">{stats.balance.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-mint to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">반가운 수입</span>
              <div className="text-4xl font-bold tracking-tighter text-emerald-600/70 tabular-nums">+{stats.income.toLocaleString()}</div>
            </div>
            <div className="bg-gradient-to-br from-pastel-rose to-white p-10 rounded-[2.5rem] soft-shadow">
              <span className="text-[11px] font-bold text-pastel-text/50 uppercase tracking-widest block mb-4">필요한 지출</span>
              <div className="text-4xl font-bold tracking-tighter text-rose-600/60 tabular-nums">-{stats.expense.toLocaleString()}</div>
            </div>
          </div>

          <section className="bg-white rounded-[2.5rem] p-10 soft-shadow border border-pastel-lavender/30 overflow-hidden relative">
            <div className="absolute top-0 right-0 p-8 opacity-10 text-pastel-purple">
              <BrainCircuit size={120} />
            </div>

            <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10 relative z-10">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-pastel-purple/20 rounded-2xl flex items-center justify-center text-pastel-purple">
                  <Sparkles size={28} />
                </div>
                <div>
                  <h3 className="text-2xl font-bold text-pastel-text">Gemini AI 스마트 리포트</h3>
                  <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mt-1">우리 가족의 지출 습관을 Gemini가 분석합니다.</p>
                </div>
              </div>
              <button 
                onClick={handleGenerateAdvice}
                disabled={isAnalyzingAdvice}
                className={`bg-pastel-purple text-white px-8 py-4 rounded-2xl text-[11px] font-bold uppercase tracking-widest shadow-lg transition-all flex items-center gap-3
                  ${isAnalyzingAdvice ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
              >
                {isAnalyzingAdvice ? <RefreshCw size={16} className="animate-spin" /> : <Sparkles size={16} />}
                {isAnalyzingAdvice ? '분석 중...' : '리포트 생성'}
              </button>
            </div>

            {financialAdvice ? (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-in fade-in slide-in-from-bottom-4 relative z-10">
                <div className="space-y-3">
                  <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest border-b border-pastel-sand pb-2 block">소비 요약</span>
                  <p className="text-sm font-medium leading-relaxed text-pastel-text/80">{financialAdvice.summary}</p>
                </div>
                <div className="space-y-3">
                  <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest border-b border-pastel-sand pb-2 block">AI 조언</span>
                  <p className="text-sm font-medium leading-relaxed text-pastel-text/80">{financialAdvice.advice}</p>
                </div>
                <div className="space-y-3">
                  <span className="text-[10px] font-bold text-rose-300 uppercase tracking-widest border-b border-pastel-sand pb-2 block">월말 예측</span>
                  <p className="text-sm font-medium leading-relaxed text-pastel-text/80">{financialAdvice.prediction}</p>
                </div>
              </div>
            ) : (
              <div className="py-12 text-center bg-pastel-sand/10 rounded-3xl border border-dashed border-pastel-lavender/30">
                <p className="text-xs font-bold text-zinc-300 uppercase tracking-widest">분석된 결과가 없습니다. '리포트 생성' 버튼을 눌러주세요.</p>
              </div>
            )}
          </section>

          <section className="space-y-6">
            <div className="flex items-center justify-between px-2">
               <h3 className="text-xl font-bold flex items-center gap-3">
                 <div className="p-2.5 bg-pastel-purple text-white rounded-xl shadow-sm"><Activity size={18} /></div>
                 월간 소비 흐름
               </h3>
               <div className="flex gap-4 items-center">
                  <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full bg-emerald-300" />
                    <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">수입</span>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <div className="w-2 h-2 rounded-full bg-rose-300" />
                    <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">지출</span>
                  </div>
               </div>
            </div>
            <CalendarView 
              currentDate={historyDate} 
              transactions={monthlyTransactions} 
              diaries={diaries}
              onDateClick={handleCalendarDateClick} 
            />
          </section>
        </div>
      )}

      {activeTab === 'HISTORY' && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-700">
          <div className="flex justify-between items-center bg-white/40 backdrop-blur-md p-2 rounded-3xl border border-white/50 soft-shadow">
            <div className="flex gap-2">
              <button onClick={() => setHistoryViewMode('LIST')} className={`p-3 rounded-2xl transition-all ${historyViewMode === 'LIST' ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300'}`}><List size={20} /></button>
              <button onClick={() => setHistoryViewMode('CALENDAR')} className={`p-3 rounded-2xl transition-all ${historyViewMode === 'CALENDAR' ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-300'}`}><CalendarIcon size={20} /></button>
            </div>
          </div>

          {historyViewMode === 'CALENDAR' && (
            <CalendarView currentDate={historyDate} transactions={monthlyTransactions} diaries={diaries} onDateClick={handleHistoryCalendarDateClick} />
          )}

          <div className="space-y-16">
            {(Object.entries(transactionsByDate) as [string, Transaction[]][]).map(([date, items]) => (
              <div key={date} className="flex flex-col lg:flex-row gap-8">
                <div className="lg:w-28 shrink-0 flex flex-col pt-2">
                  <span className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest mb-1">{new Date(date).toLocaleString('ko-KR', { weekday: 'short' })}</span>
                  <span className="text-3xl font-bold tabular-nums text-pastel-text/40 tracking-tighter">{date.split('-')[2]}</span>
                </div>
                <div className="flex-1 space-y-6">
                  {items.map(t => {
                    const cat = categories.find(c => c.id === t.categoryId);
                    const user = users.find(u => u.id === t.userId);
                    const isLiked = (t.likes || []).includes(currentUser.id);
                    const isDisliked = (t.dislikes || []).includes(currentUser.id);
                    return (
                      <div key={t.id} className="bg-white rounded-3xl soft-shadow border border-pastel-lavender/20 flex flex-col overflow-hidden transition-all hover:scale-[1.01]">
                        <div className="p-6 flex items-center justify-between">
                          <div className="flex items-center gap-6">
                            <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 22)}</div>
                            <div>
                              <div className="flex items-center gap-3 mb-1">
                                <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{cat?.name}</span>
                                <span className="text-[9px] font-bold text-zinc-400 bg-pastel-sand px-2 py-0.5 rounded-full">{user?.name}</span>
                                {t.description.startsWith('[고정]') && <span className="text-[8px] font-bold text-white bg-pastel-purple px-2 py-0.5 rounded-full flex items-center gap-1"><Repeat size={8} /> 고정</span>}
                              </div>
                              <p className="text-sm font-medium text-pastel-text/90">{t.description}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <span className={`text-xl font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500/80' : 'text-pastel-text'}`}>
                              {t.type === TransactionType.INCOME ? '+' : ''} {t.amount.toLocaleString()}
                            </span>
                          </div>
                        </div>
                        <div className="px-6 py-3 bg-pastel-sand/10 border-t border-pastel-sand/30 flex items-center justify-between">
                          <div className="flex items-center gap-4">
