const GrapeGrain: React.FC<{ filled: boolean; color?: string; index: number; number: number }> = ({ filled, color = '#D4C6F0', index, number }) => (
  <div 
    className={`relative w-11 h-11 rounded-full transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] flex items-center justify-center text-[10px] font-bold
      ${filled ? 'scale-105 shadow-lg z-10' : 'scale-100 bg-white/40 border border-white/60 text-zinc-300'}`}
    style={{ 
      backgroundColor: filled ? color : 'rgba(255,255,255,0.4)',
      color: filled ? 'white' : '#A1A1AA',
      boxShadow: filled ? `0 8px 16px -4px ${color}66` : 'none',
      transitionDelay: `${(index % 12) * 40}ms`
    }}
  >
    {number}
    {filled && (
      <div className="absolute inset-0 grape-shine rounded-full" />
    )}
  </div>
);

const GrapeBunchLayout: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  const rows = target === 33 ? [7, 6, 5, 4, 3, 3, 2, 2, 1] : [5, 4, 3, 2, 1];
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-1.5 py-10 mx-auto animate-in fade-in zoom-in duration-1000">
      <div className="w-1.5 h-8 bg-emerald-800/20 rounded-t-full -mb-2 z-0" />

      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-1.5 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            if (num > target) return null;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

