const GrapeBunchLayout: React.FC<{ count: number; target: number; color?: string }> = ({ count, target, color }) => {
  const rows = target === 33 ? [7, 6, 5, 4, 3, 3, 2, 2, 1] : [5, 4, 3, 2, 1];
  let globalIndex = 0;

  return (
    <div className="flex flex-col items-center gap-1.5 py-10 mx-auto animate-in fade-in zoom-in duration-1000">
      <div className="w-1.5 h-8 bg-emerald-800/20 rounded-t-full -mb-2 z-0" />

      {rows.map((rowSize, rowIndex) => (
        <div key={rowIndex} className="flex gap-1.5 justify-center">
          {Array.from({ length: rowSize }).map((_, i) => {
            const num = ++globalIndex;
            if (num > target) return null;
            return (
              <GrapeGrain 
                key={num} 
                number={num} 
                index={num} 
                filled={num <= count} 
                color={color} 
              />
            );
          })}
        </div>
      ))}
    </div>
  );
};

