    { id: 's2', text: '두루마리 휴지', isBought: true, addedByUserId: 'u2' }
  ]);
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([
    { id: 'sub1', name: '넷플릭스', amount: 17000, billingDate: 14, userId: 'u1', isShared: true, iconId: 'netflix' },
    { id: 'sub2', name: '유튜브 프리미엄', amount: 14900, billingDate: 25, userId: 'u2', isShared: true, iconId: 'youtube' }
  ]);
  const [chores, setChores] = useState<Chore[]>([
    { id: 'ch1', title: '분리수거 하기', assignedToUserId: 'u1', isCompleted: false, frequency: 'WEEKLY', points: 10 },
    { id: 'ch2', title: '거실 청소기 돌리기', assignedToUserId: 'u2', isCompleted: false, frequency: 'DAILY', points: 5 }
  ]);
  const [bucketGoals, setBucketGoals] = useState<BucketGoal[]>([
    { id: 'bg1', title: '내년 유럽 여행 가기', targetAmount: 5000000, currentAmount: 1200000, isCompleted: false },
    { id: 'bg2', title: '1주년 기념 파인다이닝', targetAmount: 400000, currentAmount: 400000, isCompleted: true }
  ]);

  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [historyDate, setHistoryDate] = useState(new Date());
  const [selectedSummaryCategory, setSelectedSummaryCategory] = useState<Category | null>(null);

  // Home Summary Calculations
  const monthlyStats = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filtered = transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
    const income = filtered.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = filtered.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions, historyDate]);

  const budgetStatuses = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
      const catTransactions = transactions.filter(t => t.categoryId === cat.id);
      const spent = catTransactions.reduce((sum, t) => sum + t.amount, 0);
      const limit = cat.budgetLimit || 1;
      const percentage = (spent / limit) * 100;
      return { categoryId: cat.id, spent, limit, percentage };
    });
  }, [categories, transactions]);

  // Handlers
  const addShoppingItem = (text: string) => {
    if (!text.trim()) return;
    setShoppingItems([...shoppingItems, { id: Date.now().toString(), text, isBought: false, addedByUserId: currentUser.id }]);
    setToast({ message: '장바구니에 추가되었습니다!', type: 'success' });
  };

  const toggleChore = (id: string) => {
    setChores(chores.map(c => c.id === id ? { ...c, isCompleted: !c.isCompleted } : c));
    setToast({ message: '고생하셨어요! 👏', type: 'success' });
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* DASHBOARD (HOME) */}
      {activeTab === 'HOME' && (
        <div className="space-y-12 animate-in fade-in duration-700">
          <div className="flex flex-col md:flex-row gap-6">
             <div className="flex-1 bg-gradient-to-br from-pastel-purple/20 to-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/30">
                <span className="text-[10px] font-bold text-pastel-purple uppercase tracking-widest block mb-2">Hello, {currentUser.name}!</span>
                <h2 className="text-3xl font-bold tracking-tighter">함께 만드는 행복한 일상</h2>
                <div className="mt-8 grid grid-cols-2 gap-4">
                   <div className="bg-white/60 p-5 rounded-2xl">
                      <span className="text-[9px] font-bold text-zinc-400 block mb-1">이번 달 지출</span>
                      <p className="text-xl font-bold tracking-tighter tabular-nums">{monthlyStats.expense.toLocaleString()}원</p>
                   </div>
                   <div className="bg-white/60 p-5 rounded-2xl">
                      <span className="text-[9px] font-bold text-zinc-400 block mb-1">모은 꿈</span>
                      <p className="text-xl font-bold tracking-tighter tabular-nums">{bucketGoals.filter(b => !b.isCompleted).length}개</p>
                   </div>
                </div>
             </div>
             <div className="md:w-1/3 bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/30 flex flex-col justify-between">
                <div>
                   <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest block mb-4">오늘의 할 일</span>
                   <div className="space-y-3">
                      {chores.filter(c => !c.isCompleted).slice(0, 2).map(c => (
                        <div key={c.id} className="flex items-center gap-3">
                           <div className="w-1.5 h-1.5 rounded-full bg-pastel-purple" />
                           <span className="text-xs font-semibold">{c.title}</span>
                        </div>
                      ))}
                   </div>
                </div>
                <button onClick={() => setActiveTab('HARMONY')} className="text-[10px] font-bold text-pastel-purple uppercase tracking-widest mt-6 hover:underline">모두 보기 →</button>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <section className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20">
                <div className="flex items-center justify-between mb-6">
                   <h3 className="text-sm font-bold flex items-center gap-2"><ShoppingBag size={16} /> 장바구니</h3>
                   <span className="text-[9px] font-bold text-zinc-300">{shoppingItems.filter(i => !i.isBought).length} 남음</span>
                </div>
                <div className="space-y-4">
                   {shoppingItems.filter(i => !i.isBought).slice(0, 3).map(i => (
                     <div key={i.id} className="flex items-center gap-3 text-xs font-medium bg-pastel-sand/30 p-3 rounded-xl">{i.text}</div>
                   ))}
                </div>
             </section>
             <section className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20">
                <div className="flex items-center justify-between mb-6">
                   <h3 className="text-sm font-bold flex items-center gap-2"><CreditCard size={16} /> 구독 서비스</h3>
                   <span className="text-[9px] font-bold text-zinc-300">{subscriptions.length}개</span>
                </div>
                <div className="space-y-4">
                   {subscriptions.map(s => (
                     <div key={s.id} className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                           <div className="w-8 h-8 bg-pastel-sand rounded-xl flex items-center justify-center text-pastel-purple">
                              {renderCategoryIcon(s.iconId, 16)}
                           </div>
                           <span className="text-xs font-semibold">{s.name}</span>
                        </div>
                        <span className="text-[10px] font-bold text-zinc-400">{s.billingDate}일</span>
                     </div>
                   ))}
                </div>
             </section>
             <section className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20">
                <div className="flex items-center justify-between mb-6">
                   <h3 className="text-sm font-bold flex items-center gap-2"><Target size={16} /> 버킷리스트</h3>
                </div>
                {bucketGoals.filter(b => !b.isCompleted).slice(0, 1).map(b => (
                  <div key={b.id} className="space-y-3">
                     <p className="text-xs font-bold">{b.title}</p>
                     <div className="h-2 w-full bg-pastel-sand rounded-full overflow-hidden">
                        <div className="h-full bg-pastel-purple rounded-full" style={{ width: `${(b.currentAmount / b.targetAmount) * 100}%` }} />
                     </div>
                     <p className="text-[9px] font-bold text-zinc-300 text-right">₩{b.currentAmount.toLocaleString()} / ₩{b.targetAmount.toLocaleString()}</p>
                  </div>
                ))}
             </section>
          </div>
        </div>
      )}

      {/* WALLET (Finances) */}
      {activeTab === 'WALLET' && (
        <div className="space-y-10 animate-in fade-in duration-700">
           <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow w-fit">
              {[
                { id: 'SUMMARY', label: '요약' },
                { id: 'LIST', label: '내역' },
                { id: 'BUDGET', label: '예산' },
                { id: 'SUBS', label: '구독' }
              ].map(t => (
                <button key={t.id} onClick={() => setWalletSubTab(t.id as any)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-bold tracking-widest uppercase transition-all ${walletSubTab === t.id ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-400'}`}>{t.label}</button>
              ))}
           </div>

           {walletSubTab === 'SUMMARY' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {/* Reusing Summary Cards Logic */}
                {categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
                   const sum = transactions.filter(t => t.categoryId === cat.id).reduce((s, t) => s + t.amount, 0);
                   return (
                     <button key={cat.id} onClick={() => setSelectedSummaryCategory(cat)} className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20 hover:scale-[1.02] transition-all text-left">
                        <div className="w-10 h-10 rounded-xl flex items-center justify-center mb-4" style={{ backgroundColor: cat.color + '40', color: cat.color }}>{renderCategoryIcon(cat.iconId, 20)}</div>
                        <h4 className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest mb-1">{cat.name}</h4>
                        <p className="text-2xl font-bold tracking-tighter">{sum.toLocaleString()}원</p>
                     </button>
                   );
                })}
             </div>
           )}

           {walletSubTab === 'BUDGET' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
               {budgetStatuses.map(status => (
                 <BudgetCard key={status.categoryId} category={categories.find(c => c.id === status.categoryId)!} status={status as any} users={users} />
               ))}
             </div>
           )}

           {walletSubTab === 'SUBS' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {subscriptions.map(s => (
                  <div key={s.id} className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20 flex flex-col items-center text-center">
                     <div className="w-16 h-16 bg-pastel-sand rounded-3xl flex items-center justify-center text-pastel-purple mb-6 shadow-inner">{renderCategoryIcon(s.iconId, 28)}</div>
                     <h4 className="text-sm font-bold text-pastel-text mb-1">{s.name}</h4>
                     <p className="text-xs font-bold text-pastel-purple mb-4">{s.amount.toLocaleString()}원 / 월</p>
                     <div className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest bg-pastel-sand px-3 py-1 rounded-full">결제일: 매달 {s.billingDate}일</div>
                  </div>
                ))}
                <button className="border-2 border-dashed border-pastel-lavender/40 rounded-[2.5rem] p-8 flex flex-col items-center justify-center text-zinc-300 hover:bg-pastel-sand/50 transition-all">
                   <Plus size={32} />
                   <span className="text-[10px] font-bold uppercase mt-4">구독 추가</span>
                </button>
             </div>
           )}
        </div>
      )}

      {/* LIFE (Shopping) */}
      {activeTab === 'LIFE' && (
        <div className="max-w-3xl mx-auto space-y-12 animate-in fade-in duration-700">
           <div className="text-center">
              <h2 className="text-3xl font-bold tracking-tighter">함께 준비하는 장바구니</h2>
              <p className="text-xs text-zinc-400 mt-2 uppercase tracking-widest">우리 집 냉장고를 스마트하게 관리하세요.</p>
           </div>

           <div className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20">
              <div className="flex gap-3 mb-10">
                 <input 
                   type="text" 
                   placeholder="사야 할 품목을 입력하세요 (예: 계란 1판)" 
                   className="flex-1 p-4 bg-pastel-sand/30 rounded-2xl outline-none"
                   onKeyDown={(e) => { if(e.key === 'Enter') { addShoppingItem(e.currentTarget.value); e.currentTarget.value = ''; } }}
                 />
                 <button className="bg-pastel-purple text-white p-4 rounded-2xl shadow-md hover:scale-105 active:scale-95 transition-all"><Plus size={24} /></button>
              </div>

              <div className="space-y-4">
                 {shoppingItems.map(item => (
                   <div key={item.id} className={`flex items-center justify-between p-5 rounded-2xl border transition-all ${item.isBought ? 'bg-pastel-sand/30 border-transparent opacity-50' : 'bg-white border-pastel-lavender/20 soft-shadow'}`}>
                      <div className="flex items-center gap-4">
                         <button 
                           onClick={() => setShoppingItems(shoppingItems.map(i => i.id === item.id ? { ...i, isBought: !i.isBought } : i))}
                           className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${item.isBought ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender'}`}
                         >
                           {item.isBought && <Check size={14} className="text-white" />}
                         </button>
                         <span className={`text-sm font-semibold ${item.isBought ? 'line-through text-zinc-400' : 'text-pastel-text'}`}>{item.text}</span>
                      </div>
                      <div className="flex items-center gap-4">
                        <span className="text-[9px] font-bold text-zinc-300 uppercase">{users.find(u => u.id === item.addedByUserId)?.name} 추가</span>
                        <button onClick={() => setShoppingItems(shoppingItems.filter(i => i.id !== item.id))} className="text-zinc-200 hover:text-rose-400 transition-colors"><Trash2 size={16} /></button>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* HARMONY (Chores, Praise, Bucket) */}
      {activeTab === 'HARMONY' && (
        <div className="space-y-12 animate-in fade-in duration-700">
           <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow w-fit">
              {[
                { id: 'CHORES', label: '가사 분담' },
                { id: 'PRAISE', label: '칭찬 보드' },
                { id: 'BUCKET', label: '꿈의 목표' }
              ].map(t => (
                <button key={t.id} onClick={() => setHarmonySubTab(t.id as any)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-bold tracking-widest uppercase transition-all ${harmonySubTab === t.id ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-400'}`}>{t.label}</button>
              ))}
           </div>

           {harmonySubTab === 'CHORES' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {chores.map(chore => {
                   const user = users.find(u => u.id === chore.assignedToUserId);
                   return (
                     <div key={chore.id} className={`bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20 flex items-center justify-between transition-all ${chore.isCompleted ? 'opacity-50' : ''}`}>
                        <div className="flex items-center gap-6">
                           <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-xs" style={{ backgroundColor: user?.color }}>{user?.avatar}</div>
                           <div>
                              <h4 className="text-base font-bold text-pastel-text mb-1">{chore.title}</h4>
                              <div className="flex items-center gap-2">
                                 <span className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest bg-pastel-sand px-2 py-0.5 rounded-full">{chore.frequency}</span>
                                 <span className="text-[9px] font-bold text-pastel-purple">+{chore.points} points</span>
                              </div>
                           </div>
                        </div>
                        <button onClick={() => toggleChore(chore.id)} className={`w-10 h-10 rounded-full border-2 flex items-center justify-center transition-all ${chore.isCompleted ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender hover:border-pastel-purple text-pastel-lavender hover:text-pastel-purple'}`}>
                           <Check size={20} className={chore.isCompleted ? 'text-white' : ''} />
                        </button>
                     </div>
                   );
                })}
             </div>
           )}

           {harmonySubTab === 'BUCKET' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {bucketGoals.map(goal => (
                  <div key={goal.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 relative overflow-hidden group">
                     {goal.isCompleted && <div className="absolute top-0 right-0 p-8 text-emerald-100"><CheckCircle2 size={120} /></div>}
                     <div className="relative z-10 space-y-8">
                        <div>
                           <h4 className="text-xl font-bold text-pastel-text mb-2">{goal.title}</h4>
                           <p className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">목표 금액: ₩{goal.targetAmount.toLocaleString()}</p>
                        </div>
                        <div className="space-y-3">
                           <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden border border-pastel-lavender/10">
                              <div className="h-full bg-pastel-purple rounded-full transition-all duration-1000" style={{ width: `${(goal.currentAmount / goal.targetAmount) * 100}%` }} />
                           </div>
                           <div className="flex justify-between items-end">
                              <span className="text-2xl font-bold tracking-tighter tabular-nums text-pastel-purple">{((goal.currentAmount / goal.targetAmount) * 100).toFixed(0)}%</span>
                              <span className="text-[11px] font-bold text-zinc-400">₩{goal.currentAmount.toLocaleString()} 모음</span>
                           </div>
                        </div>
                        <div className="flex gap-2">
                           <button className="flex-1 bg-pastel-sand text-pastel-text py-3 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-pastel-lavender/20 transition-all">금액 추가</button>
                           {goal.isCompleted && <div className="flex items-center gap-2 text-emerald-500 font-bold text-[10px] uppercase bg-emerald-50 px-4 rounded-2xl"><PartyPopper size={14} /> 완성!</div>}
                        </div>
                     </div>
                  </div>
                ))}
                <button className="border-2 border-dashed border-pastel-lavender/40 rounded-[3rem] p-10 flex flex-col items-center justify-center text-zinc-300 hover:bg-pastel-sand/50 transition-all min-h-[300px]">
                   <Target size={48} />
                   <span className="text-[10px] font-bold uppercase mt-4 tracking-widest">새로운 꿈 추가하기</span>
                </button>
             </div>
           )}
        </div>
      )}

      {/* DIARY */}
      {activeTab === 'DIARY' && (
        <div className="space-y-12 animate-in fade-in duration-700">
          {/* Reusing existing Diary Logic */}
          <div className="flex justify-between items-center">
             <h2 className="text-3xl font-bold tracking-tighter">함께하는 일기</h2>
             <button onClick={() => setIsAddModalOpen(true)} className="bg-pastel-purple text-white px-8 py-3 rounded-3xl text-xs font-bold shadow-md">일기 쓰기</button>
          </div>
          <CalendarView currentDate={historyDate} transactions={[]} diaries={diaries} users={users} hideFinancials={true} onDateClick={() => {}} />
          <div className="space-y-6">
             {diaries.map(d => (
                <div key={d.id} className="bg-white p-8 rounded-[2.5rem] soft-shadow border border-pastel-lavender/20">
                   <div className="flex items-center gap-4 mb-4">
                      <div className="w-8 h-8 rounded-full text-white flex items-center justify-center text-[10px] font-bold" style={{ backgroundColor: users.find(u => u.id === d.userId)?.color }}>{users.find(u => u.id === d.userId)?.avatar}</div>
                      <span className="text-xs font-bold">{users.find(u => u.id === d.userId)?.name}</span>
                      <span className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest ml-auto">{d.date}</span>
                   </div>
                   <p className="text-sm font-medium leading-relaxed">{d.text}</p>
                </div>
             ))}
          </div>
        </div>
      )}

      {/* DETAIL MODALS */}
      {selectedSummaryCategory && (
        <CategoryDetailModal 
          category={selectedSummaryCategory}
          transactions={transactions.filter(t => t.categoryId === selectedSummaryCategory.id)}
          users={users}
          onClose={() => setSelectedSummaryCategory(null)}
        />
      )}

      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)} 
          onSubmit={(tx) => {
            setTransactions([{ ...tx, id: Date.now().toString(), likes: [], dislikes: [], comments: [] }, ...transactions]);
            setToast({ message: '성공적으로 저장되었습니다!', type: 'success' });
          }} 
          categories={categories} 
          users={users} 
          currentUser={currentUser} 
        />
      )}
    </Layout>
  );
};

export default App;

