                             {item.isBought && <Check size={18} className="text-white" />}
                           </button>
                           <div>
                              <span className={`text-base font-bold ${item.isBought ? 'line-through text-zinc-400' : 'text-pastel-text'}`}>{item.text}</span>
                              <div className="flex items-center gap-2 mt-1">
                                 <span className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest">{users.find(u => u.id === item.addedByUserId)?.name}의 요청</span>
                              </div>
                           </div>
                        </div>
                        <button onClick={() => setShoppingItems(shoppingItems.filter(i => i.id !== item.id))} className="p-2 text-zinc-200 hover:text-rose-400 transition-colors"><Trash2 size={18} /></button>
