              {[
                { id: 'CHORES', label: '가사 분담', icon: Utensils },
                { id: 'PRAISE', label: '칭찬 보드', icon: Heart },
                { id: 'BUCKET', label: '꿈의 목표', icon: Target }
              ].map(t => (
                <button key={t.id} onClick={() => setHarmonySubTab(t.id as any)} className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-bold tracking-widest uppercase transition-all ${harmonySubTab === t.id ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-400 hover:text-zinc-500'}`}>
                  <t.icon size={14} /> {t.label}
                </button>
              ))}
           </div>

           {harmonySubTab === 'CHORES' && (
             <div className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {chores.map(chore => {
                    const user = users.find(u => u.id === chore.assignedToUserId);
                    return (
                      <div key={chore.id} className={`bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex items-center justify-between group transition-all ${chore.isCompleted ? 'opacity-50' : 'hover:border-pastel-purple/20'}`}>
                          <div className="flex items-center gap-6">
                            <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-white font-bold text-sm shadow-md" style={{ backgroundColor: user?.color }}>{user?.avatar}</div>
                            <div>
                                <h4 className="text-base font-bold text-pastel-text mb-2">{chore.title}</h4>
                                <div className="flex items-center gap-3">
                                  <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest bg-pastel-sand px-3 py-1 rounded-full">{chore.frequency}</span>
                                  <span className="text-[10px] font-bold text-pastel-purple flex items-center gap-1"><Star size={12} /> {chore.points} pt</span>
                                </div>
                            </div>
                          </div>
                          <button onClick={() => toggleChore(chore.id)} className={`w-12 h-12 rounded-full border-2 flex items-center justify-center transition-all ${chore.isCompleted ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender hover:border-pastel-purple text-pastel-lavender group-hover:text-pastel-purple'}`}>
                            <Check size={24} className={chore.isCompleted ? 'text-white' : ''} />
                          </button>
                      </div>
                    );
                  })}
                </div>
                <div className="bg-pastel-purple/10 p-10 rounded-[3rem] border border-pastel-purple/20 flex flex-col md:flex-row items-center justify-between gap-6">
                   <div className="flex items-center gap-6 text-center md:text-left">
                      <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center text-pastel-purple shadow-sm"><Trophy size={32} /></div>
                      <div>
                         <h4 className="text-lg font-bold text-pastel-text">이번 주 베스트 멤버</h4>
                         <p className="text-xs font-bold text-pastel-purple/70 uppercase tracking-widest mt-1">Reward: 주말 외식 결정권!</p>
                      </div>
                   </div>
                   <div className="flex -space-x-3">
                      {users.map(u => (
                        <div key={u.id} className="w-12 h-12 rounded-full border-4 border-white flex items-center justify-center text-white font-bold text-xs shadow-lg" style={{ backgroundColor: u.color }}>{u.avatar}</div>
                      ))}
                   </div>
                </div>
             </div>
           )}

           {harmonySubTab === 'BUCKET' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {bucketGoals.map(goal => (
                  <div key={goal.id} className="bg-white p-12 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 relative overflow-hidden group">
                     {goal.isCompleted && <div className="absolute top-0 right-0 p-10 text-emerald-100 opacity-50"><CheckCircle2 size={150} /></div>}
                     <div className="relative z-10 space-y-10">
                        <div>
                           <h4 className="text-2xl font-bold text-pastel-text mb-2">{goal.title}</h4>
                           <p className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest">목표 금액: ₩{goal.targetAmount.toLocaleString()}</p>
                        </div>
                        <div className="space-y-4">
                           <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden border border-pastel-lavender/10">
                              <div className="h-full bg-pastel-purple rounded-full transition-all duration-1000 ease-out" style={{ width: `${(goal.currentAmount / goal.targetAmount) * 100}%` }} />
                           </div>
                           <div className="flex justify-between items-end">
                              <span className="text-3xl font-bold tracking-tighter tabular-nums text-pastel-purple">{((goal.currentAmount / goal.targetAmount) * 100).toFixed(0)}%</span>
                              <span className="text-[12px] font-bold text-zinc-400 tabular-nums">₩{goal.currentAmount.toLocaleString()} 적립</span>
                           </div>
                        </div>
                        <div className="flex gap-3">
                           <button className="flex-1 bg-pastel-sand/50 text-pastel-text py-4 rounded-2xl text-[11px] font-bold uppercase tracking-widest hover:bg-pastel-lavender/20 transition-all flex items-center justify-center gap-2"><Plus size={16} /> 저축하기</button>
                           {goal.isCompleted && <div className="flex items-center gap-2 text-emerald-500 font-bold text-[11px] uppercase bg-emerald-50 px-6 rounded-2xl"><PartyPopper size={18} /> 미션 완료!</div>}
                        </div>
                     </div>
                  </div>
                ))}
                <button className="border-2 border-dashed border-pastel-lavender/40 rounded-[3.5rem] p-12 flex flex-col items-center justify-center text-zinc-300 hover:bg-pastel-sand/50 transition-all min-h-[350px]">
                   <div className="w-20 h-20 bg-pastel-sand rounded-full flex items-center justify-center mb-6"><Target size={48} /></div>
                   <span className="text-[11px] font-bold uppercase tracking-[0.2em]">새로운 꿈 설계하기</span>
                </button>
             </div>
           )}

           {harmonySubTab === 'PRAISE' && (
              <div className="bg-white p-12 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 text-center py-32">
                 <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center text-rose-300 mx-auto mb-8 shadow-inner"><Heart size={48} fill="currentColor" /></div>
                 <h3 className="text-2xl font-bold text-pastel-text mb-4">사랑과 격려의 칭찬 보드</h3>
                 <p className="text-sm text-zinc-400 font-medium max-w-md mx-auto leading-relaxed">준비 중인 기능입니다. 서로의 노력을 응원하고 칭찬 스티커를 주고받는 공간으로 곧 찾아옵니다!</p>
              </div>
           )}
        </div>
      )}

      {/* 5. DIARY */}
      {activeTab === 'DIARY' && (
        <div className="space-y-12 animate-in fade-in duration-700">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
             <div>
                <h2 className="text-3xl font-bold tracking-tighter">함께 기록하는 하루</h2>
                <p className="text-xs text-zinc-400 mt-2 uppercase tracking-widest">돈으로 환산할 수 없는 우리의 소중한 순간들.</p>
             </div>
             <button onClick={() => setIsAddModalOpen(true)} className="bg-pastel-purple text-white px-10 py-4 rounded-3xl text-xs font-bold shadow-xl hover:scale-105 transition-all flex items-center gap-3"><PenLine size={18} /> 오늘 일기 쓰기</button>
          </div>
          <CalendarView currentDate={historyDate} transactions={[]} diaries={diaries} users={users} hideFinancials={true} onDateClick={() => {}} />
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             {diaries.length === 0 ? (
                <div className="col-span-full py-32 text-center opacity-30">
                   <p className="text-sm font-bold uppercase tracking-widest">아직 기록된 일기가 없습니다.</p>
                </div>
             ) : (
                diaries.map(d => (
                  <div key={d.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col group">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-10 h-10 rounded-2xl text-white flex items-center justify-center text-[11px] font-bold shadow-md" style={{ backgroundColor: users.find(u => u.id === d.userId)?.color }}>{users.find(u => u.id === d.userId)?.avatar}</div>
                        <div>
                          <span className="text-xs font-bold text-pastel-text">{users.find(u => u.id === d.userId)?.name}</span>
                          <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest block">{d.date}</span>
                        </div>
                    </div>
                    <p className="text-base font-medium leading-relaxed text-pastel-text/90 flex-1">{d.text}</p>
                    <div className="mt-8 pt-6 border-t border-pastel-sand flex justify-end">
                       <button className="text-rose-300 hover:text-rose-500 transition-colors"><Heart size={20} /></button>
                    </div>
                  </div>
                ))
             )}
          </div>
        </div>
      )}

      {/* 상세 모달 및 폼 */}
      {selectedSummaryCategory && (
        <CategoryDetailModal 
          category={selectedSummaryCategory}
          transactions={transactions.filter(t => t.categoryId === selectedSummaryCategory.id)}
          users={users}
          onClose={() => setSelectedSummaryCategory(null)}
        />
      )}

      {isAddModalOpen && (
        <TransactionForm 
          onClose={() => setIsAddModalOpen(false)} 
          onSubmit={addTransaction} 
          categories={categories} 
          users={users} 
          currentUser={currentUser} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, Save, Users, User as UserIcon, Plus, Trash2, Tag, Palette, Layout, Sparkles, BrainCircuit, RefreshCw, ChevronRight, AlertCircle, ArrowRight } from 'lucide-react';
import { Category, TransactionType, User, Transaction } from '../types';
import { ICON_MAP } from '../App';
import { suggestCategoryBudget } from '../services/geminiService';

interface BudgetSettingModalProps {
  categories: Category[];
  users: User[];
  transactions: Transaction[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const BudgetSettingModal: React.FC<BudgetSettingModalProps> = ({ categories, users, transactions, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(
    categories.find(c => c.type === TransactionType.EXPENSE)?.id || null
  );
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  const activeCategory = useMemo(() => 
    localCategories.find(c => c.id === activeCategoryId),
    [localCategories, activeCategoryId]
  );

  const currentSpent = useMemo(() => {
    if (!activeCategory) return 0;
    return transactions
      .filter(t => t.categoryId === activeCategory.id && t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);
  }, [activeCategory, transactions]);

  const percentage = activeCategory && activeCategory.budgetLimit > 0 
    ? (currentSpent / activeCategory.budgetLimit) * 100 
    : 0;

  const getStatusColor = (p: number) => {
    if (p >= 100) return 'text-rose-600 bg-rose-600';
    if (p >= 85) return 'text-rose-500 bg-rose-500';
    if (p >= 60) return 'text-orange-400 bg-orange-400';
    return 'text-emerald-500 bg-emerald-500';
  };

  const getStatusText = (p: number) => {
    if (p >= 100) return '예산 초과';
    if (p >= 85) return '위험';
    if (p >= 60) return '주의';
    return '안전';
  };

  const handleGlobalLimitChange = (id: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, budgetLimit: limit } : c));
  };

  const handleIndividualLimitChange = (catId: string, userId: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => {
      if (c.id !== catId) return c;
      return {
        ...c,
        individualLimits: {
          ...(c.individualLimits || {}),
          [userId]: limit
        }
      };
    }));
  };

  const handleUpdateCategoryField = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAddNewCategory = () => {
    const newId = `c_budget_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 예산 항목',
      group: '기타',
      type: TransactionType.EXPENSE,
      budgetLimit: 0,
      color: '#D4C6F0',
      iconId: 'other',
      individualLimits: {}
    };
    setLocalCategories(prev => [...prev, newCat]);
    setActiveCategoryId(newId);
  };

  const handleDeleteCategory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('이 예산 항목을 정말 삭제할까요? 관련 기록의 분류가 사라질 수 있습니다.')) {
      setLocalCategories(prev => prev.filter(c => c.id !== id));
      if (activeCategoryId === id) {
        setActiveCategoryId(null);
      }
    }
  };

  const handleAiSuggestBudget = async (category: Category) => {
    setIsSuggesting(true);
    setAiMessage(null);
    try {
      const catTransactions = transactions.filter(t => t.categoryId === category.id);
      const suggestion = await suggestCategoryBudget(category.name, catTransactions);

      handleGlobalLimitChange(category.id, suggestion.recommendedLimit.toString());
      setAiMessage(suggestion.reasoning);
    } catch (err) {
      alert('AI 추천에 실패했습니다. 다시 시도해주세요.');
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSave = () => {
    onSave(localCategories);
    onClose();
  };

  const expenseCategories = localCategories.filter(c => c.type === TransactionType.EXPENSE);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-5xl shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center bg-white/50">
          <div className="flex items-center gap-4">
             <div className="w-12 h-12 bg-pastel-purple/20 rounded-2xl flex items-center justify-center text-pastel-purple">
                <BrainCircuit size={24} />
             </div>
             <div>
                <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">스마트 예산 설계</h2>
                <p className="text-[10px] text-zinc-400 mt-1">AI의 지능적인 가이드로 우리 가족의 완벽한 예산 계획을 세워보세요.</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        <div className="flex flex-1 overflow-hidden">
          {/* Left: Category List */}
          <div className="w-1/3 border-r border-pastel-sand bg-pastel-sand/10 flex flex-col">
            <div className="p-6 border-b border-pastel-sand/50">
               <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">예산 항목 리스트</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar">
              {expenseCategories.map(cat => (
                <div key={cat.id} className="relative group/item">
                  <button
                    onClick={() => { setActiveCategoryId(cat.id); setAiMessage(null); }}
                    className={`w-full text-left p-6 transition-all border-b border-pastel-sand/50 flex items-center justify-between
                      ${activeCategoryId === cat.id ? 'bg-white border-r-2 border-r-pastel-purple' : 'hover:bg-white/50'}`}
                  >
                    <div className="flex items-center gap-4 pr-8">
                      <div className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ backgroundColor: cat.color + '40', color: cat.color }}>
                         {React.createElement(ICON_MAP[cat.iconId] || ICON_MAP.other, { size: 16 })}
                      </div>
                      <div className="overflow-hidden">
                        <h4 className="text-[11px] font-bold text-pastel-text truncate">{cat.name}</h4>
                        <p className="text-[9px] text-zinc-400 font-bold tabular-nums">₩{cat.budgetLimit.toLocaleString()}</p>
                      </div>
                    </div>
                    {activeCategoryId === cat.id && <ChevronRight size={14} className="text-pastel-purple" />}
                  </button>
                  <button 
                    onClick={(e) => handleDeleteCategory(e, cat.id)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-zinc-200 hover:text-rose-400 opacity-0 group-hover/item:opacity-100 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              ))}
            </div>
            <div className="p-6 bg-white/50 border-t border-pastel-sand flex flex-col gap-2">
               <button 
                 onClick={handleAddNewCategory}
                 className="w-full py-4 text-[10px] font-bold text-pastel-purple uppercase tracking-widest border border-pastel-purple/30 rounded-2xl hover:bg-pastel-purple hover:text-white transition-all flex items-center justify-center gap-2"
               >
                 <Plus size={14} /> 직접 추가하기
               </button>
            </div>
          </div>

          {/* Right: Detailed Setting */}
          <div className="flex-1 p-10 overflow-y-auto custom-scrollbar bg-white">
            {activeCategory ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-right-4">
                {/* Visual Preview Section */}
                <div className="space-y-4">
                  <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest flex items-center gap-2">
                    <Activity size={12} /> 예산 상태 프리뷰
                  </label>
                  <div className="bg-pastel-sand/10 p-6 rounded-4xl border border-pastel-lavender/20 flex flex-col gap-4">
                    <div className="flex justify-between items-end">
                      <div className="space-y-1">
                        <span className={`text-[10px] font-bold uppercase tracking-[0.2em] ${getStatusColor(percentage).split(' ')[0]}`}>
                          {getStatusText(percentage)}
                        </span>
                        <div className="text-2xl font-bold tracking-tighter tabular-nums text-pastel-text">
                          {percentage.toFixed(1)}% <span className="text-sm font-medium text-zinc-300 ml-1">사용 중</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">현재 지출 / 설정 예산</span>
                        <div className="text-sm font-bold tabular-nums text-pastel-text">
                          {currentSpent.toLocaleString()} / <span className="text-pastel-purple">{activeCategory.budgetLimit.toLocaleString()}</span> 원
                        </div>
                      </div>
                    </div>

                    <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden relative">
                      <div 
                        className={`h-full transition-all duration-1000 ease-out rounded-full ${getStatusColor(percentage).split(' ')[1]}`}
                        style={{ width: `${Math.min(percentage, 100)}%` }}
                      >
                        <div className="w-full h-full grape-shine opacity-30" />
                      </div>
                      {percentage > 100 && (
                        <div className="absolute inset-0 bg-rose-500/20 animate-pulse" />
                      )}
                    </div>

                    <div className="flex justify-between text-[8px] font-bold text-zinc-300 uppercase tracking-[0.2em]">
                      <span>0%</span>
                      <span>60% (주의)</span>
                      <span>85% (위험)</span>
                      <span>100% (초과)</span>
                    </div>
                  </div>
                </div>

                {/* AI Suggestion Banner */}
                <div className="bg-gradient-to-r from-pastel-purple/10 to-transparent p-8 rounded-4xl border border-pastel-purple/20 flex flex-col md:flex-row items-center gap-6">
                   <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center text-pastel-purple shadow-sm shrink-0">
                      <Sparkles size={28} />
                   </div>
                   <div className="flex-1 space-y-2">
                      <h4 className="text-sm font-bold text-pastel-text">적정 한도가 궁금하신가요?</h4>
                      <p className="text-[11px] text-zinc-400 font-medium leading-relaxed">최근 지출 내역을 분석하여 가장 현실적인 한도를 제안합니다.</p>
                      {aiMessage && (
                        <div className="mt-4 p-4 bg-white/80 rounded-2xl border border-pastel-purple/10 animate-in zoom-in-95">
                           <p className="text-[11px] font-medium text-pastel-purple italic">" {aiMessage} "</p>
                        </div>
                      )}
                   </div>
                   <button 
                     onClick={() => handleAiSuggestBudget(activeCategory)}
                     disabled={isSuggesting}
                     className="bg-pastel-purple text-white px-6 py-4 rounded-2xl text-[10px] font-bold uppercase tracking-widest shadow-md hover:scale-105 active:scale-95 transition-all flex items-center gap-2 disabled:opacity-50"
                   >
                     {isSuggesting ? <RefreshCw size={14} className="animate-spin" /> : <Sparkles size={14} />}
                     AI 추천 받기
                   </button>
                </div>

                <div className="grid grid-cols-2 gap-10">
                   <div className="space-y-10">
                      <div className="space-y-4">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
                          <Tag size={12} /> 항목 정보
                        </label>
                        <div className="space-y-4">
                           <input 
                             type="text" 
                             placeholder="항목 명칭"
                             value={activeCategory.name}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'name', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl border-none outline-none focus:ring-2 focus:ring-pastel-purple/20"
                           />
                           <input 
                             type="text" 
                             placeholder="그룹 분류"
                             value={activeCategory.group}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'group', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl border-none outline-none focus:ring-2 focus:ring-pastel-purple/20"
                           />
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
                          <Users size={12} /> 공동 지출 한도 설정
                        </label>
                        <div className="relative group">
                          <input 
                            type="text" 
                            value={activeCategory.budgetLimit.toLocaleString()} 
                            onChange={(e) => handleGlobalLimitChange(activeCategory.id, e.target.value)}
                            className="w-full text-4xl font-bold text-pastel-text outline-none bg-transparent tabular-nums border-b border-pastel-sand focus:border-pastel-purple pb-2 transition-all" 
                          />
