import React, { useState, useMemo } from 'react';
/* Added Activity to the imports from lucide-react */
import { X, Save, Users, User as UserIcon, Plus, Trash2, Tag, Palette, Layout, Sparkles, BrainCircuit, RefreshCw, ChevronRight, AlertCircle, ArrowRight, Activity } from 'lucide-react';
import { Category, TransactionType, User, Transaction } from '../types';
import { ICON_MAP } from '../App';
import { suggestCategoryBudget } from '../services/geminiService';

interface BudgetSettingModalProps {
  categories: Category[];
  users: User[];
  transactions: Transaction[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const BudgetSettingModal: React.FC<BudgetSettingModalProps> = ({ categories, users, transactions, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(
    categories.find(c => c.type === TransactionType.EXPENSE)?.id || null
  );
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  const activeCategory = useMemo(() => 
    localCategories.find(c => c.id === activeCategoryId),
    [localCategories, activeCategoryId]
  );

  const currentSpent = useMemo(() => {
    if (!activeCategory) return 0;
    return transactions
      .filter(t => t.categoryId === activeCategory.id && t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);
  }, [activeCategory, transactions]);

  const percentage = activeCategory && activeCategory.budgetLimit > 0 
    ? (currentSpent / activeCategory.budgetLimit) * 100 
    : 0;

  const getStatusColor = (p: number) => {
    if (p >= 100) return 'text-rose-600 bg-rose-600';
    if (p >= 85) return 'text-rose-500 bg-rose-500';
    if (p >= 60) return 'text-orange-400 bg-orange-400';
    return 'text-emerald-500 bg-emerald-500';
  };

  const getStatusText = (p: number) => {
    if (p >= 100) return '예산 초과';
    if (p >= 85) return '위험';
    if (p >= 60) return '주의';
    return '안전';
  };

  const handleGlobalLimitChange = (id: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, budgetLimit: limit } : c));
  };

  const handleIndividualLimitChange = (catId: string, userId: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => {
      if (c.id !== catId) return c;
      return {
        ...c,
        individualLimits: {
          ...(c.individualLimits || {}),
          [userId]: limit
        }
      };
    }));
  };

  const handleUpdateCategoryField = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAddNewCategory = () => {
    const newId = `c_budget_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 예산 항목',
      group: '기타',
      type: TransactionType.EXPENSE,
      budgetLimit: 0,
      color: '#D4C6F0',
      iconId: 'other',
      individualLimits: {}
    };
    setLocalCategories(prev => [...prev, newCat]);
    setActiveCategoryId(newId);
  };

  const handleDeleteCategory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('이 예산 항목을 정말 삭제할까요? 관련 기록의 분류가 사라질 수 있습니다.')) {
      setLocalCategories(prev => prev.filter(c => c.id !== id));
      if (activeCategoryId === id) {
        setActiveCategoryId(null);
      }
    }
  };

  const handleAiSuggestBudget = async (category: Category) => {
    setIsSuggesting(true);
    setAiMessage(null);
    try {
      const catTransactions = transactions.filter(t => t.categoryId === category.id);
      const suggestion = await suggestCategoryBudget(category.name, catTransactions);

      handleGlobalLimitChange(category.id, suggestion.recommendedLimit.toString());
      setAiMessage(suggestion.reasoning);
    } catch (err) {
      alert('AI 추천에 실패했습니다. 다시 시도해주세요.');
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSave = () => {
    onSave(localCategories);
    onClose();
  };

  const expenseCategories = localCategories.filter(c => c.type === TransactionType.EXPENSE);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-5xl shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center bg-white/50">
          <div className="flex items-center gap-4">
             <div className="w-12 h-12 bg-pastel-purple/20 rounded-2xl flex items-center justify-center text-pastel-purple">
                <BrainCircuit size={24} />
             </div>
             <div>
                <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">스마트 예산 설계</h2>
                <p className="text-[10px] text-zinc-400 mt-1">AI의 지능적인 가이드로 우리 가족의 완벽한 예산 계획을 세워보세요.</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Left: Category List */}
          <div className="w-1/3 border-r border-pastel-sand bg-pastel-sand/10 flex flex-col">
            <div className="p-6 border-b border-pastel-sand/50">
               <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">예산 항목 리스트</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar">
              {expenseCategories.map(cat => (
                <div key={cat.id} className="relative group/item">
                  <button
                    onClick={() => { setActiveCategoryId(cat.id); setAiMessage(null); }}
                    className={`w-full text-left p-6 transition-all border-b border-pastel-sand/50 flex items-center justify-between
                      ${activeCategoryId === cat.id ? 'bg-white border-r-2 border-r-pastel-purple' : 'hover:bg-white/50'}`}
                  >
                    <div className="flex items-center gap-4 pr-8">
                      <div className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ backgroundColor: cat.color + '40', color: cat.color }}>
                         {React.createElement(ICON_MAP[cat.iconId] || ICON_MAP.other, { size: 16 })}
                      </div>
                      <div className="overflow-hidden">
                        <h4 className="text-[11px] font-bold text-pastel-text truncate">{cat.name}</h4>
                        <p className="text-[9px] text-zinc-400 font-bold tabular-nums">₩{cat.budgetLimit.toLocaleString()}</p>
                      </div>
                    </div>
                    {activeCategoryId === cat.id && <ChevronRight size={14} className="text-pastel-purple" />}
                  </button>
                  <button 
                    onClick={(e) => handleDeleteCategory(e, cat.id)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-zinc-200 hover:text-rose-400 opacity-0 group-hover/item:opacity-100 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              ))}
            </div>
            <div className="p-6 bg-white/50 border-t border-pastel-sand flex flex-col gap-2">
               <button 
                 onClick={handleAddNewCategory}
                 className="w-full py-4 text-[10px] font-bold text-pastel-purple uppercase tracking-widest border border-pastel-purple/30 rounded-2xl hover:bg-pastel-purple hover:text-white transition-all flex items-center justify-center gap-2"
               >
                 <Plus size={14} /> 직접 추가하기
               </button>
            </div>
          </div>

          {/* Right: Detailed Setting */}
          <div className="flex-1 p-10 overflow-y-auto custom-scrollbar bg-white">
            {activeCategory ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-right-4">
                {/* Visual Preview Section */}
                <div className="space-y-4">
                  <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest flex items-center gap-2">
                    <Activity size={12} /> 예산 상태 프리뷰
                  </label>
                  <div className="bg-pastel-sand/10 p-6 rounded-4xl border border-pastel-lavender/20 flex flex-col gap-4">
                    <div className="flex justify-between items-end">
                      <div className="space-y-1">
                        <span className={`text-[10px] font-bold uppercase tracking-[0.2em] ${getStatusColor(percentage).split(' ')[0]}`}>
                          {getStatusText(percentage)}
                        </span>
                        <div className="text-2xl font-bold tracking-tighter tabular-nums text-pastel-text">
                          {percentage.toFixed(1)}% <span className="text-sm font-medium text-zinc-300 ml-1">사용 중</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">현재 지출 / 설정 예산</span>
                        <div className="text-sm font-bold tabular-nums text-pastel-text">
                          {currentSpent.toLocaleString()} / <span className="text-pastel-purple">{activeCategory.budgetLimit.toLocaleString()}</span> 원
                        </div>
                      </div>
                    </div>

                    <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden relative">
                      <div 
                        className={`h-full transition-all duration-1000 ease-out rounded-full ${getStatusColor(percentage).split(' ')[1]}`}
                        style={{ width: `${Math.min(percentage, 100)}%` }}
                      >
                        <div className="w-full h-full grape-shine opacity-30" />
                      </div>
                      {percentage > 100 && (
                        <div className="absolute inset-0 bg-rose-500/20 animate-pulse" />
                      )}
                    </div>

                    <div className="flex justify-between text-[8px] font-bold text-zinc-300 uppercase tracking-[0.2em]">
                      <span>0%</span>
                      <span>60% (주의)</span>
                      <span>85% (위험)</span>
                      <span>100% (초과)</span>
                    </div>
                  </div>
                </div>

                {/* AI Suggestion Banner */}
                <div className="bg-gradient-to-r from-pastel-purple/10 to-transparent p-8 rounded-4xl border border-pastel-purple/20 flex flex-col md:flex-row items-center gap-6">
                   <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center text-pastel-purple shadow-sm shrink-0">
                      <Sparkles size={28} />
                   </div>
                   <div className="flex-1 space-y-2">
                      <h4 className="text-sm font-bold text-pastel-text">적정 한도가 궁금하신가요?</h4>
                      <p className="text-[11px] text-zinc-400 font-medium leading-relaxed">최근 지출 내역을 분석하여 가장 현실적인 한도를 제안합니다.</p>
                      {aiMessage && (
                        <div className="mt-4 p-4 bg-white/80 rounded-2xl border border-pastel-purple/10 animate-in zoom-in-95">
                           <p className="text-[11px] font-medium text-pastel-purple italic">" {aiMessage} "</p>
                        </div>
                      )}
                   </div>
                   <button 
                     onClick={() => handleAiSuggestBudget(activeCategory)}
                     disabled={isSuggesting}
                     className="bg-pastel-purple text-white px-6 py-4 rounded-2xl text-[10px] font-bold uppercase tracking-widest shadow-md hover:scale-105 active:scale-95 transition-all flex items-center gap-2 disabled:opacity-50"
                   >
                     {isSuggesting ? <RefreshCw size={14} className="animate-spin" /> : <Sparkles size={14} />}
                     AI 추천 받기
                   </button>
                </div>

                <div className="grid grid-cols-2 gap-10">
                   <div className="space-y-10">
                      <div className="space-y-4">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
                          <Tag size={12} /> 항목 정보
                        </label>
                        <div className="space-y-4">
                           <input 
                             type="text" 
                             placeholder="항목 명칭"
                             value={activeCategory.name}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'name', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl border-none outline-none focus:ring-2 focus:ring-pastel-purple/20"
                           />
                           <input 
                             type="text" 
                             placeholder="그룹 분류"
                             value={activeCategory.group}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'group', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl border-none outline-none focus:ring-2 focus:ring-pastel-purple/20"
                           />
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
                          <Tag size={12} /> 공동 지출 한도 설정
                        </label>
                        <div className="relative group">
                          <input 
                            type="text" 
                            value={activeCategory.budgetLimit.toLocaleString()} 
                            onChange={(e) => handleGlobalLimitChange(activeCategory.id, e.target.value)}
                            className="w-full text-4xl font-bold text-pastel-text outline-none bg-transparent tabular-nums border-b border-pastel-sand focus:border-pastel-purple pb-2 transition-all" 
                          />
                          <span className="absolute right-0 bottom-2 text-xs font-bold text-zinc-300">원</span>
                        </div>
                        {percentage > 100 && (
                          <div className="text-[10px] font-bold text-rose-500 flex items-center gap-1.5 animate-in slide-in-from-top-1">
                            <AlertCircle size={12} /> 현재 지출보다 낮은 예산입니다.
                          </div>
                        )}
                      </div>
                   </div>

                   <div className="space-y-10">
                      <div className="space-y-6">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
                          <UserIcon size={12} /> 개인별 지출 한도 분배
                        </label>
                        <div className="space-y-4">
                          {users.map(user => (
                            <div key={user.id} className="flex items-center justify-between gap-6 p-4 bg-pastel-sand/20 rounded-2xl border border-transparent hover:border-pastel-lavender/30 transition-all">
                              <div className="flex items-center gap-3 shrink-0">
                                <div className="w-8 h-8 rounded-full text-white flex items-center justify-center text-[10px] font-bold" style={{ backgroundColor: user.color }}>
                                  {user.avatar}
                                </div>
                                <span className="text-xs font-bold text-pastel-text">{user.name}</span>
                              </div>
                              <div className="relative flex-1 max-w-[150px]">
                                <input 
                                  type="text" 
                                  placeholder="미설정"
                                  value={activeCategory.individualLimits?.[user.id]?.toLocaleString() || ''}
                                  onChange={(e) => handleIndividualLimitChange(activeCategory.id, user.id, e.target.value)}
                                  className="w-full text-right font-bold text-sm bg-transparent outline-none pr-8 tabular-nums"
                                />
                                <span className="absolute right-0 top-0.5 text-[10px] font-bold text-zinc-300">원</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="flex items-center gap-2 text-[10px] font-bold text-zinc-300 uppercase tracking-widest">
