  id: string;
  name: string;
  avatar: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string;
  type: TransactionType;
  budgetLimit: number;
  individualLimits?: Record<string, number>;
  color: string;
  iconId: string;
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Comment {
  id: string;
  userId: string;
  text: string;
  date: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
