    { id: 'e2', text: '세탁 세제', isStocked: false, addedByUserId: 'u1' },
    { id: 'e3', text: '샴푸/린스', isStocked: true, addedByUserId: 'u2' }
  ]);
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([
    { id: 'sub1', name: '넷플릭스', amount: 17000, billingDate: 14, userId: 'u1', isShared: true, iconId: 'netflix' },
    { id: 'sub2', name: '유튜브 프리미엄', amount: 14900, billingDate: 25, userId: 'u2', isShared: true, iconId: 'youtube' }
  ]);
  const [chores, setChores] = useState<Chore[]>([
    { id: 'ch1', title: '분리수거 하기', assignedToUserId: 'u1', isCompleted: false, frequency: 'WEEKLY', points: 10 },
    { id: 'ch2', title: '거실 청소기 돌리기', assignedToUserId: 'u2', isCompleted: false, frequency: 'DAILY', points: 5 }
  ]);
  const [stickerGoals, setStickerGoals] = useState<StickerGoal[]>([
    { id: 'g1', title: '칭찬 포도송이: 치킨 쏘기!', targetCount: 20, currentCount: 12, assignedToUserId: 'u2', createdByUserId: 'u1', isCompleted: false },
    { id: 'g2', title: '설거지 요정 포도송이', targetCount: 10, currentCount: 10, assignedToUserId: 'u1', createdByUserId: 'u2', isCompleted: true },
  ]);
  const [bucketGoals, setBucketGoals] = useState<BucketGoal[]>([
    { id: 'bg1', title: '내년 유럽 여행 가기', targetAmount: 5000000, currentAmount: 1200000, isCompleted: false },
    { id: 'bg2', title: '1주년 기념 파인다이닝', targetAmount: 400000, currentAmount: 400000, isCompleted: true }
  ]);

  // UI 상태
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [selectedSummaryCategory, setSelectedSummaryCategory] = useState<Category | null>(null);

  // --- 통계 계산 ---
  const monthlyStats = useMemo(() => {
    const targetYear = historyDate.getFullYear();
    const targetMonth = historyDate.getMonth();
    const filtered = transactions.filter(t => {
      const d = new Date(t.date);
      return d.getFullYear() === targetYear && d.getMonth() === targetMonth;
    });
    const income = filtered.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
    const expense = filtered.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions, historyDate]);

  const budgetStatuses = useMemo(() => {
    return categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
      const catTransactions = transactions.filter(t => t.categoryId === cat.id);
      const spent = catTransactions.reduce((sum, t) => sum + t.amount, 0);
      const limit = cat.budgetLimit || 1;
      const percentage = (spent / limit) * 100;
      return { 
        categoryId: cat.id, 
        spent, 
        limit, 
        percentage,
        status: percentage >= 100 ? 'EXCEEDED' : percentage >= 85 ? 'DANGER' : percentage >= 60 ? 'WARNING' : 'SAFE'
      } as BudgetStatus;
    });
  }, [categories, transactions]);

  // --- 핸들러 ---
  const addShoppingItem = (text: string) => {
    if (!text.trim()) return;
    setShoppingItems([...shoppingItems, { id: Date.now().toString(), text, isBought: false, addedByUserId: currentUser.id }]);
    setToast({ message: '장바구니에 추가되었습니다!', type: 'success' });
  };

  const addEssentialItem = (text: string) => {
    if (!text.trim()) return;
    setEssentialItems([...essentialItems, { id: Date.now().toString(), text, isStocked: true, addedByUserId: currentUser.id }]);
    setToast({ message: '필수 생활 용품으로 등록되었습니다!', type: 'success' });
  };

  const toggleEssentialStatus = (id: string) => {
    const item = essentialItems.find(i => i.id === id);
    if (!item) return;
    const newStatus = !item.isStocked;
    setEssentialItems(essentialItems.map(i => i.id === id ? { ...i, isStocked: newStatus } : i));
    if (!newStatus) {
      addShoppingItem(item.text);
      setToast({ message: '물품이 부족하여 장바구니에 자동 추가되었습니다.', type: 'info' });
    } else {
      setToast({ message: '재고가 보충되었습니다!', type: 'success' });
    }
  };

  const giveSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const newCount = g.currentCount + 1;
      const completed = newCount >= g.targetCount;
      if (completed) setToast({ message: '🎉 포도송이 완성! 보상을 확인하세요!', type: 'success' });
      else setToast({ message: '🍇 칭찬 스티커 한 알을 붙였습니다!', type: 'success' });
      return { ...g, currentCount: newCount, isCompleted: completed };
    }));
  };

  const toggleChore = (id: string) => {
    setChores(chores.map(c => c.id === id ? { ...c, isCompleted: !c.isCompleted } : c));
    setToast({ message: '고생하셨어요! 수고의 포인트가 적립되었습니다 👏', type: 'success' });
  };

  const addTransaction = (data: any) => {
    setTransactions([{ ...data, id: Date.now().toString(), likes: [], dislikes: [], comments: [] }, ...transactions]);
    setToast({ message: '거래 내역이 성공적으로 저장되었습니다!', type: 'success' });
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      onOpenAddModal={() => setIsAddModalOpen(true)}
      currentUser={currentUser}
      users={users}
      onSwitchUser={setCurrentUser}
    >
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* 1. HOME (DASHBOARD) */}
      {activeTab === 'HOME' && (
        <div className="space-y-12 animate-in fade-in duration-700">
          <div className="flex flex-col md:flex-row gap-8">
             <div className="flex-1 bg-gradient-to-br from-pastel-purple/20 to-white p-12 rounded-[3.5rem] soft-shadow border border-pastel-lavender/30 relative overflow-hidden">
                <div className="absolute -top-10 -right-10 text-pastel-purple/10 opacity-40 group-hover:scale-110 transition-transform">
                  <Sparkles size={200} />
                </div>
                <div className="relative z-10">
                  <span className="text-[11px] font-bold text-pastel-purple uppercase tracking-[0.2em] block mb-3">Welcome Home, {currentUser.name}</span>
                  <h2 className="text-4xl font-bold tracking-tighter leading-tight">우리가 꿈꾸는<br/>조화로운 삶</h2>
                  <div className="mt-10 grid grid-cols-2 gap-6">
                     <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2rem] border border-white">
                        <span className="text-[10px] font-bold text-zinc-400 block mb-2 uppercase tracking-widest">이번 달 지출</span>
                        <p className="text-2xl font-bold tracking-tighter tabular-nums text-pastel-text">{monthlyStats.expense.toLocaleString()}원</p>
                     </div>
                     <div className="bg-white/80 backdrop-blur-sm p-6 rounded-[2rem] border border-white">
                        <span className="text-[10px] font-bold text-zinc-400 block mb-2 uppercase tracking-widest">진행 중인 꿈</span>
                        <p className="text-2xl font-bold tracking-tighter tabular-nums text-pastel-purple">{bucketGoals.filter(b => !b.isCompleted).length}개</p>
                     </div>
                  </div>
                </div>
             </div>

             <div className="md:w-[350px] bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/30 flex flex-col">
                <div className="flex-1">
                   <div className="flex items-center justify-between mb-8">
                     <span className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest">오늘의 미션</span>
                     <Flame size={18} className="text-rose-300" />
                   </div>
                   <div className="space-y-5">
                      {chores.filter(c => !c.isCompleted).length === 0 ? (
                        <p className="text-xs font-medium text-zinc-300 py-4 text-center">할 일을 모두 마쳤습니다!</p>
                      ) : (
                        chores.filter(c => !c.isCompleted).slice(0, 3).map(c => (
                          <div key={c.id} className="flex items-center gap-4 group cursor-pointer" onClick={() => setActiveTab('HARMONY')}>
                             <div className="w-2 h-2 rounded-full bg-pastel-purple group-hover:scale-125 transition-transform" />
                             <span className="text-sm font-semibold text-pastel-text group-hover:text-pastel-purple transition-colors truncate">{c.title}</span>
                          </div>
                        ))
                      )}
                   </div>
                </div>
                <button onClick={() => setActiveTab('HARMONY')} className="flex items-center justify-center gap-2 w-full py-4 mt-8 bg-pastel-sand/50 rounded-2xl text-[10px] font-bold text-pastel-purple uppercase tracking-widest hover:bg-pastel-sand transition-all">하모니 센터 가기 →</button>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
             <section className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col h-[320px]">
                <div className="flex items-center justify-between mb-8">
                   <h3 className="text-base font-bold flex items-center gap-3"><ShoppingBag size={20} className="text-pastel-purple" /> 장바구니</h3>
                   <span className="bg-pastel-sand text-[10px] font-bold px-3 py-1 rounded-full text-zinc-400">{shoppingItems.filter(i => !i.isBought).length} items</span>
                </div>
                <div className="space-y-4 flex-1 overflow-hidden">
                   {shoppingItems.filter(i => !i.isBought).slice(0, 4).map(i => (
                     <div key={i.id} className="flex items-center gap-3 text-xs font-medium bg-pastel-sand/30 p-4 rounded-2xl border border-transparent hover:border-pastel-purple/10 transition-all">{i.text}</div>
                   ))}
                </div>
             </section>

             <section className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col h-[320px]">
                <div className="flex items-center justify-between mb-8">
                   <h3 className="text-base font-bold flex items-center gap-3"><CreditCard size={20} className="text-emerald-300" /> 정기 구독</h3>
                   <span className="text-[10px] font-bold text-zinc-300 uppercase">Total {subscriptions.length}</span>
                </div>
                <div className="space-y-4 flex-1 overflow-hidden">
                   {subscriptions.map(s => (
                     <div key={s.id} className="flex items-center justify-between p-2">
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 bg-pastel-sand/50 rounded-2xl flex items-center justify-center text-pastel-purple">
                              {renderCategoryIcon(s.iconId, 18)}
                           </div>
                           <span className="text-xs font-bold text-pastel-text">{s.name}</span>
                        </div>
                        <span className="text-[10px] font-bold text-zinc-300 tabular-nums">매달 {s.billingDate}일</span>
                     </div>
                   ))}
                </div>
             </section>

             <section className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col h-[320px]">
                <div className="flex items-center justify-between mb-8">
                   <h3 className="text-base font-bold flex items-center gap-3"><Target size={20} className="text-rose-300" /> 우리의 목표</h3>
                </div>
                <div className="space-y-8 flex-1">
                  {bucketGoals.filter(b => !b.isCompleted).slice(0, 2).map(b => (
                    <div key={b.id} className="space-y-3">
                       <div className="flex justify-between items-end">
                          <p className="text-xs font-bold text-pastel-text">{b.title}</p>
                          <span className="text-[10px] font-bold text-pastel-purple">{((b.currentAmount / b.targetAmount) * 100).toFixed(0)}%</span>
                       </div>
                       <div className="h-2 w-full bg-pastel-sand rounded-full overflow-hidden">
                          {/* Fixed variable: goal -> b */}
                          <div className="h-full bg-pastel-purple rounded-full" style={{ width: `${(b.currentAmount / b.targetAmount) * 100}%` }} />
                       </div>
                    </div>
                  ))}
                </div>
             </section>
          </div>
        </div>
      )}

      {/* 2. WALLET (Finances) */}
      {activeTab === 'WALLET' && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow w-fit mx-auto md:mx-0">
              {[
                { id: 'SUMMARY', label: '요약', icon: LayoutPanelLeft },
                { id: 'LIST', label: '내역', icon: List },
                { id: 'BUDGET', label: '예산', icon: PieChart },
                { id: 'SUBS', label: '구독', icon: CreditCard }
              ].map(t => (
                <button key={t.id} onClick={() => setWalletSubTab(t.id as any)} className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-bold tracking-widest uppercase transition-all ${walletSubTab === t.id ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-400 hover:text-zinc-500'}`}>
                  <t.icon size={14} /> {t.label}
                </button>
              ))}
           </div>

           {walletSubTab === 'SUMMARY' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {categories.filter(c => c.type === TransactionType.EXPENSE).map(cat => {
                   const sum = transactions.filter(t => t.categoryId === cat.id).reduce((s, t) => s + t.amount, 0);
                   return (
                     <button key={cat.id} onClick={() => setSelectedSummaryCategory(cat)} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 hover:scale-[1.02] transition-all text-left flex flex-col group relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:scale-110 transition-transform">{renderCategoryIcon(cat.iconId, 80)}</div>
                        <div className="w-14 h-14 rounded-2xl flex items-center justify-center mb-6 shadow-inner" style={{ backgroundColor: cat.color + '40', color: cat.color }}>{renderCategoryIcon(cat.iconId, 24)}</div>
                        <h4 className="text-[11px] font-bold text-zinc-400 uppercase tracking-widest mb-2">{cat.name}</h4>
                        <p className="text-3xl font-bold tracking-tighter tabular-nums">{sum.toLocaleString()}원</p>
                     </button>
                   );
                })}
             </div>
           )}

           {walletSubTab === 'BUDGET' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
               {budgetStatuses.map(status => (
                 <BudgetCard key={status.categoryId} category={categories.find(c => c.id === status.categoryId)!} status={status} users={users} />
               ))}
             </div>
           )}

           {walletSubTab === 'SUBS' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {subscriptions.map(s => (
                  <div key={s.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col items-center text-center group hover:border-pastel-purple/30 transition-all">
                     <div className="w-20 h-20 bg-pastel-sand rounded-[2rem] flex items-center justify-center text-pastel-purple mb-8 shadow-inner group-hover:scale-110 transition-transform">{renderCategoryIcon(s.iconId, 32)}</div>
                     <h4 className="text-base font-bold text-pastel-text mb-2">{s.name}</h4>
                     <p className="text-sm font-bold text-pastel-purple mb-6">{s.amount.toLocaleString()}원 / 월</p>
                     <div className="text-[10px] font-bold text-zinc-400 uppercase tracking-[0.2em] bg-pastel-sand px-4 py-2 rounded-full">Day {s.billingDate}</div>
                  </div>
                ))}
                <button className="border-2 border-dashed border-pastel-lavender/40 rounded-[3rem] p-10 flex flex-col items-center justify-center text-zinc-300 hover:bg-pastel-sand/50 transition-all min-h-[280px]">
                   <div className="bg-pastel-sand w-16 h-16 rounded-full flex items-center justify-center mb-4"><Plus size={32} /></div>
                   <span className="text-[10px] font-bold uppercase tracking-widest">구독 서비스 추가</span>
                </button>
             </div>
           )}

           {walletSubTab === 'LIST' && (
              <div className="bg-white rounded-[3.5rem] p-10 soft-shadow border border-pastel-lavender/20">
                 <div className="space-y-12">
                   {transactions.map(t => {
                     const cat = categories.find(c => c.id === t.categoryId);
                     const user = users.find(u => u.id === t.userId);
                     return (
                       <div key={t.id} className="flex items-center justify-between group">
                          <div className="flex items-center gap-6">
                             <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 20)}</div>
                             <div>
                                <div className="flex items-center gap-2 mb-1">
                                   <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{t.date}</span>
                                   <span className="w-1 h-1 rounded-full bg-zinc-200" />
                                   <span className="text-[9px] font-bold text-pastel-purple uppercase">{user?.name}</span>
                                </div>
                                <p className="text-sm font-bold text-pastel-text">{t.description}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className={`text-lg font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-pastel-text'}`}>
                                {t.type === TransactionType.INCOME ? '+' : '-'} {t.amount.toLocaleString()}
                             </p>
                             <div className="flex items-center justify-end gap-3 mt-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button className="text-zinc-200 hover:text-rose-400 transition-colors"><Trash2 size={14} /></button>
                             </div>
                          </div>
                       </div>
                     );
                   })}
                 </div>
              </div>
           )}
        </div>
      )}

      {/* 3. LIFE (Shopping & Essentials) */}
      {activeTab === 'LIFE' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="text-center">
              <div className="inline-flex p-4 bg-pastel-purple/10 text-pastel-purple rounded-3xl mb-6">
                <ShoppingBag size={32} />
              </div>
              <h2 className="text-4xl font-bold tracking-tighter">우리 집 생활 도우미</h2>
              <p className="text-xs text-zinc-400 mt-3 uppercase tracking-widest">필수품 재고와 장바구니를 똑똑하게 관리하세요.</p>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* 장바구니 섹션 */}
              <div className="bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex flex-col">
                <div className="flex items-center justify-between mb-8 px-2">
                   <h3 className="text-xl font-bold flex items-center gap-3"><ShoppingBag size={24} className="text-pastel-purple" /> 오늘 사야 할 것</h3>
                   <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{shoppingItems.filter(i => !i.isBought).length} 남음</span>
                </div>

                <div className="flex gap-3 mb-8">
                   <input 
                     type="text" 
                     placeholder="품목 입력..." 
                     className="flex-1 p-4 bg-pastel-sand/30 rounded-2xl outline-none text-sm font-medium"
                     onKeyDown={(e) => { if(e.key === 'Enter') { addShoppingItem(e.currentTarget.value); e.currentTarget.value = ''; } }}
                   />
                   <button className="bg-pastel-purple text-white w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg active:scale-95 transition-all"><Plus size={24} /></button>
                </div>

                <div className="space-y-3 flex-1 overflow-y-auto max-h-[500px] custom-scrollbar pr-2">
                   {shoppingItems.map(item => (
                     <div key={item.id} className={`flex items-center justify-between p-5 rounded-3xl border transition-all ${item.isBought ? 'bg-pastel-sand/20 border-transparent opacity-50' : 'bg-white border-pastel-lavender/10 soft-shadow'}`}>
                        <div className="flex items-center gap-4">
                           <button 
                             onClick={() => setShoppingItems(shoppingItems.map(i => i.id === item.id ? { ...i, isBought: !i.isBought } : i))}
                             className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${item.isBought ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender hover:border-pastel-purple'}`}
                           >
                             {item.isBought && <Check size={14} className="text-white" />}
                           </button>
                           <span className={`text-sm font-bold ${item.isBought ? 'line-through text-zinc-300' : 'text-pastel-text'}`}>{item.text}</span>
                        </div>
                        <button onClick={() => setShoppingItems(shoppingItems.filter(i => i.id !== item.id))} className="text-zinc-200 hover:text-rose-400 transition-colors p-1"><Trash2 size={16} /></button>
                     </div>
                   ))}
                </div>
              </div>

              {/* 생활 필수품 리스트 섹션 */}
              <div className="bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex flex-col">
                <div className="flex items-center justify-between mb-8 px-2">
                   <div className="flex flex-col">
                      <h3 className="text-xl font-bold flex items-center gap-3"><ClipboardList size={24} className="text-rose-300" /> 필수 생활 용품</h3>
                      <p className="text-[10px] text-zinc-300 mt-1 uppercase font-bold tracking-widest">상시 구비 품목 관리</p>
                   </div>
                   <div className="flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-rose-300 animate-pulse" />
                      <span className="text-[9px] font-bold text-zinc-300 uppercase tracking-widest">{essentialItems.filter(i => !i.isStocked).length} 부족함</span>
                   </div>
                </div>

                <div className="flex gap-3 mb-8">
                   <input 
                     type="text" 
                     placeholder="필수품 추가..." 
                     className="flex-1 p-4 bg-pastel-sand/30 rounded-2xl outline-none text-sm font-medium"
                     onKeyDown={(e) => { if(e.key === 'Enter') { addEssentialItem(e.currentTarget.value); e.currentTarget.value = ''; } }}
                   />
                   <button className="bg-rose-300 text-white w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg active:scale-95 transition-all"><Plus size={24} /></button>
