    // 삼각형 형태를 위해 역순으로 채우기 (5, 4, 3, 2, 1 ...)
    // 20개의 경우: 6-5-4-3-2 = 20
    // 10개의 경우: 4-3-2-1 = 10

    // 시작 행의 크기를 찾습니다 (Sum of 1 to n >= targetCount)
    let startSize = 1;
    let sum = 0;
    while (sum < targetCount) {
      startSize++;
      sum = 0;
      for (let i = 0; i < startSize; i++) {
        sum += (startSize - i);
      }
