  const getGrapeRows = (targetCount: number) => {
    const rows = [];
    let startSize = 1;
    let sum = 0;
    while (sum < targetCount) {
      startSize++;
      sum = 0;
      for (let i = 0; i < startSize; i++) sum += (startSize - i);
    }
    let remaining = targetCount;
    let currentRowSize = startSize;
    let count = 0;
    while (remaining > 0) {
      const size = Math.min(currentRowSize, remaining);
      rows.push(Array.from({ length: size }, (_, i) => count++));
      remaining -= size;
      currentRowSize--;
      if (currentRowSize <= 0 && remaining > 0) currentRowSize = 1;
    }
    return rows;
  };

