           addShoppingItem(i.text);
           setToast({ message: '물품이 부족하여 장바구니에 자동 추가되었습니다.', type: 'info' });
        } else {
           setToast({ message: '재고가 보충되었습니다!', type: 'success' });
        }
        return { ...i, isStocked: newStatus };
      }
      return i;
    }));
  };

  const giveSticker = (goalId: string) => {
    setStickerGoals(prev => prev.map(g => {
      if (g.id !== goalId || g.isCompleted) return g;
      const newCount = g.currentCount + 1;
      const completed = newCount >= g.targetCount;
      if (completed) setToast({ message: '🎉 포도송이 완성! 보상을 확인하세요!', type: 'success' });
