                           {/* 포도송이 비주얼 */}
                           <div className="relative mb-12 flex flex-col items-center w-full min-h-[300px] justify-center">
                              <div className="absolute top-0 left-1/2 -translate-x-1/2 flex flex-col items-center">
                                 <div className="w-1.5 h-10 bg-emerald-800/40 rounded-full mb-[-10px]" />
                                 <div className="flex gap-2">
                                    <div className="w-10 h-6 bg-emerald-600/20 rounded-[50%_50%_10%_10%] rotate-[-25deg]" />
                                    <div className="w-10 h-6 bg-emerald-600/30 rounded-[50%_50%_10%_10%] rotate-[25deg]" />
                                 </div>
                              </div>
                              <div className="mt-8 flex flex-col items-center">
                                 {rows.map((row, rowIdx) => (
                                    <div key={rowIdx} className="flex justify-center gap-1.5" style={{ marginTop: rowIdx === 0 ? '0' : '-12px' }}>
                                       {row.map((grapeIdx) => (
                                          <div key={grapeIdx} className={`w-12 h-12 rounded-full transition-all duration-700 transform border-2 relative ${grapeIdx < goal.currentCount ? 'bg-gradient-to-br from-pastel-purple to-purple-500 border-purple-400 shadow-[0_4px_10px_rgba(168,85,247,0.4)] scale-105 z-10' : 'bg-zinc-50 border-zinc-100 scale-95 opacity-60'}`}>
                                             {grapeIdx < goal.currentCount && <><div className="absolute inset-0 grape-shine opacity-80" /><div className="absolute top-1.5 left-2 w-3 h-3 bg-white/30 rounded-full blur-[1px]" /></>}
                                          </div>
                                       ))}
                                    </div>
                                 ))}
                              </div>
                           </div>

                           <button onClick={() => giveSticker(goal.id)} disabled={goal.isCompleted} className={`w-full py-5 rounded-3xl font-bold uppercase tracking-[0.2em] shadow-lg transition-all flex items-center justify-center gap-3 group ${goal.isCompleted ? 'bg-pastel-sand text-zinc-300' : 'bg-pastel-purple text-white hover:scale-[1.02] active:scale-95'}`}>
                              <Plus size={20} className="group-hover:rotate-90 transition-transform" /> 칭찬 스티커 한 알 붙이기
                           </button>
                        </div>
                      );
                   })}
                </div>
             </div>
           )}

           {harmonySubTab === 'CHORES' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {chores.map(chore => {
                   const user = users.find(u => u.id === chore.assignedToUserId);
                   return (
                     <div key={chore.id} className={`bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex items-center justify-between transition-all ${chore.isCompleted ? 'opacity-50' : ''}`}>
                        <div className="flex items-center gap-6">
                           <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-white font-bold shadow-md" style={{ backgroundColor: user?.color }}>{user?.avatar}</div>
                           <div><h4 className="text-base font-bold text-pastel-text mb-2">{chore.title}</h4><div className="flex items-center gap-3"><span className="text-[10px] font-bold text-zinc-300 bg-pastel-sand px-3 py-1 rounded-full uppercase tracking-widest">{chore.frequency}</span><span className="text-[10px] font-bold text-pastel-purple flex items-center gap-1"><Star size={12} /> {chore.points} pt</span></div></div>
                        </div>
                        <button onClick={() => toggleChore(chore.id)} className={`w-12 h-12 rounded-full border-2 flex items-center justify-center ${chore.isCompleted ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender'}`}><Check size={24} className={chore.isCompleted ? 'text-white' : 'text-zinc-200'} /></button>
                     </div>
                   );
                })}
             </div>
           )}

           {harmonySubTab === 'BUCKET' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 {bucketGoals.map(b => (
                    <div key={b.id} className="bg-white p-12 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 relative group overflow-hidden">
                       <div className="relative z-10 space-y-10">
                          <div><h4 className="text-2xl font-bold text-pastel-text mb-2">{b.title}</h4><p className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest">목표 금액: ₩{b.targetAmount.toLocaleString()}</p></div>
                          <div className="space-y-4">
                             <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden border border-pastel-lavender/10"><div className="h-full bg-pastel-purple rounded-full transition-all duration-1000" style={{ width: `${(b.currentAmount / b.targetAmount) * 100}%` }} /></div>
                             <div className="flex justify-between items-end"><span className="text-3xl font-bold tracking-tighter text-pastel-purple">{((b.currentAmount / b.targetAmount) * 100).toFixed(0)}%</span><span className="text-[12px] font-bold text-zinc-400">₩{b.currentAmount.toLocaleString()} 적립</span></div>
                          </div>
                       </div>
                    </div>
                 ))}
                 <button className="border-2 border-dashed border-pastel-lavender/40 rounded-[3.5rem] p-12 flex flex-col items-center justify-center text-zinc-300 hover:bg-pastel-sand/50 transition-all min-h-[350px]">
                   <div className="w-20 h-20 bg-pastel-sand rounded-full flex items-center justify-center mb-6"><Target size={48} /></div>
                   <span className="text-[11px] font-bold uppercase tracking-[0.2em]">새로운 꿈 설계하기</span>
                </button>
              </div>
           )}
        </div>
      )}

      {/* 5. DIARY (일기) */}
      {activeTab === 'DIARY' && (
        <div className="space-y-12 animate-in fade-in duration-700">
           <div className="flex justify-between items-center gap-6">
              <div><h2 className="text-3xl font-bold tracking-tighter">함께 기록하는 하루</h2><p className="text-xs text-zinc-400 mt-2 uppercase tracking-widest">돈으로 환산할 수 없는 우리의 소중한 순간들.</p></div>
              <button 
                onClick={() => {
                   const text = prompt('오늘의 소중한 순간을 한 문장으로 남겨주세요.');
                   if(text) addDiaryEntry(text);
                }} 
                className="bg-pastel-purple text-white px-10 py-4 rounded-3xl text-xs font-bold shadow-xl flex items-center gap-3 hover:scale-105 transition-all"
              >
                <PenLine size={18} /> 오늘 일기 쓰기
              </button>
           </div>
           <CalendarView currentDate={historyDate} transactions={[]} diaries={diaries} users={users} hideFinancials={true} onDateClick={() => {}} />
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {diaries.length === 0 ? (
                <div className="col-span-full py-32 text-center opacity-30 text-sm font-bold uppercase tracking-widest">기록된 일기가 없습니다.</div>
              ) : (
                diaries.map(d => (
                  <div key={d.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col group">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-10 h-10 rounded-2xl text-white flex items-center justify-center text-[11px] font-bold shadow-md" style={{ backgroundColor: users.find(u => u.id === d.userId)?.color }}>{users.find(u => u.id === d.userId)?.avatar}</div>
                        <div>
                          <span className="text-xs font-bold text-pastel-text">{users.find(u => u.id === d.userId)?.name}</span>
                          <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest block">{d.date}</span>
                        </div>
                    </div>
                    <p className="text-base font-medium leading-relaxed text-pastel-text/90 flex-1">{d.text}</p>
                    <div className="mt-8 pt-6 border-t border-pastel-sand flex justify-end">
                       <button className="text-rose-300 hover:text-rose-500 transition-colors"><Heart size={20} /></button>
                    </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {/* 공통 모달들 */}
      {selectedSummaryCategory && (
        <CategoryDetailModal category={selectedSummaryCategory} transactions={transactions.filter(t => t.categoryId === selectedSummaryCategory.id)} users={users} onClose={() => setSelectedSummaryCategory(null)} />
      )}
      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={addTransaction} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isBudgetModalOpen && (
        <BudgetSettingModal 
          categories={categories}
          users={users}
          transactions={transactions}
          onClose={() => setIsBudgetModalOpen(false)}
          onSave={(updated) => {
            setCategories(updated);
            setToast({ message: '예산 계획이 성공적으로 업데이트되었습니다.', type: 'success' });
          }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, Save, User as UserIcon, Plus, Trash2, Tag, Palette, BrainCircuit, RefreshCw, ChevronRight, AlertCircle, Sparkles, Activity } from 'lucide-react';
import { Category, TransactionType, User, Transaction } from '../types';
import { ICON_MAP } from '../App';
import { suggestCategoryBudget } from '../services/geminiService';

interface BudgetSettingModalProps {
  categories: Category[];
  users: User[];
  transactions: Transaction[];
  onClose: () => void;
  onSave: (updatedCategories: Category[]) => void;
}

export const BudgetSettingModal: React.FC<BudgetSettingModalProps> = ({ categories, users, transactions, onClose, onSave }) => {
  const [localCategories, setLocalCategories] = useState<Category[]>(categories);
  const [activeCategoryId, setActiveCategoryId] = useState<string | null>(
    categories.find(c => c.type === TransactionType.EXPENSE)?.id || null
  );
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  const activeCategory = useMemo(() => 
    localCategories.find(c => c.id === activeCategoryId),
    [localCategories, activeCategoryId]
  );

  const currentSpent = useMemo(() => {
    if (!activeCategory) return 0;
    return transactions
      .filter(t => t.categoryId === activeCategory.id && t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);
  }, [activeCategory, transactions]);

  // 실시간 입력값에 기반한 퍼센트 계산
  const percentage = useMemo(() => {
    if (!activeCategory || activeCategory.budgetLimit <= 0) return 0;
    return (currentSpent / activeCategory.budgetLimit) * 100;
  }, [activeCategory, currentSpent]);

  const getStatusColor = (p: number) => {
    if (p >= 100) return 'text-rose-600 bg-rose-600';
    if (p >= 85) return 'text-rose-500 bg-rose-500';
    if (p >= 60) return 'text-orange-400 bg-orange-400';
    return 'text-emerald-500 bg-emerald-500';
  };

  const getStatusText = (p: number) => {
    if (p >= 100) return '예산 초과';
    if (p >= 85) return '위험';
    if (p >= 60) return '주의';
    return '안전';
  };

  const handleGlobalLimitChange = (id: string, newLimit: string) => {
    // 숫자만 추출하여 실시간 상태 업데이트
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, budgetLimit: limit } : c));
  };

  const handleIndividualLimitChange = (catId: string, userId: string, newLimit: string) => {
    const limit = parseInt(newLimit.replace(/[^0-9]/g, ''), 10) || 0;
    setLocalCategories(prev => prev.map(c => {
      if (c.id !== catId) return c;
      return {
        ...c,
        individualLimits: {
          ...(c.individualLimits || {}),
          [userId]: limit
        }
      };
    }));
  };

  const handleUpdateCategoryField = (id: string, field: keyof Category, value: any) => {
    setLocalCategories(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const handleAddNewCategory = () => {
    const newId = `c_budget_${Date.now()}`;
    const newCat: Category = {
      id: newId,
      name: '새 예산 항목',
      group: '기타',
      type: TransactionType.EXPENSE,
      budgetLimit: 0,
      color: '#D4C6F0',
      iconId: 'other',
      individualLimits: {}
    };
    setLocalCategories(prev => [...prev, newCat]);
    setActiveCategoryId(newId);
  };

  const handleDeleteCategory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('이 예산 항목을 정말 삭제할까요?')) {
      setLocalCategories(prev => prev.filter(c => c.id !== id));
      if (activeCategoryId === id) {
        setActiveCategoryId(localCategories.find(c => c.id !== id)?.id || null);
      }
    }
  };

  const handleAiSuggestBudget = async (category: Category) => {
    setIsSuggesting(true);
    setAiMessage(null);
    try {
      const suggestion = await suggestCategoryBudget(category.name, transactions.filter(t => t.categoryId === category.id));
      handleGlobalLimitChange(category.id, suggestion.recommendedLimit.toString());
      setAiMessage(suggestion.reasoning);
    } catch (err) {
      alert('AI 추천에 실패했습니다.');
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSave = () => {
    onSave(localCategories);
    onClose();
  };

  const expenseCategories = localCategories.filter(c => c.type === TransactionType.EXPENSE);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-pastel-sand/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-5xl w-full max-w-5xl shadow-2xl border border-pastel-lavender/30 flex flex-col max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="p-8 border-b border-pastel-sand flex justify-between items-center bg-white/50">
          <div className="flex items-center gap-4">
             <div className="w-12 h-12 bg-pastel-purple/20 rounded-2xl flex items-center justify-center text-pastel-purple">
                <BrainCircuit size={24} />
             </div>
             <div>
                <h2 className="text-sm font-bold text-pastel-text uppercase tracking-widest">스마트 예산 설계</h2>
                <p className="text-[10px] text-zinc-400 mt-1">실시간으로 예산 적정성을 확인하고 계획하세요.</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-pastel-sand rounded-full transition-colors text-zinc-300">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Left List */}
          <div className="w-1/3 border-r border-pastel-sand bg-pastel-sand/10 flex flex-col">
            <div className="p-6 border-b border-pastel-sand/50">
               <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">지출 예산 리스트</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar">
              {expenseCategories.map(cat => (
                <button
                  key={cat.id}
                  onClick={() => { setActiveCategoryId(cat.id); setAiMessage(null); }}
                  className={`w-full text-left p-6 transition-all border-b border-pastel-sand/50 flex items-center justify-between group
                    ${activeCategoryId === cat.id ? 'bg-white border-r-4 border-r-pastel-purple shadow-sm' : 'hover:bg-white/50'}`}
                >
                  <div className="flex items-center gap-4 pr-6">
                    <div className="w-8 h-8 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: cat.color + '40', color: cat.color }}>
                       {React.createElement(ICON_MAP[cat.iconId] || ICON_MAP.other, { size: 16 })}
                    </div>
                    <div className="overflow-hidden">
                      <h4 className="text-[11px] font-bold text-pastel-text truncate">{cat.name}</h4>
                      <p className="text-[9px] text-zinc-400 font-bold tabular-nums">한도: {cat.budgetLimit.toLocaleString()}원</p>
                    </div>
                  </div>
                  <ChevronRight size={14} className={`transition-all ${activeCategoryId === cat.id ? 'text-pastel-purple translate-x-1' : 'text-zinc-200'}`} />
                </button>
              ))}
            </div>
            <div className="p-6 bg-white/50 border-t border-pastel-sand">
               <button onClick={handleAddNewCategory} className="w-full py-4 text-[10px] font-bold text-pastel-purple uppercase tracking-widest border-2 border-dashed border-pastel-purple/20 rounded-2xl hover:bg-pastel-purple hover:text-white transition-all">
                 + 항목 추가하기
               </button>
            </div>
          </div>

          {/* Right Content */}
          <div className="flex-1 p-10 overflow-y-auto custom-scrollbar bg-white">
            {activeCategory ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-right-4">
                {/* 실시간 프리뷰 영역 */}
                <div className="space-y-4">
                  <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest flex items-center gap-2">
                    <Activity size={12} /> 예산 상태 실시간 프리뷰
                  </label>
                  <div className="bg-pastel-sand/10 p-8 rounded-4xl border border-pastel-lavender/20 flex flex-col gap-6">
                    <div className="flex justify-between items-end">
                      <div className="space-y-1">
                        <span className={`text-[10px] font-bold uppercase tracking-[0.2em] px-3 py-1 rounded-full ${getStatusColor(percentage).split(' ')[0]} bg-white shadow-sm`}>
                          {getStatusText(percentage)}
                        </span>
                        <div className="text-4xl font-bold tracking-tighter tabular-nums text-pastel-text mt-2">
                          {percentage.toFixed(1)}% <span className="text-sm font-medium text-zinc-300 ml-1">사용 예정</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className="text-[9px] font-bold text-zinc-300 uppercase block mb-1">현재 소비액 / 입력 한도</span>
                        <div className="text-base font-bold tabular-nums text-pastel-text">
                          {currentSpent.toLocaleString()} / <span className="text-pastel-purple">{activeCategory.budgetLimit.toLocaleString()}</span> 원
                        </div>
                      </div>
                    </div>

                    <div className="h-5 w-full bg-pastel-sand/50 rounded-full overflow-hidden relative border border-white">
                      <div 
                        className={`h-full transition-all duration-700 ease-[cubic-bezier(0.34,1.56,0.64,1)] rounded-full ${getStatusColor(percentage).split(' ')[1]}`}
                        style={{ width: `${Math.min(percentage, 100)}%` }}
                      >
                        <div className="w-full h-full grape-shine opacity-30" />
                      </div>
                    </div>
                  </div>
                </div>

                {/* 입력 폼 */}
                <div className="grid grid-cols-2 gap-10">
                   <div className="space-y-10">
                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">지출 한도 금액</label>
                        <div className="relative border-b-2 border-pastel-sand focus-within:border-pastel-purple transition-colors pb-2">
                          <input 
                            type="text" 
                            value={activeCategory.budgetLimit.toLocaleString()} 
                            onChange={(e) => handleGlobalLimitChange(activeCategory.id, e.target.value)}
                            className="w-full text-4xl font-bold text-pastel-text outline-none bg-transparent tabular-nums" 
                            placeholder="0"
                          />
                          <span className="absolute right-0 bottom-2 text-xs font-bold text-zinc-300 uppercase">원</span>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">카테고리 정보</label>
                        <div className="flex flex-col gap-3">
                           <input 
                             type="text" 
                             value={activeCategory.name}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'name', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl outline-none"
                             placeholder="항목 명칭"
                           />
                           <input 
                             type="text" 
                             value={activeCategory.group}
                             onChange={(e) => handleUpdateCategoryField(activeCategory.id, 'group', e.target.value)}
                             className="w-full p-4 bg-pastel-sand/30 text-sm font-bold rounded-2xl outline-none"
                             placeholder="그룹 명칭"
                           />
                        </div>
                      </div>
                   </div>

                   <div className="space-y-10">
                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">구성원별 분배</label>
                        <div className="space-y-3">
                          {users.map(user => (
                            <div key={user.id} className="flex items-center justify-between p-4 bg-pastel-sand/20 rounded-2xl border border-transparent hover:border-pastel-lavender/30 transition-all">
                              <div className="flex items-center gap-3">
                                <div className="w-7 h-7 rounded-full text-white flex items-center justify-center text-[9px] font-bold" style={{ backgroundColor: user.color }}>{user.avatar}</div>
                                <span className="text-xs font-bold text-pastel-text">{user.name}</span>
                              </div>
                              <div className="relative w-32">
                                <input 
                                  type="text" 
                                  value={activeCategory.individualLimits?.[user.id]?.toLocaleString() || ''}
                                  onChange={(e) => handleIndividualLimitChange(activeCategory.id, user.id, e.target.value)}
                                  placeholder="미설정"
                                  className="w-full text-right font-bold text-sm bg-transparent outline-none pr-5 tabular-nums"
                                />
                                <span className="absolute right-0 top-0.5 text-[8px] font-bold text-zinc-300">원</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">비주얼 스타일</label>
                        <div className="flex flex-wrap gap-2">
                          {['#F9E2E6', '#F7D1BA', '#FAF3DD', '#D1E8E2', '#E8E4F8', '#D4C6F0', '#E2F0EB'].map(color => (
                            <button
                              key={color}
                              onClick={() => handleUpdateCategoryField(activeCategory.id, 'color', color)}
                              className={`w-9 h-9 rounded-xl border-2 transition-all ${activeCategory.color === color ? 'border-pastel-purple scale-110 shadow-sm' : 'border-transparent'}`}
                              style={{ backgroundColor: color }}
                            />
                          ))}
                        </div>
                      </div>
                   </div>
                </div>

                {/* AI 추천 버튼 */}
                <div className="bg-gradient-to-r from-pastel-purple/10 to-transparent p-8 rounded-4xl border border-pastel-purple/20 flex flex-col md:flex-row items-center gap-6">
                   <div className="w-14 h-14 bg-white rounded-3xl flex items-center justify-center text-pastel-purple shadow-sm shrink-0"><Sparkles size={24} /></div>
                   <div className="flex-1">
                      <h4 className="text-sm font-bold text-pastel-text">AI 한도 추천</h4>
                      <p className="text-[11px] text-zinc-400 font-medium leading-relaxed mt-1">
