                     className="bg-white text-pastel-purple border border-pastel-purple px-6 py-4 rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-pastel-purple hover:text-white transition-all flex items-center gap-2 disabled:opacity-50"
                   >
                     {isSuggesting ? <RefreshCw size={14} className="animate-spin" /> : <BrainCircuit size={14} />} AI 제안받기
