                   currentDate={historyDate} 
                   transactions={transactions} 
                   onDateClick={setSelectedWalletDate} 
                 />

                 <div className="bg-white rounded-[3.5rem] p-10 soft-shadow border border-pastel-lavender/20">
                    <div className="flex justify-between items-center mb-10">
                       <h3 className="text-base font-bold text-pastel-text flex items-center gap-3">
                         <List size={20} className="text-pastel-purple" /> 
                         {selectedWalletDate ? `${selectedWalletDate} 상세 내역` : '월간 전체 내역'}
                       </h3>
                       {selectedWalletDate && (
                         <button onClick={() => setSelectedWalletDate(null)} className="text-[10px] font-bold text-pastel-purple uppercase tracking-widest border border-pastel-purple/20 px-4 py-2 rounded-xl hover:bg-pastel-purple/5 transition-all">전체 내역 보기</button>
                       )}
                    </div>
                    <div className="space-y-10">
                      {filteredTransactions.length === 0 ? (
                        <div className="py-20 text-center opacity-30 text-xs font-bold uppercase tracking-widest">기록된 내역이 없습니다.</div>
                      ) : (
                        filteredTransactions.map(t => {
                          const cat = categories.find(c => c.id === t.categoryId);
                          const user = users.find(u => u.id === t.userId);
                          return (
                            <div key={t.id} className="flex items-center justify-between group">
                               <div className="flex items-center gap-6">
                                  <div className="w-12 h-12 rounded-2xl flex items-center justify-center" style={{ backgroundColor: cat?.color + '40', color: cat?.color }}>{renderCategoryIcon(cat?.iconId || 'other', 20)}</div>
                                  <div>
                                     <div className="flex items-center gap-2 mb-1">
                                        <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{t.date}</span>
                                        <span className="text-[9px] font-bold text-pastel-purple uppercase bg-pastel-purple/5 px-2 rounded-full">{user?.name}</span>
                                     </div>
                                     <p className="text-sm font-bold text-pastel-text">{t.description}</p>
                                  </div>
                               </div>
                               <p className={`text-lg font-bold tabular-nums tracking-tighter ${t.type === TransactionType.INCOME ? 'text-emerald-500' : 'text-pastel-text'}`}>
                                  {t.type === TransactionType.INCOME ? '+' : '-'} {t.amount.toLocaleString()}
                               </p>
                            </div>
                          );
                        })
                      )}
                    </div>
                 </div>
              </div>
           )}

           {walletSubTab === 'BUDGET' && (
             <div className="space-y-8">
               <div className="flex justify-end px-2">
                 <button 
                   onClick={() => setIsBudgetModalOpen(true)}
                   className="flex items-center gap-2 bg-white px-6 py-3 rounded-2xl text-[10px] font-bold text-pastel-purple uppercase tracking-widest soft-shadow border border-pastel-lavender/30 hover:border-pastel-purple transition-all"
                 >
                   <Settings size={14} /> 예산 계획 수정하기
                 </button>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {budgetStatuses.map(status => (
                     <BudgetCard key={status.categoryId} category={categories.find(c => c.id === status.categoryId)!} status={status} users={users} />
                  ))}
               </div>
             </div>
           )}

           {walletSubTab === 'SUBS' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {subscriptions.map(s => (
                  <div key={s.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col items-center text-center group">
                     <div className="w-20 h-20 bg-pastel-sand rounded-[2rem] flex items-center justify-center text-pastel-purple mb-8 group-hover:scale-110 transition-transform">{renderCategoryIcon(s.iconId, 32)}</div>
                     <h4 className="text-base font-bold text-pastel-text mb-2">{s.name}</h4>
                     <p className="text-sm font-bold text-pastel-purple mb-6">{s.amount.toLocaleString()}원 / 월</p>
                     <div className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest bg-pastel-sand px-4 py-2 rounded-full">Day {s.billingDate}</div>
                  </div>
                ))}
             </div>
           )}
        </div>
      )}

      {/* 3. LIFE (생활) */}
      {activeTab === 'LIFE' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex flex-col">
                <h3 className="text-xl font-bold flex items-center gap-3 mb-8"><ShoppingBag size={24} className="text-pastel-purple" /> 오늘 사야 할 것</h3>
                <div className="flex gap-3 mb-8">
                   <input type="text" placeholder="품목 입력..." className="flex-1 p-4 bg-pastel-sand/30 rounded-2xl outline-none" onKeyDown={(e) => { if(e.key === 'Enter') { addShoppingItem(e.currentTarget.value); e.currentTarget.value = ''; } }} />
                   <button className="bg-pastel-purple text-white w-12 h-12 rounded-2xl flex items-center justify-center shadow-lg"><Plus size={24} /></button>
                </div>
                <div className="space-y-3 flex-1 overflow-y-auto max-h-[500px] custom-scrollbar pr-2">
                   {shoppingItems.map(item => (
                     <div key={item.id} className={`flex items-center justify-between p-5 rounded-3xl border transition-all ${item.isBought ? 'bg-pastel-sand/20 border-transparent opacity-50' : 'bg-white border-pastel-lavender/10 soft-shadow'}`}>
                        <div className="flex items-center gap-4">
                           <button onClick={() => setShoppingItems(prev => prev.map(i => i.id === item.id ? { ...i, isBought: !i.isBought } : i))} className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${item.isBought ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender'}`}>
                             {item.isBought && <Check size={14} className="text-white" />}
                           </button>
                           <span className={`text-sm font-bold ${item.isBought ? 'line-through text-zinc-300' : 'text-pastel-text'}`}>{item.text}</span>
                        </div>
                        <button onClick={() => setShoppingItems(prev => prev.filter(i => i.id !== item.id))} className="text-zinc-200 hover:text-rose-400"><Trash2 size={16} /></button>
                     </div>
                   ))}
                </div>
              </div>

              <div className="bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex flex-col">
                <h3 className="text-xl font-bold flex items-center gap-3 mb-8"><ClipboardList size={24} className="text-rose-300" /> 필수 생활 용품</h3>
                <div className="space-y-4 flex-1 overflow-y-auto max-h-[500px] custom-scrollbar pr-2">
                   {essentialItems.map(item => (
                     <div key={item.id} className={`flex items-center justify-between p-6 rounded-[2.5rem] border ${item.isStocked ? 'bg-white border-pastel-lavender/10 soft-shadow' : 'bg-rose-50/50 border-rose-100'}`}>
                        <div className="flex items-center gap-5">
                           <button onClick={() => toggleEssentialStatus(item.id)} className={`w-10 h-10 rounded-2xl flex items-center justify-center ${item.isStocked ? 'bg-pastel-mint text-emerald-600' : 'bg-rose-100 text-rose-500'}`}>
                             {item.isStocked ? <PackageCheck size={20} /> : <AlertCircle size={20} />}
                           </button>
                           <div>
                              <span className="text-base font-bold text-pastel-text">{item.text}</span>
                              <span className={`text-[9px] font-bold uppercase block mt-1 ${item.isStocked ? 'text-emerald-500' : 'text-rose-500'}`}>
                                {item.isStocked ? '충분함' : '부족함'}
                              </span>
                           </div>
                        </div>
                     </div>
                   ))}
                </div>
              </div>
           </div>
        </div>
      )}

      {/* 4. HARMONY (하모니) */}
      {activeTab === 'HARMONY' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="flex bg-pastel-sand p-1.5 rounded-3xl soft-shadow w-fit mx-auto md:mx-0">
              {[
                { id: 'CHORES', label: '가사 분담', icon: Utensils },
                { id: 'PRAISE', label: '칭찬 보드', icon: Heart },
                { id: 'BUCKET', label: '꿈의 목표', icon: Target }
              ].map(t => (
                <button key={t.id} onClick={() => setHarmonySubTab(t.id as any)} className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-bold tracking-widest uppercase transition-all ${harmonySubTab === t.id ? 'bg-white text-pastel-purple shadow-sm' : 'text-zinc-400 hover:text-zinc-500'}`}>
                  <t.icon size={14} /> {t.label}
                </button>
              ))}
           </div>

           {harmonySubTab === 'PRAISE' && (
             <div className="space-y-10">
                <div className="flex flex-col items-center text-center mb-10">
                   <div className="inline-flex p-4 bg-rose-50 text-rose-400 rounded-full mb-4 shadow-inner"><Heart size={32} fill="currentColor" /></div>
                   <h2 className="text-2xl font-bold text-pastel-text">추억의 포도송이 칭찬 보드</h2>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                   {stickerGoals.map(goal => {
                      const user = users.find(u => u.id === goal.assignedToUserId);
                      const rows = (target: number) => {
                         const r = []; let c = 0; let s = 1; let sum = 0;
                         while (sum < target) { s++; sum = 0; for(let i=0; i<s; i++) sum += (s-i); }
                         let rem = target; let curS = s;
                         while(rem > 0) { const sz = Math.min(curS, rem); r.push(Array.from({length: sz}, () => c++)); rem -= sz; curS--; if(curS <= 0 && rem > 0) curS = 1; }
                         return r;
                      };
                      return (
                        <div key={goal.id} className="bg-white p-12 rounded-[4rem] soft-shadow border border-pastel-lavender/20 flex flex-col items-center relative overflow-hidden group">
                           {goal.isCompleted && (
                              <div className="absolute inset-0 bg-yellow-400/5 backdrop-blur-[1px] flex items-center justify-center z-20 animate-in fade-in duration-1000">
                                 <div className="p-8 bg-white/90 rounded-full shadow-2xl flex flex-col items-center scale-110">
                                    <PartyPopper size={48} className="text-yellow-500 mb-2" />
                                    <span className="text-sm font-bold text-pastel-text uppercase tracking-widest">Mission Complete!</span>
                                 </div>
                              </div>
                           )}
                           <div className="w-full flex justify-between items-start mb-6 relative z-10">
                              <div className="flex items-center gap-4">
                                 <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-sm shadow-md" style={{ backgroundColor: user?.color }}>{user?.avatar}</div>
                                 <div><h4 className="text-base font-bold text-pastel-text mb-1">{goal.title}</h4><span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest">{user?.name}의 포도송이</span></div>
                              </div>
                              <div className="bg-pastel-sand px-4 py-1.5 rounded-full text-[10px] font-bold text-pastel-purple tabular-nums">{goal.currentCount} / {goal.targetCount} 알</div>
                           </div>

                           <div className="relative mb-12 flex flex-col items-center w-full min-h-[300px] justify-center">
                              <div className="absolute top-0 left-1/2 -translate-x-1/2 flex flex-col items-center">
                                 <div className="w-1.5 h-10 bg-emerald-800/40 rounded-full mb-[-10px]" />
                                 <div className="flex gap-2"><div className="w-10 h-6 bg-emerald-600/20 rounded-[50%_50%_10%_10%] rotate-[-25deg]" /><div className="w-10 h-6 bg-emerald-600/30 rounded-[50%_50%_10%_10%] rotate-[25deg]" /></div>
                              </div>
                              <div className="mt-8 flex flex-col items-center">
                                 {rows(goal.targetCount).map((row, rowIdx) => (
                                    <div key={rowIdx} className="flex justify-center gap-1.5" style={{ marginTop: rowIdx === 0 ? '0' : '-12px' }}>
                                       {row.map((grapeIdx) => (
                                          <div key={grapeIdx} className={`w-12 h-12 rounded-full transition-all duration-700 transform border-2 relative ${grapeIdx < goal.currentCount ? 'bg-gradient-to-br from-pastel-purple to-purple-500 border-purple-400 shadow-[0_4px_10px_rgba(168,85,247,0.4)] scale-105 z-10' : 'bg-zinc-50 border-zinc-100 scale-95 opacity-60'}`}>
                                             {grapeIdx < goal.currentCount && <><div className="absolute inset-0 grape-shine opacity-80" /><div className="absolute top-1.5 left-2 w-3 h-3 bg-white/30 rounded-full blur-[1px]" /></>}
                                          </div>
                                       ))}
                                    </div>
                                 ))}
                              </div>
                           </div>

                           <button onClick={() => giveSticker(goal.id)} disabled={goal.isCompleted} className={`w-full py-5 rounded-3xl font-bold uppercase tracking-[0.2em] shadow-lg transition-all flex items-center justify-center gap-3 group ${goal.isCompleted ? 'bg-pastel-sand text-zinc-300' : 'bg-pastel-purple text-white hover:scale-[1.02] active:scale-95'}`}>
                              <Plus size={20} className="group-hover:rotate-90 transition-transform" /> 칭찬 스티커 한 알 붙이기
                           </button>
                        </div>
                      );
                   })}
                </div>
             </div>
           )}

           {harmonySubTab === 'CHORES' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {chores.map(chore => {
                   const user = users.find(u => u.id === chore.assignedToUserId);
                   return (
                     <div key={chore.id} className={`bg-white p-10 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 flex items-center justify-between transition-all ${chore.isCompleted ? 'opacity-50' : ''}`}>
                        <div className="flex items-center gap-6">
                           <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-white font-bold shadow-md" style={{ backgroundColor: user?.color }}>{user?.avatar}</div>
                           <div><h4 className="text-base font-bold text-pastel-text mb-2">{chore.title}</h4><div className="flex items-center gap-3"><span className="text-[10px] font-bold text-zinc-300 bg-pastel-sand px-3 py-1 rounded-full uppercase tracking-widest">{chore.frequency}</span><span className="text-[10px] font-bold text-pastel-purple flex items-center gap-1"><Star size={12} /> {chore.points} pt</span></div></div>
                        </div>
                        <button onClick={() => toggleChore(chore.id)} className={`w-12 h-12 rounded-full border-2 flex items-center justify-center ${chore.isCompleted ? 'bg-pastel-purple border-pastel-purple' : 'border-pastel-lavender'}`}><Check size={24} className={chore.isCompleted ? 'text-white' : 'text-zinc-200'} /></button>
                     </div>
                   );
                })}
             </div>
           )}

           {harmonySubTab === 'BUCKET' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 {bucketGoals.map(b => (
                    <div key={b.id} className="bg-white p-12 rounded-[3.5rem] soft-shadow border border-pastel-lavender/20 relative group overflow-hidden">
                       <div className="relative z-10 space-y-10">
                          <div><h4 className="text-2xl font-bold text-pastel-text mb-2">{b.title}</h4><p className="text-[11px] font-bold text-zinc-300 uppercase tracking-widest">목표 금액: ₩{b.targetAmount.toLocaleString()}</p></div>
                          <div className="space-y-4">
                             <div className="h-4 w-full bg-pastel-sand/50 rounded-full overflow-hidden border border-pastel-lavender/10"><div className="h-full bg-pastel-purple rounded-full transition-all duration-1000" style={{ width: `${(b.currentAmount / b.targetAmount) * 100}%` }} /></div>
                             <div className="flex justify-between items-end"><span className="text-3xl font-bold tracking-tighter text-pastel-purple">{((b.currentAmount / b.targetAmount) * 100).toFixed(0)}%</span><span className="text-[12px] font-bold text-zinc-400">₩{b.currentAmount.toLocaleString()} 적립</span></div>
                          </div>
                       </div>
                    </div>
                 ))}
              </div>
           )}
        </div>
      )}

      {/* 5. DIARY (일기) */}
      {activeTab === 'DIARY' && (
        <div className="space-y-12 animate-in fade-in duration-700">
           <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div><h2 className="text-3xl font-bold tracking-tighter">함께 기록하는 하루</h2><p className="text-xs text-zinc-400 mt-2 uppercase tracking-widest">소중한 순간들을 남겨보세요.</p></div>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-6 bg-white px-6 py-3 rounded-3xl soft-shadow border border-pastel-lavender/30">
                  <button onClick={() => changeMonth(-1)} className="text-zinc-300 hover:text-pastel-purple transition-colors"><ChevronLeft size={20} /></button>
                  <span className="text-xs font-bold text-pastel-text min-w-[100px] text-center">{historyDate.getFullYear()}년 {historyDate.getMonth() + 1}월</span>
                  <button onClick={() => changeMonth(1)} className="text-zinc-300 hover:text-pastel-purple transition-colors"><ChevronRight size={20} /></button>
                </div>
                <button 
                  onClick={() => { const text = prompt('오늘의 소중한 순간을 남겨주세요.'); if(text) addDiaryEntry(text); }} 
                  className="bg-pastel-purple text-white px-10 py-4 rounded-3xl text-xs font-bold shadow-xl flex items-center gap-3 hover:scale-105 transition-all"
                >
                  <PenLine size={18} /> 오늘 일기 쓰기
                </button>
              </div>
           </div>
           <CalendarView currentDate={historyDate} transactions={[]} diaries={diaries} users={users} hideFinancials={true} onDateClick={() => {}} />
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {diaries.length === 0 ? (
                <div className="col-span-full py-32 text-center opacity-30 text-sm font-bold uppercase tracking-widest">기록된 일기가 없습니다.</div>
              ) : (
                diaries.map(d => (
                  <div key={d.id} className="bg-white p-10 rounded-[3rem] soft-shadow border border-pastel-lavender/20 flex flex-col group">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-10 h-10 rounded-2xl text-white flex items-center justify-center text-[11px] font-bold shadow-md" style={{ backgroundColor: users.find(u => u.id === d.userId)?.color }}>{users.find(u => u.id === d.userId)?.avatar}</div>
                        <div>
                          <span className="text-xs font-bold text-pastel-text">{users.find(u => u.id === d.userId)?.name}</span>
                          <span className="text-[10px] font-bold text-zinc-300 uppercase tracking-widest block">{d.date}</span>
                        </div>
                    </div>
                    <p className="text-base font-medium leading-relaxed text-pastel-text/90 flex-1">{d.text}</p>
                    <div className="mt-8 pt-6 border-t border-pastel-sand flex justify-end">
                       <button className="text-rose-300 hover:text-rose-500 transition-colors"><Heart size={20} /></button>
                    </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {/* 모달 */}
      {selectedSummaryCategory && (
        <CategoryDetailModal category={selectedSummaryCategory} transactions={transactions.filter(t => t.categoryId === selectedSummaryCategory.id)} users={users} onClose={() => setSelectedSummaryCategory(null)} />
      )}
      {isAddModalOpen && (
        <TransactionForm onClose={() => setIsAddModalOpen(false)} onSubmit={addTransaction} categories={categories} users={users} currentUser={currentUser} />
      )}
      {isBudgetModalOpen && (
        <BudgetSettingModal 
          categories={categories} users={users} transactions={transactions} 
          onClose={() => setIsBudgetModalOpen(false)} 
          onSave={(updated) => { setCategories(updated); setToast({ message: '예산 계획이 업데이트되었습니다.', type: 'success' }); }} 
        />
      )}
    </Layout>
  );
};

export default App;

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  group: string;
  type: TransactionType;
  budgetLimit: number;
  individualLimits?: Record<string, number>;
  color: string;
  iconId: string;
}

export interface GeoLocation {
  lat: number;
  lng: number;
  address?: string;
}

export interface Comment {
  id: string;
  userId: string;
  text: string;
  date: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  categoryId: string;
  userId: string;
  date: string;
  description: string;
  photoUrl?: string;
  location?: GeoLocation;
  likes?: string[];
  dislikes?: string[];
  comments?: Comment[];
}

export interface DiaryEntry {
  id: string;
  date: string;
  userId: string;
  text: string;
  reactions: string[];
  title?: string;
}

export interface ScheduleEntry {
  id: string;
  userId: string;
  date: string;
  time?: string;
  title: string;
  description?: string;
  isCompleted: boolean;
  category: 'PRIVATE' | 'SHARED' | 'IMPORTANT';
}

export interface FixedExpense {
  id: string;
  description: string;
  amount: number;
  categoryId: string;
  userId: string;
  dayOfMonth: number;
  lastProcessedMonth?: string;
}

export interface StickerGoal {
  id: string;
  title: string;
  targetCount: number;
  currentCount: number;
  assignedToUserId: string;
  createdByUserId: string;
  isCompleted: boolean;
}

export interface BudgetStatus {
  categoryId: string;
  spent: number;
  limit: number;
  percentage: number;
  status: 'SAFE' | 'WARNING' | 'DANGER' | 'EXCEEDED';
  individualStatus?: Record<string, { spent: number; limit: number; percentage: number }>;
}

export interface FinancialAdvice {
  advice: string;
  summary: string;
  prediction: string;
}

// --- NEW LIFESTYLE TYPES ---

export interface ShoppingItem {
  id: string;
  text: string;
  isBought: boolean;
  addedByUserId: string;
}

export interface EssentialItem {
  id: string;
  text: string;
  isStocked: boolean;
  addedByUserId: string;
}

export interface Subscription {
  id: string;
  name: string;
  amount: number;
  billingDate: number;
  userId: string;
  isShared: boolean;
  iconId: string;
}

export interface Chore {
  id: string;
  title: string;
  assignedToUserId: string;
  isCompleted: boolean;
  frequency: 'DAILY' | 'WEEKLY' | 'MONTHLY';
  points: number;
}

export interface BucketGoal {
  id: string;
  title: string;
  targetAmount: number;
  currentAmount: number;
  deadline?: string;
  isCompleted: boolean;
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  ChevronLeft, ChevronRight, Plus, X, Heart, Calendar as CalendarIcon, 
  List, PieChart, Activity, Sparkles, Repeat, BrainCircuit, RefreshCw, 
  Trash2, BookHeart, PenLine, Check, LayoutPanelLeft, ShoppingBag, 
