  const [walletSubTab, setWalletSubTab] = useState<'SUMMARY' | 'LIST' | 'BUDGET' | 'SUBS'>('SUMMARY');
  const [harmonySubTab, setHarmonySubTab] = useState<'CHORES' | 'PRAISE' | 'BUCKET'>('CHORES');
